/* characters q20 (136 mục) — R2.6 bồi tiểu sử Đạo Cổ Hoàng */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q20"]=window.__LIBQ["tien-nghich"]["q20"]||{};window.__LIBQ["tien-nghich"]["q20"]["characters"]={"updatedAt":"2026-07-16","count":136,"chars":[{"id":"vuong-lam","name":"Vương Lâm","aliases":["Bạch Phát Dược Thiên Tôn","Lục Mặc"],"canhGioiCaoNhat":"Bạch Phát Dược Thiên Tôn, Tam cổ cửu tinh đã dung hợp hai mươi bảy tinh, có mười giọt máu Cổ Tổ gồm Hồn Huyết (@c1908)","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Sau một năm xông Thiên Tôn Niết, Vương Lâm được toàn Tiên Tộc biết đến với danh Bạch Phát Dược Thiên Tôn, là Dược Thiên Tôn thứ bốn mươi chín và được xem là mạnh nhất dưới Đại Thiên Tôn. Danh tiếng của hắn thay thế Minh Đạo Tôn, kéo theo vô số lời đồn về Hồn Khải, sinh linh thiên ngoại, việc cự tuyệt các Đại Thiên Tôn và lựa chọn Song Tử. Hắn ở Tử Dương Tông tiếp các Dược Thiên Tôn tới luận đạo, rồi phần lớn thời gian ngồi bên Tự Thú Giới cảm nhận màn ngăn với quê hương trong động phủ giới và biết mình nên rời đi.","anchor":"Người này mái tóc bạc trắng nên mới được gọi là Bạch Phát Dược Thiên Tôn","bridge":true,"khoang":"@c1866"},{"mucCt":"ky","text":"Sau một năm yên lặng ở Tử Dương Tông, khí tức quê hương giúp mộc bổn nguyên trong cơ thể Vương Lâm đại thành, gần tới mức ngưng tụ bổn nguyên chân thân. Lôi đình chân thân của hắn đã viên mãn từ khi dung nhập bổn nguyên đặc thù ở Đông Lâm Tông, ngũ hành chân thân chỉ còn thiếu kim bổn nguyên, và hắn biết nếu có thêm mảnh vỡ Tiên Cực Kiếm thì kim bổn nguyên sẽ đại thành, đẩy tu vi từ Không Kiếp trung kỳ tới Kim Tôn Không Kiếp hậu kỳ. Ngoài sinh tử, nhân quả, chân giả, hắn còn hiểu ra một tia luân hồi bổn nguyên, như vừa mở một cánh cửa mới cần cảm ngộ thêm. Hắn dùng súc địa thành thốn mang Lưu Kim Bưu và Hải Long rời Đông Châu, mang theo ngọc giản Cô Nhai giao để khi gặp nguy cơ không giải quyết được ở Trung Châu thì Oa Oa, Hàm Hàm biết và Song Tử Đại Thiên Tôn ra tay trợ giúp. Vài tháng sau, trong tuyết đầu mùa, hắn mặc bạch y đội mũ che mặt tới ngoài Đông môn Tổ Thành, đệ nhất hùng thành của Tiên Cương đại lục, tự nói Vương mỗ đã tới. Dù biết nơi này nguy hiểm, hắn vẫn tới vì muốn gặp lại người điên từng có ân và cùng hắn Mộng Đạo ở Chu Tước Tinh, xem chuyến đi như lần cuối đứng trên mặt đất Tiên Tộc để không còn tiếc nuối. Bước qua Đông môn giữa tiên uy nồng đậm, thấy mọi tu sĩ đều đi bộ như phàm nhân và cả Thiên Tôn cũng phải tuân theo ước định của thành, hắn lạnh lùng phủ định rằng điều đó không gồm có hắn.","anchor":"Giữa tiếng bước chân loạt xoạt trên tuyết, Vương Lâm tiến vào bên trong cửa đông","bridge":true,"khoang":"@c1867"},{"mucCt":"ky","text":"Vương Lâm vào Đông Thành, thuê một gian phòng có tiên khí và cấm chế để tạm nghỉ, rồi cho Lưu Kim Bưu mang Hải Long đi tìm Hứa Lập Quốc. Một mình uống rượu trong gió tuyết, hắn nhớ tới Liên Đạo Phi và chuyện trong động phủ giới. Sau đó hắn phá đòn tập kích của tu sĩ Lý gia bằng một chỉ, suy đoán cây cung Lý Quảng trong thân thể khiến Lý gia cảm ứng được, không truy sát vì chưa có thù oán, rồi phát hiện Hứa Lập Quốc bị phong ấn và chuyển hướng xử lý việc Lý Phủ tiếp tục vượt quá giới hạn.","anchor":"hẳn là cây cung của Lý Quảng trong thân thể ta có quan hệ với Lý gia","bridge":true,"khoang":"@c1868"},{"mucCt":"ky","text":"Vương Lâm hiện thân trên đường Đông Thành, chỉ bằng ánh mắt kim quang đã hủy mũi tên truy sát và đánh ngất xạ thủ áo đen. Hắn chữa lành Hải Long, bóp nát mũi tên đen, đọc thần thức xạ thủ để lấy tin tức rồi đưa Lưu Kim Bưu, Hải Long và xạ thủ tới trước Lý Phủ. Khi vào phủ, hắn phá song sư trấn môn, dùng chưởng ấn đánh tan mưa tên của mấy trăm cung thủ và điểm một chỉ khiến đợt tiễn trận kế tiếp đứng im giữa không trung.","anchor":"Thần thức ngưng tụ lại, dung hợp vào thiên linh của người này","bridge":true,"khoang":"@c1869"},{"mucCt":"ky","anchor":"Giờ phút này kim quang trong hai mắt Vương Lâm chính là lực lượng, là oai nghiêm của Tiên Cực Kiếm, trấn áp thiên địa vạn vật!","text":"Vương Lâm nhìn thấu thế trận cung tiễn và ba cao thủ ẩn giấu của Lý Phủ, cảnh cáo họ không được tiếp tục bắn tên. Hắn dùng kim quang mang uy áp Tiên Cực Kiếm phá hủy hàng loạt cung, ép lộ thạch thất và công khai thân phận Bạch Phát Dược Thiên Tôn. Sau khi lão tổ Lý gia nhận lỗi, hắn nhận lời lưu lại Tiễn Các xem Tiễn Đạo, hứa sau này gửi trả cung Lý Quảng, rồi lạnh nhạt nghe thánh chỉ sắc phong yêu cầu bảy ngày sau tới Tiên Đạo Điện.","bridge":true,"khoang":"@c1870"},{"mucCt":"ky","text":"Vương Lâm xuất hiện tại đệ nhất môn trong lễ sắc phong, áo trắng tóc bạc, thần sắc bình tĩnh nhưng lộ tang thương qua nếp nhăn nơi đuôi mắt. Khi cửu môn dùng sát khí của mười vạn hắc giáp cấm binh ép tới, hắn vận sát lục lôi đình lực từ lôi đình bổn nguyên chân thân để đẩy lui hắc quang quanh thân. Trước hư ảnh mãnh hổ màu đen, hắn kích hoạt ký hiệu Thiên Ngưu Hồn và Hồn Khải, đánh một quyền làm hư ảnh tan nát, phá thông đạo đen của tám cửa còn lại, khiến cấm binh phun máu lui lại nhưng không chết. Hắn đi tới trước Tiên Đạo Điện, ánh mắt khiến lão thanh y hoảng sợ lui lại rồi lạnh lùng quát lão cũng phải lui ra.","anchor":"Ở nơi đó, Vương Lâm chắp tay sau lưng, gió buổi sớm thổi tung y phục và mái tóc bạc của hắn","bridge":true,"khoang":"@c1871"},{"mucCt":"ky","text":"Vương Lâm ném lão già mặc thanh y khỏi sân rộng trước Tiên Đạo Điện, rồi giữ lễ bái kiến Tiên Hoàng để tiếp tục đại lễ sắc phong. Trong nghi thức, hắn nhận ra sự đáng ngại của Thượng Huyền Đạo quốc sư qua ánh mắt như kéo mình vào luân hồi, đồng thời chứng kiến Tiên Hoàng dùng Cực Hỏa Đạo diệt Thiên Sư Thú. Khi sợi tóc bạc còn sót lại sau biển lửa khiến hắn có cảm giác quen thuộc, hắn lập tức lao lên chụp lấy trước mặt Tiên Hoàng và cảm tạ như nhận bảo vật được ban.","anchor":"- Vương Lâm bái kiến Tiên Hoàng!","bridge":true,"khoang":"@c1872"},{"mucCt":"ky","text":"Vương Lâm nhận sợi tóc bạc trong đại lễ sắc phong và cảm thấy nó quen thuộc như một bộ phận thân thể mình. Khi bị lão tổ một vương phủ khiêu chiến, hắn kích phát Thiên Ngưu Hồn Khải, dùng một quyền phá bóng đen rồi thi triển Thiên Ngưu Chàng đánh tan bóng đen cùng chiến mã do đối phương hiến tế thọ nguyên ngưng tụ. Sau đó hắn cảm nhận đạo pháp đáng sợ của Thượng Huyền Đạo quốc sư và cuối chương nhận ra thanh niên mặc hoa sam chính là người điên mà mình muốn gặp ở Tổ Thành.","anchor":"Hình dạng của đối phương đã thay đổi nhưng hắn liếc mắt một cái là nhận ra đó chính là người điên!","bridge":true,"khoang":"@c1873"},{"text":"Vương Lâm được Đạo Phi nhận nhầm là ân công, hạ xuống đối diện và gọi hắn là Người điên. Khi nhận ra Đạo Phi không còn ký ức về mình trong động phủ giới, hắn nhắm mắt bi thương dù bị Đạo Phi bóp cổ.","anchor":"Vương Lâm nhắm mắt lại, trong mắt ẩn chứa một vẻ bi thương","mucCt":"vua","bridge":true,"khoang":"@c1874"},{"mucCt":"vua","text":"Vương Lâm được Tiên Hoàng bỏ nghi thức khiêu chiến và sắc phong làm Dược Thiên Tôn thứ bốn mươi chín, danh hiệu Bạch Phát Dược Thiên Tôn, nhưng từ chối cơ hội vào nơi bế quan của tiên tổ vì vẫn giữ cảnh giác. Sau khi rời hoàng cung, hắn đưa Hải Long và Lưu Kim Bưu về tửu lâu phía đông thành, quyết định mang Hứa Lập Quốc rời tổ thành tiên tộc để đi cổ tộc, rồi nhận lời Hải Tử Thiên Tôn đến Đế Sơn và trên đường tuyết cảm nhận nguy cơ mãnh liệt.","anchor":"hôm nay sẽ sắc phong ngươi là vị Dược Thiên Tôn thứ bốn mươi chín của tiên tộc","bridge":true,"khoang":"@c1875"},{"mucCt":"ky","text":"Vương Lâm cùng Hài Tử Thiên Tôn bị sát cục tuyết khóa trước sau trên phố dài, hắn chọn tin nàng và nhận phần đồ án bốn cạnh. Hắn mặc Thiên Ngưu Hồn Khải, dùng một quyền dung hợp nhiều tầng thần thông đánh tan đồ án nhưng bị lực lượng Vô xâm nhập thành lưới phong ấn trong cơ thể. Trong lúc bị nhiều Thiên Tôn vây sát, hắn phản kích giết ba người, bị ngân kiếm đâm vào thiên linh ba tấc nhưng vẫn giữ tỉnh táo, lao tiếp về cuối phố và hiển hóa Thiên Ngưu phá nát băng long hợp kích.","anchor":"Hai mắt Vương Lâm ẩn dưới máu tươi vô cùng tỉnh táo","bridge":true,"khoang":"@c1876"},{"mucCt":"ky","text":"Vương Lâm bị hơn ba mươi kẻ bị cưỡng ép nâng tu vi vây sát trong phố tuyết ở tổ thành, bèn gọi Thiên Ngưu phá vòng vây rồi hóa sương đen cắn nuốt tinh khí, huyết nhục và nguyên thần của nhiều nhóm địch. Sau khi nhận ra nguyên thần địch nhân hỗn tạp và sát cục có bố trí giam cầm, hắn tự mình nghênh chiến ba kẻ gần Dược Thiên Tôn cùng hai Hồn khải sứ giả cấp Dược Thiên Tôn, giết họ nhưng bị thương nặng. Cuối chương, hắn dùng phân thân cực mạnh đã ẩn trong hư vô cùng các mảnh cốt âm đao lập trận phản kim quang, phá giam cầm trong cơ thể và dùng một chỉ đối đầu ngón tay bí ẩn sau lưng.","anchor":"Từ đầu hắn vẫn không sử dụng phân thân mà vẫn ẩn giấu, chính là vì chờ ngón tay này xuất hiện","bridge":true,"khoang":"@c1877"},{"mucCt":"ky","text":"Trên con phố gió tuyết bị giam cầm, Vương Lâm dốc toàn bộ chiến lực hiện tại vào một chỉ, kết hợp phân thân trong hư vô, Hồn Khải, các chân thân, bổn nguyên và mảnh vỡ cốt âm đao để đối kháng ngón tay thần bí. Sau khi bị đạo Hữu/Không hóa giải nhiều tầng lực lượng, hắn dùng Tàn Dạ phá phần lớn mũi tên máu nhưng vẫn bị bảy mảnh tên xuyên thân. Khi thấy sát cục còn tiếp tục hiến thân tạo ra trăm thân ảnh Thiên Tôn, hắn đổi ý không rời đi nữa mà quyết định giết sạch để phá cục, lần đầu buông lỏng cấm chế cho sát lục lôi đình chân thân và Thái Sơ bổn nguyên.","anchor":"Không để Vương mỗ rời đi, vậy thì Vương mỗ hôm nay đơn giản là không đi nữa","bridge":true,"khoang":"@c1878"},{"mucCt":"ky","text":"Trong trận chiến trên đường tuyết, Vương Lâm chuyển sang trạng thái tóc đen, đồng tử đen và khí chất tàn nhẫn xa lạ, khiến Hải Tử Thiên Tôn kinh hãi. Hắn dùng sát lục lôi đình màu đen tàn sát các lớp tử sĩ, phá trận địa khí, đánh tan ngón tay hóa Vô và kéo nửa cánh tay trong hư vô ra nghiền nát. Trước mấy vạn thân ảnh, hắn chủ động vứt Thiên Ngưu Hồn Khải, bức Ngũ hành chân thân cùng cấm chế, thái sơ, lôi đình, sinh tử, nhân quả, chân giả rời khỏi thân, để bản thể chỉ còn Mặc Diệt và sát lục. Sau khi hắc khí hóa thành trường bào đen, hắn mở mắt diệt sạch mấy vạn người, kéo thân ảnh ánh sáng trắng ra khỏi hư vô, phủ định kẻ đó là quốc sư rồi bóp nát.","anchor":"Tóc trên đầu hắn toàn bộ đã biến thành màu đen. hai mắt bình tĩnh, khóe miệng không còn mỉm cười nữa","bridge":true,"khoang":"@c1879"},{"mucCt":"ky","text":"Trong trạng thái tóc đen, Vương Lâm phủ nhận tên Vương Lâm và tự xưng đúng ra là Lục Mặc. Hắn phất tay làm ngũ hành chân thân sụp đổ thành bổn nguyên rồi thu vào tay phải, sau đó chất vấn Hải Tử về sát cục, nhất mạch quốc sư và lai lịch thiên ngoại. Khi Cửu Đế hiện thân cứu Hải Tử, hắn lần đầu giao thủ với Đại Thiên Tôn bằng lực lượng sát lục và hủy diệt, rồi khi bình minh tới lại trở về tóc bạc và nhận ra từ nay ban ngày là tóc bạc, đêm xuống là tóc đen. Sau đó hắn nhận mảnh vỡ Tiên Cực kiếm, bỏ lại Hồn Khải, rời Tổ Thành và sáng hôm sau gọi Hứa Lập Quốc khiến phong ấn ký ức của đối phương tan ra.","anchor":"Ta không phải tên là Vương Lâm, ta. Tên ta đúng ra phải là Lục Mặc","bridge":true,"khoang":"@c1880"},{"mucCt":"ky","text":"Vương Lâm chứng kiến Hứa Lập Quốc khôi phục ký ức và để mặc cuộc tranh sủng giữa Hứa Lập Quốc với Lưu Kim Bưu. Khi người điên bóp cổ mình, hắn không chống cự mà nói mình tới tổ thành để gặp người điên rồi định rời đi, nhưng tiếng gọi “Sư tôn” khiến hắn chấn động quay lại. Sau khi Tiên hoàng đưa Đạo Phi đi, Vương Lâm nhận ra đây là cái bẫy dùng Đạo Phi làm mồi để ép hắn xuống địa cung, song vẫn thu Hứa Lập Quốc, Lưu Kim Bưu và Hải Long vào không gian trữ vật rồi một mình trở lại tổ thành.","anchor":"Có một số việc biết rõ là nguy hiếm, nhưng có một vài người vẫn cứ muốn làm","bridge":true,"khoang":"@c1881"},{"mucCt":"ky","text":"Tại Tổ Thành, Vương Lâm bóp vỡ ngọc giản ước định để gọi Song Tử Đại Thiên Tôn, nhờ họ vây khốn Tiên Hoàng một ngày để hắn xuống địa cung. Sau đó hắn chủ động buông thả sát lục và hủy diệt, khiến tóc trắng hóa đen, tuyết hóa đen, bóng tối ăn mòn đường từ đông thành tới hoàng cung. Trên đường xông vào, hắn phá Long Quỷ do mấy vạn hắc giáp cấm binh ngưng tụ và diệt sạch đội quân chắn trước hoàng cung.","anchor":"Sát lục giáng xuống thế gian, thay thế ánh sáng bởi bóng tối","bridge":true,"khoang":"@c1882"},{"mucCt":"ky","text":"Vương Lâm dùng hắc tuyết khiến hoàng cung xuống cấp, thử quốc sư bằng một cước phá đất rồi bắt và bóp tan thân ảnh Đạo Diễn Hồn. Hắn nghe quốc sư tiết lộ bí mật động phủ giới, bị chọn làm đối tượng thay Minh Đạo Tôn trong Phản tổ đại pháp, đồng thời vạch ra giới hạn quốc sư không thể rời tổ thành hoặc hoàng cung.","anchor":"Ngươi không thể ra khỏi tổ thành! Hoặc có lẽ, ngươi không thể ra khỏi hoàng cung!","bridge":true,"khoang":"@c1883"},{"mucCt":"ky","text":"Vương Lâm nghe quốc sư giải thích kế phản tổ quanh Minh Đạo Tôn nhưng vẫn giữ vẻ lạnh lùng, liên tiếp chất vấn cách phối hợp, điều kiện và việc cứu Liên Đạo Phi trước. Hắn không nhận Tiên Cương thệ phù, tự lập huyết thệ bằng một giọt máu, nói nếu lời quốc sư là thật thì sẽ giúp tộc của quốc sư một lần. Khi bước xuống ao máu, hắn âm thầm thả một tia khí tức sát lục từ chân phải theo nước ao chui vào cơ thể Minh Đạo Tôn, khiến cục diện truyền thừa bắt đầu biến động.","anchor":"Từ trong chân phải Vương Lâm lan ra một tia khí tức sát lục","bridge":true,"khoang":"@c1884"},{"mucCt":"ky","text":"Vương Lâm dùng huyết thệ nổ thành huyết vụ mang khí tức bản thân để khiến Minh Đạo Tôn chuyển mục tiêu sang quốc sư. Hắn bỏ qua giao dịch truyền thừa và giải thoát bộ tộc quốc sư, chỉ còn chấp niệm cứu Liên Đạo Phi. Khi lao tới chín sợi xích, hắn bị kim quang trên người Liên Đạo Phi bức lui, trạng thái tóc đen tan rã trở lại tóc bạc và phải tạm liên thủ với quốc sư chống Minh Đạo Tôn trước khi nhảy xuống ao tránh chưởng ấn màu vàng.","anchor":"Thứ duy nhất còn tồn tại trong hắn là chấp niệm cần cứu người điên mà bản thân hắn khi tóc bạc lưu lại","bridge":true,"khoang":"@c1885"},{"mucCt":"ky","text":"Vương Lâm đáp xuống một ngọn trong Cửu Tọa tiên sơn, chứng kiến chưởng ấn của Tiên Hoàng bị tiên sơn hấp thu và nghe quốc sư thúc giục cùng chế phục Minh Đạo Tôn. Hắn dùng chín mươi mốt tàn ảnh né cú va chạm của Minh Đạo Tôn, hỏi lai lịch tiên sơn, rồi thi triển Tàn Dạ phối hợp huyết nhân của quốc sư vây công. Sau khi bị ba khối huyết nhục chứa lực Tiên Tổ đánh trúng, hắn kích phát Thiên Ngưu Hồn Khải tới đỉnh điểm, dung hợp lực Đạo cổ với tu vi đánh ra một quyền hóa chân thân Thiên Ngưu, nhưng cuối chương vẫn cảm thấy nguy cơ sinh tử khi xương Minh Đạo Tôn nát bấy.","anchor":"Thần sắc Vương Lâm ngưng trọng, thân thể từ trên lồ hổng trên bầu trời hạ xuống","bridge":true,"khoang":"@c1886"},{"mucCt":"ky","text":"Vương Lâm bị dư lực xương cốt Minh Đạo Tôn mang sức mạnh Tiên Tổ uy hiếp sinh tử, nên chủ động làm vỡ Thiên Ngưu Hồn Khải để chống đỡ và giữ thế quan sát. Khi quốc sư đề nghị giúp hắn nhận truyền thừa, hắn không tin mà dồn sức cuối của Thiên Ngưu đánh sụp thân ảnh vàng của Minh Đạo Tôn. Sau đó hắn chứng kiến đầu Tiên Tổ Liên Vân Quyết xuất thế, bị kim quang từ mắt phải Tiên Tổ hút vào trong và rơi vào kế hoạch đoạt thân thể của quốc sư.","anchor":"Ở tiên tộc này, những người mà ta có thể tin tưởng, không bao gồm cả ngươi","bridge":true,"khoang":"@c1887"},{"mucCt":"ky","text":"Trong mắt phải Tiên Tổ, thân thể Vương Lâm bị kim quang truyền thừa xâm chiếm, cải tạo máu thịt xương cốt và bị quốc sư lợi dụng để trấn áp tâm thần. Quốc sư tưởng đã xóa được linh hồn hắn và chiếm thân thể, nhưng linh hồn thật của Vương Lâm vẫn ẩn trong Thiên Nghịch châu, lạnh lùng quan sát toàn bộ kế hoạch giải phong ấn Điệu Vong tộc.","anchor":"trong đó đang có linh hồn hắn lạnh lùng nhìn tất cả mọi việc","bridge":true,"khoang":"@c1888"},{"chuong":"@c1889","importance":"major","mucCt":"ky","tieuDe":"Ẩn hồn trong Thiên Nghịch","text":"Sau khi thân thể bị quốc sư chiếm và bị mắt phải nuốt vào, Vương Lâm dung nhập linh hồn vào Thiên Nghịch, giả như hồn bị hủy để quan sát toàn cục. Hắn nhận ra mưu đồ dùng thân thể mình và Đạo Phi làm hai mắt đầu tiên tổ nhằm lừa pháp tắc giải phong ấn, đồng thời nghi ngờ người chiếm thân thể mình chưa chắc thật sự là quốc sư. Dù có thể đoạt lại thân thể bất cứ lúc nào, hắn vẫn tiếp tục ẩn nấp, không khinh cử vọng động.","anchor":"Linh hồn Vương Lâm tiếp tục ẩn nấp, không khinh cử vọng động"},{"mucCt":"ky","text":"Vương Lâm ẩn trong mắt phải đầu lâu Tiên Tổ, thông qua thân thể Tiên Tổ quan sát toàn bộ biến hóa mà chưa ra tay vì cục diện còn chưa rõ. Khi kim kiếm vàng của hư ảnh Tiên Tổ hiện ra, hắn cảm nhận một lời kêu gọi sâu xa. Sau khi Đạo Nhất và Võ Phong xuất hiện bên cạnh Tiên Hoàng, hắn nhận ra biến hóa trong địa cung giống một ván cờ, bản thân là quân cờ và cả Đại Thiên Tôn cũng có thể bị cuốn vào.","anchor":"Vương Lâm ở trong mắt phải của Tiên Tổ nhìn rõ ràng mọi chuyện","bridge":true,"khoang":"@c1890"},{"mucCt":"ky","text":"Thân thể Vương Lâm bị quốc sư giả chiếm giữ và bị sức mạnh Tiên Hoàng càn quét, nhưng linh hồn thật của hắn được Thiên Nghịch Châu che phủ nên không bị phát hiện. Khi mọi người chú ý vào Hải Tử và Cửu Đế, linh hồn hắn từ trong Thiên Nghịch Châu lan ra, nắm giữ lại thân thể của chính mình. Hắn nhờ đó hiểu ra chân tướng kế hoạch Điệu Vong Tộc và vai trò then chốt của thân thể mình.","anchor":"linh hồn hắn từ bên trong Thiên Nghịch Châu lan ra, nắm giữ lại thân thể của chính mình","bridge":true,"khoang":"@c1891"},{"mucCt":"vua","text":"Vương Lâm bị xác định là nhân vật mấu chốt của kế hoạch đoạt xá trong đầu Tiên Tổ. Hắn ở trong mắt phải đầu Tiên Tổ, thu khí tức nghe toàn bộ chân tướng bên ngoài, rồi nhớ lời Thanh Ngưu chân nhân về vật lão tổ Đại Hồn Môn để lại sau ba trăm năm và sinh nghi vì mình đã bị tính kế.","anchor":"Vì thế, Vương Lâm cực kỳ quan trọng","bridge":true,"khoang":"@c1892"},{"mucCt":"ky","text":"Vương Lâm ẩn trong đầu lâu Tiên Tổ, chờ Tiên Hoàng tự bạo và các Đại Thiên Tôn bị Trớ Thuật kiềm chế mới từ mắt trái bước ra. Hắn chặn linh hồn Tiên Hoàng trước khi đoạt xá Liên Đạo Phi, thu linh hồn này vào không gian trữ vật rồi dìu Liên Đạo Phi ra ngoài. Giữa cảnh đầu lâu nứt vỡ và thiên địa sụp đổ, hắn tuyên bố muốn lấy cả đầu lâu Tiên Tổ lẫn Liên Đạo Phi.","anchor":"Thân ảnh Vương Lâm bước từng bước đi ra","bridge":true,"khoang":"@c1893"},{"mucCt":"ky","text":"Vương Lâm hiện thân sau biến cố Tiên Hoàng tự bạo, khiến Cửu Đế nhận ra hắn không chết mà còn nhìn như tăng tiến. Khi Đạo Nhất công kích, hắn buông người điên đang hôn mê và dùng sát lục lôi đình màu đen đẩy lui đối phương. Sau đó hắn lấy hai con ngươi Tiên Tổ trao cho Song Tử, chém hai tai Tiên Tổ trao cho Võ Phong để phá thế liên thủ, rồi quay sang nhắc Hải Tử về việc Điệu Vong tộc từng lợi dụng hắn nhằm khuyên Hải Tử không tham chiến.","anchor":"Chẳng những không chết mà nhìn bề ngoài thì tu vi hắn còn tăng tiến","bridge":true,"khoang":"@c1894"},{"mucCt":"ky","text":"Vương Lâm bộc phát chiến ý từ minh ngộ Chiến pháp tắc, lấy mảnh vỡ Tiên Cực kiếm dung nhập vào cơ thể khiến Kim bổn nguyên đại thành và ngũ hành viên mãn. Hắn tách ngũ hành chân thân, tam đại hư bổn nguyên, cấm chế bổn nguyên và thái sơ bổn nguyên ra ngoài, để bản thể tóc đen dùng lôi đình nối sát lục và mặc diệt đối chiến Đạo Nhất. Sau khi áp chế Đạo Nhất và phong tỏa đường lui của hắn, Vương Lâm cảnh cáo Đạo Khất Tông cũng không trốn thoát. Cuối chương, hắn dung hợp chân thân và các bổn nguyên trở lại, thành trạng thái nửa đen nửa trắng, sau lưng hiện hư ảnh mặt trời nửa đen nửa trắng được nhận ra là hình dáng ban đầu của Đại Thiên Tôn Chi Dương.","anchor":"Hắn lại có thể dựa vào thực lực tự thân, mạnh mẽ ngưng tụ ra Đại Thiên Tôn Chi Dương","bridge":true,"khoang":"@c1895"},{"mucCt":"ky","text":"Vương Lâm dùng Đại Thiên Tôn Chi Dương hai nửa đen trắng bức lui Cửu Đế, rồi hóa chín mươi chín hư ảnh vượt qua loan đao của Đạo Nhất và điểm chỉ khiến đối phương rơi xuống. Hắn xuyên tơ đen qua sóng gợn lam của Hài Tử, dẫm ngực Đạo Nhất để ra giá, buộc Đạo Nhất giao đầu lâu trẻ con tràn tử khí và cảm thấy vật này quen thuộc trong tâm thần. Sau đó hắn áy náy vì món nợ với Song Tử, quyết dùng toàn lực ngăn cuộc chiến cổ tộc và tiên tộc, nhưng cuối chương bị Cửu Đế cùng Song Tử ép phải lưu lại Liên Đạo Phi.","anchor":"Ta nợ Song Tử Đại Thiên Tôn rất nhiều.","bridge":true,"khoang":"@c1896"},{"mucCt":"ky","text":"Vì lời Song Tử và nguy cơ tiên tộc đại loạn, Vương Lâm buộc phải nghe rõ lý do Liên Đạo Phi phải ở lại thay đầu tiên tổ trấn áp bảy mươi hai châu. Hắn thu đầu tiên tổ vào không gian trữ vật, đau khổ rời cấm cung và thề lần sau quay lại hoàng cung tiên tộc sẽ cứu Liên Đạo Phi ra. Sau biến cố, hắn chia tay Song Tử, nói sẽ về Đại Hồn Môn một chuyến rồi rời tiên tộc.","anchor":"Ta muốn quay lại Đại Hồn Môn một chuyến.sau đó, rời khỏi tiên tộc","bridge":true,"khoang":"@c1897"},{"mucCt":"ky","text":"Sau nửa năm, Vương Lâm tới Đại Hồn Môn ở Thiên Ngưu Châu và nhìn lại kế hoạch sâu xa của thiên tài Điệu Vong tộc. Hắn hiểu nơi từng tưởng nhỏ bé này ẩn chứa bí mật xuyên ngàn vạn năm, liên quan tới việc giải phong ấn Điệu Vong tộc và cắt đứt huyết mạch Tiên Tổ. Với tu vi vượt xa toàn bộ Đại Hồn Môn, hắn lặng lẽ vào Tàng Hồn các, vượt qua các tầng cấm chế tới tầng mười. Tại đó hắn thấy vật được lưu lại cho mình, rồi rời đi sau khi nói rằng chuyện bị lợi dụng đã xóa bỏ với Hài Tử.","anchor":"Vương Lâm nhìn Đại Hồn Môn. thần sắc phức tạp","bridge":true,"khoang":"@c1898"},{"mucCt":"ky","text":"Vương Lâm dẫn Hứa Lập Quốc và Lưu Kim Bưu đi qua Hàn Châu hướng tới vùng biển ngăn tiên cổ. Hắn nhìn thấu màn tranh chấp của hai thuộc hạ, bảo Hứa Lập Quốc chia áo cho Lưu Kim Bưu rồi khi hàn khí quá nặng thì thu cả hai vào không gian trữ vật. Sau đó hắn đứng trên khối băng trôi xa vùng đất tiên tộc, nhớ chuyện cũ, nhắc tới Liên Đạo Phi và hướng về Huyền La sư tôn ở phía cổ tộc.","anchor":"Vương Lâm tùy ý vung tay phải lên. đem Hứa Lập Quốc và Lưu Kim Bưu thu vào trong không gian trữ vật","bridge":true,"khoang":"@c1899"},{"mucCt":"ky","text":"Vương Lâm cưỡi Hải Long rời tiên tộc về cổ Tộc, chọn không dùng súc địa thành thốn mà vừa đi vừa điều tức, vì tin có Huyền La ở cổ Tộc nên chuyến này không còn nguy cơ sinh tử lớn. Hắn xác định sẽ tới hoàng thành Đạo Cổ để yên lặng tu hành, hoàn thành lời hứa bảo vệ Đạo Cổ nhất mạch và chuyển thế của Huyền La, đồng thời tiếc nuối vì chưa tìm được Thanh Thủy, Tư Đồ và Lý Thiến Mai ở tiên tộc. Trên đường, hắn nhớ Lý Mộ Uyển, kiểm lại huyết kiếm, phá tầng phong ấn khiến sát khí của kiếm bùng lên, rồi nhớ lời hứa đối xử tử tế với hậu nhân Diệp Mịch. Chương cũng xác nhận sau kim bổn nguyên đại thành và ngũ hành chân thân quy nhất, tu vi hắn đã lên Không Kiếp hậu kỳ, chiến lực đạt mức đệ nhất nhân dưới Đại Thiên Tôn và hắn vạch đường tu hành tiếp theo bằng ngũ hành chân thân, sát lục lôi đình chân thân, hư bổn nguyên cùng đầu lâu Tiên Tổ.","anchor":"Vương Lâm không thi triển súc địa thành thốn, dùng tốc độ nhanh nhất đi tới ba mươi sáu quận của cổ Tộc mà tùy ý ngồi trên Hải Long","bridge":true,"khoang":"@c1900"},{"mucCt":"ky","text":"Vương Lâm đặt chân lên vùng đất cổ tộc, nhớ tới hiểu biết từng nhận từ Huyền La và sách cổ của Song Tử Đại Thiên Tôn, rồi nhận ra bản thân cần tìm ngọc giản bản đồ trước khi tới hoàng thành Đạo cổ. Hắn vào gần Hắc Thạch Thành, bị binh sĩ Cổ Thần chất vấn thân phận và yêu cầu lệnh bài, tộc ấn. Khi hắn hiện chín tinh điểm cổ Thần trên mi tâm, các binh sĩ lập tức kính sợ xưng là thần thánh đại nhân, dâng bản đồ sơ lược và cho biết sứ đoàn Đạo Cổ sắp đến thành.","anchor":"Vương Lâm mỉm cười, trên mi tâm chậm rãi hiện ra chín tinh điểm","bridge":true,"khoang":"@c1901"},{"mucCt":"ky","text":"Vương Lâm nghe tin Kế Đô hoàng tử đi cùng sứ đoàn Đạo Cổ nên định nhân cơ hội hỏi thăm mười hai quận Đạo Cổ. Hắn đối đáp với Lương Vân, Khổng Ti và Mạch Lạc, nghe tới các khái niệm dung yêu luyện ma, thông, dung, luyện thì chấn động nhưng vẫn giữ vẻ bình thường. Khi Kế Đô hoàng tử giáng lâm và mọi người trong ngoài Hắc Thạch thành quỳ lạy, hắn là người duy nhất đứng yên, khiến hoàng tử coi là bất kính và sai Đà Lạc giết hắn.","anchor":"Trong ngoài thành trì lúc này chỉ có duy nhất một người không quỳ, đó là Vương Lâm","bridge":true,"khoang":"@c1902"},{"mucCt":"ky","text":"Vương Lâm không quỳ trước hoàng quyền Thủy Cổ và lần đầu cảm thấy mình không hợp trật tự Cổ Tộc. Hắn bình tĩnh xuyên qua cú chụp của Cổ Yêu, chỉ bằng ánh mắt và một câu đã khiến Cổ Yêu quỳ phục. Sau đó hắn bước lên Cổ Ma của sứ đoàn Đạo Cổ, ép Diệp Hải cùng những người còn lại kính sợ, hỏi chuyện tuyển phi và lấy ngọc giản bản đồ Đạo Cổ hoàng thành.","anchor":"Ba chữ này thốt ra không có tiếng ầm vang như sấm sét","bridge":true,"khoang":"@c1903"},{"mucCt":"ky","text":"Vương Lâm rời Hắc Thạch Thành theo lời mời của Kế Đô tới hành cung U Quận. Tại đại điện, Kế Đô bái kiến hắn bằng danh hiệu Bạch Phát Dược Thiên Tôn và đưa ngọc giản danh sách cao thủ Tiên Tộc cho hắn xem, trong đó hình vẽ của hắn phát kim quang ngang hàng nhóm Đại Thiên Tôn.","anchor":"Vãn bối Kế Đô hoàng tử của Thủy Cổ, bái kiến Bạch Phát Dược Thiên Tôn","bridge":true,"khoang":"@c1904"},{"mucCt":"ky","text":"Vương Lâm nhìn ra Kế Đô đã sớm nghi ngờ thân phận mình từ Hắc Thạch Thành, cố ý dùng bức họa và Đại Cổ Yêu để nghiệm chứng. Hắn ép Kế Đô nói ra người đứng sau lời chỉ điểm, biết quốc sư Thủy Cổ đã dùng tính mạng bói ra cơ hội đổi vận cho Kế Đô. Sau khi cân nhắc, hắn nhận ngọc giản liên lạc và lễ vật, chỉ để ngỏ việc được gọi là nghĩa phụ nếu sau này thật sự rời Đạo Cổ, qua đó giữ lại một đường lui ngoài Đạo Cổ nhất mạch.","anchor":"Trong lòng Vương Lâm đã quyết định. Hắn không thể đặt tương lai của mình ở Đạo Cổ nhất mạch, nương theo cơ hội hôm này mà giữ lại một đường lui!","bridge":true,"khoang":"@c1905"},{"mucCt":"ky","text":"Vương Lâm từ Thủy Cổ nhất mạch đến Đạo Cổ hoàng thành theo bản đồ trong ngọc giản. Hắn xuyên qua cấm chế Thiên Không Thành như ngoại lệ ngoài nhận thức chỉ Tiên Cương Cửu Dương mới làm được. Trước lư hương Đạo Cổ Điện, hắn vái sư tôn Huyền La để biểu thị đã lựa chọn đứng về Đạo Cổ, muốn bảo vệ Đạo Cổ và sư tôn chuyển thế. Một vái chưa xong đã khiến chín cây hương cháy dữ dội, khói xanh cuồn cuộn khom mình như không chịu nổi lực vái.","anchor":"Một vái này của hắn biểu lộ trong lòng hắn đã quyết định.","bridge":true,"khoang":"@c1906"},{"mucCt":"ky","text":"Vương Lâm tới đào viên phía sau Đạo Cổ Điện gặp lại Huyền La, uống chén trà do sư tôn chuẩn bị và cảm nhận nơi này ấm áp như gia đình. Hắn nhắc lại lời hứa tới bảo vệ Đạo Cổ nhất mạch, quyết định tạm ở lại cho tới khi hoàn thành hứa hẹn với Huyền La. Ba ngày sau, trước Đạo Cổ Điện, hắn dùng khí thế chấn động chín thuộc hạ của Huyền La, được họ bái kiến là Thiếu Thiên Tôn, rồi nghe Huyền La công khai giao cho hắn vai trò thay mình bảo vệ Đạo Cổ và quyền chọn tân hoàng tôn về sau.","anchor":"Đệ tử đã đồng ý với sư tôn là sẽ tới đây, bảo vệ Đạo Cổ nhất mạch","bridge":true,"khoang":"@c1907"},{"mucCt":"ky","text":"Vương Lâm bị hoàng quyền Đạo Cổ đặt vào thế phải quỳ trước Đạo Cổ hoàng tôn, nhưng chỉ dùng ánh mắt và uy áp huyết mạch đã khiến Thường Thị chấn động. Sau đó hắn nhận ngọc bội tím, tạ ơn theo khuôn phép, đồng thời nói với Huyền La rằng lời hứa bảo vệ Đạo Cổ nhất mạch trong động phủ giới vẫn sẽ tiếp tục. Huyền La đưa hắn tới đầm lầy sát khí ở Bình Thiên Quận, mở đầu chuỗi nơi tu hành bản nguyên và chuẩn bị dẫn hắn bái kiến Cổ Đạo Đại Thiên Tôn.","anchor":"Trong động phủ giới, đệ tử đã từng hứa với sư tôn sẽ bảo vệ Đạo Cổ nhất mạch","bridge":true,"khoang":"@c1908"}],"nhanMach":[{"ten":"Hai cô bé không nêu tên","tag":"khac","quanHe":"gặp bên Tự Thú Giới","ghiChu":"Tiếng cười của hai cô bé khiến lòng Vương Lâm bình tĩnh lại."},{"ten":"Liên Đạo Phi","tag":"ban-be","quanHe":"Bằng hữu có ân","ghiChu":"Vương Lâm vào Tổ Thành vì muốn gặp lại người điên từng cùng hắn Mộng Đạo tại Chu Tước Tinh."},{"ten":"Lý Vân","tag":"doi-thu","quanHe":"Tu sĩ Lý gia được sai dò khí tức cung của lão tổ; khả năng là kẻ theo dõi và tập kích Vương Lâm trong Đông Thành.","ghiChu":"Xuất hiện trong biến cố Lý Phủ cảm ứng cung Lý Quảng @c1868"},{"ten":"Lý Sơn","tag":"doi-thu","quanHe":"Tu sĩ Lý gia được sai cùng Lý Vân dò khí tức cung; được nhắc là đã tách ra đi bắt đồng bọn của Vương Lâm.","ghiChu":"Biến cố khiến Vương Lâm nhận xét Lý Phủ hơi quá @c1868"},{"ten":"Tu sĩ Lý gia huyết ảnh","tag":"doi-thu","quanHe":"Kẻ ẩn thân theo dõi, bắn tên tập kích Vương Lâm rồi bị phá đòn và bỏ chạy.","ghiChu":"Nghi là Lý Vân nhưng chương chưa định danh thẳng @c1868"},{"ten":"Lão già trong mật thất Lý Phủ","tag":"doi-thu","quanHe":"Người kích hoạt mũi tên màu tím và sai người dò khí tức cung của lão tổ.","ghiChu":"Khơi đầu hành động của Lý Phủ trong Đông Thành @c1868"},{"ten":"Nam tử trung niên truy kích của Lý Phủ","tag":"doi-thu","quanHe":"Kẻ truy sát thuộc Lý Phủ bị Vương Lâm đánh ngất và lục thần thức.","ghiChu":"Gặp trong vụ truy sát Lưu Kim Bưu và Hải Long ở Đông Thành."},{"ten":"Lão tổ Lý gia","tag":"khac","quanHe":"người đứng đầu Lý Phủ đối thoại và nhận lỗi với Vương Lâm","ghiChu":"Sau xung đột vì cung lão tổ, lão tổ Lý gia mời Vương Lâm vào Tiễn Các và chấp nhận lời hứa gửi trả cung sau này."},{"ten":"Sứ giả thanh bào truyền chỉ của Tiên Hoàng","tag":"khac","quanHe":"người truyền thánh chỉ sắc phong","ghiChu":"Đến Lý Phủ đọc chỉ yêu cầu Vương Lâm bảy ngày sau tới Tiên Đạo Điện dự đại lễ sắc phong."},{"ten":"Liên Đạo Chân","tag":"khac","quanHe":"biến số Vương Lâm nghĩ tới trước đại lễ sắc phong","ghiChu":"Vương Lâm không rõ Liên Đạo Chân sẽ làm gì trong đại lễ sắp tới."},{"ten":"Lão già mặc thanh y","tag":"doi-thu","quanHe":"Người chủ trì quy chế cửu môn trong lễ sắc phong","ghiChu":"Bị Vương Lâm dùng khí thế ép lui trước Tiên Đạo Điện."},{"ten":"Thượng Huyền Đạo","tag":"doi-thu","quanHe":"Quốc sư Tiên Tộc khiến Vương Lâm cảnh giác trong đại lễ sắc phong.","ghiChu":"Ánh mắt của Thượng Huyền Đạo làm Vương Lâm thoáng cảm giác như cả đời lướt qua trước mắt."},{"ten":"Thiên Sư Thú bị thương","tag":"khac","quanHe":"Sinh linh thiên ngoại bị diệt trong nghi thức sắc phong của Vương Lâm.","ghiChu":"Sau khi Thiên Sư Thú bị Tiên Hoàng thiêu chết, sợi tóc bạc còn lại bị Vương Lâm đoạt lấy."},{"ten":"La Công","tag":"doi-thu","quanHe":"Người khiêu chiến trong đại lễ sắc phong","ghiChu":"Lão tổ một vương phủ chủ động đánh với Vương Lâm và bị hắn đánh bại."},{"ten":"Nữ tử ở bên cạnh Đạo Phi","tag":"khac","quanHe":"Đầu mối liên quan tới Đạo Phi được Tiên Hoàng nhắc trước mặt Vương Lâm.","ghiChu":"Nàng đã tỉnh lại và đang cảm ngộ tại nơi bế quan của tiên tổ."},{"ten":"Hải Tử Thiên Tôn","tag":"dong-minh","quanHe":"Đồng hành trong sát cục phố dài","ghiChu":"Vương Lâm chọn tin nàng và chia hướng ứng phó đồ án tuyết."},{"ten":"Chủ nhân ngón tay bí ẩn","tag":"doi-thu","quanHe":"kẻ bố trí sát cục và giam cầm chiến lực","ghiChu":"Lần đầu lộ qua ngón tay tập kích sau lưng Vương Lâm ở phố tuyết."},{"ten":"Cửu Đế Đại Thiên Tôn","tag":"doi-thu","quanHe":"Đối thủ giao thủ trực diện","ghiChu":"Cửu Đế cứu Hải Tử và dàn xếp bằng mảnh vỡ Tiên Cực kiếm trong lần Vương Lâm tóc đen ra tay với Đại Thiên Tôn."},{"ten":"Song Tử Đại Thiên Tôn","tag":"dong-minh","quanHe":"nhờ thực hiện ước định","ghiChu":"Nhờ Song Tử Đại Thiên Tôn vây khốn Tiên Hoàng một ngày để mình xuống địa cung."},{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"đối đầu trực diện","ghiChu":"Xem Tiên Hoàng là kẻ dùng Đạo Phi ép mình tới hoàng cung."},{"ten":"Minh Đạo Tôn","tag":"khac","quanHe":"Cùng bị đặt vào bố cục Phản tổ đại pháp","ghiChu":"Minh Đạo Tôn là lựa chọn của Tiên Hoàng, còn Vương Lâm là lựa chọn của quốc sư."},{"ten":"Minh Đạo Tôn","tag":"doi-thu","quanHe":"Đối tượng bị Vương Lâm âm thầm đưa khí tức sát lục nhập thể trong ao máu.","ghiChu":"Quan hệ đối địch và bị lợi dụng trong nghi thức phản tổ."},{"ten":"Thượng Huyền Đạo","tag":"dong-minh","quanHe":"Tạm thời nhận điều kiện và huyết thệ với quốc sư để đổi lấy khả năng cứu Liên Đạo Phi.","ghiChu":"Sự hợp tác còn đặt trên nghi ngờ."},{"ten":"Quốc sư giả của Điệu Vong Tộc","tag":"doi-thu","quanHe":"Bị chiếm thân thể","ghiChu":"Quốc sư giả từng chiếm thân thể Vương Lâm trước khi bị Tiên Hoàng xóa sạch."},{"ten":"Hải Tử Thiên Tôn","tag":"khac","quanHe":"Người trong kế hoạch Điệu Vong Tộc","ghiChu":"Hải Tử nói thân thể Vương Lâm là then chốt để tộc nhân Điệu Vong Tộc đoạt xá."},{"ten":"Hải Tử Thiên Tôn","tag":"doi-thu","quanHe":"Đối tượng được Vương Lâm thuyết phục đứng ngoài cuộc tranh đoạt đầu lâu Tiên Tổ.","ghiChu":"Quan hệ căng thẳng vì Điệu Vong tộc từng lợi dụng Vương Lâm giải phong ấn."},{"ten":"Đạo Khất Tông","tag":"doi-thu","quanHe":"mục tiêu bị uy hiếp","ghiChu":"Sau khi Đạo Nhất bỏ chạy, Vương Lâm tuyên bố Đạo Khất Tông không trốn thoát."},{"ten":"Người điên","tag":"ban-be","quanHe":"bằng hữu có ân","ghiChu":"Vương Lâm nhớ người điên từng có ân với mình và từng cùng mình Mộng Đạo tại Chu Tước Tinh, nên vẫn đến Tổ Thành dù biết nguy hiểm."},{"ten":"Lưu Kim Bưu","tag":"dong-hanh","quanHe":"đồng hành","ghiChu":"Đi cùng Vương Lâm rời Tử Dương Tông và được hắn mang theo khi rời Đông Châu."},{"ten":"Hải Long","tag":"dong-hanh","quanHe":"đồng hành","ghiChu":"Được Vương Lâm mang theo khi dùng súc địa thành thốn rời Đông Châu."},{"ten":"Cô Nhai Thiên Tôn","tag":"dong-minh","quanHe":"người tiễn biệt và hỗ trợ","ghiChu":"Đã giao ngọc giản cho Vương Lâm để khi hắn gặp nguy cơ ở Trung Châu có thể cầu viện Song Tử Đại Thiên Tôn."},{"ten":"Oa Oa","tag":"dong-minh","quanHe":"người bảo hộ theo ước định","ghiChu":"Cùng Hàm Hàm có thể biết khi Vương Lâm gặp nguy cơ nhờ ngọc giản Cô Nhai giao."},{"ten":"Hàm Hàm","tag":"dong-minh","quanHe":"người bảo hộ theo ước định","ghiChu":"Cùng Oa Oa có thể biết khi Vương Lâm gặp nguy cơ nhờ ngọc giản Cô Nhai giao."},{"ten":"Lưu Kim Bưu","tag":"dong-minh","quanHe":"thuộc hạ gọi hắn là chủ nhân","ghiChu":"Được hắn cứu khỏi truy sát và sai đi gõ cửa Lý Phủ.","gap":"@c1869"},{"ten":"Hải Long","tag":"dong-minh","quanHe":"tọa kỵ đi cùng phe","ghiChu":"Được hắn vuốt đầu chữa lành vết thương do mũi tên đen gây ra.","gap":"@c1869"},{"ten":"Song Tử","tag":"dong-minh","quanHe":"người khuyên can trong biến cố cấm cung","ghiChu":"Vì mắc nợ Song Tử, Vương Lâm buộc phải nghe nàng giải thích."},{"ten":"Hài Tử","tag":"doi-thu","quanHe":"người ngăn hắn mang Liên Đạo Phi đi","ghiChu":"Hài Tử tuyên bố sẽ ra tay nếu Vương Lâm cố chấp."},{"ten":"Cửu Đế","tag":"doi-thu","quanHe":"người uy hiếp bằng Trớ Thuật","ghiChu":"Cửu Đế dùng việc không áp chế Trớ Thuật để buộc Vương Lâm cân nhắc."},{"ten":"Lão tổ Đại Hồn Môn","tag":"khac","quanHe":"nhìn thấu kế hoạch và nhận lời khẩn cầu","ghiChu":"Vương Lâm thấy vật lão tổ lưu lại trong tầng mười Tàng Hồn các."},{"ten":"Hài Tử","tag":"khac","quanHe":"liên hệ qua chuyện xóa bỏ lợi dụng","ghiChu":"Vương Lâm nhắc chuyện thiên tài Điệu Vong tộc lợi dụng hắn đã xóa bỏ với Hài Tử."},{"ten":"Lương Vân","tag":"khac","quanHe":"Thành chủ Hắc Thạch thành tiếp xúc và mời Vương Lâm ở lại chờ Kế Đô hoàng tử.","ghiChu":"Gặp ngoài Hắc Thạch thành @c1902"},{"ten":"Khổng Ti","tag":"khac","quanHe":"Yêu thánh Hắc Thạch thành tự giới thiệu với Vương Lâm.","ghiChu":"Gặp ngoài Hắc Thạch thành @c1902"},{"ten":"Mạch Lạc","tag":"khac","quanHe":"Ma thánh Hắc Thạch thành nhận xét Vương Lâm chưa có khí tức yêu ma.","ghiChu":"Gặp ngoài Hắc Thạch thành @c1902"},{"ten":"Kế Đô hoàng tử","tag":"doi-thu","quanHe":"Kế Đô hoàng tử coi việc Vương Lâm không quỳ là bất kính và sai Đà Lạc giết hắn.","ghiChu":"Xung đột ngoài Hắc Thạch thành @c1902"},{"ten":"Đà Lạc","tag":"doi-thu","quanHe":"Cổ Yêu dưới quyền Kế Đô hoàng tử vung tay chụp giết Vương Lâm.","ghiChu":"Theo lệnh hoàng tử @c1902"},{"ten":"Diệp Hải","tag":"khac","quanHe":"người trong sứ đoàn Đạo Cổ bị Vương Lâm uy áp và giao bản đồ","ghiChu":"Gặp tại Hắc Thạch Thành trong chuyến tuyển phi @c1903"},{"ten":"Tống Trí cô nương","tag":"khac","quanHe":"nữ tử được mời đi theo sứ đoàn, ánh mắt giao nhau với Vương Lâm","ghiChu":"Xuất hiện cuối chương @c1903"},{"ten":"Kế Đô hoàng tử","tag":"dong-minh","quanHe":"Người cầu viện và xin nhận làm nghĩa tử","ghiChu":"Kế Đô dâng lễ, xin Vương Lâm làm nghĩa phụ và trợ giúp tranh ngôi Thủy Cổ Hoàng."},{"ten":"Hoàng muội của Kế Đô","tag":"khac","quanHe":"Người chứng kiến cuộc thỏa thuận","ghiChu":"Nàng quỳ theo Kế Đô và chứng kiến Vương Lâm để ngỏ đường lui Thủy Cổ."},{"ten":"Quốc sư Thủy Cổ","tag":"khac","quanHe":"Người gián tiếp dẫn tới cuộc gặp","ghiChu":"Lời bói bằng tính mạng của quốc sư khiến Kế Đô tìm cách nắm lấy Vương Lâm làm cơ hội đổi vận."},{"ten":"Đạo Cổ Hoàng","tag":"khac","quanHe":"bị chú ý bởi hoàng quyền Đạo Cổ","ghiChu":"Một vái trước Đạo Cổ Điện khiến Đạo Cổ Hoàng ra lệnh tra thân phận người gây dị tượng khói xanh."},{"ten":"Huyền La","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Huyền La đón Vương Lâm trở về Đạo Cổ, chuẩn bị trà từ năm xưa và giao cho hắn vai trò bảo vệ Đạo Cổ nhất mạch."},{"ten":"Chín người dưới trướng Huyền La","tag":"dong-minh","quanHe":"Thuộc hạ được giao nghe lệnh","ghiChu":"Huyền La tuyên bố chín người này từ nay nghe theo hiệu lệnh của Vương Lâm."},{"ten":"Thường Thị","tag":"doi-thu","quanHe":"Xung đột lễ nghi","ghiChu":"Thường Thị quát buộc Vương Lâm quỳ trước Đạo Cổ Hoàng theo tộc quy."}],"tuViMoc":[{"chuong":"@c1867","canhGioi":"Luân hồi bổn nguyên một tia","text":"Ở Đông Lâm Tông, Vương Lâm hiểu thêm bổn nguyên thứ tư thuộc hệ hư là luân hồi, hiện chỉ mới mở ra một tia và còn cần cảm ngộ sâu hơn; đây là mốc hệ bổn nguyên, không phải tu vi chính.","importance":"major"},{"chuong":"@c1867","canhGioi":"Luân hồi bổn nguyên","text":"Vương Lâm hiểu thêm một tia luân hồi bổn nguyên, thuộc hệ hư bổn nguyên chứ không phải cảnh giới tu vi chính; loại bổn nguyên này mới mở ra cánh cửa cảm ngộ ban đầu, còn cần tiếp tục lĩnh hội để đại thành.","importance":"major"},{"chuong":"@c1867","canhGioi":"Mộc bổn nguyên đại thành","text":"Một năm ở Tử Dương Tông giúp mộc bổn nguyên trong cơ thể Vương Lâm đại thành, gần tới mức ngưng tụ bổn nguyên chân thân.","importance":"minor"},{"chuong":"@c1867","canhGioi":"Lôi đình chân thân viên mãn","text":"Lôi đình chân thân của Vương Lâm dung nhập bổn nguyên đặc thù và đã viên mãn ở Đông Lâm Tông, không cần tiếp tục cảm ngộ bổn nguyên đặc thù.","importance":"major"},{"chuong":"@c1867","canhGioi":"Không Kiếp trung kỳ","text":"Mốc hệ bổn nguyên (không phải tu vi chính): mộc bổn nguyên đại thành gần mức ngưng tụ bổn nguyên chân thân, lôi đình chân thân viên mãn, hiểu ra một tia luân hồi bổn nguyên là hư bổn nguyên thứ tư sau sinh tử, nhân quả, chân giả; chỉ còn kim bổn nguyên chưa viên mãn để tiến lên Kim Tôn Không Kiếp hậu kỳ.","importance":"major"},{"chuong":"@c1895","canhGioi":"Ngũ hành viên mãn","text":"Kim bổn nguyên đại thành nhờ mảnh vỡ Tiên Cực kiếm, khiến ngũ hành của Vương Lâm hoàn toàn viên mãn; đây là mốc bổn nguyên, không phải đại cảnh giới tu vi chính.","importance":"major"},{"chuong":"@c1895","canhGioi":"Hình dáng ban đầu của Đại Thiên Tôn Chi Dương","text":"Vương Lâm dung hợp các chân thân và bổn nguyên, tự ngưng ra hư ảnh Đại Thiên Tôn Chi Dương nửa đen nửa trắng; đây là dấu hiệu tiệm cận cấp Đại Thiên Tôn, không phải xác nhận đã thành Đại Thiên Tôn.","importance":"major"},{"chuong":"@c1896","canhGioi":"Mầm mống Đại Thiên Tôn Chi Dương","text":"Đại Thiên Tôn Chi Dương của Vương Lâm hiện ra hai nửa đen trắng, mới là mầm mống chưa khai hoa kết trái nhưng đã khiến Cửu Đế nhận ra không phải dạng bình thường.","importance":"major"},{"chuong":"@c1900","canhGioi":"Không Kiếp hậu kỳ","text":"Kim bổn nguyên đại thành khiến tu vi Vương Lâm từ Không Kiếp trung kỳ tăng lên Không Kiếp hậu kỳ.","importance":"minor"},{"chuong":"@c1901","canhGioi":"Tam cổ cửu tinh","text":"Thân thể cổ tộc của Vương Lâm đã đạt cửu tinh của cả cổ Thần, cổ Yêu và cổ Ma; đây thuộc hệ cổ tộc, không phải tu vi chính.","importance":"major"}],"diem":[{"text":"Thiếu niên phàm nhân tư chất kém quyết chí tu tiên, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh làm nền tảng mọi đột phá sau này","chuong":"@c0001"},{"text":"Tự nổ thân thể đấu Đằng Hóa Nguyên (Nguyên Anh kỳ) để báo thù diệt tộc, linh hồn chi hỏa tồn tại xuyên Vực Ngoại rồi đoạt xá thân Mã Lương","chuong":"@c0100"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, khai mở con đường luyện thể và thôn hồn độc đáo","chuong":"@c0176"},{"text":"Dung hợp bổn tôn và phân thân thành một thể thống nhất, đạt tam tinh Cổ Thần và Hóa Thần hậu kỳ với ý cảnh cấp Anh Biến","chuong":"@c0365"},{"text":"Vượt mười bảy tầng Thiên Tôn Niết, được sắc phong Dược Thiên Tôn — danh hiệu thứ bốn mươi chín trong lịch sử","chuong":"@c1856"},{"text":"Đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh, ngưng hình dáng ban đầu Đại Thiên Tôn Chi Dương, bước vào hàng ngũ đỉnh cao cổ tộc","chuong":"@c1901"}]},"nguon":["@c1866","@c1867","@c1868","@c1869","@c1870","@c1871","@c1872","@c1873","@c1874","@c1875","@c1876","@c1877","@c1878","@c1879","@c1880","@c1881","@c1882","@c1883","@c1884","@c1885","@c1886","@c1887","@c1888","@c1889","@c1890","@c1891","@c1892","@c1893","@c1894","@c1895","@c1896","@c1897","@c1898","@c1899","@c1900","@c1901","@c1902","@c1903","@c1904","@c1905","@c1906","@c1907","@c1908"],"tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh và tán công vươn lên đột phá; Thâm trầm mưu trí, giỏi ẩn nhẫn bố cục và phản kích trong thế yếu; Quyết đoán tàn nhẫn với kẻ thù nhưng nặng tình với cố nhân; Không chịu khuất phục trước hoàng quyền và trật tự áp đặt","gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"vaiTro":"Nhân vật chính — tu sĩ phàm nhân nghịch thiên, Dược Thiên Tôn tam cổ cửu tinh của Đạo Cổ","blurb":"Vương Lâm xuất thân là thiếu niên phàm nhân tư chất kém ở Thạch Thôn, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, ý chí khổ tu và vô số lần sinh tử — từ đoạt xá thân Mã Lương, truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, đến vượt mười bảy tầng Thiên Tôn Niết — mà từng bước vươn tới đỉnh cao tu đạo. Tính tới giai đoạn trở về Cổ Tộc, hắn đã được sắc phong Dược Thiên Tôn, đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh, ngưng hình dáng ban đầu của Đại Thiên Tôn Chi Dương, và đối diện trực tiếp áp lực hoàng quyền Đạo Cổ mà vẫn không quỳ gối. Sau biến cố Tiên Hoàng tự bạo, hắn tách tà"},{"id":"minh-dao-ton","name":"Minh Đạo Tôn","canhGioiCaoNhat":"Đạo Tôn @c1866","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1866","importance":"normal","mucCt":"vua","tieuDe":"Bị thúc Phản Cổ","text":"Minh Đạo Tôn bị danh tiếng của Vương Lâm thay thế, chịu đau đớn trong ao nước đen dưới địa cung hoàng thành Trung Châu và không ngừng gào tên Vương Lâm. Hắn bị Tiên Hoàng dùng Phản Cổ đại pháp để thay đổi huyết mạch, biến oán hận thành điều kiện mưu cầu huyết mạch Tiên Tổ và khả năng Phản Cổ.","anchor":"Ngươi cướp đi hết thảy của ta, ta nhất định phải tự mình đoạt lại"},{"chuong":"@c1870","importance":"bridge","mucCt":"gon","anchor":"Lúc này Vương Lâm đã vượt qua cả Minh Đạo Tôn","text":"Minh Đạo Tôn được nhắc làm mốc so sánh địa vị, khi Vương Lâm hiện đã vượt qua cả ông trong nhận thức của các thế lực như tứ đại vương phủ."},{"chuong":"@c1872","importance":"bridge","mucCt":"gon","tieuDe":"Tiền lệ huyết tế","text":"Minh Đạo Tôn được nhắc như tiền lệ từng dẫn tới sinh linh hình kiếm trong nghi thức huyết tế sắc phong.","anchor":"Năm đó Minh Đạo Tôn lúc huyết tế đưa tới một sinh linh có hình kiếm"},{"mucCt":"vua","text":"Minh Đạo Tôn bị đặt trong ao máu trước tế đàn địa cung, hai mắt nhắm nghiền và chịu thống khổ. Hắn là người được Tiên Hoàng chọn cho Phản tổ đại pháp để trở thành Tiên Tổ thứ hai.","anchor":"Phản tổ đại pháp, người mà hắn lựa chọn chính là Minh Đạo Tôn","bridge":true,"khoang":"@c1883"},{"chuong":"@c1884","importance":"normal","tieuDe":"Thức tỉnh trong ao máu","mucCt":"ky","text":"Minh Đạo Tôn ngồi trong ao máu, được quốc sư nói là thiên tài tiên tộc và đệ nhất nhân trong Dược Thiên Tôn, bị Tiên Hoàng chọn làm đối tượng phản tổ nhờ chấp niệm hận Vương Lâm. Sau khi Vương Lâm thả khí tức sát lục theo nước ao nhập thể, hắn mở bừng mắt, vẻ mê mang chuyển sang điên cuồng, làm địa cung lạnh buốt và nước ao nhanh chóng đóng băng.","anchor":"Minh Đạo Tôn trong nước ao mở bừng đôi mắt vẫn đóng chặt"},{"chuong":"@c1885","importance":"normal","mucCt":"ky","tieuDe":"Kim quang thối rữa","text":"Minh Đạo Tôn thức tỉnh trong ao đã kết băng, mất thần trí và điên cuồng lao vào Vương Lâm. Sau khi bị huyết vụ mang khí tức Vương Lâm đánh lừa, hắn chuyển sang tấn công Thượng Huyền Đạo. Trong giao chiến, thân thể hắn thối rữa nhưng kim quang trong cơ thể bùng phát dữ dội, rồi tiếp tục truy kích xuống không gian dưới ao.","anchor":"Toàn thân Minh Đạo Tôn tỏa ra kim quang nhưng sự thối nát trên thân thể không hề dừng lại"},{"chuong":"@c1886","importance":"normal","mucCt":"ky","tieuDe":"Xương nát lộ truyền thừa","text":"Minh Đạo Tôn bị kim quang trong cơ thể ăn mòn, thân thể thối rữa lộ xương đen nhưng vẫn phát cuồng lao vào ngọn núi nơi Vương Lâm đứng. Hắn bị Thượng Huyền Đạo và Vương Lâm vây công, trong quá trình Phản tổ đại pháp vì thức tỉnh sớm mà huyết nhục bị bóc tách, đồng thời bắn ra các khối huyết nhục chứa lực Tiên Tổ đánh trúng Vương Lâm. Cuối chương, thân thể hắn chỉ còn xương đen và quầng sáng vàng truyền thừa Tiên Tổ, rồi xương cốt nứt nát sau thần niệm không cam lòng.","anchor":"Toàn thân Minh Đạo Tôn bị thối rữa càng nhiều, dưới da thịt lộ ra xương cốt màu đen"},{"chuong":"@c1887","importance":"normal","mucCt":"vua","tieuDe":"Kim quang bị đánh sụp","text":"Sau khi huyết nhục tróc ra và xương cốt nổ tung, Minh Đạo Tôn vẫn còn đốm sáng vàng ngưng tụ thân thể để hoàn thành Phản Tổ Đại Pháp. Thân ảnh vàng vừa thành hình đã bị một quyền mang sức cuối của Thiên Ngưu từ Vương Lâm đánh sụp, nhưng đốm sáng màu vàng không bị tổn thương và bị hút vào mắt phải Tiên Tổ.","anchor":"nhìn bộ dạng của hắn không ngờ chính là Minh Đạo Tôn lại một lần nữa ngưng tụ lại thân thể"},{"chuong":"@c1889","importance":"normal","mucCt":"vua","tieuDe":"Thế thân truyền thừa","text":"Minh Đạo Tôn bị Tiên hoàng nêu là thế thân chịu phần gian nan trong truyền thừa để Đạo Phi cuối cùng thành công. Quốc sư còn dự tính dùng sự xuất hiện của Vương Lâm để kích thích và duy trì sự điên cuồng của Minh Đạo Tôn.","anchor":"sự tồn tại của Minh Đạo Tôn chính là để triệt tiêu sự gian nan của truyền thừa"},{"chuong":"@c1892","importance":"bridge","mucCt":"gon","text":"Minh Đạo Tôn bị Tiên hoàng nêu là một trong những người bị Cửu Đế lợi dụng trong chuỗi âm mưu quanh đầu Tiên Tổ.","anchor":"Ngươi còn lợi dụng Minh Đạo Tôn, lợi dụng Liên Đạo Phi"}],"nhanMach":[{"ten":"Tiên Hoàng","tag":"khac","quanHe":"bị lợi dụng","ghiChu":"Tiên Hoàng dùng oán hận của Minh Đạo Tôn để thúc đẩy quá trình Phản Cổ."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người được đem so sánh địa vị","ghiChu":"Vương Lâm được nhận định đã vượt qua cả Minh Đạo Tôn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị khí tức sát lục của Vương Lâm nhập vào cơ thể trong ao máu.","ghiChu":"Biến cố này khiến hắn thức tỉnh trước khi quốc sư thi triển bí thuật."}],"tuViMoc":[],"diem":[{"text":"Kỷ lục dừng ở tầng mười sáu Thiên Nhân suy kiếp, được công nhận là đệ nhất trong Dược Thiên Tôn","chuong":"@c1832"},{"text":"Bị Vương Lâm kích động, công khai chất vấn rồi bị ép vào thế tiến thoái đều tổn Đạo Tâm","chuong":"@c1861"},{"text":"Đạo niệm sụp đổ sau khi Vương Lâm vượt tầng mười sáu trước, danh tiếng bị thay thế hoàn toàn","chuong":"@c1862"},{"text":"Chịu thống khổ Phản Cổ trong ao máu địa cung, mất thần trí và điên cuồng","chuong":"@c1885"},{"text":"Bị Tiên hoàng xác nhận là thế thân chịu phần gian nan trong truyền thừa để Đạo Phi thành công","chuong":"@c1889"},{"text":"Bị nêu là một trong những người bị Cửu Đế lợi dụng trong chuỗi âm mưu","chuong":"@c1892"}]},"nguon":["@c1866","@c1870","@c1872","@c1883","@c1884","@c1885","@c1886","@c1887","@c1889","@c1892"],"tinhCach":"kiêu ngạo, coi thường kẻ dới; dễ bị kích động bởi danh tiếng; Đạo Tâm không đủ vững trước áp lực","gioiTinh":"nam","vaiTro":"Dược Thiên Tôn đứng đầu — thế thân truyền thừa bị Vương Lâm vượt qua và bị lợi dụng","blurb":"Minh Đạo Tôn là Dược Thiên Tôn cực mạnh, từng đứng đầu hàng Dược Thiên Tôn và giữ kỷ lục dừng ở tầng mười sáu của Thiên Nhân suy kiếp. Hắn bị Vương Lâm vượt mặt khiến Đạo niệm sụp đổ, sau đó bị đưa vào ao máu địa cung chịu thống khổ Phản Cổ, lộ ra thực chất là thế thân chịu phần gian nan trong truyền thừa mà Cửu Đế sắp đặt cho Đạo Phi."},{"id":"huyen-la-dai-thien-ton","name":"Huyền La Đại Thiên Tôn","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ở nơi bế quan tại Đạo Cổ nhất tộc, Huyền La nghe tin Vương Lâm vang danh Tiên Tộc thì vừa than thở vừa tự hào. Hắn nhớ Vương Lâm là người do mình phát hiện từ động phủ giới và nhận làm đệ tử, nhưng vẫn giữ kín việc này, nhất là với hoàng tôn Đạo Cổ.","anchor":"Hắn than thở vì Vương Lâm có thể đạt được vị trí cao như vậy tại Tiên Tộc","bridge":true,"khoang":"@c1866"}],"diem":[{"text":"Giữ kỷ lục tám giọt máu tươi trong kiếp cổ Mạch Thương Khung Huyết, một trong chín vầng mặt trời","chuong":"@c1611"},{"text":"Phong ấn tin tức hồn huyết, phân hóa mặt trời đỏ thành gần trăm vạn phần dung nhập vào thân tộc nhân Đạo cổ, đích thân tới Thất Đạo Tông đón Vương Lâm","chuong":"@c1615"},{"text":"Âm thầm bám theo Vương Lâm từ phía sau suốt cuộc truy kích, coi đây là lần khảo nghiệm đệ tử thay vì ra tay giúp","chuong":"@c1665"},{"text":"Chính thức hiện thân mời Vương Lâm làm đệ tử duy nhất, thần thức người khác không thể cảm nhận sự tồn tại củaông","chuong":"@c1692"},{"text":"Trở thành chỗ dựa bí mật cho Vương Lâm, thân phận đệ tử duy nhất của ông là bảo hộ ngầm trong các cuộc đối đầu","chuong":"@c1841"},{"text":"Tại nơi bế quan ở Đạo Cổ nhất tộc, nghe tin Vương Lâm vang danh Tiên Tộc thì vừa than thở vừa tự hào","chuong":"@c1866"}]},"nguon":["@c1866"],"vaiTro":"Đại thiên tôn Cổ quốc — sư phụ duy nhất của Vương Lâm, cường giả giữ kỷ lục cổ Mạch Thương Khung Huyết","tinhCach":"Mưu lược thâm trầm, giỏi dùng thuật bói toán truy nguyên; quyết đoán khi phong ấn tin tức và đích thân hành động; kiên nhẫn quan sát, lấy thử thách làm phép khảo nghiệm đệ tử; bình thản trước biến cố nhưng vẫn có thể rung động trước sự kiện chưa từng có","blurb":"Huyền La đại thiên tôn là cường giả thuộc Cổ quốc, từng giữ kỷ lục tám giọt máu tươi trong kiếp cổ Mạch Thương Khung Huyết và tranh đoạt bảo vật Thái Cổ Thần Cảnh cùng Đạo Nhất đại thiên tôn. Sau khi cảm ứng hồn huyết ngưng tụ, ông dùng thuật bói toán truy tìm nguồn gốc, phong ấn tin tức rồi âm thầm bám theo Vương Lâm suốt hành trình khảo nghiệm, cuối cùng chính thức hiện thân mời Vương Lâm làm đệ tử duy nhất. Sự tồn tại của ông trở thành chỗ dựa bí mật cho Vương Lâm trong các cuộc đối đầu về sau, và ông vẫn theo dõi đệ tử từ nơi bế quan tại Đạo Cổ nhất tộc."},{"id":"hoang-ton-dao-co","name":"Hoàng tôn Đạo Cổ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1866","trangThai":"song","blurb":"Hoàng tôn của Đạo Cổ nhất mạch, tự nhận vai thủ hộ tộc khi Huyền La vắng mặt. Hắn nắm giữ hồn phách bí ẩn mà quốc sư cho rằng có thể giúp hắn thống trị toàn bộ Tiên Cương đại lục, đồng thời âm thầm theo dõi nhất cử nhất động của Huyền La và tiến hành tuyển hậu bằng phương thức dung nhập tàn hồn.","vaiTro":"Hoàng tôn Đạo Cổ nhất mạch — mưu đồ nắm quyền Tiên Cương đại lục","tinhCach":"Kiêu ngạo, khinh thường tu sĩ động phủ giới; tham vọng quyền lực, tính toán thâm sâu; quyết đoán tàn nhẫn","tabs":{"diem":[{"text":"Lộ diện tại hoàng cung, tay cầm quả cầu chứa hồn phách đang ngủ say, mưu đồ nắm Tiên Cương","chuong":"@c1700"},{"text":"Thấy Huyền La trở về một mình, âm thầm cười lạnh và bỏ ý định truy tìm nữ tử năm đó","chuong":"@c1702"},{"text":"Tiến hành tuyển hậu bằng cách để nữ tử dung nhập tàn hồn, liên tiếp thất bại","chuong":"@c1866"}],"kinhLich":[{"mucCt":"vua","text":"Hoàng tôn Đạo Cổ đang tuyển hậu bằng cách để các nữ tử dung nhập tàn hồn nhưng vẫn thất bại liên tiếp. Khi tin Vương Lâm truyền vào hoàng cung, hắn không nhận ra đó là người từng khiến mình ghen ghét, song vẫn phát động lực lượng thu thập tư liệu vì khả năng Vương Lâm trở thành Đại Thiên Tôn thứ sáu của Tiên Tộc.","anchor":"Khi tin tức này truyền vào hoàng cung, hoàng tôn Đạo Cổ đang tiến hành tuyển hậu","bridge":true,"khoang":"@c1866"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"đối tượng điều tra","ghiChu":"Không nhận ra Vương Lâm là người từng khiến mình ghen ghét."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1866"]},{"id":"tien-hoang","name":"Tiên Hoàng","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1866","importance":"normal","mucCt":"ky","tieuDe":"Bày mưu Đại Thiên Tôn","text":"Tiên Hoàng xuất hiện bên ao nước đen, cho Minh Đạo Tôn cơ hội thông qua Phản Cổ đại pháp để có huyết mạch Tiên Tổ, nhưng thành bại tùy thuộc oán hận của Minh Đạo Tôn. Sau đó hắn rời đi và tự tính kế tái hiện huy hoàng Tiên Tổ, định dùng Cửu Đế khai đao, trọng dụng Đạo Nhất, giết Võ Phong để lấy tư cách Đại Thiên Tôn cho Đạo Phi, còn Song Tử tạm thời chưa đáng lo nếu chưa song hồn quy nhất.","anchor":"Thân ảnh của Tiên Hoàng cất bước đi ra"},{"chuong":"@c1870","importance":"normal","mucCt":"vua","tieuDe":"Ban chỉ sắc phong","anchor":"Nội dung cụ thể Vương Lâm không nghe, chỉ nghe được trong chỉ ý của Tiên Hoàng là bảo hắn sáng sớm bảy ngày sau tới Tiên Đạo Điện","text":"Tiên Hoàng ban ý chỉ yêu cầu Vương Lâm sáng sớm bảy ngày sau tới Tiên Đạo Điện trong hoàng cung để tiến hành đại lễ sắc phong Dược Thiên Tôn. Chương cũng nêu mỗi đời Tiên Hoàng đều tự thân sắc phong tu sĩ Dược Thiên Tôn."},{"chuong":"@c1871","importance":"bridge","mucCt":"gon","tieuDe":"Chuẩn bị sắc phong","text":"Tiên Hoàng đồng ý cho các gia tộc tới xem lễ và được lão thanh y nói sẽ tự mình sắc phong Vương Lâm sau khi hắn đi qua cửu môn.","anchor":"Đến lúc đó Tiên Hoàng bệ hạ sẽ tự mình sắc phong cho ngươi"},{"mucCt":"ky","text":"Tiên Hoàng ngồi trên long ỷ trong Tiên Đạo Điện, bỏ qua việc Vương Lâm trấn áp lão già mặc thanh y vì xem đó là nô tài bất kính với đệ nhất Dược Thiên Tôn, rồi giao Thượng Huyền Đạo chủ trì đại lễ sắc phong. Khi Thiên Sư Thú bị huyết tế dẫn tới, ông dùng lửa năm màu giết nó trước toàn trường để phô diễn thần uy. Sau đó ông kinh ngạc vì sợi tóc bạc không bị Cực Hỏa Đạo thiêu hủy, còn bàn tay lửa năm màu của mình bị sợi tóc xuyên thủng.","anchor":"Thôi, ngươi thân là đệ nhất trong Dược Thiên Tôn, nô tài kia bất kính với ngươi, việc này cũng không làm khó ngươi nữa.","bridge":true,"khoang":"@c1872"},{"mucCt":"vua","text":"Tiên Hoàng cho phép Vương Lâm giữ sợi tóc bạc trong đại lễ sắc phong. Cuối chương, ông bất đắc dĩ gọi Đạo Phi, dùng lực lượng nhu hòa đẩy hắn ra khỏi quốc sư và nhắc rằng đây là đại lễ sắc phong của ân công hắn.","anchor":"Đạo Phi, đừng gây chuyện nữa. Lúc này là đại lễ sắc phong của ân công của ngươi","bridge":true,"khoang":"@c1873"},{"chuong":"@c1875","importance":"normal","mucCt":"ky","tieuDe":"Sắc phong Bạch Phát","text":"Tiên Hoàng giải thích trạng thái của Đạo Phi bằng giọng của một người anh, cho biết Đạo Phi sau khi trở về trí nhớ lúc tỉnh lúc mê. Hắn bỏ nghi thức khiêu chiến, chính thức sắc phong Vương Lâm làm Dược Thiên Tôn thứ bốn mươi chín của tiên tộc với danh hiệu Bạch Phát Dược Thiên Tôn. Hắn dùng quyền lợi vào nơi bế quan của tiên tổ để mời Vương Lâm, nói cơ hội này cực hiếm và mong hóa giải hiểu lầm. Khi Vương Lâm từ chối, hắn im lặng gật đầu, không khuyên thêm.","anchor":"hôm nay sẽ sắc phong ngươi là vị Dược Thiên Tôn thứ bốn mươi chín của tiên tộc"},{"chuong":"@c1877","importance":"bridge","mucCt":"gon","tieuDe":"Bị nghi ban hồn phong","text":"Tiên Hoàng bị Vương Lâm suy đoán là người duy nhất ở tổ thành có thể nâng hai kẻ xa lạ lên sức mạnh Dược Thiên Tôn và ban hồn phong.","anchor":"Ở tổ thành này, có thể làm được điều này chỉ có tiên hoàng"},{"chuong":"@c1881","importance":"normal","mucCt":"ky","tieuDe":"Đưa Đạo Phi đi","text":"Tiên Hoàng xuất hiện từ vòng xoáy màu vàng sau lưng Đạo Phi đúng lúc ký ức của Đạo Phi có dấu hiệu khôi phục. Hắn đặt tay lên vai làm Đạo Phi mê man, khiến dấu chưởng ấn đang hiện ra biến mất, rồi nói sẽ đưa Đạo Phi tới nơi bế quan của tiên tổ để khôi phục hoàn toàn ký ức. Hành động này khiến Vương Lâm nhận ra Tiên Hoàng dùng Đạo Phi làm mồi để dụ mình vào địa cung.","anchor":"Người này mặc hoàng bào, đầu đội đế quan, chính là tiên hoàng"},{"mucCt":"vua","text":"Tiên Hoàng trở thành mục tiêu bị Vương Lâm nhờ Song Tử Đại Thiên Tôn vây khốn một ngày. Hắn giao chiến với Song Tử trên bầu trời hoàng cung trong vầng mặt trời màu vàng, đồng thời quát rằng Vương Lâm xông vào hoàng cung là bất kính và phản bội tiên tộc.","anchor":"trong mặt trời màu vàng chính là Tiên Hoàng mặc hoàng bào","bridge":true,"khoang":"@c1882"},{"mucCt":"vua","text":"Tiên Hoàng đang giao chiến với Song Tử Đại Thiên Tôn nên tạm thời không thể ra tay với Vương Lâm trong hoàng cung. Theo lời quốc sư, hắn từng định giết Vương Lâm nhưng vì đa nghi nên không làm, sau đó lại muốn mượn Vương Lâm để thành toàn Minh Đạo Tôn trong địa cung.","anchor":"Tiên Hoàng vốn định giết ngươi, nhưng ta hiểu rõ Đạo Chân.","bridge":true,"khoang":"@c1883"},{"mucCt":"vua","text":"Tiên Hoàng được quốc sư nhắc là người đã chuẩn bị toàn diện truyền thừa, dùng Minh Đạo Tôn làm trung tâm phản tổ và có thủ đoạn khống chế sau khi phản tổ thành công. Hắn cũng là người bố trí chín sợi xích giam Liên Đạo Phi, trong lúc này đang giao chiến với Song Tử Đại Thiên Tôn nên tạm bị vây khốn.","anchor":"Tiên Hoàng đã bày mưu trên người Minh Đạo Tôn nhiều năm","bridge":true,"khoang":"@c1884"},{"chuong":"@c1885","importance":"bridge","mucCt":"vua","tieuDe":"Nghi vấn lựa chọn","text":"Tiên Hoàng được nhắc tới như người đã lựa chọn giữa Minh Đạo Tôn và Liên Đạo Phi, đồng thời có thể đã biết việc Vương Lâm động vào xích sắt.","anchor":"Người Tiên Hoàng lựa chọn rốt cục là Minh Đạo Tôn hay là đệ đệ Liên Đạo Phi của hắn"},{"mucCt":"vua","text":"Tiên Hoàng đánh chưởng ấn màu vàng kim xuống không gian cấm cung, nhưng đòn này bị đôi mắt ngọn núi hình đầu Tiên Tổ trong Cửu Tọa tiên sơn hấp thu và biến mất. Tiếng gầm giận dữ của ông truyền tới từ tầng tầng không gian, cho thấy ông muốn chạy tới nơi này nhưng bị Song Tử Đại Thiên Tôn ngăn cản.","anchor":"Giọng nói đó thuộc về Tiên Hoàng, tiếng gầm giống như bị tầng tầng không gian ngăn cách","bridge":true,"khoang":"@c1886"},{"chuong":"@c1887","importance":"bridge","mucCt":"gon","tieuDe":"Nguồn gốc từ Tiên Tổ","text":"Tiên hoàng được nhắc qua thân phận Liên Vân Quyết là thủy tổ của tiên hoàng và cả Tiên tộc.","anchor":"Hắn chính là thủy tổ của tiên hoàng, là thủy tổ của cả tiên tộc"},{"chuong":"@c1889","importance":"normal","mucCt":"ky","tieuDe":"Lộ kế đầu Tiên Tổ","text":"Tiên hoàng dùng giọt máu vàng chặn lời cuối của đầu tiên tổ, ngăn nghi thức giải phong ấn của quốc sư hoàn tất. Hắn bước ra từ lỗ thủng, tuyên bố đã nhìn thấu kế hoạch của quốc sư với Đạo Phi, Minh Đạo Tôn và Vương Lâm. Hắn tiết lộ kế hoạch thật của mình là khiến đầu tiên tổ tỉnh lại để dùng cái đầu như pháp bảo mạnh nhất của tiên tộc và kế thừa tu vi tiên tổ trong lúc nguy cấp. Sau đó hắn điều khiển kim quang đầu tiên tổ đánh tan công kích của Song Tử, vẫn tự tin dù bị uy hiếp bằng Tử Lâm Tín Thuật.","anchor":"Tiếng cười dài vang vọng không trung của tiên hoàng từ trong lỗ thủng vọng ra"},{"mucCt":"ky","text":"Tiên Hoàng đứng trên đầu lâu Tiên Tổ, thừa nhận đã chờ Cửu Đế và bị vạch rõ kế hoạch lợi dụng quốc sư để đoạt quyền điều khiển đầu lâu. Hắn phát động Bát Cực Đạo, Cực Hóa Đạo và Tiên Hỏa Đạo, rồi dùng máu dẫn hư ảnh Tiên Tổ cùng kim kiếm vàng đối kháng bốn Đại Thiên Tôn. Khi bị yêu cầu thả Vương Lâm và phong ấn lại đầu lâu, hắn không thỏa hiệp mà cưỡng ép hấp thu lực lượng, nhưng bị phong ấn Điệu vong tộc bên trong đầu lâu cản trở.","anchor":"Tiên Hoàng cắn đầu lưỡi, phun ra một ngụm máu tươi","bridge":true,"khoang":"@c1890"},{"chuong":"@c1891","importance":"major","mucCt":"ky","tieuDe":"Giải phong Điệu Vong","text":"Trong lúc bốn Đại Thiên Tôn bên ngoài phá kim quang, Tiên Hoàng dùng máu thịt hậu nhân Tiên Tổ dẫn động phép tắc Thiên Cương, tự hủy ngón tay, bàn tay và nửa cánh tay phải để vĩnh viễn giải phong ấn Điệu Vong Tộc. Sau khi đạt mục đích, hắn dùng sức mạnh tràn vào thân thể Vương Lâm để xóa sạch quốc sư giả, rồi hấp thu sức mạnh từ đầu Tiên Tổ nhưng bị Hải Tử thức tỉnh quốc sư thật cắt đứt. Hắn kinh hoảng nhận ra kế hoạch tưởng nằm trong tay mình lại đã bị Điệu Vong Tộc tính trước.","anchor":"Lấy máu thịt hậu nhân Tiên Tổ của ta. dẫn động phép tắc Thiên Cương"},{"chuong":"@c1892","importance":"major","mucCt":"ky","tieuDe":"Bị ép thí tổ","text":"Tiên hoàng bị Cửu Đế và Hải Tử vạch rõ là cha của Hải Tử, đồng thời là hậu nhân có huyết mạch Tiên Tổ cần dùng để phá trớ thuật. Hắn chất vấn các Đại Thiên Tôn, chỉ ra Cửu Đế đã lợi dụng Vương Lâm, Song Tử, Minh Đạo Tôn, Liên Đạo Phi, chính hắn và linh hồn tiên tộc. Sau khi biết lựa chọn còn lại là bị giết và rút huyết mạch, hắn trầm mặc rồi ra tay nâng đầu Tiên Tổ lên.","anchor":"Tiên hoàng kia sau một lúc trầm mặc. giống như đã có lựa chọn"},{"chuong":"@c1893","importance":"normal","mucCt":"ky","tieuDe":"Tự bạo đoạt xá thất bại","text":"Tiên Hoàng dùng lực huyết mạch làm nứt đầu lâu Tiên Tổ, giả vờ hấp thu sương vàng để dụ Cửu Đế, Đạo Nhất và Võ Phong cùng ra tay. Hắn tự bạo thân thể Đại Thiên Tôn, khiến lực nổ hòa với thần thông của ba người và phá hủy nặng cấm cung, địa cung cùng hoàng cung. Sau đó linh hồn hắn lao tới mắt trái đầu lâu định đoạt xá Liên Đạo Phi, nhưng bị Vương Lâm chặn lại và thu vào không gian trữ vật.","anchor":"Hắn lựa chọn tự bạo rồi"},{"chuong":"@c1894","importance":"bridge","mucCt":"gon","tieuDe":"Tự bạo gây lệch cục","text":"Việc Tiên Hoàng bỏ thân thể Đại Thiên Tôn và tự bạo tiếp tục là nguyên nhân khiến Cửu Đế tính sai, đồng thời Trớ Thuật bị chia sẻ lên các Đại Thiên Tôn và Tiên Hoàng.","anchor":"Tiên Hoàng lại bỏ qua thân thể Đại Thiên Tôn. lựa chọn tự bạo"},{"chuong":"@c1895","importance":"bridge","mucCt":"gon","tieuDe":"Cái chết được nhắc","text":"Cửu Đế nhắc Tiên Hoàng đã tử vong để lay động Song Tử trong lúc Đạo Nhất sắp bị Trớ Thuật hủy diệt.","anchor":"Tiên Hoàng đã tử vong, ngươi chẳng lẽ còn muốn nhìn Đạo Nhất bị Trớ Thuật hủy diệt mới được"},{"chuong":"@c1897","importance":"bridge","mucCt":"vua","tieuDe":"Cái chết gây khủng hoảng","text":"Cái chết của Tiên Hoàng khiến Liên Đạo Phi trở nên trọng yếu với tiên tộc và làm Song Tử nhận định tiên tộc về sau không còn huyết mạch Tiên Hoàng.","anchor":"Tiên Hoàng đã chết, Liên Đạo Phi rất quan trọng với tiên tộc"}],"nhanMach":[{"ten":"Minh Đạo Tôn","tag":"khac","quanHe":"quân cờ","ghiChu":"Dùng Minh Đạo Tôn tu Phản Cổ đại pháp trong ao nước đen."},{"ten":"Đạo Phi","tag":"ho-hang","quanHe":"hoàng đệ","ghiChu":"Đặt Đạo Phi vào kế hoạch đoạt tư cách Đại Thiên Tôn."},{"ten":"Thượng Đạo Huyền","tag":"cap-tren","quanHe":"Quốc sư trọng thần bên cạnh Tiên Hoàng","ghiChu":"Thượng Đạo Huyền là tông chủ đời nay của Đạo Môn."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người được sắc phong Dược Thiên Tôn","ghiChu":"Ban chỉ yêu cầu Vương Lâm tới Tiên Đạo Điện dự đại lễ sắc phong."},{"ten":"Sứ giả thanh bào truyền chỉ của Tiên Hoàng","tag":"cap-tren","quanHe":"người dưới quyền truyền chỉ","ghiChu":"Sai sứ giả thanh bào tới Lý Phủ đọc thánh chỉ."},{"ten":"Thượng Huyền Đạo","tag":"dong-minh","quanHe":"Quốc sư được Tiên Hoàng giao chủ trì đại lễ sắc phong.","ghiChu":"Đứng bên cạnh long ỷ trong Tiên Đạo Điện và thay Tiên Hoàng mở huyết tế tiên."},{"ten":"Thiên Sư Thú bị thương","tag":"doi-thu","quanHe":"Sinh linh thiên ngoại bị Tiên Hoàng giết trong nghi thức sắc phong.","ghiChu":"Tiên Hoàng dùng lửa năm màu bao phủ và thiêu chết Thiên Sư Thú."},{"ten":"Lão già mặc thanh y","tag":"khac","quanHe":"Nô tài bất kính bị Tiên Hoàng bỏ qua sau khi bị Vương Lâm trấn áp.","ghiChu":"Tiên Hoàng xem sự việc không đáng làm khó Vương Lâm."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người được sắc phong","ghiChu":"Tiên Hoàng xử lý việc Vương Lâm giữ sợi tóc bạc và nhắc Đạo Phi rằng Vương Lâm là ân công của hắn."},{"ten":"Liên Đạo Phi","tag":"ho-hang","quanHe":"Người trong hoàng tộc cần ngăn cản","ghiChu":"Tiên Hoàng gọi tên Đạo Phi và ngăn hắn gây sự với quốc sư."},{"ten":"Nữ tử ở bên cạnh Đạo Phi","tag":"khac","quanHe":"Người được Tiên Hoàng nhắc là từng ở bên cạnh Đạo Phi khi Đạo Phi được tìm thấy.","ghiChu":"Tiên Hoàng tiết lộ nàng đã tỉnh lại và đang cảm ngộ tại nơi bế quan của tiên tổ."},{"ten":"Song Tử Đại Thiên Tôn","tag":"doi-thu","quanHe":"giao chiến","ghiChu":"Bị Song Tử vây khốn theo lời nhờ của Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"quy kết phản bội","ghiChu":"Quy kết việc Vương Lâm xông vào hoàng cung là phản bội tiên tộc."},{"ten":"Liên Đạo Phi","tag":"doi-thu","quanHe":"Dùng chín sợi xích bố trí phong tỏa Liên Đạo Phi.","ghiChu":"Động vào xích sẽ khiến hắn phát hiện."},{"ten":"Tiên Tổ Liên Vân Quyết","tag":"ho-hang","quanHe":"Thủy tổ","ghiChu":"Liên Vân Quyết được xác nhận là thủy tổ của tiên hoàng."},{"ten":"Quốc sư giả của Điệu Vong Tộc","tag":"doi-thu","quanHe":"Lợi dụng rồi diệt khẩu","ghiChu":"Sau khi giải phong ấn Điệu Vong Tộc, Tiên Hoàng xóa dấu vết của quốc sư giả trong thân thể Vương Lâm."},{"ten":"Hải Tử Thiên Tôn","tag":"doi-thu","quanHe":"Bị phá kế hoạch hấp thu truyền thừa","ghiChu":"Hải Tử thức tỉnh sức mạnh quốc sư chân chính và cắt đứt nguồn kim quang từ đầu Tiên Tổ."},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"người trở nên trọng yếu sau cái chết của hắn","ghiChu":"Liên Đạo Phi bị dùng thay đầu tiên tổ trấn áp bảy mươi hai châu."},{"ten":"Lão tổ Đại Hồn Môn","tag":"khac","quanHe":"người bị nghi đã tính trước biến cố của hắn","ghiChu":"Vương Lâm suy đoán lão tổ Đại Hồn Môn có thể đã tính ra việc Tiên Hoàng đoạt xá và tự bạo."}],"tuViMoc":[],"diem":[{"text":"Bị chí bảo Thiên Nghịch đánh trọng thương, phải bế quan không màng thế sự","chuong":"@c1213"},{"text":"Dùng thân ảnh kim sắc và thánh chỉ buộc Lục Ma Châu cùng Thiên Ngưu Châu đình chiến, thể hiện uy quyền tuyệt đối của Tiên Hoàng","chuong":"@c1818"},{"text":"Bày bố kế hoạch dùng Minh Đạo Tôn làm trung tâm Phản Cổ đại pháp, đồng thời lợi dụng quốc sư để mở phong ấn đầu lâu Tiên Tổ nhằm giải phong Điệu Vong tộc","chuong":"@c1891"},{"text":"Bị Cửu Đế và Hải Tử vạch rõ là cha Hải Tử, hậu nhân huyết mạch Tiên Tổ bị ép hiến thân làm tế phẩm","chuong":"@c1892"},{"text":"Tự bạo thân thể Đại Thiên Tôn trong mưu đồ đoạt xá thất bại, tử vong gây chấn động cục diện Tiên Tộc","chuong":"@c1893"},{"text":"Hồn phách bị Vương Lâm dung nhập vào đầu lâu Tiên Tổ, hòa vào Đại Thiên Tôn chi dương","chuong":"@c1926"}]},"nguon":["@c1866","@c1867","@c1870","@c1871","@c1872","@c1873","@c1875","@c1877","@c1881","@c1882","@c1883","@c1884","@c1885","@c1886","@c1887","@c1889","@c1890","@c1891","@c1892","@c1893","@c1894","@c1895","@c1897"],"canhGioiCaoNhat":"Đại Thiên Tôn @c1890","vaiTro":"Bát Cực Đại Thiên Tôn — Tiên Hoàng Trung Châu, ca ca Liên Đạo Phi","tinhCach":"kiêu ngạo, trọng uy quyền; quyết đoán, ra tay dứt khoát; thâm trầm, giỏi bố cục; biết đổi thái độ trước cục diện bất lợi","blurb":"Tiên Hoàng, tức Liên Đạo Chân, là Bát Cực Đại Thiên Tôn của Tiên Tộc và chủ nhân hoàng cung Trung Châu, được xem là kiêu ngạo nhất trong các Đại Thiên Tôn. Từng bị chí bảo Thiên Nghịch đánh trọng thương phải bế quan, sau khi xuất quan hắn dùng thánh chỉ can thiệp chiến cuộc, sắc phong Vương Lâm và âm thầm bày bố kế hoạch quanh đầu lâu Tiên Tổ cùng Điệu Vong tộc. Cuối cùng hắn tự bạo thân thể Đại Thiên Tôn trong mưu đồ đoạt xá thất bại, hồn phách sau đó bị Vương Lâm thu lấy rồi dung nhập vào đầu lâu Tiên Tổ, hòa vào Đại Thiên Tôn chi dương.","gioiTinh":"nam","theLuc":[{"ten":"Hoàng tộc Tiên Tộc","trangThai":"gan-bo"}],"aliases":["Liên Đạo Chân","Tiên Hoàng đời này","Tiên hoàng","Đạo Chân","Tiên Hoàng Liên Đạo Chân"]},{"id":"co-dao-dai-thien-ton","name":"Cổ Đạo Đại Thiên Tôn","cn":"","aliases":["Cổ Đạo","lão tổ Cổ Tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Cổ Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn (@c1908)","trangThai":"song","blurb":"Cổ Đạo Đại Thiên Tôn là đệ nhất nhân trong Cửu Dương Tiên Cương, bậc tiền bối cùng thời Cổ Tổ, cư ngụ trên đỉnh Cổ Đạo Sơn. Uy thế lịch sử từng giết Đại Thiên Tôn trong đại chiến khiến Tiên Tộc dù chiếm ưu thế số lượng Đại Thiên Tôn vẫn không dám tùy tiện tiến công Cổ Tộc. Hắn là chỗ dựa then chốt giúp hoàng quyền Đạo Cổ nhất mạch áp chế các thế lực khác trong tộc, đồng thời từng truyền khẩu dụ thừa nhận quyền kế vị hoàng hậu Diệp Vi.","vaiTro":"Đệ nhất cường giả Cổ Tộc — lão tổ trấn giữ hoàng quyền Đạo Cổ","tinhCach":"Uy nghiêm áp đảo, lấy sức mạnh tuyệt đối làm lẽ trị tộc; thận trọng quan sát, không vội hành động khi chưa thấu triệt đối phương; trọng lời hứa, nói xuống núi thì xuống núi","tabs":{"diem":[{"text":"Được xưng tụng đệ nhất nhân Cửu Dương Tiên Cương, từng giết Đại Thiên Tôn trong đại chiến","chuong":"@c1866"},{"text":"Là nhân tố quan trọng chống lưng hoàng quyền Cổ Tộc, giúp áp chế các Đại Thiên Tôn khác","chuong":"@c1904"},{"text":"Dùng ý chí đặt thử thách trên Cổ Đạo Sơn để thử Vương Lâm, rồi quan sát dị tượng trên người hắn","chuong":"@c1912"},{"text":"Hóa bàn tay đen như Ngũ Chỉ Sơn từ tháp cao trấn áp lực lượng Tiên Tộc, giữ lời xuống núi","chuong":"@c1914"},{"text":"Từng truyền khẩu dụ thừa nhận Diệp Vi kế vị hoàng hậu Đạo Cổ nhất mạch","chuong":"@c1922"},{"text":"Thở dài khi Thái Cổ Thần Cảnh hoàn thành, không truy sát Vương Lâm sau cái chết Đạo Cổ hoàng tôn","chuong":"@c1928"}],"kinhLich":[{"mucCt":"vua","text":"Cổ Đạo Đại Thiên Tôn được nhắc là đệ nhất nhân trong Cửu Dương Tiên Cương, từng giết Đại Thiên Tôn trong đại chiến Tiên Cổ và khiến Tiên Tộc rút lui. Hiện hắn vẫn ở Cổ Phong của Cổ Tộc, tạo thành uy hiếp khiến Tiên Tộc không dám tiến đánh.","anchor":"Cổ Đạo Đại Thiên Tôn hằng năm vẫn ở trên Cổ Phong của Cổ Tộc","bridge":true,"khoang":"@c1866"},{"chuong":"@c1904","importance":"bridge","mucCt":"gon","tieuDe":"Uy hiếp chống lưng hoàng quyền","text":"Cổ Đạo Đại Thiên Tôn được Vương Lâm suy xét là nhân tố quan trọng giúp hoàng quyền Cổ Tộc áp chế các Đại Thiên Tôn.","anchor":"sở dĩ có thể áp chế Đại Thiên Tôn, trên thực tế còn có quan hệ rất lớn tới Cổ Đạo Đại Thiên Tôn"},{"chuong":"@c1908","importance":"normal","mucCt":"vua","tieuDe":"Muốn gặp Vương Lâm","text":"Cổ Đạo Đại Thiên Tôn được Đạo Cổ Hoàng xem là chỗ dựa cho hoàng quyền và được Huyền La gọi là lão tổ Cổ Tộc khiến Tiên Tộc không dám xâm phạm. Huyền La nói đã báo cáo chuyện Vương Lâm với ông từ năm đó và ông muốn gặp Vương Lâm một lần, có thể mang tới cơ duyên lớn.","anchor":"Cổ Đạo Đại Thiên Tôn quanh năm bế quan, đối với chuyện của ngươi năm đó vi sư đã báo cáo với hắn"}],"tuViMoc":[{"chuong":"@c1866","canhGioi":"Đại Thiên Tôn","text":"Được nhắc là Đại Thiên Tôn mạnh nhất trong Cửu Dương Tiên Cương.","importance":"major"}],"nhanMach":[{"ten":"Huyền La","tag":"khac","quanHe":"cùng phía Cổ Tộc được đem ra so sánh","ghiChu":"Cả hai được nhắc trong so sánh về mức khó tiếp cận Tổ Thành của người Cổ Tộc."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Muốn gặp Vương Lâm theo lời Huyền La.","ghiChu":"Cuộc gặp được Huyền La xem là cơ duyên lớn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1866","@c1867","@c1904","@c1908"]},{"id":"cuu-de-dai-thien-ton","name":"Cửu Đế Đại Thiên Tôn","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Cửu Đế được nhắc trong lời đồn là một trong các Đại Thiên Tôn bị Vương Lâm cự tuyệt. Trong tính toán của Tiên Hoàng, nếu âm mưu thành công thì Cửu Đế sẽ là người đầu tiên bị dùng để khai đao nhằm ép những người khác thuần phục.","anchor":"Lão già Cửu Đế này. nếu ta thành công sẽ dùng hắn khai đao","bridge":true,"khoang":"@c1866"},{"chuong":"@c1867","importance":"normal","tieuDe":"Đế Sơn áp chế hoàng quyền","mucCt":"vua","text":"Ở trên Đế Sơn giữa Đông Thành và Tây Thành, tạo áp lực khiến cả Tổ Thành và hoàng cung như bị vạn sơn áp đỉnh. Nhiều người suy đoán Đạo Môn tồn tại là để đối kháng với Đế Sơn đang dần lấn át hoàng quyền.","anchor":"Người đó chính là Cửu Đế Đại Thiên Tôn, khiến cho cả Tổ Thành"},{"chuong":"@c1875","importance":"bridge","mucCt":"gon","tieuDe":"Sai người mời khách","text":"Cửu Đế Đại Thiên Tôn là người ra lệnh cho Hải Tử Thiên Tôn mời Vương Lâm tới Đế Sơn.","anchor":"Lời mời của Cửu Đế Đại Thiên Tôn hiển nhiên là phải tuân theo"},{"chuong":"@c1877","importance":"bridge","mucCt":"gon","tieuDe":"Bị tính tới cứu viện","text":"Cửu Đế Đại Thiên Tôn được Vương Lâm nhắc trong suy luận rằng thế trận có thể đã bố trí người hạn chế ông, nhằm ngăn cứu viện bên ngoài lọt vào phố tuyết.","anchor":"hai là tìm người tới hạn chế Cửu Đế Đại Thiên Tôn"},{"mucCt":"ky","text":"Cửu Đế hiện thân sau lưng Hải Tử, ôm nàng kéo lui và đỡ một chưởng diệt sát của Vương Lâm tóc đen. Ông nhận ra trên người đối phương có lực lượng đại biểu sát lục và hủy diệt, rồi giao thủ bằng tuyết kiếm và ấn ký ánh sáng. Cuối cùng Cửu Đế nói Hải Tử vô tội, trao mảnh vỡ Tiên Cực kiếm cho Vương Lâm để chấm dứt chuyện hôm nay và mang Hải Tử rời đi.","anchor":"Lúc này Hải Tử là người vô tội, vật này tặng cho ngươi","bridge":true,"khoang":"@c1880"},{"chuong":"@c1881","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc trong suy luận","text":"Cửu Đế được Vương Lâm nhắc lại trong chuỗi suy luận về lý do Tiên Hoàng không muốn tự mình ra tay sau trận đánh trước đó.","anchor":"cùng với Cửu Đế đánh một trận"},{"chuong":"@c1883","importance":"bridge","mucCt":"gon","tieuDe":"Uy hiếp Tiên Hoàng","text":"Cửu Đế được nhắc là mối uy hiếp lớn đối với Tiên Hoàng trong tổ thành, khiến Tiên Hoàng phải tránh làm hắn hoài nghi khi sắp đặt việc sắc phong và trận chém giết trên phố dài.","anchor":"Cửu Đế đối với Tiên Hoàng là một mối uy h**p rất lớn."},{"mucCt":"vua","text":"Cửu Đế bước ra từ lỗ thủng trên bầu trời khi Tiên hoàng cho rằng Tử Lâm Tín Thuật chưa đủ ép mình thỏa hiệp. Lời chen vào của lão khiến thế đối đầu quanh Vương Lâm và đầu tiên tổ xuất hiện biến số mới.","anchor":"chỉ thấy từ bên trong lỗ thủng trên bầu trời, Cửu Đế Đại Thiên Tôn bước ra","bridge":true,"khoang":"@c1889"},{"mucCt":"ky","text":"Cửu Đế hiện thân trước Tiên Hoàng, chỉ ra mưu đồ lợi dụng quốc sư để hấp thu đầu lâu Tiên Tổ. Ông biến hóa từ dáng già nua thành nam tử trung niên, dùng mặt trời trắng và bạch lang nghênh kích kim kiếm, đồng thời gọi Đạo Nhất và Võ Phong cùng ra tay. Sau khi kim kiếm bị phá, ông yêu cầu phong ấn lại đầu lâu Tiên Tổ để duy trì thế cục năm Đại Thiên Tôn.","anchor":"Đạo Nhất, Võ Phong, hai người các ngươi giờ vẫn còn bất động thì còn đợi tới khi nào","bridge":true,"khoang":"@c1890"},{"chuong":"@c1891","importance":"normal","mucCt":"vua","tieuDe":"Xác nhận Hải Tử","text":"Bị Tiên Hoàng chất vấn, Cửu Đế xác nhận Hải Tử là con gái mình. Hắn nói thọ nguyên và việc trở thành Đại Thiên Tôn năm xưa đều nhờ Điệu Vong Tộc, đồng thời hé lộ kế hoạch chỉ thật sự khởi động sau khi Vương Lâm xuất hiện trên Tiên Cương.","anchor":"Tiên hoàng, nó là con gái của ta"},{"chuong":"@c1892","importance":"normal","mucCt":"ky","tieuDe":"Công khai kế hoạch","text":"Cửu Đế công khai kế hoạch Điệu Vong Tộc do thiên tài của tộc này nghĩ ra và nói mình từng nhận ân giúp thành Đại Thiên Tôn nên phải trợ giúp. Hắn giải thích vai trò của Hải Tử, Vương Lâm và linh miếu bảy mươi hai châu, rồi ép Tiên hoàng dùng huyết mạch phá đầu Tiên Tổ. Hắn còn phân chia lợi ích từ thi thể Tiên Tổ cho Song Tử, Vũ Phong, Đạo Nhất và chính mình, đồng thời xác nhận trớ thuật của Tiên Tổ là rào cản chết chóc cần hậu nhân thí tổ mới phá được.","anchor":"Kế hoạch này là do thiên tài của Điệu Vong Tộc nghĩ ra"},{"mucCt":"vua","text":"Cửu Đế là người đầu tiên lao tới khi nhận ra Tiên Hoàng có biến, hóa bạch lang công kích hắn. Khi Trớ Thuật bùng phát sau vụ tự bạo, Cửu Đế nhờ tu vi cao nhất nên cưỡng ép đối kháng, nhưng da thịt xuất hiện ký hiệu quỷ dị và không thể phân thần ngăn Vương Lâm.","anchor":"Tu vi Cửu Đế cao nhất, hơn nữa lực lượng của Trớ Thuật bị bốn người chia sẻ","bridge":true,"khoang":"@c1893"},{"mucCt":"ky","text":"Cửu Đế bị Trớ Thuật làm đau đớn nhưng vẫn cưỡng ép áp chế, nhận ra mình tính sai vì Tiên Hoàng tự bạo và Vương Lâm còn sống. Hắn thừa nhận xem thường Vương Lâm, vừa hứa cho rời đi an toàn và trợ giúp thành Đại Thiên Tôn nếu giao đầu lâu, vừa đe dọa đây có thể là mồ chôn của Vương Lâm. Khi Vương Lâm trao mắt Tiên Tổ cho Song Tử, hắn nổi giận gọi Đạo Nhất, Võ Phong và Hải Tử cùng đoạt đầu lâu, rồi thi triển lực lượng thái dương đối kháng Song Tử.","anchor":"Vương Lâm, lão phu thừa nhận là lại một lần nữa xem thường ngươi","bridge":true,"khoang":"@c1894"},{"mucCt":"ky","text":"Cửu Đế vừa giao chiến với Song Tử vừa quan sát tình thế Đạo Nhất, kinh hãi khi thấy Đạo Nhất bị Vương Lâm áp chế và Trớ Thuật đẩy vào nguy cơ tử vong. Hắn thoát khỏi Song Tử để lao tới can thiệp, đồng thời dùng cái chết của Tiên Hoàng và thân phận tiên tộc để khiến Song Tử khựng lại. Khi Vương Lâm ngưng ra hình dáng ban đầu của Đại Thiên Tôn Chi Dương, Cửu Đế bị chấn động.","anchor":"Cửu Đế thoát khỏi Song Tử. bỗng nhiên cất bước lao tới, nhìn như muốn ngăn cản Vương Lâm truy kích nhưng trên thực tế lại mang theo sát khí","bridge":true,"khoang":"@c1895"}],"nhanMach":[{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"bị nhắm tới","ghiChu":"Tiên Hoàng dự định dùng Cửu Đế khai đao nếu kế hoạch thành công."},{"ten":"Hải Tử Thiên Tôn","tag":"su-mon","quanHe":"Ra tay cứu giúp","ghiChu":"Cửu Đế kéo Hải Tử khỏi một chưởng của Vương Lâm tóc đen và mang nàng rời đi."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Giao thủ rồi dàn xếp","ghiChu":"Cửu Đế đỡ đòn, giao thủ với trạng thái tóc đen của Vương Lâm và trao mảnh vỡ Tiên Cực kiếm để hóa giải."},{"ten":"Hải Tử Thiên Tôn","tag":"cha-me","quanHe":"Cha của Hải Tử","ghiChu":"Công khai xác nhận Hải Tử là con gái mình trước Tiên Hoàng."},{"ten":"Điệu Vong Tộc","tag":"an-nhan","quanHe":"Nhận ân từ tộc này","ghiChu":"Thọ nguyên và cơ hội trở thành Đại Thiên Tôn của hắn năm xưa đều liên quan tới Điệu Vong Tộc."},{"ten":"Liên Đạo Chân","tag":"doi-thu","quanHe":"thế lực gây áp lực lên hoàng quyền","ghiChu":"Đế Sơn của Cửu Đế Đại Thiên Tôn được mô tả dần lấn át hoàng quyền Tiên Tộc."},{"ten":"Thượng Đạo Huyền","tag":"doi-thu","quanHe":"đối trọng thế lực","ghiChu":"Đạo Môn do Thượng Đạo Huyền đứng đầu bị nhiều người suy đoán là tồn tại để đối kháng Đế Sơn."}],"tuViMoc":[],"diem":[{"text":"Được giới thiệu là Đại Thiên Tôn ở Trung Châu, bá đạo nhất trong năm tuyệt thế cường giả Tiên Tộc","chuong":"@c1826"},{"text":"Truyền thần thông ấn ký hình trứng và ban ngọc giản bảo mệnh cho Hải Tử với tư cách sư tôn","chuong":"@c1838"},{"text":"Xuất hiện trên bầu trời Sơn Hải cùng Đạo Nhất và Võ Phong để cứu Hải Tử","chuong":"@c1842"},{"text":"Trên Đế Sơn đánh giá Vương Lâm hơn Minh Đạo Tôn về đạo ngộ, chiến lực cùng tâm cơ, rồi trực tiếp muốn thu nhận làm đệ tử","chuong":"@c1864"},{"text":"Hiện thân trước Tiên Hoàng, vạch trần mưu đồ lợi dụng quốc sư để hấp thu đầu lâu Tiên Tổ và xác nhận Hải Tử là con gái ruột","chuong":"@c1891"},{"text":"Công khai kế hoạch Điệu Vong Tộc, tiết lộ từng nhận ân trợ giúp thành Đại Thiên Tôn từ thiên tài tộc này","chuong":"@c1892"}]},"nguon":["@c1866","@c1867","@c1875","@c1877","@c1880","@c1881","@c1883","@c1889","@c1890","@c1891","@c1892","@c1893","@c1894","@c1895"],"aliases":["Cửu Đế"],"gioiTinh":"nam","canhGioiCaoNhat":"Đại Thiên Tôn @c1895","vaiTro":"Đại Thiên Tôn Trung Châu — sư tôn và cha của Hải Tử Thiên Tôn","tinhCach":"bá đạo, uy áp tuyệt đối; trọng đạo ngộ và chiến lực khi đánh giá người; quyết đoán bảo hộ con gái; mưu lược thâm viễn, dám đối đầu Tiên Hoàng","blurb":"Cửu Đế Đại Thiên Tôn là một trong năm tuyệt thế cường giả Tiên Tộc tại Trung Châu, được lão tổ Đạo Ma Tông đánh giá là người bá đạo nhất. Ông là sư tôn của Hải Tử Thiên Tôn và về sau xác nhận nàng chính là con gái ruột của mình; từng nhiều lần can dự trực tiếp vào các biến cố trên Đế Sơn liên quan đến Vương Lâm, Tiên Hoàng và kế hoạch Điệu Vong Tộc. Trên Đế Sơn, ông quan sát Vương Lâm vượt các tầng qua phiến lá thu, đánh giá Vương Lâm hơn Minh Đạo Tôn cả về đạo ngộ lẫn chiến lực, rồi đích thân muốn thu nhận Vương Lâm làm đệ tử, đồng thời đối đầu với Tiên Hoàng để bảo vệ Hải Tử và vạch trần mưu"},{"id":"dao-nhat-dai-thien-ton","name":"Đạo Nhất Đại Thiên Tôn","aliases":["Đạo Nhất","Đạo Khất"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1866","importance":"normal","mucCt":"vua","tieuDe":"Được Tiên Hoàng tính dùng","text":"Đạo Nhất được nhắc là một trong các Đại Thiên Tôn bị Vương Lâm cự tuyệt lời mời. Tiên Hoàng đánh giá hắn giảo trá, từng hại chết sư huynh để đoạt tư cách Đại Thiên Tôn, vì vậy thuộc kiểu người có thể được trọng dụng.","anchor":"Nhưng hắn lại hại chết sư huynh mà cướp lấy tư cách này"},{"chuong":"@c1890","importance":"normal","mucCt":"vua","tieuDe":"Một chỉ hóa nhất","text":"Đạo Nhất theo tiếng gọi của Cửu Đế xuất hiện bên trái Tiên Hoàng, thần sắc ngưng trọng giữa lúc vạn vật như bất động. Ông dùng một chỉ chứa đạo vạn vật hóa nhất công kích Tiên Hoàng, bị dư lực kim kiếm cuốn lui rồi đồng ý duy trì thế cục năm Đại Thiên Tôn.","anchor":"Đạo Nhất thiên tôn cất bước đi ra, thần sắc cực kỳ ngưng trọng"},{"chuong":"@c1891","importance":"normal","mucCt":"gon","tieuDe":"Biến số ngoài dự tính","text":"Đạo Nhất được Tiên Hoàng nhắc như một biến số xuất hiện nhanh hơn dự liệu trong kế hoạch của hắn.","anchor":"nhưng Đạo Nhất và Vũ Phong, sao hai người bọn họ lại tới nhanh như vậy"},{"chuong":"@c1892","importance":"normal","mucCt":"vua","tieuDe":"Biết thiếu mấu chốt","text":"Đạo Nhất thừa nhận Cửu Đế từng nói cho hắn kế hoạch Điệu Vong Tộc nhưng không tiết lộ Vương Lâm là mấu chốt. Cửu Đế hứa giao đầu Tiên Tổ cho hắn để hình thần quy nhất nếu kế hoạch thành công.","anchor":"Bổn tôn hôm nay cũng mới biết Vương Lâm này chính là nhân vật mấu chốt của kế hoạch"},{"mucCt":"vua","text":"Đạo Nhất cùng Võ Phong và Cửu Đế lao tới công kích Tiên Hoàng, nhưng đòn đánh của hắn bị cuốn vào vụ tự bạo. Sau khi đầu lâu Tiên Tổ nứt rộng, hắn bị Trớ Thuật phản phệ, hắc khí bốc ra và khuôn mặt nhanh chóng thối rữa.","anchor":"Tu vi Đạo Nhất yếu nhất, giờ phút này phát ra tiếng kêu thảm thiết","bridge":true,"khoang":"@c1893"},{"mucCt":"vua","text":"Đạo Nhất bị hắc khí Trớ Thuật tra tấn, phẫn nộ vì Vương Lâm là kẻ dưới cấp mà dám đối đầu nên ra tay trước. Hắn bị sát lục lôi đình màu đen đẩy lui, khiến Trớ Thuật trong cơ thể nặng thêm, nhưng sau đó vẫn bị Cửu Đế gọi tiếp tục đoạt đầu lâu Tiên Tổ.","anchor":"Đây là lần đầu tiên sau khi Đạo Nhất trở thành Đại Thiên Tôn","bridge":true,"khoang":"@c1894"},{"mucCt":"ky","text":"Đạo Nhất mang sát khí lao vào giết Vương Lâm để rửa nhục, nhưng bị Vương Lâm tóc đen cùng ngũ hành chân thân liên thủ áp chế. Trớ Thuật trong cơ thể hắn bùng phát, thiêu đốt linh hồn và khiến hắn cảm nhận bóng ma tử vong. Hắn phải thiêu đốt lực lượng bản thể phá phong tỏa để trốn khỏi chiến trường, tạm bỏ mặc cả tông môn lẫn tiên tộc.","anchor":"Hắn cảm nhận được bóng ma tử vong đang nhanh chóng bao phủ lấy mình","bridge":true,"khoang":"@c1895"}],"nhanMach":[{"ten":"Tiên Hoàng","tag":"khac","quanHe":"được nhắm để trọng dụng","ghiChu":"Tiên Hoàng xem Đạo Nhất là người có thể dùng trong kế hoạch."}],"tuViMoc":[],"diem":[{"text":"Từng tranh đoạt bảo vật với Huyền La đại thiên tôn khi mặt trời thứ chín xuất hiện tại Thái Cổ Thần Cảnh","chuong":"@c1599"},{"text":"Dùng thần niệm ẩn trong đạo bào tím của lão tổ Đạo Ma Tông để tiếp cận và mời chào Vương Lâm lần đầu","chuong":"@c1825"},{"text":"Chân thân xuất hiện từ vầng mặt trời trên bầu trời đêm, dùng uy áp thiên địa và tặng đạo tinh để chiêu mộ Vương Lâm nhưng bị cự tuyệt","chuong":"@c1863"},{"text":"Theo tiếng gọi của Cửu Đế, cùng Võ Phong liên thủ đối đầu Tiên Hoàng, thi triển chiêu một chỉ hóa nhất","chuong":"@c1890"},{"text":"Bị Trớ Thuật hắc khí tra tấn, phẫn nộ lao vào giết Vương Lâm để rửa nhục nhưng bị ngũ hành chân thân ngăn lại","chuong":"@c1895"},{"text":"Âm khí bao phủ gầm thét lao ra khỏi Đạo Nhất Tông, nhìn về dị tượng Thái Cổ Thần Cảnh để cầu giải Trớ Thuật","chuong":"@c1928"}]},"nguon":["@c1866","@c1890","@c1891","@c1892","@c1893","@c1894","@c1895"],"canhGioiCaoNhat":"Đại Thiên Tôn @c1895","gioiTinh":"nam","vaiTro":"Chưởng môn Đạo Nhất tông tại Nam Châu — một trong năm thái dương, đại thiên tôn","tinhCach":"quyền uy sâu rộng, uy áp thiên địa; chủ động chiêu mộ nhân tài bằng nhiều thủ đoạn; quan sát thận trọng trước khi hành động; tự tôn cao ngạo, phẫn nộ khi bị kẻ dưới cấp xúc phạm","blurb":"Đạo Nhất đại thiên tôn là chưởng môn Đạo Nhất tông ở Nam Châu, một trong năm vị thái dương cấp đại thiên tôn có ảnh hưởng bao trùm cả châu, dưới trướng có cả lão tổ Thiên Tôn của Đạo Ma Tông. Ông nhiều lần chủ động mời chào Vương Lâm — từ thần niệm ẩn trong đạo bào tím, đến chân thân hiện ra từ vầng mặt trời tặng đạo tinh — nhưng đều bị cự tuyệt. Sau đó ông theo tiếng gọi của Cửu Đế liên thủ đối đầu Tiên Hoàng, bị Trớ Thuật hắc khí tra tấn rồi mang sát khí tấn công Vương Lâm nhưng bị ngũ hành chân thân ngăn lại, cuối cùng gầm thét lao ra khỏi Đạo Nhất Tông nhìn về dị tượng Thái Cổ Thần Cảnh để"},{"id":"vo-phong-dai-thien-ton","name":"Võ Phong Đại Thiên Tôn","aliases":["Võ Phong","Vũ Phong"],"trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Võ Phong được nhắc là một trong các Đại Thiên Tôn bị Vương Lâm cự tuyệt lời mời. Trong mưu tính của Tiên Hoàng, hắn bị xem là bất kính và đáng chết, còn tư cách Đại Thiên Tôn của hắn sẽ được dùng để đưa Đạo Phi lên vị trí Đại Thiên Tôn.","anchor":"Võ Phong kia bất kính Tiên Hoàng","bridge":true,"khoang":"@c1866"},{"chuong":"@c1890","importance":"normal","mucCt":"vua","tieuDe":"Một quyền võ đạo","text":"Võ Phong xuất hiện bên phải Tiên Hoàng giữa cảnh phong vân biến sắc. Ông tung một quyền chứa toàn bộ lực lượng, võ đạo, cảm ngộ thiên địa và tín niệm đỉnh phong, sau đó bị kim kiếm đánh lui và xác nhận đồng ý với Cửu Đế cùng Đạo Nhất.","anchor":"Võ Phong Đại Thiên Tôn đầu trọc bước ra"},{"chuong":"@c1891","importance":"normal","mucCt":"gon","tieuDe":"Biến số ngoài dự tính","text":"Võ Phong được Tiên Hoàng nhắc cùng Đạo Nhất như yếu tố xuất hiện quá nhanh so với kế hoạch ban đầu.","anchor":"ngoài việc Đạo Nhất và Vũ Phong xuất hiện một cách nhanh chóng"},{"mucCt":"vua","text":"Vũ Phong im lặng rồi gật đầu xác nhận từng biết phần kế hoạch Điệu Vong Tộc mà Cửu Đế đã tiết lộ. Cửu Đế hứa hai tai Tiên Tổ cho hắn dung nhập vào đạo để nghe quỹ tích phép tắc Tiên Cương.","anchor":"Vũ Phong trầm mặc trong chổc lát, rồi gật đầu","bridge":true,"khoang":"@c1892"},{"chuong":"@c1893","importance":"major","mucCt":"vua","tieuDe":"Trúng phản phệ đầu lâu","text":"Võ Phong cùng Đạo Nhất và Cửu Đế đánh Tiên Hoàng đúng lúc Tiên Hoàng tự bạo thân thể. Đòn công kích của hắn bị kéo vào biến cố, sau đó thân thể bị hắc khí bao quanh, bắt đầu thối rữa và phải lùi lại khi Vương Lâm xuất hiện.","anchor":"Võ Phong cũng kêu thảm một tiếng, thân thể bị hắc khí bao quanh"},{"mucCt":"vua","text":"Võ Phong bị Trớ Thuật khiến thân thể già yếu nhanh và do dự trước lời Cửu Đế gọi tham chiến. Sau khi Vương Lâm chém hai tai Tiên Tổ giao cho hắn, hắn nhận vật mình cần, không muốn tiếp tục chịu Trớ Thuật khi tranh đấu nên rời khỏi chiến trường.","anchor":"Hắn đã không cần phải tham gia nữa","bridge":true,"khoang":"@c1894"}],"nhanMach":[{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"bị nhắm giết","ghiChu":"Tiên Hoàng dự tính lấy tư cách Đại Thiên Tôn của Võ Phong cho Đạo Phi."}],"tuViMoc":[],"diem":[{"text":"Được nhắc là Đại Thiên Tôn Bắc Châu thuộc Càn Khôn Đạo, một trong năm Đại Thiên Tôn, vị trí siêu nhiên hiếm khi mời chào ai","chuong":"@c1822"},{"text":"Chất vấn Tiên Hoàng khi Minh Đạo Tôn dùng ngoại lực can thiệp Thiên Tôn Niết, bảo vệ sự công bằng cho Vương Lâm","chuong":"@c1858"},{"text":"Bước lên chặn khí thế Tiên Hoàng khi Tiên Hoàng định ra tay ngăn Vương Lâm phá truyền tống, hai Đại Thiên Tôn đối đầu","chuong":"@c1860"},{"text":"Đích thân giáng lâm mời Vương Lâm rượu, đề nghị kết thiện duyên với thân phận sư đệ thay vì đệ tử","chuong":"@c1864"},{"text":"Liên thủ cùng Đạo Nhất và Cửu Đế đánh Tiên Hoàng, tung một quyền chứa toàn bộ lực lượng võ đạo","chuong":"@c1890"},{"text":"Trúng phản phệ đầu lâu của Tiên Hoàng, bị Trớ Thuật khiến thân thể già yếu nhanh chóng","chuong":"@c1893"}]},"nguon":["@c1866","@c1890","@c1891","@c1892","@c1893","@c1894"],"canhGioiCaoNhat":"Đại Thiên Tôn @c1890","gioiTinh":"nam","vaiTro":"Đại Thiên Tôn Bắc Châu — một trong năm Đại Thiên Tôn của Càn Khôn Đạo","tinhCach":"điềm tĩnh, tự trọng vị thế cao nên ít chủ động mời chào người khác; trọng thực lực và biết nhìn nhận nhân tài; hành sự công bằng, sẵn sàng đối đầu đồng cấp để giữ lẽ phải","blurb":"Võ Phong Đại Thiên Tôn là một trong năm Đại Thiên Tôn thuộc Càn Khôn Đạo tại Bắc Châu, nắm vị trí siêu nhiên và hiếm khi chủ động chiêu mời ai. Trong Thiên Tôn Niết, ông hai lần bước ra chặn Tiên Hoàng can thiệp kết quả thí luyện, rồi đích thân giáng lâm mời Vương Lâm rượu và đề nghị kết thiện duyên với thân phận sư đệ nhưng bị cự tuyệt. Về sau ông liên thủ cùng Đạo Nhất và Cửu Đế đánh Tiên Hoàng, song trúng phản phệ đầu lâu khiến thân thể già yếu nhanh chóng dưới Trớ Thuật, rồi lui về bế quan nơi băng tầng."},{"id":"dao-phi","name":"Đạo Phi","aliases":["người điên","thanh niên áo hoa"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1866","importance":"normal","mucCt":"vua","tieuDe":"Quân bài của Tiên Hoàng","text":"Đạo Phi được Tiên Hoàng nhắc là hoàng đệ mà hắn đã hao phí nhiều tâm huyết. Trong kế hoạch của Tiên Hoàng, Đạo Phi sẽ nhận tư cách từ Võ Phong để trở thành Đại Thiên Tôn.","anchor":"khiến Đạo Phi trở thành Đại Thiên Tôn"},{"mucCt":"vua","text":"Đạo Phi rời hiện trường qua truyền tống trận trong trạng thái trí nhớ lúc tỉnh lúc mê, được Tiên Hoàng nói có lẽ khi tỉnh táo mới nhận ra Vương Lâm. Tiên Hoàng còn cho biết Đạo Phi sẽ được đưa tới nơi bế quan của tiên tổ, nơi nữ tử từng ở bên cạnh hắn hiện đang cảm ngộ.","anchor":"Đạo Phi từ sau khi trở về đã trở nên như thế này","bridge":true,"khoang":"@c1875"}],"nhanMach":[{"ten":"Tiên Hoàng","tag":"ho-hang","quanHe":"hoàng huynh","ghiChu":"Bị đặt vào kế hoạch thành Đại Thiên Tôn của Tiên Hoàng."},{"ten":"Nữ tử ở bên cạnh Đạo Phi","tag":"khac","quanHe":"Người từng ở bên cạnh Đạo Phi khi hắn được tìm thấy.","ghiChu":"Nàng đã tỉnh lại và đang ở nơi bế quan của tiên tổ."}],"tuViMoc":[]},"nguon":["@c1866","@c1875"]},{"id":"song-tu-dai-thien-ton","name":"Song Tử Đại Thiên Tôn","aliases":["Song Tử","Song Tử Đại Thiên Tôn"],"trangThai":"song @c1898","tabs":{"kinhLich":[{"chuong":"@c1866","importance":"normal","mucCt":"vua","tieuDe":"Chưa song hồn quy nhất","text":"Song Tử Đại Thiên Tôn được nhắc là người Vương Lâm lựa chọn dù đã suy yếu. Tiên Hoàng đánh giá rằng nếu Song Tử chưa song hồn quy nhất thì chưa phải mối lo đáng kể trong kế hoạch của hắn.","anchor":"lựa chọn Song Tử Đại Thiên Tôn đã suy yếu"},{"chuong":"@c1867","importance":"minor","mucCt":"gon","text":"Được xác lập trong ước định sẽ ra tay trợ giúp nếu Vương Lâm gặp nguy cơ không giải quyết được ở Trung Châu, sau khi từng thi triển dung hồn thật lấy lại một phần ký ức Tổ Thành cho hắn.","anchor":"đến lúc đó còn cần Song Tử Đại Thiên Tôn ra tay trợ giúp"},{"mucCt":"ky","text":"Song Tử Đại Thiên Tôn được ngọc giản của Vương Lâm gọi tới, nhận ra hắn và hỏi tới Tiểu Bưu Tử. Khi Vương Lâm nhắc lại ước định và xin họ vây khốn Tiên Hoàng một ngày, họ không hỏi thêm mà hóa thành hai đạo cầu vồng bay tới hoàng cung. Sau đó họ giao chiến với Tiên Hoàng trên bầu trời trong vầng mặt trời màu tím.","anchor":"Hai cô bé này sau khi nhìn bốn phía một chút","bridge":true,"khoang":"@c1882"},{"mucCt":"vua","text":"Song Tử Đại Thiên Tôn giao chiến trên bầu trời với Tiên Hoàng. Trận chiến này giữ chân Tiên Hoàng, khiến hắn không thể đối phó Vương Lâm trong hoàng cung.","anchor":"nhưng Song Tử Đại Thiên Tôn cũng đủ để vây khốn Tiên Hoàng","bridge":true,"khoang":"@c1883"},{"chuong":"@c1884","importance":"bridge","tieuDe":"Giao chiến Tiên Hoàng","mucCt":"gon","text":"Song Tử Đại Thiên Tôn được quốc sư nhắc là đang giao chiến với Tiên Hoàng, khiến Tiên Hoàng tạm bị vây khốn khi nghi thức truyền thừa diễn ra.","anchor":"dù đang giao chiến với Song Tử Đại Thiên Tôn"},{"mucCt":"vua","text":"Song Tử Đại Thiên Tôn không hiện hình trực tiếp, nhưng tiếng kêu của hai cô bé thay thế tiếng rống Tiên Hoàng trong không gian cấm cung. Diễn biến này được xác nhận là việc họ ngăn Tiên Hoàng tiếp cận nơi Minh Đạo Tôn và truyền thừa Tiên Tổ đang biến hóa.","anchor":"Hiển nhiên hành động của Tiên Hoàng đã bị Song Tử Đại Thiên Tôn ngăn cản","bridge":true,"khoang":"@c1886"},{"mucCt":"ky","text":"Song Tử đuổi theo Tiên hoàng xuất hiện, kiêng kị cái đầu tiên tổ nhưng vẫn dùng tử dương và kiếm ảnh tím công kích. Sau khi kiếm quang bị kim quang đầu tiên tổ đánh tan, hai thân thể hợp nhất thành nữ tử áo trắng. Nàng thi triển Tử Lâm Tín Thuật, dùng tử quang bao phủ tổ thành và gọi thiên thạch tím khổng lồ để uy hiếp Tiên hoàng giao Vương Lâm.","anchor":"Hai thân thể giống như là hai làn khói, không ngờ ngưng tụ lại với nhau","bridge":true,"khoang":"@c1889"},{"mucCt":"vua","text":"Song Tử cùng Cửu Đế áp sát Tiên Hoàng nhưng bị thần thông từ đầu lâu Tiên Tổ bức lui. Khi kim kiếm vàng chém xuống, nàng dùng tử khí hóa thành rừng trúc tím như vạn kiếm để đối kháng, rồi nêu điều kiện buộc Tiên Hoàng thả Vương Lâm.","anchor":"Thả Vương Lâm ra! Bổn tôn sẽ rời đi","bridge":true,"khoang":"@c1890"},{"chuong":"@c1892","importance":"normal","mucCt":"vua","tieuDe":"Chỉ cứu Vương Lâm","text":"Sau khi hai tiểu cô nương dung hợp thành bản thể, Song Tử nói nàng không biết và cũng không muốn biết kế hoạch của Cửu Đế. Nàng tuyên bố mục tiêu duy nhất là mang Vương Lâm đi, còn Cửu Đế hay Tiên hoàng nếu ngăn cản đều là địch nhân của nàng.","anchor":"Bổn tôn tới đây chỉ để mang Vương Lâm đi"},{"chuong":"@c1893","importance":"bridge","mucCt":"gon","tieuDe":"Chứng kiến Vương Lâm xuất hiện","text":"Song Tử đứng xa quan sát đầu lâu Tiên Tổ và lộ vẻ kinh hỉ khi thấy Vương Lâm hiện thân.","anchor":"Song Tử ở phía xa xa lúc nhìn thấy thân ảnh Vương Lâm lập tức lộ vẻ kinh hỉ"},{"mucCt":"ky","text":"Song Tử đến cạnh Vương Lâm trong trạng thái suy yếu rồi tách lại thành hai cô bé. Họ nhận hai con ngươi Tiên Tổ do Vương Lâm lấy ra từ đầu lâu để cảm tạ việc tương trợ. Khi Cửu Đế và Đạo Nhất lao tới, hai cô bé dù tái nhợt vẫn quyết đoán dung hợp thành Song Tử Đại Thiên Tôn chính thức để cản hai người.","anchor":"sắc mặt tuy rằng tái nhợt nhưng thần sắc lại lộ vẻ quyết đoán","bridge":true,"khoang":"@c1894"},{"mucCt":"ky","text":"Song Tử tiếp tục giao chiến với Cửu Đế để ngăn hắn can dự vào trận giữa Vương Lâm và Đạo Nhất. Khi Cửu Đế nhắc Tiên Hoàng đã chết và Đạo Nhất sắp bị Trớ Thuật hủy diệt, nàng khựng lại vì vẫn thuộc về tiên tộc.","anchor":"Bước chân Song Tử sững lại. Nàng dù sao cũng thuộc về tiên tộc","bridge":true,"khoang":"@c1895"},{"mucCt":"vua","text":"Song Tử bị Cửu Đế nhắc chuyện từng giúp Vương Lâm lấy đầu lâu Tiên Tổ và bị đe dọa bằng số phận Tử Dương tông nếu tiên tộc bị cổ tộc đánh tan. Nàng giữ thái độ lạnh lùng rằng chuyện mình đã quyết không cần nói nhiều, nhưng cuối chương lại quay sang khuyên Vương Lâm lưu Liên Đạo Phi lại.","anchor":"Vương Lâm. Lưu Liên Đạo Phi lại đi.","bridge":true,"khoang":"@c1896"},{"mucCt":"ky","text":"Song Tử nhiều lần khuyên Vương Lâm để Liên Đạo Phi ở lại vì Tiên Hoàng đã chết và Liên Đạo Phi rất quan trọng với tiên tộc. Sau biến cố, nàng nói mình có được hai mắt tiên tổ, sẽ về Tử Dương Tông bế quan, đồng thời thừa nhận lập trường tiên tộc của mình. Cuối cùng nàng hóa lại thành hai tiểu cô nương và rời đi.","anchor":"Liên Đạo Phi quả thật là không thể để cho ngươi mang đi","bridge":true,"khoang":"@c1897"},{"mucCt":"vua","text":"Song Tử không tham gia nên không trúng Trớ Thuật. Sau khi trở lại Tử Dương tông, hai cô bé bế quan dung hợp hai mắt Tiên Tổ để chữa trị suy yếu ngoài ý muốn từ lần chuyển thế trước.","anchor":"Sau khi trở lại Tử Dương tông, hai cô bé này liền bế quan, dung hợp hai mắt của Tiên Tổ","bridge":true,"khoang":"@c1898"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"thực hiện lời hứa giúp một lần","ghiChu":"Được Vương Lâm dùng ngọc giản gọi tới và nhận lời vây Tiên Hoàng."},{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"giao chiến","ghiChu":"Giao chiến với Tiên Hoàng trên bầu trời hoàng cung."},{"ten":"Lưu Kim Bưu","tag":"khac","quanHe":"hỏi thăm","ghiChu":"Vừa hiện thân đã hỏi Vương Lâm về Tiểu Bưu Tử."},{"ten":"Cô Nhai Thiên Tôn","tag":"dong-minh","quanHe":"người nhắc tới ước định","ghiChu":"Cô Nhai nêu rõ khi Vương Lâm gặp nguy cơ thì còn cần Song Tử Đại Thiên Tôn ra tay."},{"ten":"Cửu Đế","tag":"doi-thu","quanHe":"Vừa giao chiến trước đó và bị Cửu Đế đe dọa bằng số phận Tử Dương tông.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"người nàng yêu cầu giữ lại cho tiên tộc","ghiChu":"Nàng xác nhận Liên Đạo Phi không thể để Vương Lâm mang đi."},{"ten":"Tiên Tổ","tag":"khac","quanHe":"dung hợp hai mắt","ghiChu":"Dùng hai mắt Tiên Tổ để chữa trị suy yếu chuyển thế."}],"tuViMoc":[],"diem":[{"text":"Được công nhận là Thiên Tôn cường đại nhất trước khi chuyển thế, linh hồn phân liệt thành hai ấu nữ Hàm Hàm và Oa Oa","chuong":"@c1826"},{"text":"Một mình ép lui ba Đại Thiên Tôn (Cửu Đế, Võ Phong, Đạo Nhất) để tuyên bố giữ Vương Lâm tại Tử Dương Tông","chuong":"@c1865"},{"text":"Giao chiến với Tiên Hoàng trên bầu trời, giữ chân đối phương không cho can dự cuộc chiến bên dưới","chuong":"@c1883"},{"text":"Dung hợp bản thểuyên bố chỉ cứu Vương Lâm, không quan tâm kế hoạch của các bên khác","chuong":"@c1892"},{"text":"Trở về Tử Dương Tông bế quan dung hợp hai hồn sau đại chiến","chuong":"@c1898"}]},"nguon":["@c1866","@c1867","@c1882","@c1883","@c1884","@c1886","@c1889","@c1890","@c1892","@c1893","@c1894","@c1895","@c1896","@c1897","@c1898"],"canhGioiCaoNhat":"Đại Thiên Tôn @c1896","gioiTinh":"khong-ro","theLuc":[{"ten":"Tử Dương tông","trangThai":"gan-bo"}],"vaiTro":"Đại Thiên Tôn Tiên Tộc — cường giả bậc nhất Đông Châu, tọa trấn Tử Dương Tông","tinhCach":"uy áp tuyệt đối, một mình ép lui nhiều Đại Thiên Tôn; trọng nghĩa, chỉ cứu người mình muốn cứu; hành sự kín đáo, ẩn thân dưới hình hài haiấu nữ sau chuyển thế","blurb":"Song Tử Đại Thiên Tôn là Thiên Tôn cường đại nhất trong năm vị Đại Thiên Tôn của Tiên Tộc, tọa trấn Tử Dương Tông tại Đông Châu. Sau khi chuyển thế gặp biến cố, linh hồn phân liệt thành hai ấu nữ — Hàm Hàm và Oa Oa — khiến thực lực suy giảm nhưng vẫn đủ uy để một mình ép lui ba Đại Thiên Tôn nhằm bảo toàn Vương Lâm. Nàng sau đó giao chiến trực tiếp với Tiên Hoàng để giữ chân đối phương, rồi trở về Tử Dương Tông bế quan dung hợp hai hồn."},{"id":"hai-tu-thien-ton","name":"Hải Tử Thiên Tôn","aliases":["Hải Tử","Tử Hải","Hải Tử quốc sư","Hài Tử Thiên Tôn"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1866","importance":"bridge","mucCt":"gon","text":"Hải Tử Thiên Tôn được nhắc trong lời đồn là quý mến Vương Lâm nhưng bị hắn lạnh lùng cự tuyệt.","anchor":"Cũng nghe đồn Hải Tử Thiên Tôn quý mến người này"},{"chuong":"@c1874","importance":"bridge","tieuDe":"Được nhắc nhận đan","text":"Hải Tử Thiên Tôn được thiếu niên áo xanh nhắc là người mà Đạo Phi định tặng đan dược đang luyện.","anchor":"đan dược mà người định tặng cho Hải Tử Thiên Tôn","mucCt":"gon"},{"chuong":"@c1875","importance":"normal","mucCt":"ky","tieuDe":"Dẫn đường gặp sát cơ","text":"Hải Tử Thiên Tôn tới phòng Vương Lâm giữa gió tuyết, nói theo lệnh sư tôn mời hắn tới Đế Sơn. Nàng dẫn Vương Lâm đi tới truyền tống trận của Đế Sơn, hỏi khi nào hắn rời đi và cùng hắn đi qua con phố dài phủ tuyết. Khi sát cơ xuất hiện, nàng nhận ra dao động phong ấn giam cầm và nói không ai biết nàng đến tìm Vương Lâm.","anchor":"ta theo lệnh của sư tôn mời ngươi tới Đế Sơn một chuyến"},{"mucCt":"vua","text":"Hải Tử Thiên Tôn đi cùng Vương Lâm tới khu vực Đế Sơn thì bị cuốn vào sát cục trên phố dài, nàng phẫn nộ vì âm mưu này có thể liên lụy sư tôn. Sau khi được Vương Lâm tin tưởng giao xử lý phía sau, nàng đối phó đồ án ba cạnh nhưng về sau bị chín người chỉ vây không giết ngăn lại, không thể thoát ra cứu viện và thê lương gọi Vương Lâm.","anchor":"Phía sau truyền tới giọng nói thê lương của Hải Tử Thiên Tôn","bridge":true,"khoang":"@c1876"},{"mucCt":"vua","text":"Hải Tử Thiên Tôn được Vương Lâm giải vây khi chín kẻ đang vây nàng bỏ chạy khỏi sương đen. Nàng nhận ra trận chém giết đã vượt xa khả năng tham dự của mình, xác nhận hơn ba mươi Thiên Tôn xa lạ kia không thuộc nhóm Thiên Tôn nàng từng biết, rồi bị Vương Lâm đẩy lùi và dặn không ra tay khi đợt địch mới xuất hiện.","anchor":"Hải Tử Thiên Tôn quan hệ rất rộng. Thiên Tôn tu sĩ phần lớn đều có ấn tượng","bridge":true,"khoang":"@c1877"},{"chuong":"@c1878","importance":"bridge","mucCt":"gon","tieuDe":"Bị chấn động cản bước","text":"Hải Tử Thiên Tôn định tới trợ giúp Vương Lâm nhưng bị uy lực va chạm trong sát cục làm chấn động tâm thần, không thể tiến thêm.","anchor":"càng khiến cho Hải Tử Thiên Tôn đang định tới trợ giúp chấn động tâm thần"},{"mucCt":"vua","text":"Hải Tử Thiên Tôn chứng kiến Vương Lâm tóc đen tàn sát các lớp tử sĩ và cảm thấy người trước mặt khác hẳn Vương Lâm nàng biết. Khi hắn quay sang từng bước tiến về phía mình, nàng hoảng sợ chất vấn thân phận của hắn.","anchor":"Thanh âm của Hải Tử Thiên Tôn hoảng sợ đến cực điểm, vang vọng trong đêm tối yên tĩnh","bridge":true,"khoang":"@c1879"},{"chuong":"@c1880","importance":"normal","mucCt":"ky","tieuDe":"Bị nghi thiên ngoại","text":"Hải Tử kinh hãi trước Vương Lâm tóc đen và bị hắn chất vấn là mồi nhử trong sát cục, có liên hệ với nhất mạch quốc sư và có thể đến từ thiên ngoại. Khi Vương Lâm tóc đen định đánh chết nàng, nàng không giải thích, không né tránh mà nhắm mắt rơi lệ. Cửu Đế Đại Thiên Tôn hiện thân cứu nàng, nói nàng vô tội rồi đưa nàng rời đi.","anchor":"Hải Tử Thiên Tôn không né tránh, nhắm hai mắt lại, hai hàng lệ trào ra"},{"chuong":"@c1889","importance":"bridge","mucCt":"gon","tieuDe":"Theo sau Cửu Đế","text":"Hải Tử Thiên Tôn sắc mặt tái nhợt đi theo sau Cửu Đế khi lão bước vào chiến trường.","anchor":"Ở phía sau hắn. Hải Tử Thiên Tôn sắc mặt tái nhợt đi theo"},{"chuong":"@c1891","importance":"major","mucCt":"ky","tieuDe":"Thức tỉnh quốc sư thật","text":"Khi phong ấn Điệu Vong Tộc bị giải khai, Hải Tử thức tỉnh ký ức và sức mạnh thuộc quốc sư chân chính. Nàng thi triển Điệu Vong chi lực khiến kim quang quanh đầu Tiên Tổ co rút, cắt đứt quá trình Tiên Hoàng hấp thu truyền thừa. Sau đó nàng tự nhận mình là quốc sư, giải thích linh hồn thuộc Điệu Vong Tộc nhưng thân thể thuộc Tiên Cương Đại Lục nên có thể rời khỏi Tổ Thành.","anchor":"Sức mạnh này đến tử Điệu Vong Tộc, nó thuộc về quốc sư chân chính"},{"chuong":"@c1892","importance":"normal","mucCt":"ky","tieuDe":"Nắm linh miếu","text":"Hải Tử được xác nhận có thân thể thuộc Đại Lục Tiên Cương nhưng linh hồn thuộc Điệu Vong Tộc, trong linh hồn còn có tầng bảo vệ do tộc nhân chết đi dung hợp thành. Nàng tuyên bố nếu Tiên hoàng không kế thừa Tiên Tổ thì lực lượng bí mật Điệu Vong Tộc trên bảy mươi hai châu sẽ phát động. Khi ấy các linh miếu sẽ nghe lệnh nàng, đánh thức linh hồn bị phong ấn để làm chấn động sức trấn áp của đầu Tiên Tổ.","anchor":"Trên toàn bộ bảy mươi hai châu của tiên tộc, tất cả những linh miếu sẽ đều nghe theo hiệu lệnh của ta"},{"mucCt":"vua","text":"Pháp thuật Hải Tử áp lên đầu lâu Tiên Tổ bị một nhát chém của Tiên Hoàng đánh rách, khiến sắc mặt nàng tái nhợt và khóe miệng tràn máu. Về sau nàng nhìn thấy Vương Lâm xuất hiện thì sửng sốt rồi kích động.","anchor":"sắc mặt Hài Tử quốc sư ớ phía xa xa lập tức ta nhợt","bridge":true,"khoang":"@c1893"},{"chuong":"@c1894","importance":"normal","mucCt":"vua","tieuDe":"Đứng trước lựa chọn","text":"Hải Tử được Cửu Đế gọi tham chiến và bị coi là nhân tố có thể quyết định nếu liên thủ với Đạo Nhất. Vương Lâm trực tiếp nhắc chuyện Điệu Vong tộc từng lợi dụng hắn giải phong ấn để khuyên nàng không can dự, khiến lựa chọn phe của Hải Tử trở thành nút thắt của thế cục.","anchor":"Ta không biết nên gọi ngươi là Hải Tử Thiên Tôn hay là Hải Tử quốc sư"},{"chuong":"@c1895","importance":"normal","mucCt":"vua","tieuDe":"Đứng ngoài chiến cuộc","text":"Hải Tử Thiên Tôn chọn không tham chiến, nhắm mắt đứng ngoài mặc cho Cửu Đế bất mãn. Về cuối, hắn chấn động khi thấy sau lưng Vương Lâm xuất hiện hư ảnh Đại Thiên Tôn Chi Dương.","anchor":"Hài Tử Thiên Tôn trầm mặc, than nhẹ một tiếng, đứng ở nơi đó không ra tay mà nhắm mắt lại"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng hành trong sát cục phố dài","ghiChu":"Được Vương Lâm tin tưởng giao ứng phó hướng sau."},{"ten":"Cửu Đế Đại Thiên Tôn","tag":"su-mon","quanHe":"Được cứu và che chở","ghiChu":"Cửu Đế hiện thân kéo Hải Tử khỏi một chưởng diệt sát của Vương Lâm tóc đen."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị chất vấn và bị định giết","ghiChu":"Vương Lâm tóc đen nghi nàng là mồi nhử trong sát cục và có lai lịch thiên ngoại."},{"ten":"Cửu Đế Đại Thiên Tôn","tag":"cha-me","quanHe":"Cha","ghiChu":"Cửu Đế xác nhận Hải Tử là con gái mình."},{"ten":"Quốc sư giả của Điệu Vong Tộc","tag":"khac","quanHe":"Người bị dùng làm vỏ bọc","ghiChu":"Quốc sư giả được sắp đặt để che giấu thân phận quốc sư thật của Hải Tử."},{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"Phá kế hoạch hấp thu truyền thừa","ghiChu":"Nàng thu hồi kim quang về đầu Tiên Tổ, cắt nguồn sức mạnh Tiên Hoàng đang hấp thu."}],"tuViMoc":[{"chuong":"@c1891","canhGioi":"Quốc sư chân chính của Điệu Vong Tộc","text":"Thức tỉnh ký ức và sức mạnh Điệu Vong Tộc thuộc hệ thân phận truyền thừa, không phải tu vi chính.","importance":"major"}],"diem":[{"text":"Được nhắc là Thiên Tôn cực mạnh của Sơn Hải Châu và từng đánh bại Vương Lâm ba năm trước","chuong":"@c1831"},{"text":"Dùng trận pháp mực đen phong bế biển Sơn Hải, giao thủ với Vương Lâm rồi được hắn cứu khỏi phong ấn","chuong":"@c1838"},{"text":"Ở Thiên Tôn Niết, công khai quát đám đông và đứng ra bênh vực Vương Lâm","chuong":"@c1858"},{"text":"Được Cửu Đế sắp xếp để Vương Lâm trở thành sư huynh, bản thân kinh hỉ khi có sư huynh","chuong":"@c1862"},{"text":"Thức tỉnh ký ức và sức mạnh quốc sư chân chính của Điệu Vong Tộc khi phong ấn bị giải khai","chuong":"@c1891"},{"text":"Chọn không tham chiến dù bị Cửu Đế gọi vào chiến cuộc và bị coi là nhân tố có thể quyết định cục diện","chuong":"@c1895"}]},"nguon":["@c1866","@c1874","@c1875","@c1876","@c1877","@c1878","@c1879","@c1880","@c1889","@c1891","@c1892","@c1893","@c1894","@c1895"],"gioiTinh":"nu","canhGioiCaoNhat":"Thiên Tôn @c1895","vaiTro":"Thiên Tôn cực mạnh Sơn Hải Châu — quốc sư Điệu Vong Tộc","tinhCach":"kiêu ngạo tự tin trong chiến đấu; trọng nghĩa khí, dám công khai bênh vực Vương Lâm; thẳng thắn, dễ bộc lộ cảm xúc; biết tự chế khi đứng trước lựa chọn lớn","blurb":"Hải Tử Thiên Tôn, tên thật Nghệ Đình, là Thiên Tôn cực mạnh của Sơn Hải Châu, từ nhỏ theo Cửu Đế Đại Thiên Tôn tu luyện tại Đế Sơn và về sau được sắp xếp thành sư muội của Vương Lâm. Nàng từng đánh bại Vương Lâm khi hắn chưa mặc Hồn Khải, nhưng qua các lần giao thủ và biến cố Thiên Tôn Niết đã dần nhận rõ sức mạnh của hắn. Khi phong ấn Điệu Vong Tộc bị giải khai, Hải Tử thức tỉnh ký ức cùng sức mạnh quốc sư chân chính, nắm thân phận then chốt trong chiến cuộc cuối cùng nhưng chọn đứng ngoài giao tranh."},{"id":"dong-lam-dai-thien-ton","name":"Đông Lâm Đại Thiên Tôn","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1866","importance":"bridge","mucCt":"gon","text":"Đông Lâm Đại Thiên Tôn được nhắc là từng không phải đối thủ của Cổ Đạo và có lời đồn đã chết sau khi khiêu chiến Cổ Đạo.","anchor":"Dù là Đông Lâm Đại Thiên Tôn của Tiên Tộc trước kia cũng không phải là đối thủ của hắn"}],"diem":[{"text":"Được xác nhận là lão tổ đời đầu Đông Lâm Tông, từng đạt cấp Đại Thiên Tôn","chuong":"@c1851"},{"text":"Thi thể thất tung sau khi chết, cái chết thành nghi vấn","chuong":"@c1852"},{"text":"Từng không phải đối thủ của Cổ Đạo, có lời đồn chết sau khi khiêu chiến","chuong":"@c1866"},{"text":"Được dùng làm chuẩn so sánh thực lực giữa các Đại Thiên Tôn","chuong":"@c1864"}]},"nguon":["@c1866"],"vaiTro":"Lão tổ khai sáng Đông Lâm Tông — Đại Thiên Tôn đã mất, di hài thất tung","blurb":"Đông Lâm Đại Thiên Tôn là lão tổ đời đầu của Đông Lâm Tông, từng đạt cảnh giới Đại Thiên Tôn. Sau khi qua đời, thi thể không rõ tung tích, cái chết trở thành nghi vấn. Thường được dùng làm chuẩn so sánh thực lực giữa các Đại Thiên Tôn."},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","aliases":["Tiểu Bưu Tử"],"trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Lưu Kim Bưu xuất hiện bên Vương Lâm cùng hai cô bé, bị hai cô gọi là Tiểu Bưu Tử và nhắc chuyện đã lừa đồ của Tiểu Lang. Hắn khẩn khoản xin hai tiểu tổ tông đừng gọi mình bằng biệt danh ấy.","anchor":"Van các người đó hai tiểu tổ tông, đừng gọi ta là Tiểu Bưu Tử","bridge":true,"khoang":"@c1866"},{"chuong":"@c1867","importance":"minor","mucCt":"gon","text":"Cùng Vương Lâm đi xuống khỏi Tử Dương Tông và được mang theo bằng súc địa thành thốn rời Đông Châu tới Trung Châu.","anchor":"sử dụng súc địa thành thốn mang theo Lưu Kim Bưu và Hải Long rời khỏi Đông Châu"},{"mucCt":"vua","text":"Lưu Kim Bưu đứng bên cửa sổ nhà trọ, hưng phấn trước khu đèn đuốc tiếng nhạc của Đông Thành và dựa vào bản tính Hứa Lập Quốc để đoán nơi cần tìm. Được Vương Lâm gật đầu, hắn lập tức mang Hải Long Kim Tôn rời phòng.","anchor":"Động tác này của hắn khiến Lưu Kim Bưu lập tức kích động hẳn","bridge":true,"khoang":"@c1868"},{"chuong":"@c1869","importance":"normal","mucCt":"vua","tieuDe":"Đá Cổng Lý Phủ","text":"Lưu Kim Bưu bị xạ thủ áo đen truy sát trên đường Đông Thành, nhờ Hải Long đỡ tên thay và Vương Lâm hiện thân cứu mạng. Sau khi được đưa tới Lý Phủ, hắn phấn chấn nhận lệnh đi gõ cửa, đá văng đại môn rồi theo sau Vương Lâm chứng kiến song sư và tiễn trận bị phá.","anchor":"Hắn thích nhất là sĩ nhục kẻ khác"},{"mucCt":"vua","anchor":"Lưu Kim Bưu kia cực kỳ vui mừng.","text":"Lưu Kim Bưu đi cùng phe Vương Lâm tại Lý Phủ và nhờ có Vương Lâm làm chủ nhân mà được Lý gia tiếp đãi như khách quý. Việc này khiến hắn cực kỳ vui mừng.","bridge":true,"khoang":"@c1870"},{"chuong":"@c1875","importance":"bridge","mucCt":"gon","tieuDe":"Theo về tửu lâu","text":"Lưu Kim Bưu được Vương Lâm đưa cùng Hải Long về gian phòng trong tửu lâu phía đông thành.","anchor":"mà mang theo Hải Long và Lưu Kim Bưu về gian phòng trong tửu lâu"},{"chuong":"@c1880","importance":"bridge","mucCt":"vua","tieuDe":"Chờ ở cửa đông","text":"Lưu Kim Bưu đi cùng Vương Lâm và Hài Long tới cửa đông Tổ Thành, chờ Hứa Lập Quốc và người điên tới để chuẩn bị rời đi.","anchor":"Vương Lâm mang theo Lưu Kim Bưu và Hài Long đứng ở cửa thành phía đông"},{"mucCt":"vua","text":"Lưu Kim Bưu bị Hứa Lập Quốc đẩy khỏi vị trí cạnh Vương Lâm và bị ánh mắt uy hiếp làm run sợ vì dư uy cũ. Nhờ Hải Long trên vai rít gào chống Hứa Lập Quốc, hắn lấy lại vẻ đắc ý, nhưng cuối chương vẫn bị Vương Lâm thu vào không gian trữ vật cùng Hứa Lập Quốc và Hải Long.","anchor":"Bị Hứa Lập Quốc trừng mắt nhìn, trong lòng Lưu Kim Bưu kia lập tức run lên","bridge":true,"khoang":"@c1881"},{"mucCt":"ky","text":"Lưu Kim Bưu rét run khi đi qua Hàn Châu, chỉ nhờ con rắn nhỏ hình rồng trên vai thỉnh thoảng thở khí mới chống chịu được hàn khí. Hắn tức giận vì bị Hứa Lập Quốc khoe áo và châm chọc, cầu cứu Vương Lâm nhưng lại từ chối vào không gian trữ vật vì sợ Hứa Lập Quốc ở riêng với chủ nhân. Sau khi Vương Lâm buộc Hứa Lập Quốc chia áo, hắn tiếp tục đi theo cho đến khi bị Vương Lâm thu vào không gian trữ vật trước chuyến vượt biển.","anchor":"Chủ nhân, ta.ta còn có thể chịu được!","bridge":true,"khoang":"@c1899"}],"nhanMach":[{"ten":"Hai cô bé không nêu tên","tag":"khac","quanHe":"bị trêu chọc","ghiChu":"Hai cô bé gọi hắn là Tiểu Bưu Tử và rủ xuống núi lừa gạt người khác."},{"ten":"Tiểu Lang","tag":"khac","quanHe":"từng lừa đồ","ghiChu":"Bị hai cô bé nói đã lừa mất mấy món đồ của Tiểu Lang."},{"ten":"Hải Long","tag":"dong-minh","quanHe":"Cùng rời nhà trọ ở Đông Thành để tìm Hứa Lập Quốc.","ghiChu":"Hải Long thu nhỏ thân thể nằm trên vai Lưu Kim Bưu @c1868"},{"ten":"Nam tử trung niên truy kích của Lý Phủ","tag":"doi-thu","quanHe":"Bị người này cầm cung truy sát trong Đông Thành.","ghiChu":"Hải Long chắn giúp một mũi tên nên Lưu Kim Bưu thoát chết."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"chủ nhân","ghiChu":"Nhờ thân phận đi theo Vương Lâm, Lưu Kim Bưu được Lý gia tiếp đãi trọng hậu."},{"ten":"Lão tổ Lý gia","tag":"khac","quanHe":"người thuộc phía Lý Phủ tiếp đãi hắn","ghiChu":"Sau khi Lý Phủ hòa giải với Vương Lâm, Lưu Kim Bưu cũng được đãi như khách quý."},{"ten":"Vương Lâm","tag":"dong-hanh","quanHe":"đồng hành","ghiChu":"Đi cùng Vương Lâm rời Tử Dương Tông và rời Đông Châu."},{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"người được nhắc làm đối chiếu","ghiChu":"Hành động đá cổng Lý Phủ và lời hét của hắn giống việc Hứa Lập Quốc từng làm năm ngoái.","gap":"@c1869"}],"tuViMoc":[],"diem":[{"text":"Dùng ngọc giản chứa khí tức Toái Niết phá hộ sơn đại trận, tống tiền Thiên Cương Tông dưới danh thế cường giả.","chuong":"@c1158"},{"text":"Lừa Quy Nguyên Tông bằng kim quang mang khí tức giả Toái Niết, nhưng bị Vương Lâm truy kích và bại lộ tu vi thực tế chỉ là Âm Hư.","chuong":"@c1198"},{"text":"Đạo lừa đảo đạt tới mức tự lừa bản thân, khiến ký ức và nguyên thần cũng bị ảnh hưởng.","chuong":"@c1302"},{"text":"Giả dạng Chu Tước đời thứ sáu để lừa lão tổ Hỏa Tước tộc trong lúc ẩn náu cùng Hứa Lập Quốc.","chuong":"@c1335"},{"text":"Bị Vương Lâm tước tự do, bắt làm nô bộc ngàn năm sau vụ tính toán máu tươi của Người điên.","chuong":"@c1474"},{"text":"Sau khi chuyển thế, khôi phục hai đời ký ức và tiếp tục đi theo Vương Lâm, mở ra nhận thức mới về đạo lừa gạt.","chuong":"@c1848"}]},"nguon":["@c1866","@c1867","@c1868","@c1869","@c1870","@c1875","@c1880","@c1881","@c1899"],"canhGioiCaoNhat":"không rõ trong đợt @c1868","tinhCach":"Xảo quyệt, giỏi giả mạo khí thế để tống tiền; Tham lợi nhưng biết sợ cường giả; Dai dẳng với đạo lừa gạt đến mức tự lừa bản thân; Linh hoạt nương theo Vương Lâm để sinh tồn","gioiTinh":"nam","theLuc":[{"ten":"Vương Lâm","trangThai":"gan-bo"}],"vaiTro":"Kẻ lừa đảo kỳ cựu, nô bộc ngàn năm của Vương Lâm","blurb":"Lưu Kim Bưu, bí danh Kim Bưu Tử, là tu sĩ chuyên dùng thủ đoạn giả mạo khí tức Toái Niết để lừa gạt các tông môn và người yếu thế. Sau khi bị Vương Lâm truy kích, mất bảo vật rồi nhiều lần bị cuốn vào kế hoạch của Vương Lâm và Hứa Lập Quốc, lão bị tước tự do, phải làm nô bộc ngàn năm. Về sau chuyển thế tại Tiên Cương, lão khôi phục ký ức hai đời, tiếp tục đi theo Vương Lâm và thức tỉnh nhận thức mới về đạo lừa gạt."},{"id":"hai-co-be-khong-neu-ten","name":"Hai cô bé không nêu tên","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ @c1866","trangThai":"song","blurb":"Hai cô bé xuất hiện gần Tự Thú Giới trong Tử Dương Tông, tiếng cười của họ làm lòng Vương Lâm bình tĩnh lại. Họ trêu Lưu Kim Bưu bằng biệt danh Tiểu Bưu Tử và nhắc chuyện hắn lừa đồ của Tiểu Lang.","vaiTro":"Hai cô bé ở Tử Dương Tông","tinhCach":[{"text":"hồn nhiên, tinh nghịch","chuong":"@c1866"},{"text":"không e dè khi trêu chọc Lưu Kim Bưu","chuong":"@c1866"}],"tabs":{"diem":[{"text":"Tiếng cười non nớt của hai cô bé phá vỡ sự tĩnh lặng bên Tự Thú Giới.","chuong":"@c1866"},{"text":"Gọi Lưu Kim Bưu là Tiểu Bưu Tử và rủ nhau xuống núi lừa gạt người khác.","chuong":"@c1866"}],"kinhLich":[{"mucCt":"gon","text":"Hai cô bé cười đùa gần Tự Thú Giới, gọi Lưu Kim Bưu là Tiểu Bưu Tử, trách hắn bắt nạt Tiểu Lang và rủ xuống núi lừa gạt người khác.","anchor":"Tiểu Bưu Tử, chúng ta xuống núi lừa gạt người khác đi","bridge":true,"khoang":"@c1866"}],"tuViMoc":[],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"khac","quanHe":"trêu chọc","ghiChu":"Gọi hắn là Tiểu Bưu Tử."},{"ten":"Tiểu Lang","tag":"khac","quanHe":"nhắc tới","ghiChu":"Nói Tiểu Lang bị Lưu Kim Bưu lừa mất mấy món đồ."},{"ten":"Vương Lâm","tag":"khac","quanHe":"xuất hiện gần bên","ghiChu":"Tiếng cười của họ khiến lòng Vương Lâm bình tĩnh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1866"]},{"id":"tieu-lang","name":"Tiểu Lang","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ @c1866","trangThai":"khong-ro","blurb":"Tiểu Lang là người được hai cô bé nhắc tới trong cảnh bên Tự Thú Giới. Theo lời họ, mấy món đồ của Tiểu Lang đã bị Lưu Kim Bưu lừa mất.","vaiTro":"Người bị nhắc trong chuyện của Lưu Kim Bưu","tinhCach":[{"text":"chưa rõ tính cách, chỉ được nhắc qua lời hai cô bé","chuong":"@c1866"}],"tabs":{"diem":[{"text":"Bị hai cô bé nhắc là người bị Lưu Kim Bưu lừa mất mấy món đồ.","chuong":"@c1866"}],"kinhLich":[{"chuong":"@c1866","importance":"bridge","mucCt":"gon","text":"Tiểu Lang được hai cô bé nhắc là đã bị Lưu Kim Bưu lừa mất mấy món đồ.","anchor":"Mấy món đồ của Tiểu Lang đều bị ngươi lừa đi cả rồi"},{"chuong":"@c1897","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc tới","text":"Tiểu Lang được hai tiểu cô nương phân thể của Song Tử nhắc sẽ xem tình hình mấy ngày qua trước khi nghỉ ngơi.","anchor":"trước tiên phải xem Tiều Lang mấy ngày này ra sao đã"}],"tuViMoc":[],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"khac","quanHe":"bị lừa đồ","ghiChu":"Theo lời hai cô bé, mấy món đồ của Tiểu Lang bị Lưu Kim Bưu lừa đi."},{"ten":"Hai cô bé không nêu tên","tag":"khac","quanHe":"được nhắc tới","ghiChu":"Hai cô bé bênh vực khi trêu Lưu Kim Bưu."},{"ten":"Song Tử","tag":"khac","quanHe":"người nhắc tới tình hình của hắn","ghiChu":"Hai tiểu cô nương phân thể của Song Tử nói sẽ xem hắn ra sao."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1866","@c1897"]},{"id":"hai-long","name":"Hải Long","trangThai":"song","tabs":{"diem":[{"text":"Bị Vương Lâm dùng cấm chế phong ấn và hồn khí khuất phục tại hồ trung tâm Đạo Ma Tông, từ tiên thú hung mãnh trở thành tọa kỵ trung thành","chuong":"@c1819"},{"text":"Chở Vương Lâm xuyên sa mạc tới Địa Môn, phóng uy áp tương đương Kim Tôn khiến Trịnh Thiên Lâm kinh hãi","chuong":"@c1828"},{"text":"Phóng uy Kim Tôn tại Thiên Phong khiến cường giả chấn động, chở Vương Lâm từ Địa Môn qua Mạnh Thổ Tông tới Thiên Châu","chuong":"@c1830"},{"text":"Hộ pháp bảo vệ thân thể Vương Lâm trong động phủ Sơn Hải Châu và đối đầu hải thú bạch tuộc nhiều tháng","chuong":"@c1834"},{"text":"Đỡ mũi tên đen cắm vào bụng phá sinh cơ để cứu Lưu Kim Bưu trong Đông Thành, sau được Vương Lâm cứu chữa","chuong":"@c1869"},{"text":"Được triệu ra hộ pháp trước lần cảm ngộ thứ ba của Vương Lâm, càng kính sợ hắn sau đột phá","chuong":"@c1853"}],"kinhLich":[{"chuong":"@c1867","importance":"minor","mucCt":"gon","text":"Được Vương Lâm dùng súc địa thành thốn mang theo cùng Lưu Kim Bưu rời Đông Châu tới Trung Châu.","anchor":"sử dụng súc địa thành thốn mang theo Lưu Kim Bưu và Hải Long rời khỏi Đông Châu"},{"chuong":"@c1868","importance":"bridge","mucCt":"gon","tieuDe":"Rời nhà trọ","text":"Hải Long Kim Tôn thu nhỏ thân thể nằm trên vai Lưu Kim Bưu rồi cùng hắn rời nhà trọ ở Đông Thành.","anchor":"Hải Long Kim Tôn kia thu nhỏ thân thể lại bằng một ngón tay"},{"chuong":"@c1869","importance":"normal","mucCt":"gon","tieuDe":"Đỡ Tên Cứu Chủ","text":"Hải Long chở Lưu Kim Bưu chạy trốn trong Đông Thành, bị mũi tên đen cắm vào bụng phá sinh cơ rồi được Vương Lâm chữa lành hoàn toàn.","anchor":"mũi tên cắm ở bụng cũng bị b*n r*, da thịt ở vết thương hoàn toàn khôi phục"},{"chuong":"@c1875","importance":"bridge","mucCt":"gon","tieuDe":"Theo về tửu lâu","text":"Hải Long được Vương Lâm đưa từ hoàng cung về gian phòng trong tửu lâu phía đông thành.","anchor":"mà mang theo Hải Long và Lưu Kim Bưu về gian phòng trong tửu lâu"},{"chuong":"@c1880","importance":"bridge","mucCt":"vua","tieuDe":"Theo tới cửa đông","text":"Hài Long cùng Vương Lâm và Lưu Kim Bưu đứng ở cửa đông Tổ Thành, chuẩn bị rời khỏi nơi này.","anchor":"Vương Lâm mang theo Lưu Kim Bưu và Hài Long đứng ở cửa thành phía đông"},{"mucCt":"vua","text":"Hải Long đang thu nhỏ bằng ngón tay trên vai Lưu Kim Bưu, khi thấy Hứa Lập Quốc thì ngẩng đầu rít gào. Tiếng rít của nó trở thành chỗ dựa để Lưu Kim Bưu khiêu khích lại Hứa Lập Quốc, rồi cuối chương nó bị Vương Lâm thu vào không gian trữ vật.","anchor":"lúc này sau khi nhìn thấy Hứa Lập Quốc liền ngẩng mạnh đầu","bridge":true,"khoang":"@c1881"},{"mucCt":"vua","text":"Hải Long chở Vương Lâm đi qua vùng biển hướng về cổ Tộc. Dưới khí tức của Vương Lâm, nó tăng tốc trong vùng pháp tắc ngăn cách tiên cổ.","anchor":"Hải Long vạn trượng lúc này đang gào thét uốn lượn ở ngoài khơi","bridge":true,"khoang":"@c1900"}],"tuViMoc":[],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"dong-minh","quanHe":"Đi cùng Lưu Kim Bưu trong lúc tìm Hứa Lập Quốc ở Đông Thành.","ghiChu":"Quan hệ thân cận được thể hiện khi Hải Long nằm trên vai Lưu Kim Bưu @c1868"},{"ten":"Nam tử trung niên truy kích của Lý Phủ","tag":"doi-thu","quanHe":"Bị người này bắn trọng thương khi bảo vệ Lưu Kim Bưu.","ghiChu":"Mũi tên đen cắm vào bụng Hải Long trước khi Vương Lâm chữa trị."},{"ten":"Vương Lâm","tag":"dong-hanh","quanHe":"đồng hành","ghiChu":"Được Vương Lâm mang theo khi rời Đông Châu."},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"người cứu chữa","ghiChu":"Được Vương Lâm vuốt đầu hóa giải hắc khí và khôi phục vết thương.","gap":"@c1869"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867","@c1868","@c1869","@c1875","@c1880","@c1881","@c1900"],"canhGioiCaoNhat":"Kim Tôn @c1868","gioiTinh":"nam","vaiTro":"Tiên thú thủ hộ Đạo Ma Tông — tọa kỵ trung thành của Vương Lâm sau khi bị thu phục","tinhCach":"hung mãnh bản năng khi chưa thần phục; trung thành tuyệt đối sau khi quy thuận; kính sợ uy áp chủ nhân; thân thiết tình cảm với Lưu Kim Bưu","blurb":"Hải Long là tiên thú màu lam vạn trượng do lão tổ Thiên Tôn lưu lại trấn giữ hồ trung tâm Đạo Ma Tông, sở hữu tu vi tương đương Kim Tôn. Sau khi bị Vương Lâm dùng cấm chế phong ấn và hồn khí khuất phục, nó trở thành tọa kỵ trung thành, chở hắn xuyên sa mạc qua Địa Môn, Thiên Châu rồi đồng hành suốt hành trình Sơn Hải Châu, Đông Châu và Trung Châu. Hải Long nhiều lần hộ pháp bảo vệ thân thể Vương Lâm khi hắn bế quan, đỡ tên cứu Lưu Kim Bưu, và phóng uy áp Kim Tôn khiến cường giả bốn phương kinh hãi.","aliases":["Hài Long"]},{"id":"co-nhai-thien-ton","name":"Cô Nhai Thiên Tôn","trangThai":"song","tabs":{"diem":[{"text":"Bị Lưu Kim Bưu mạo nhận danh nghĩa chủ nhân để hù dọa Vân Môn","chuong":"@c1846"},{"text":"Đi cùng Song Tử Đại Thiên Tôn tới nơi, chỉ có thể lặng nhìn hành động của hai cô bé","chuong":"@c1864"},{"text":"Đại diện Song Tử tâng bốc và chào Vương Lâm là Bạch Phát Dược Thiên Tôn","chuong":"@c1865"},{"text":"Đưa ngọc giản cho Vương Lâm theo ước định, tiễn hắn rời Tử Dương Tông","chuong":"@c1867"}],"kinhLich":[{"chuong":"@c1867","importance":"normal","tieuDe":"Ước định ngọc giản trợ giúp","mucCt":"vua","text":"Đứng ngoài Tử Dương Tông cùng Oa Oa, Hàm Hàm tiễn Vương Lâm rời đi. Giải thích đã đưa ngọc giản cho hắn theo ước định: nếu ở Trung Châu gặp nguy cơ không giải quyết được thì Oa Oa, Hàm Hàm sẽ biết và Song Tử Đại Thiên Tôn ra tay trợ giúp.","anchor":"Có mà.ta đã đưa ngọc giản cho hắn, một khi ở Trung Châu gặp phải nguy cơ không giải quyết được"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"người hỗ trợ","ghiChu":"Giao ngọc giản để Vương Lâm có thể báo nguy khi gặp chuyện ở Trung Châu."},{"ten":"Oa Oa","tag":"dong-minh","quanHe":"người cùng giữ ước định","ghiChu":"Cùng tham gia cơ chế trợ giúp Vương Lâm khi có nguy cơ."},{"ten":"Hàm Hàm","tag":"dong-minh","quanHe":"người cùng giữ ước định","ghiChu":"Cùng tham gia cơ chế trợ giúp Vương Lâm khi có nguy cơ."},{"ten":"Song Tử Đại Thiên Tôn","tag":"dong-minh","quanHe":"người sẽ được cầu viện","ghiChu":"Cô Nhai nói khi cần còn phải nhờ Song Tử Đại Thiên Tôn ra tay."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867"],"gioiTinh":"nam","vaiTro":"Thiên Tôn đi cùng Song Tử Đại Thiên Tôn, bị Lưu Kim Bưu mạo nhận danh nghĩa","tinhCach":"biết tiến biết lui trước kẻ mạnh; khéo giao thiệp, vừa tâng bốc vừa giữ thể diện","blurb":"Cô Nhai Thiên Tôn là một Thiên Tôn đồng hành cùng Song Tử Đại Thiên Tôn. Trước đó danh xưng của hắn bị Lưu Kim Bưu mạo nhận làm chủ nhân để uy hiếp Vân Môn, song quan hệ thực sự giữa hai người chưa được nguyên tác xác nhận. Về sau hắn đại diện Song Tử mời chào Vương Lâm, thừa nhận cách làm của hai cô bé, và trao ngọc giản trợ giúp trước khi Vương Lâm rời đi."},{"id":"oa-oa","name":"Oa Oa","trangThai":"song","tabs":{"diem":[{"text":"Dừng giữa không trung trên Tiên Cương, nhìn thấu thần thức Vương Lâm xuyên dòng xoáy hư vô","chuong":"@c1522"},{"text":"Đá một cước suýt phế tu vi Tham Lang, phá vây khốn dễ dàng","chuong":"@c1609"},{"text":"Nhận ra Vương Lâm qua khe nứt, cùng Hàm Hàm phong bế vết nứt và giấu Tham Lang","chuong":"@c1610"},{"text":"Xông vào Tử Dương Tông nhận ra Vương Lâm, gọi nam tử trung niên là Tiểu Cô Nhai","chuong":"@c1856"},{"text":"Tự nhận từng cứu Vương Lâm, rủ Hàm Hàm đánh các Đại Thiên Tôn","chuong":"@c1865"},{"text":"Tâm trạng sa sút tiễn Vương Lâm rời đi, cùng Hàm Hàm khẳng định sẽ bảo vệ hắn","chuong":"@c1867"}],"kinhLich":[{"chuong":"@c1867","importance":"normal","tieuDe":"Tiễn biệt và quyết bảo vệ","mucCt":"vua","text":"Tâm trạng sa sút tiễn Vương Lâm rời Tử Dương Tông, hỏi hắn còn trở về không. Cùng Hàm Hàm khẳng định nếu Vương Lâm đã lựa chọn các nàng thì không thể để bất cứ kẻ nào bắt nạt hắn.","anchor":"Tiểu Vương Lâm nếu đã lựa chọn chúng ta thì không thể để bất cứ kẻ nào bắt nạt hắn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"người muốn bảo vệ","ghiChu":"Sẵn sàng trợ giúp nếu Vương Lâm gặp nguy cơ ở Trung Châu."},{"ten":"Hàm Hàm","tag":"dong-minh","quanHe":"đồng bạn","ghiChu":"Cùng nhìn theo Vương Lâm và cùng giữ ý định bảo vệ hắn."},{"ten":"Cô Nhai Thiên Tôn","tag":"dong-minh","quanHe":"người báo cơ chế trợ giúp","ghiChu":"Cô Nhai nói ngọc giản sẽ giúp các nàng biết khi Vương Lâm gặp nguy cơ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867"],"gioiTinh":"nu","vaiTro":"Nữ đồng bí ẩn trên Tiên Cương đại lục, liên quan Song Tử Đại Thiên Tôn","tinhCach":"Hồn nhiên nhưng ngang ngược; tinh nhanh, quan sát lực mạnh; chiến lực phi phàm dù hình dạng trẻ con;ọng tình nghĩa, sẵn sàng bảo vệ người thân","blurb":"Oa Oa là nữ đồng khoảng bảy tám tuổi mặc y phục lam trên Tiên Cương đại lục, tướng mạo xinh đẹp, có thể dừng giữa không trung và nhìn thấu thần thức xuyên hư vô. Cô bé có mối liên hệ với Song Tử Đại Thiên Tôn, sở hữu chiến lực vượt xa ngoại hình, từng đá một cước suýt phế tu vi Tham Lang. Về sau tái ngộ Vương Lâm tại Tử Dương Tông, tự nhận từng cứu hắn và khẳng định sẽ bảo vệ hắn trước các Đại Thiên Tôn."},{"id":"ham-ham","name":"Hàm Hàm","trangThai":"song","tabs":{"diem":[{"text":"Nắm chân Tham Lang lôi lại khi hắn cố thoát, cùng Oa giữ hắn suốt trăm năm bắt kể chuyện","chuong":"@c1608"},{"text":"Cùng Oa Oa phong bế vết nứt và giấu Tham Lang, không muốn mấy lão đầu phát hiện","chuong":"@c1610"},{"text":"Được Vương Lâm nhớ là một trong hai cô bé liên quan Song Tử Đại Thiên Tôn","chuong":"@c1822"},{"text":"Bay tới trước mặt Vương Lâm, gọi hắn là Tiểu Vương Lâm và dọa gọi cha đánh","chuong":"@c1865"},{"text":"Đứng bên Oa Oa nhìn theo Vương Lâm rời đi, thấp giọng hỏi liệu còn gặp lại hắn không","chuong":"@c1867"}],"kinhLich":[{"chuong":"@c1867","importance":"normal","tieuDe":"Nhìn theo Vương Lâm rời đi","mucCt":"vua","text":"Đứng bên cạnh Oa Oa nhìn theo Vương Lâm khuất trong gió tuyết, thấp giọng hỏi liệu còn gặp lại hắn không. Hưởng ứng quyết tâm không để kẻ nào bắt nạt Vương Lâm khi hắn đã lựa chọn các nàng.","anchor":"Hàm Hàm đứng bên cạnh nhìn về phía xa xa, thấp giọng hỏi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"người muốn bảo vệ","ghiChu":"Sẵn sàng trợ giúp nếu Vương Lâm gặp nguy cơ ở Trung Châu."},{"ten":"Oa Oa","tag":"dong-minh","quanHe":"đồng bạn","ghiChu":"Cùng nhìn theo Vương Lâm và cùng giữ ý định bảo vệ hắn."},{"ten":"Cô Nhai Thiên Tôn","tag":"dong-minh","quanHe":"người báo cơ chế trợ giúp","ghiChu":"Cô Nhai nói ngọc giản sẽ giúp các nàng biết khi Vương Lâm gặp nguy cơ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867"],"gioiTinh":"nu","vaiTro":"Cô bé bí ẩn trong đào viên, con gái Song Tử Đại Thiên Tôn, giam giữ Tham Lang cùng Oa Oa","tinhCach":"Ngang tàng, không sợ kẻ mạnh; hồn nhiên trực tính; thích nghe chuyện cổ","blurb":"Cô bé tầm tám tuổi mặc váy tím sống trong không gian kỳ dị dạng đào viên tiếp giáp tế đàn trong khe Vân Hải tinh vực, có mối liên hệ với Song Tử Đại Thiên Tôn. Cùng Oa giam giữ Tham Lang suốt trăm năm bắt kể chuyện cổ, từng giúp Vương Lâm và sau đó tái ngộ hắn với thái độ ngang tàng dọa gọi cha đánh."},{"id":"thuong-dao-huyen","name":"Thượng Đạo Huyền","aliases":["Quốc sư","Quốc sư áo trắng của tiên tộc","Thượng Huyền Đạo","Thượng Huyền Đạo quốc sư","Huyền Đạo","Quốc sư đại nhân"],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Môn","trangThai":"gan-bo"},{"ten":"Hoàng tộc Tiên Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không đổi trong @c1888","trangThai":"song","blurb":"Thượng Đạo Huyền là tông chủ đời nay của Đạo Môn, giữ vai quốc sư bên cạnh Tiên Hoàng Liên Đạo Chân với tu vi khó lường. Bề ngoài trung thành phò tá đại lễ sắc phong, thực chất hắn âm thầm bố trí sát cục và mở địa cung mưu phản, cuối cùng lộ rõ kế hoạch đoạt thân Vương Lâm thông qua truyền thừa Tiên Tổ. Kế hoạch bị Tiên Hoàng phá vỡ và lợi dụng ngược, hắn chỉ còn một đám thần thức tàn dư trong cơ thể Vương Lâm.","vaiTro":"Quốc sư tiên tộc — tông chủ Đạo Môn, trọng thần bên cạnh Tiên Hoàng Liên Đạo Chân","tinhCach":"mưu lược thâm sâu, tính toán nhiều bước; dã tâm đoạt thân bất chấp sinh tử; hành sự kín đáo,ẩn mình sau bố cục lớn","tabs":{"diem":[{"text":"Được xác lập là tông chủ Đạo Môn, quốc sư trọng thần bên cạnh Tiên Hoàng","chuong":"@c1867"},{"text":"Lộ diện bên Tiên Hoàng trong Tiên Đạo Điện, tay cầm hạt châu tím và tuyên bố quy tắc đại lễ sắc phong","chuong":"@c1872"},{"text":"Hiện thân từ pho tượng Tiên Tổ, mở địa cung mưu phản và dùng năng lực thành Vô xóa dấu vết","chuong":"@c1883"},{"text":"Lộ kế hoạch đoạt thân:ân thể tan nát hóa u quang, dùng thần niệm xâm nhập cơ thể Vương Lâm","chuong":"@c1887"},{"text":"Mượn thân Vương Lâm qua truyền thừa, chỉ còn một đám thần thức sau khi thân xác đã chết","chuong":"@c1888"},{"text":"Bị Tiên Hoàng phá kế và lợi dụng khát vọng để đoạt quyền điều khiển đầu lâu Tiên Tổ","chuong":"@c1889"}],"kinhLich":[{"chuong":"@c1867","importance":"normal","tieuDe":"Xác lập tông chủ Đạo Môn","mucCt":"vua","text":"Được xác lập là tông chủ đời nay của Đạo Môn, quốc sư trọng thần bên cạnh Tiên Hoàng Liên Đạo Chân. Tu vi khó lường, lực lượng tính toán kinh thiên động địa được mô tả có thể đối kháng tam đại quốc sư Cổ Tộc.","anchor":"Tông chủ đời nay của Đạo Môn chính là quốc sư trọng thần bên cạnh Tiên Hoàng - Thượng Đạo Huyền"},{"chuong":"@c1871","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc trong đại lễ","text":"Quốc sư đại nhân được lão thanh y nói sẽ tính toán biến hóa tương lai cho Vương Lâm trong đại lễ sắc phong.","anchor":"quốc sư đại nhân cũng sẽ tính toán biến hóa tương lai cho ngươi"},{"mucCt":"ky","text":"Thượng Huyền Đạo lộ diện bên cạnh Tiên Hoàng trong Tiên Đạo Điện, tay cầm hạt châu màu tím và khiến Vương Lâm chấn động bởi ánh mắt như kéo người vào luân hồi. Theo lệnh Tiên Hoàng, hắn bước ra chủ trì đại lễ sắc phong, dùng một chỉ mở huyết tế tiên với chín mươi chín huyết trụ từ hoàng cung phóng lên. Sau khi Tiên Hoàng diệt Thiên Sư Thú, hắn cũng sững lại trước sợi tóc bạc không bị Cực Hỏa Đạo đốt cháy.","anchor":"Bên cạnh nam tử này là một thanh niên mặc trường sam bằng vải thô, da dẻ trắng bệch, hai mắt nhỏ dài, cầm trong tay một hạt châu màu tím","bridge":true,"khoang":"@c1872"},{"mucCt":"ky","text":"Thượng Huyền Đạo tuyên bố huyết tế chấm dứt và đặt ra quy tắc ba lần khiêu chiến trước khi sắc phong. Khi hư ảnh Thiên Ngưu sau đòn của Vương Lâm lao tới, ông chỉ một cái, giảng về đạo “vô” và khiến hư ảnh tan biến, làm Vương Lâm cảm nhận được dao động đạo pháp cực kỳ đáng sợ nơi ông.","anchor":"Một chỉ này khiến cho hư ảnh Thiên Ngưu đang lao tới run mạnh.","bridge":true,"khoang":"@c1873"},{"chuong":"@c1874","importance":"bridge","tieuDe":"Bị Đạo Phi nghi ngờ","text":"Thượng Huyền Đạo bị Đạo Phi nghi là người đánh La Công, nhưng Tiên Hoàng nói rõ chuyện La Công khiêu chiến thất bại không liên quan đến ông.","anchor":"không có liên quan gì đến quốc sư","mucCt":"gon"},{"chuong":"@c1876","importance":"bridge","mucCt":"gon","tieuDe":"Lực lượng Vô được nhớ tới","text":"Vương Lâm nhận ra lực lượng phong ấn trong sát cục phố dài thuộc về Vô và liên tưởng tới Thượng Huyền Đạo.","anchor":"Luồng lực lượng Vô này Vương Lâm chỉ thấy ở trên người quốc sư Thượng Huyền Đạo mà thôi"},{"chuong":"@c1877","importance":"bridge","mucCt":"gon","tieuDe":"Bị nghi liên quan sát cục","text":"Thượng Huyền Đạo bị Vương Lâm nghi ngờ có bóng dáng trong trận chém giết và đồ án giam cầm ở bốn phía.","anchor":"Trận chém giết này ở bên trong có bóng dáng của quốc sư"},{"chuong":"@c1879","importance":"bridge","mucCt":"gon","text":"Bị Vương Lâm nhắc tới để phủ định thân ảnh ánh sáng trắng không phải quốc sư thật.","anchor":"Ngươi không phải là quốc sư!"},{"chuong":"@c1880","importance":"bridge","mucCt":"gon","tieuDe":"Bị nêu trong sát cục","text":"Thượng Huyền Đạo và nhất mạch quốc sư bị Vương Lâm tóc đen nêu là một bên liên quan sát cục và có tông môn đến từ thiên ngoại.","anchor":"Sát cục này trừ nhất mạch của quốc sư còn có ngươi"},{"chuong":"@c1883","importance":"major","mucCt":"ky","tieuDe":"Mở địa cung mưu phản","text":"Thượng Huyền Đạo hiện thân từ pho tượng Tiên Tổ, dùng năng lực thành Vô xóa các vết nứt do Vương Lâm tạo ra và giải thích phân thân trên phố bằng Đạo Diễn Hồn. Hắn mở địa cung, tiết lộ tộc mình tạo ra thuật động phủ giới nhưng bị Tiên Tổ phong ấn trong tổ thành, rồi muốn mượn Vương Lâm thay Minh Đạo Tôn để đoạt tu vi Tiên Tổ qua Phản tổ đại pháp.","anchor":"Phản tổ đại pháp, người mà hắn lựa chọn chính là Minh Đạo Tôn, còn người mà ta chọn, chính là Vương Lâm ngươi!"},{"mucCt":"ky","text":"Thượng Huyền Đạo đứng trên tế đàn, nói Tiên Hoàng dùng Minh Đạo Tôn, ao máu và chấp niệm hận Vương Lâm để thúc đẩy phản tổ, rồi đề nghị chuyển phần truyền thừa vốn dành cho Minh Đạo Tôn sang Vương Lâm. Điều kiện của hắn là sau khi Vương Lâm có tu vi Tiên Tổ đời thứ hai thì giải phong ấn cho tộc hắn, giúp họ thoát thân phận nô phó và rời Tiên Cương đại lục. Để lấy lòng tin, hắn lập thệ phù trước pháp tắc Tiên Cương, giao mệnh tinh của tộc mình cho Vương Lâm khiến bản thân già nua, rồi chuẩn bị thi triển bí thuật.","anchor":"Ta đưa vật này cho ngươi, hy vọng ngươi có thể tin tưởng ta","bridge":true,"khoang":"@c1884"},{"chuong":"@c1885","importance":"normal","mucCt":"ky","tieuDe":"Mở lối dưới ao","text":"Thượng Huyền Đạo bị Vương Lâm dùng huyết vụ dẫn dụ Minh Đạo Tôn công kích, buộc phải ra tay chống đỡ. Hắn cảnh báo việc Vương Lâm động vào xích sắt đã khiến Tiên Hoàng biết, đề nghị cùng trấn áp Minh Đạo Tôn và hứa chuyển lực lượng phản tổ cho Vương Lâm. Khi chưởng ấn màu vàng giáng xuống trách tội hắn phản bội, hắn mở ao nước thành lối xuống không gian khác dưới địa cung.","anchor":"Thượng Huyền Đạo, ngươi dám phản ta"},{"chuong":"@c1886","importance":"normal","mucCt":"ky","tieuDe":"Lao vào truyền thừa","text":"Thượng Huyền Đạo cùng Vương Lâm đứng trên tiên sơn, xác nhận Tiên Hoàng tạm bị Song Tử Đại Thiên Tôn cản và thời gian còn lại rất ít. Ông nhiều lần hao tổn sinh mạng thi triển thần thông, tạo thân ảnh trắng và huyết nhân, đồng thời giải thích lai lịch Cửu Tọa tiên sơn cũng như biến hóa nguy hiểm của Phản tổ đại pháp trên Minh Đạo Tôn. Khi xương Minh Đạo Tôn nứt nát và truyền thừa Tiên Tổ lộ ra, ông dùng chút sinh mạng cuối khiến thân thể tan nát, hóa u quang lao thẳng tới Minh Đạo Tôn.","anchor":"Thân thể quốc sư run lên, hơi thở dồn dập. sắc mặt cực kỳ tái nhợt"},{"chuong":"@c1887","importance":"major","mucCt":"ky","tieuDe":"Lộ kế hoạch đoạt thân","text":"Thượng Huyền Đạo tan nát thân thể hóa thành u quang, dùng thần niệm nói sẽ hy sinh sinh mệnh cuối cùng để giúp Vương Lâm nhận truyền thừa Tiên Tổ và giải phong ấn cho tộc mình. Khi Vương Lâm phá hỏng thân ảnh vàng của Minh Đạo Tôn, hắn phẫn nộ triệu hồi đầu Tiên Tổ, đưa đốm sáng vàng và Vương Lâm vào mắt phải Tiên Tổ. Trong mắt phải ấy, hắn thừa nhận vốn muốn mượn sức mạnh Tiên Tổ trấn áp tâm thần Vương Lâm, chiếm thần trí hắn, rồi đổi sang ý định dùng thân thể Vương Lâm để nhận tu vi Tiên Tổ.","anchor":"Lão phu đã đợi rất nhiều năm rồi, không thể rời khỏi nơi này, càng không thể tìm được người đoạt xá thích hợp"},{"chuong":"@c1888","importance":"major","mucCt":"ky","tieuDe":"Mượn thân giải phong ấn","text":"Thượng Huyền Đạo chỉ còn một đám thần thức trong cơ thể Vương Lâm sau khi thân thể đã chết. Hắn mượn truyền thừa Tiên Tổ để trấn áp tâm thần Vương Lâm, tưởng đoạt xá thành công, rồi dùng thân thể này mở mắt trái Tiên Tổ, hút Liên Đạo Phi vào và ép đầu lâu Tiên Tổ phát lời giải phong ấn Điệu Vong tộc.","anchor":"Thân thể hắn đã tử vong, lúc này ớ trong thân thể Vương Lâm chi là một đám thần thức"},{"chuong":"@c1889","importance":"major","mucCt":"ky","tieuDe":"Bị Tiên hoàng phá kế","text":"Người đang chiếm thân thể Vương Lâm dùng kế biến thân thể Vương Lâm và Đạo Phi thành hai mắt đầu tiên tổ để khiến đầu tiên tổ mở miệng giải phong ấn cho tộc mình. Khi giọt máu vàng của Tiên hoàng rơi xuống chặn chữ cuối, hắn bị giữ lại trong mắt phải, không thoát ra được. Sau đó hắn kinh hãi vì Tiên hoàng đã nhìn thấu các mắt xích trong kế hoạch của mình.","anchor":"Quốc sư đang chiếm cứ thân thể Vương Lâm lúc này mở mạnh hai mắt"},{"chuong":"@c1890","importance":"bridge","mucCt":"vua","text":"Quốc sư được nhắc là người bị Tiên Hoàng lợi dụng khát vọng để đoạt quyền điều khiển đầu lâu Tiên Tổ, nhưng hậu thủ phong ấn Điệu vong tộc do hắn dung hợp thần thức để lại đã cản Tiên Hoàng hấp thu đầu lâu.","anchor":"Lợi dụng khát vọng của quốc sư đạt được quyền điều khiển đầu lâu Tiên Tổ"}],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Hoàng","tag":"cap-tren","quanHe":"Quốc sư trọng thần","ghiChu":"Phụng sự bên cạnh Tiên Hoàng đời này."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng sẽ được tính toán biến hóa tương lai","ghiChu":"Được nhắc là sẽ tham dự phần nghi thức sau cửu môn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người được sắc phong khiến Thượng Huyền Đạo chú ý trong nghi thức.","ghiChu":"Ánh mắt của Thượng Huyền Đạo làm Vương Lâm chấn động và cảnh giác."},{"ten":"Liên Đạo Phi","tag":"doi-thu","quanHe":"Bị Đạo Phi nhắm tới","ghiChu":"Đạo Phi tưởng ông bắt nạt La Công và định xông tới bóp cổ ông."},{"ten":"Tiên Tổ","tag":"khac","quanHe":"Tộc nhân bị phong ấn truyền thừa","ghiChu":"Tộc của quốc sư từng theo Tiên Tổ rồi bị phong ấn đời đời trong tổ thành."},{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"Bề ngoài phục tùng, ngầm mưu tính thoát khống chế","ghiChu":"Hắn nói sinh tử tộc mình bị các đời Tiên Hoàng nắm giữ."},{"ten":"Lão tổ của Đại Hồn Môn","tag":"ho-hang","quanHe":"Thiên tài cùng tộc","ghiChu":"Được nêu làm ví dụ người từng rời tổ thành nhưng khó thoát chết."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Tạm thời đề nghị hợp tác, dùng truyền thừa Tiên Tổ đổi lấy việc giải phong ấn cho tộc mình.","ghiChu":"Hắn nhiều lần cầu Vương Lâm tin mình một lần."},{"ten":"Minh Đạo Tôn","tag":"khac","quanHe":"Giải thích Minh Đạo Tôn là trung tâm kế phản tổ do Tiên Hoàng chuẩn bị.","ghiChu":"Hắn dự định chuyển phần tu vi vốn dành cho Minh Đạo Tôn sang Vương Lâm."},{"ten":"Tiên Tổ Liên Vân Quyết","tag":"khac","quanHe":"Dùng di hài làm trung tâm nghi thức","ghiChu":"Quốc sư triệu hồi đầu Tiên Tổ và mở mắt phải để hút đốm sáng vàng cùng Vương Lâm."},{"ten":"Điệu Vong tộc","tag":"khac","quanHe":"tộc nhân","ghiChu":"Hắn hành động để giải phong ấn cho tộc nhân bị Tiên Tổ giam cầm."},{"ten":"Liên Đạo Chân","tag":"cap-tren","quanHe":"quốc sư của Tiên Hoàng","ghiChu":"Là trọng thần bên cạnh Tiên Hoàng đời này."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867","@c1871","@c1872","@c1873","@c1874","@c1876","@c1877","@c1879","@c1880","@c1883","@c1884","@c1885","@c1886","@c1887","@c1888","@c1889","@c1890"]},{"id":"lien-dao-phi","name":"Liên Đạo Phi","aliases":["Đạo Phi","người điên"],"trangThai":"song","tabs":{"diem":[{"text":"Là chủ nhân cũ của viêm long Tiểu Hồng, từng được xác nhận đã chết trong ký ức các nhân vật liên quan","chuong":"@c1591"},{"text":"Vì mê sắc đẹp Phàn San Mộng mà bị dụ tới Thất Đạo Tông để phá cuộc","chuong":"@c1599"},{"text":"Tu vi thông thiên, từng một mình giao chiến tứ đại chiến tướng cùng đệ tử Thất Đạo Tông; bị thiên đạo nuốt nhưng nhờ bất diệt thể vẫn sống","chuong":"@c1600"},{"text":"Được Vương Lâm triệu hồi ra trận, xuất hiện giữa chiến trường và gây chấn động toàn trường","chuong":"@c1670"},{"text":"Chống đỡ lực hủy diệt từ ba trăm giới sụp đổ, suy yếu quá nửa rồi rơi vào ngủ say","chuong":"@c1671"},{"text":"Thoát khỏi âm mưu đoạt xá khi bị Tiên Hoàng coi là đường lui trong mắt trái đầu lâu Tiên Tổ","chuong":"@c1893"}],"kinhLich":[{"chuong":"@c1868","importance":"bridge","mucCt":"gon","tieuDe":"Được Vương Lâm nhớ tới","text":"Liên Đạo Phi được Vương Lâm nhớ tới khi hắn uống rượu một mình trong nhà trọ và nghĩ về chuyện trong động phủ giới.","anchor":"Liên Đạo Phi. Ngươi còn nhớ chuyện trong động phủ giới hay không."},{"mucCt":"vua","anchor":"Vương Lâm trầm mặc, thần thức đảo qua Đông Thành nhưng không thấy Liên Đạo Phi.","text":"Vương Lâm dùng thần thức đảo qua Đông Thành để tìm Liên Đạo Phi nhưng không thấy, cho thấy người này không ở trong phạm vi thần thức tại Đông Thành lúc đó.","bridge":true,"khoang":"@c1870"},{"chuong":"@c1873","importance":"normal","mucCt":"ky","tieuDe":"Xông vào đại lễ","text":"Liên Đạo Phi xuất hiện từ Truyền Tống Trận ngoài cửu môn hoàng cung trong bộ dạng mặc hoa sam, cầm quạt và mắng vì không ai báo chuyện náo nhiệt cho mình. Hắn sai Hứa Lập Quốc cùng nhóm Tiểu Thanh, Tiểu Bạch, Tiểu Lam mở đường, được tu sĩ bái kiến là vương gia, rồi tưởng La Công bị quốc sư bắt nạt nên định xông tới bóp cổ Thượng Huyền Đạo. Khi Tiên Hoàng gọi tên và nhắc đây là đại lễ sắc phong ân công của hắn, hắn sững sờ hỏi lại.","anchor":"Thủ lĩnh của đám người này là một người thanh niên mặc trường sam nhiều màu, cầm trong tay một cây quạt."},{"chuong":"@c1874","importance":"normal","tieuDe":"Mất ký ức cũ","text":"Đạo Phi tái xuất trong trạng thái rối loạn ký ức, lúc gọi Vương Lâm là ân công, lúc phủ nhận cách gọi Người điên, rồi truy hỏi kẻ đánh gia gia của Tiểu Hoa. Sau khi Hứa Lập Quốc chỉ Vương Lâm, hắn nổi giận bóp cổ Vương Lâm nhưng bị Tiên Hoàng đánh lui và ra lệnh trục xuất khỏi hoàng cung.","anchor":"Thanh niên áo hoa đang bóp cổ Vương Lâm lập tức như bị cuốn đi","mucCt":"ky"},{"mucCt":"vua","text":"Liên Đạo Phi cũng bị cảm giác kêu gọi dẫn tới cửa đông Tổ Thành. Vừa thấy Vương Lâm xuất hiện, hắn nổi giận xắn áo lao lên vì vẫn oán chuyện trước đó.","anchor":"ngươi không ngờ còn dám xuất hiện trước mặt bổn vương","bridge":true,"khoang":"@c1880"},{"chuong":"@c1881","importance":"normal","mucCt":"ky","tieuDe":"Ký ức nới lỏng","text":"Liên Đạo Phi ban đầu đau khổ vì Hứa Lập Quốc bỏ mình để nhận Vương Lâm làm chủ, rồi nổi giận lao tới bóp cổ Vương Lâm. Sau khi Vương Lâm rời đi, phong ấn trong đầu hắn nới lỏng, khiến hắn nhớ lại động phủ giới, chuyện từng cứu thi thể Vương Lâm bằng máu tươi, giấc mộng đạo và nghi vấn ca ca đã phong ấn ký ức của mình. Khi hắn gọi Vương Lâm là sư tôn, Tiên hoàng xuất hiện, làm hắn mê man, xóa dấu chưởng ấn trên cánh tay và đưa hắn tới nơi bế quan của tiên tổ.","anchor":"Thân thể người điên càng thêm run rẩy, trong đầu hắn ầm một tiếng, hiện lên một hình ảnh"},{"chuong":"@c1882","importance":"bridge","mucCt":"vua","tieuDe":"Bị dùng ép Vương Lâm","text":"Liên Đạo Phi không trực tiếp xuất hiện nhưng bị Vương Lâm xác định là quân cờ Tiên Hoàng dùng để ép hắn tới hoàng cung, khiến Vương Lâm chuyển từ ý định rời đi sang hủy diệt.","anchor":"Nhưng ngươi. Lại lấy người điên bức ta tới đây"},{"mucCt":"vua","text":"Liên Đạo Phi vẫn bị chín sợi xích khóa cứng trong địa cung. Vương Lâm muốn cứu hắn trước khi xuống ao máu, nhưng quốc sư nói xích sắt do Tiên Hoàng bố trí, bản thân không thể mở và nếu động vào sẽ lập tức khiến Tiên Hoàng phát hiện.","anchor":"Liên Đạo Phi đang bị chín sợi xích khóa cứng","bridge":true,"khoang":"@c1884"},{"mucCt":"vua","text":"Liên Đạo Phi vẫn bị chín sợi xích khóa trên tế đàn. Khi Vương Lâm lao tới cứu, kim quang trên người hắn bộc phát giống lực lượng pho tượng Tiên Tổ, tạo bài xích khiến Vương Lâm không thể tới gần.","anchor":"Trong nháy mắt khi tới gần, hắc vụ bao phủ tám phương, trong tích tắc đang muốn cứu người điên thì đột nhiên trên người người điên có kim quang ngập trời tỏa ra","bridge":true,"khoang":"@c1885"},{"mucCt":"vua","text":"Liên Đạo Phi đang bị chín sợi xích sắt khóa trên tế đàn ngoài ao máu địa cung. Khi mắt trái Tiên Tổ mở ra, lực hút kéo hắn tới, làm các sợi xích lần lượt đứt và nuốt hắn vào thế giới trong mắt trái.","anchor":"người điên đang bị khóa bởi chín sợi xích sắt trên tế đàn","bridge":true,"khoang":"@c1888"},{"chuong":"@c1889","importance":"normal","mucCt":"vua","tieuDe":"Thành mắt trái Tiên Tổ","text":"Đạo Phi được Tiên hoàng và quốc sư nhắc là thân thể phản tổ đã được chuẩn bị từ đầu. Hắn bị giam trong địa cung để triển khai Phản tổ đại pháp, hóa thành mắt trái của đầu tiên tổ và trở thành mắt xích trung tâm trong cả hai kế hoạch.","anchor":"đem Đạo Phi hóa thành mắt trái"},{"chuong":"@c1892","importance":"bridge","mucCt":"gon","text":"Liên Đạo Phi bị Tiên hoàng nhắc cùng Minh Đạo Tôn như đối tượng bị Cửu Đế lợi dụng trong kế hoạch Điệu Vong Tộc.","anchor":"Ngươi còn lợi dụng Minh Đạo Tôn, lợi dụng Liên Đạo Phi"},{"chuong":"@c1893","importance":"major","mucCt":"ky","tieuDe":"Thoát khỏi đoạt xá","text":"Liên Đạo Phi hôn mê trong mắt trái đầu lâu Tiên Tổ và bị Tiên Hoàng coi là đường lui để đoạt xá, chia sẻ Trớ Thuật và chuyển bại thành thắng. Khi linh hồn Tiên Hoàng sắp nhập vào thân thể hắn, Vương Lâm xuất hiện chặn lại. Cuối chương hắn được Vương Lâm dìu ra khỏi mắt trái đầu lâu Tiên Tổ.","anchor":"đang chuẩn bị nhảy vào cơ thể thể Liên Đạo Phi nhắm mắt hôn mê"},{"chuong":"@c1894","importance":"bridge","mucCt":"gon","tieuDe":"Hôn mê cạnh Vương Lâm","text":"Liên Đạo Phi đang hôn mê bên cạnh Vương Lâm và được Vương Lâm buông ra khi Đạo Nhất lao tới công kích.","anchor":"hắn buông người điên đang hôn mê ra"},{"chuong":"@c1896","importance":"normal","mucCt":"gon","tieuDe":"Bị buộc lưu lại","text":"Liên Đạo Phi đang hôn mê bên đầu lâu Tiên Tổ và trở thành trọng tâm tranh chấp khi Cửu Đế tuyệt đối cấm Vương Lâm mang đi, còn Song Tử cũng khuyên Vương Lâm lưu nàng lại.","anchor":"Ngươi hẳn phải biết Liên Đạo Phi mà tỉnh lại thì có tác dụng gì."},{"chuong":"@c1897","importance":"normal","mucCt":"ky","tieuDe":"Đại Thiên Tôn ngủ say","text":"Liên Đạo Phi đang hôn mê trên đầu tiên tổ và bị chọn vì có huyết mạch cùng một phần truyền thừa tu vi của tiên tổ. Sau khi Hài Tử mở dấu ấn và thi triển bí thuật, hắn trở thành Đại Thiên Tôn thứ năm của tiên tộc sau Tiên Hoàng. Đại Thiên Tôn mới này không thức tỉnh mà vĩnh viễn ngủ say để thay đầu tiên tổ trấn áp linh hồn trong bảy mươi hai châu.","anchor":"Nhưng Đại Thiên Tôn này sẽ vĩnh viễn ngủ say, sẽ không tỉnh lại"},{"chuong":"@c1898","importance":"bridge","mucCt":"vua","tieuDe":"Ngủ dưới núi vàng","text":"Liên Đạo Phi vẫn chưa tỉnh dưới ngọn núi vàng trong địa cung không gian xếp chồng của hoàng cung, như đang đợi lần Vương Lâm trở lại.","anchor":"Dưới ngọn núi nọ. người điên vẫn không thức tỉnh"},{"chuong":"@c1899","importance":"bridge","mucCt":"gon","tieuDe":"Được Vương Lâm nhớ tới","text":"Liên Đạo Phi được Vương Lâm nhớ tới khi hắn đã rời xa vùng đất tiên tộc trên đường vượt biển sang cổ tộc.","anchor":"Người điên.sau khi ta trở về"}],"tuViMoc":[{"chuong":"@c1897","canhGioi":"Đại Thiên Tôn","text":"Liên Đạo Phi được bí thuật của Hài Tử phối hợp truyền thừa tiên tổ thúc thành Đại Thiên Tôn thứ năm của tiên tộc sau Tiên Hoàng, nhưng ở trạng thái ngủ say.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Bằng hữu từng có ân","ghiChu":"Từng cùng Vương Lâm Mộng Đạo tại Chu Tước Tinh."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người dùng thần thức tìm hắn","ghiChu":"Vương Lâm quét Đông Thành nhưng không phát hiện Liên Đạo Phi."},{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"Người bị sai mở đường","ghiChu":"Đạo Phi gọi Hứa Lập Quốc là Tiểu Hồng, đá hắn và ép hắn mở đường."},{"ten":"Thiếu niên thanh y đi cùng Đạo Phi","tag":"dong-hanh","quanHe":"Người đi cùng và can ngăn","ghiChu":"Thiếu niên ôm chân Đạo Phi để ngăn hắn lao vào quốc sư."},{"ten":"La Công","tag":"khac","quanHe":"Người được Đạo Phi bênh vực nhầm","ghiChu":"Đạo Phi tưởng La Công bị quốc sư bắt nạt."},{"ten":"Thượng Huyền Đạo","tag":"doi-thu","quanHe":"Mục tiêu bị Đạo Phi đòi đánh","ghiChu":"Đạo Phi chỉ thẳng quốc sư và muốn bóp chết ông."},{"ten":"Tiên Hoàng","tag":"ho-hang","quanHe":"Người ngăn hắn gây chuyện","ghiChu":"Tiên Hoàng gọi tên Đạo Phi và nhắc hắn về ân công."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Oán giận khi gặp lại","ghiChu":"Tại cửa đông Tổ Thành, Liên Đạo Phi nổi giận muốn xông lên khi thấy Vương Lâm."},{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"bị lợi dụng","ghiChu":"Bị Vương Lâm cho rằng đã bị Tiên Hoàng dùng để ép hắn tới đây."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Được Vương Lâm yêu cầu cứu trước khi nhận truyền thừa.","ghiChu":"Vương Lâm đặt việc cứu hắn làm điều kiện thăm dò quốc sư."},{"ten":"Cửu Đế","tag":"doi-thu","quanHe":"Bị Cửu Đế xem là đối tượng không thể để Vương Lâm mang đi.","ghiChu":"Tình thế phát sinh tại @c1896"},{"ten":"Song Tử","tag":"khac","quanHe":"Bị Song Tử khuyên Vương Lâm lưu lại.","ghiChu":"Tình thế phát sinh tại @c1896"},{"ten":"Hài Tử","tag":"khac","quanHe":"người thi triển bí thuật khiến hắn thành Đại Thiên Tôn ngủ say","ghiChu":"Hài Tử dùng hắn thay đầu tiên tổ trấn áp bảy mươi hai châu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Mộng Đạo","loai":"công pháp","trangThai":"dang-co","moTa":"Từng cùng Vương Lâm trải qua Mộng Đạo tại Chu Tước Tinh.","nguon":"@c1867"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867","@c1868","@c1870","@c1873","@c1874","@c1880","@c1881","@c1882","@c1884","@c1885","@c1888","@c1889","@c1892","@c1893","@c1894","@c1896","@c1897","@c1898","@c1899"],"canhGioiCaoNhat":"Đại Thiên Tôn @c1897","tinhCach":"Điên cuồng ngạo mạn, dám một mình chiến quần hùng; dễ bị mỹ nhân dụ dẫn; trọng tình nghĩa với Vương Lâm; ý chí kiên cường nhờ bất diệt thể","gioiTinh":"nam","vaiTro":"Cường giả bí ẩn Tiên Cương — bằng hữu chí thân của Vương Lâm","blurb":"Liên Đạo Phi là cường giả bí ẩn từng được viêm long Tiểu Hồng xác nhận là chủ nhân cũ, đồng thời là cố nhân và bằng hữu quan trọng của Vương Lâm. Hắn từng bị Phàn San Mộng dụ tới Thất Đạo Tông, một mình giao chiến tứ đại chiến tướng rồi bị thiên đạo nuốt nhưng nhờ bất diệt thể vẫn chưa diệt vong. Về sau hắn nhiều lần bị cuốn vào đại cục Tiên tộc, từng bị dùng làm quân cờ ép Vương Lâm, trở thành mắt trái Tiên Tổ và rơi vào trạng thái hôn mê sau biến cố đoạt xá."},{"id":"tien-to","name":"Tiên Tổ","aliases":["Liên Vân Quyết","Tiên Tổ Liên Vân Quyết","Tiên Tổ"],"trangThai":"tu-vong","tabs":{"diem":[{"text":"Phong ấn bảy mươi hai sinh linh thiên ngoại, đánh bại và trấn áp tu sĩ thiên ngoại họ Mạnh cùng Lục Ma Hạt Hồn","chuong":"@c1841"},{"text":"Sáng tạo Thiên Tôn Niết bắt chước Thái Cổ thần cảnh, để lại ấn quyết và Bát Cực Đạo cho hậu nhân tu luyện","chuong":"@c1826"},{"text":"Sợi tóc hóa thành kinh mạch trong thân Vương Lâm, mang tiên khí và bộc phát tiên lực khi cần","chuong":"@c1810"},{"text":"Đầu lâu ẩn trong cấm cung chứa thế giới truyền thừa, trở thành trung tâm tranh đoạt và nguồn lực lượng trấn áp","chuong":"@c1888"},{"text":"Bố trí Trớ Thuật trước khi chết, sau vô số vạn năm vẫn chi phối chiến cục và phong ấn giam cầm Điệu Vong Tộc","chuong":"@c1892"},{"text":"Hư ảnh kim bào tái xuất lần đầu sau vô số vạn năm kể từ khi tiêu tán trong hư không","chuong":"@c1704"}],"kinhLich":[{"chuong":"@c1872","importance":"bridge","mucCt":"gon","tieuDe":"Ấn ký Thiên Sư","text":"Tiên Tổ được nhắc qua ấn ký lưu lại trên Thiên Sư Thú bị huyết tế kéo tới trong đại lễ sắc phong.","anchor":"Đây là Thiên Sư Thú mà Tiên Tổ có lưu lại ấn ký!"},{"chuong":"@c1883","importance":"bridge","mucCt":"gon","tieuDe":"Để lại phong ấn","text":"Tiên Tổ được nhắc là người có sức mạnh vô thượng, từng mời tộc quốc sư bố trí hoàng cung và để lại phong ấn truyền thừa lên tộc này.","anchor":"Tiên Tổ có sức mạnh vô thượng"},{"chuong":"@c1884","importance":"bridge","tieuDe":"Nguồn truyền thừa","mucCt":"gon","text":"Tiên Tổ được quốc sư nhắc là tồn tại sinh ra trong hư vô, từng phong ấn tộc của quốc sư và để lại mục tiêu truyền thừa khiến người nhận có thể thành Tiên Tổ đời thứ hai.","anchor":"Tiên Tổ sinh ra trong hư vô, bất đồng với tộc ta"},{"chuong":"@c1885","importance":"bridge","mucCt":"vua","tieuDe":"Đầu lâu hóa sơn","text":"Tiên Tổ được liên hệ với kim quang huyết mạch trên Minh Đạo Tôn và Liên Đạo Phi, rồi hiện dấu vết qua ngọn núi đầu lâu trong không gian dưới ao.","anchor":"Tướng mạo hắn bất ngờ lại là Tiên Tổ"},{"chuong":"@c1886","importance":"bridge","mucCt":"vua","tieuDe":"Truyền thừa lộ ra","text":"Tiên Tổ được nhắc qua Cửu Tọa tiên sơn hình đầu Tiên Tổ, nơi bế quan, lực lượng trong huyết nhục Minh Đạo Tôn và quầng sáng truyền thừa trong thân thể hắn.","anchor":"Quầng sáng này chính là truyền thừa của Tiên Tổ mà hắn nhận được"},{"chuong":"@c1888","importance":"normal","mucCt":"vua","tieuDe":"Đầu lâu mở miệng","text":"Đầu lâu Tiên Tổ trong cấm cung có mắt phải chứa thế giới truyền thừa và hư ảnh Vương Lâm. Dưới thao túng của Thượng Huyền Đạo, mắt trái mở ra hút Liên Đạo Phi, sau đó cái miệng vốn đóng chặt chậm rãi mở và phát ra lời giải phong ấn Điệu Vong tộc.","anchor":"cái miệng vẫn luôn đóng chặt lúc này chậm rãi mở ra"},{"mucCt":"ky","text":"Đầu lâu thật của Tiên Tổ bị Tiên Hoàng điều khiển để phát ra thần thông, kim quang và lực lượng trấn áp. Hư ảnh mặc hoàng bào của ông được máu Tiên Hoàng dẫn hiện, nắm thanh kiếm vàng chém xuống, dù chỉ một thành lực lượng cũng khiến bốn Đại Thiên Tôn phải hợp lực phá giải.","anchor":"Thân ảnh này mặc hoàng bào, chính là Tiên Tổ","bridge":true,"khoang":"@c1890"},{"mucCt":"vua","text":"Đầu Tiên Tổ trở thành nguồn sức mạnh mà Tiên Hoàng muốn hấp thu để đạt tu vi truyền thừa và trở thành Tiên Tổ đời thứ hai. Phong ấn của Tiên Tổ đối với Điệu Vong Tộc cũng được nhắc là nguyên nhân khiến tộc này từng không thể rời hoàng cung và Tổ Thành.","anchor":"khiến cho thân thể của mình đạt được tu vi truyền thừa của Tiên Tổ","bridge":true,"khoang":"@c1891"},{"chuong":"@c1892","importance":"normal","mucCt":"vua","tieuDe":"Trớ thuật sau chết","text":"Tiên Tổ được xác nhận đã đặt phong ấn giam cầm Điệu Vong Tộc, còn đầu của hắn chứa sức trấn áp khiến kế hoạch của tộc này bị kìm giữ. Thân thể hắn sau khi chết mang trớ thuật, kẻ muốn hủy diệt đều phải chết trừ khi hậu nhân dùng huyết mạch lực thí tổ và chịu đại giá cắt đứt huyết mạch.","anchor":"Nếu Tiên Tổ chết, thì thân thể của hắn sẽ bị nguyền rủa"},{"chuong":"@c1893","importance":"bridge","mucCt":"gon","tieuDe":"Trớ Thuật chi phối chiến cục","text":"Đầu lâu và Trớ Thuật trước khi chết của Tiên Tổ trở thành trung tâm tranh đoạt, khiến những người động tới đầu lâu bị phản phệ.","anchor":"Cái khe này khuếch tán ra chẳng khác nào bốn người đồng thời động tới Trớ Thuật của Tiên Tổ"},{"chuong":"@c1894","importance":"bridge","mucCt":"gon","tieuDe":"Đầu lâu bị phân chia","text":"Đầu lâu Tiên Tổ trở thành trung tâm tranh đoạt, Trớ Thuật trong đó đã được giải khai, còn hai con ngươi và hai tai lần lượt bị Vương Lâm lấy ra trao cho Song Tử và Võ Phong.","anchor":"Trong đầu lâu của Tiên Tổ ẩn chứa Trớ Thuật"},{"chuong":"@c1895","importance":"bridge","mucCt":"gon","tieuDe":"Truyền thừa được nhắc","text":"Tu vi truyền thừa của Tiên Tổ được nhắc như một phần nền tảng khiến khí tức hiện thời của Vương Lâm đạt đỉnh phong.","anchor":"Đây là tu vi đỉnh phong của hắn sau khi hấp thu một chút tu vi truyền thừa của Tiên Tổ"},{"chuong":"@c1898","importance":"bridge","mucCt":"gon","tieuDe":"Huyết mạch bị cắt","text":"Tiên Tổ được nhắc qua hai tai, hai mắt và việc huyết mạch Tiên Tổ bị kế hoạch Điệu Vong tộc cắt đứt.","anchor":"Bước cuối cùng của kế hoạch này đã thành công giải phong ấn giam cầm tộc nhân của hắn. khiến cho huyết mạch Tiên Tổ bị cắt đứt"},{"chuong":"@c1900","importance":"bridge","mucCt":"vua","tieuDe":"Truyền thừa và đầu lâu","text":"Tiên Tổ được nhắc qua truyền thừa giúp Vương Lâm ngưng tụ hình dáng Đại Thiên Tôn Chi Dương, còn đầu lâu của ông được Vương Lâm nghiên cứu như then chốt khiến hình dáng ấy ngưng thật.","anchor":"Truyền thừa của Tiên Tổ không làm tu vi ta gia tăng"}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Sư Thú bị thương","tag":"khac","quanHe":"Sinh linh được người trong đại lễ nhận ra có ấn ký Tiên Tổ.","ghiChu":"Ấn ký Tiên Tổ là dấu hiệu khiến tu sĩ xung quanh kinh hô khi Thiên Sư Thú xuất hiện."},{"ten":"Thượng Huyền Đạo","tag":"khac","quanHe":"Tộc của quốc sư bị phong ấn truyền thừa","ghiChu":"Phong ấn của Tiên Tổ khiến tộc quốc sư đời đời không thể rời tổ thành."},{"ten":"Thượng Huyền Đạo","tag":"doi-thu","quanHe":"Tộc của quốc sư bị Tiên Tổ phong ấn đời đời.","ghiChu":"Quốc sư muốn Vương Lâm phá phong ấn ấy."},{"ten":"Liên Đạo Chân","tag":"ho-hang","quanHe":"tổ tiên huyết mạch","ghiChu":"Liên Đạo Chân thuộc dòng hậu nhân Tiên Tổ được nhắc trong cơ chế kế thừa danh hiệu."},{"ten":"Võ Phong","tag":"khac","quanHe":"hai tai rơi vào tay Võ Phong","ghiChu":"Võ Phong đạt được hai tai Tiên Tổ."},{"ten":"Song Tử","tag":"khac","quanHe":"hai mắt được Song Tử dung hợp","ghiChu":"Song Tử bế quan dung hợp hai mắt Tiên Tổ."},{"ten":"Điệu Vong tộc","tag":"doi-thu","quanHe":"huyết mạch bị cắt đứt bởi kế hoạch","ghiChu":"Kế hoạch Điệu Vong tộc khiến huyết mạch Tiên Tổ bị cắt đứt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867","@c1872","@c1883","@c1884","@c1885","@c1886","@c1888","@c1890","@c1891","@c1892","@c1893","@c1894","@c1895","@c1898","@c1900","@c1906"],"gioiTinh":"nam","canhGioiCaoNhat":"Không đổi trong @c1888","vaiTro":"Thủy tổ Tiên Tộc — tồn tại thượng cổ sinh ra từ hư vô, đã tiêu tán","tinhCach":"quyết liệt trấn áp ngoại địch, từng một mình trấn áp Lục Ma và phong ấn hàng chục sinh linh thiên ngoại; chú trọng truyền thừa, sáng tạo Thiên Tôn Niết và lưu lại ấn quyết, phân ảnh, cảm ngộ cho hậu nhân; đặt nặng quy củ và trật tự Tiên Tộc, định ra lễ nghi người Tiên Tộc gặp Tiên Hoàng chỉ vái khôn","blurb":"Tiên Tổ là thủy tổ của Tiên Tộc, một tồn tại sinh ra trong hư vô từ thượng cổ, từng một mình trấn áp Lục Ma, phong ấn bảy mươi hai sinh linh thiên ngoại, giao chiến với tu sĩ thiên ngoại họ Mạnh và đánh bại Ma Hạt đại nhân, để lại vô số di sản gồm Tiên Cực Kiếm, Thiên Tôn Niết, Bát Cực Đạo, ấn quyết truyền thừa cùng nhiều phong ấn khắp Tiên Cư. Dù đã tiêu tán trong hư không từ vô số vạn năm trước, dấu tích của ông vẫn ảnh hưởng sâu rộng: sợi tóc hóa kinh mạch mang tiên khí trong thân Vương Lâm, đầu lâu khổng lồ ẩn trong cấm cung chứa thế giới truyền thừa, và Trớ Thuật bố trí trước khi chết trở"},{"id":"bat-cuc-dai-thien-ton","name":"Bát Cực Đại Thiên Tôn","gioiTinh":"khong-ro","theLuc":[{"ten":"Tiên Tộc","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Đại Thiên Tôn @c1867","trangThai":"khong-ro","blurb":"Bát Cực Đại Thiên Tôn là danh hiệu được nhắc trong truyền thừa huyết mạch Tiên Tổ. Hậu nhân Tiên Tổ sau khi thức tỉnh huyết mạch có thể kế thừa danh hiệu này và đặt tên mới cho tông phái quốc sư hoàng tộc.","vaiTro":"Danh hiệu Đại Thiên Tôn","tinhCach":[{"text":"Được nhắc như danh hiệu truyền thừa","chuong":"@c1867"}],"tabs":{"diem":[{"text":"Là danh hiệu mà huyết mạch Tiên Tổ sau thức tỉnh có thể kế thừa.","chuong":"@c1867"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Tổ","tag":"khac","quanHe":"danh hiệu gắn với huyết mạch Tiên Tổ","ghiChu":"Danh hiệu được hậu nhân Tiên Tổ kế thừa sau khi huyết mạch thức tỉnh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867"]},{"id":"huyen-la","name":"Huyền La","trangThai":"song","tabs":{"diem":[{"text":"Triệu hồi Tứ Đại Linh, mở con đường chuyển thế đầu thai thông tới Tiên Cương từ La Thiên tinh vực","chuong":"@c1696"},{"text":"Nhận Vương Lâm làm đệ tử duy nhất trên con đường mình rồng, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch","chuong":"@c1699"},{"text":"Âm thầm chú ý mọi chuyện của đệ tử nhiều năm tại Cổ Tộc, chờ sẵn bình trà năm xưa để đón Vương Lâm ở đào viên","chuong":"@c1907"},{"text":"Can thiệp bảo vệ đệ tử khi Thường Thị ép Vương Lâm quỳ, giữ vững địa vị đệ tử duy nhất trước hoàng quyền Đạo Cổ","chuong":"@c1908"},{"text":"Đưa Vương Lâm qua ba nơi tạo hóa đã chuẩn bị và dẫn hắn cầu kiến Cổ Đạo Đại Thiên Tôn","chuong":"@c1909"},{"text":"Sẵn sàng mạo hiểm cứu đệ tử nếu thất bại trong thử thách trên Cổ Đạo Sơn, đau lòng quan sát từ tầng tháp cao nhất","chuong":"@c1912"}],"kinhLich":[{"chuong":"@c1899","importance":"bridge","mucCt":"gon","tieuDe":"Đích đến sư tôn","text":"Huyền La được Vương Lâm gọi là sư tôn khi Vương Lâm chuẩn bị vượt biển sang phía cổ tộc.","anchor":"Huyền La sư tôn.Đệ tử tới đây"},{"chuong":"@c1900","importance":"bridge","mucCt":"vua","tieuDe":"Được nhắc tại Cổ Tộc","text":"Huyền La được Vương Lâm nhắc là sư tôn ở cổ Tộc, khiến hành trình tới đó trở thành nơi có chỗ dựa và gắn với lời hứa bảo vệ Đạo Cổ nhất mạch cùng chuyển thế của ông.","anchor":"Dù sao thì cũng có Huyền La sư tôn nơi đó"},{"chuong":"@c1905","importance":"bridge","mucCt":"vua","text":"Huyền La được Kế Đô nhắc là sư tôn của Vương Lâm, và thân phận đệ tử duy nhất của Huyền La trở thành mấu chốt giúp Kế Đô xác nhận thân phận kép của Vương Lâm.","anchor":"Đệ tử duy nhất của Huyền La Đại Thiên Tôn của Đạo Cổ nhất mạch tên là Vương Lâm."},{"chuong":"@c1906","importance":"normal","mucCt":"vua","tieuDe":"Truyền âm ngăn vái","text":"Huyền La không trực tiếp ra mặt nhưng khí tức Đại Thiên Tôn nhu hòa ở ngọn núi phía nam được Vương Lâm cảm nhận. Khi một vái của Vương Lâm làm khói xanh sắp không chịu nổi, ông truyền âm gọi Tiểu Vương, bảo hắn đừng vái nữa và đi tới hậu sơn.","anchor":"Bên tai Vương Lâm trong nháy mắt này vang lên giọng nói rất quen thuộc."},{"chuong":"@c1907","importance":"normal","mucCt":"ky","tieuDe":"Công khai người kế thừa bảo hộ","text":"Huyền La chờ Vương Lâm ở đào viên bằng bình trà đã chuẩn bị từ năm xưa, nói ông vẫn âm thầm chú ý mọi chuyện của đệ tử tại Tiên Tộc nhưng không thể tới đón vì sợ các Đại Thiên Tôn Tiên Tộc phát hiện. Ông hứa ba ngày sau đưa Vương Lâm tới vài nơi có lợi cho tăng trưởng tu vi làm lễ bái sư đầu tiên. Trước Đạo Cổ Điện, ông giao chín thuộc hạ cho Vương Lâm nghe lệnh, rồi trước mặt Diệp Đạo công khai Vương Lâm là đệ tử mình, sẽ thay ông bảo vệ Đạo Cổ khi ông chuyển thế và có quyền chọn tân hoàng tôn.","anchor":"Từ nay về sau chín người bọn họ nghe theo hiệu lệnh của ngươi"},{"chuong":"@c1908","importance":"normal","mucCt":"ky","tieuDe":"Sư tôn như cha","text":"Huyền La can thiệp khi Thường Thị ép Vương Lâm quỳ, bảo vệ địa vị đệ tử duy nhất trước hoàng quyền Đạo Cổ. Sau khi Đạo Cổ hoàng tôn rời đi, ông cho Vương Lâm quyền rời khỏi nơi này nếu không hợp, nhưng khẳng định dù Vương Lâm lựa chọn thế nào quan hệ sư đồ vẫn không đổi. Ông tiếp tục dẫn Vương Lâm tới đầm lầy Bình Thiên Quận để nuôi lớn sát lục bản nguyên, đồng thời nói đã chuẩn bị nhiều nơi bản nguyên khác và sẽ đưa hắn gặp Cổ Đạo Đại Thiên Tôn.","anchor":"Không cần biết ngươi lựa chọn như thế nào, không cần biết ngươi ở nơi nào, Huyền La ta vẫn là sư tôn của ngươi"}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Đạo Đại Thiên Tôn","tag":"khac","quanHe":"cùng phía Cổ Tộc được đem ra so sánh","ghiChu":"Cả hai được nhắc trong so sánh về mức khó tiếp cận Tổ Thành của người Cổ Tộc."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử duy nhất","ghiChu":"Thân phận này bị Kế Đô dùng để xác nhận Vương Lâm."},{"ten":"Chín người dưới trướng Huyền La","tag":"cap-tren","quanHe":"Chủ thượng","ghiChu":"Chín cường giả Đạo Cổ dưới trướng Huyền La được ông giao cho Vương Lâm nghe lệnh."},{"ten":"Đạo Cổ Hoàng","tag":"dong-minh","quanHe":"Đại Thiên Tôn của Đạo Cổ","ghiChu":"Đạo Cổ Hoàng bái kiến Huyền La Tôn và được Huyền La công khai nói về vai trò tương lai của Vương Lâm trong Đạo Cổ."},{"ten":"Thường Thị","tag":"doi-thu","quanHe":"Ngăn Thường Thị ép đệ tử mình quỳ lạy.","ghiChu":"Đụng độ vì quy củ hoàng quyền trước Đạo Cổ Điện."},{"ten":"Đại Thiên Tôn đời thứ nhất của Đạo Cổ nhất mạch","tag":"su-mon","quanHe":"Người đời trước để lại đầm lầy Bình Thiên Quận cho Huyền La.","ghiChu":"Huyền La giữ nơi này lại để chuẩn bị cho Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1867","@c1899","@c1900","@c1905","@c1906","@c1907","@c1908"],"gioiTinh":"nam","aliases":["Huyền La Đại Thiên Tôn","Đạo Cổ Đại Thiên Tôn","Huyền La Tôn"],"canhGioiCaoNhat":"Đại Thiên Tôn Đạo Cổ (@c1908)","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"vaiTro":"Đại Thiên Tôn Cửu Dương — sư tôn duy nhất của Vương Lâm tại Cổ Tộc","tinhCach":"Uy nghiêm, uy áp kinh người nhưng nội tâm trọng nghĩa tình; kiên nhẫn chờ đợi và âm thầm che chở đệ tử nhiều năm; thận trọng trước thân phận nhạy cảm, biết tiến thoái trong quan hệ giữa các thế lực; sẵn sàng mạo hiểm vì đệ tử khi cần","blurb":"Huyền La là Đại Thiên Tôn cảnh Cửu Dương trấn giữ động phủ giới tại La Thiên tinh vực, người mở con đường chuyển thế đầu thai thông tới Tiên Cương và nhận Vương Lâm làm đệ tử duy nhất, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch. Sau nhiều năm âm thầm chờ đợi và chú ý mọi chuyện của đệ tử tại Cổ Tộc, ông đích thân dẫn Vương Lâm cầu kiến Cổ Đạo, can thiệp bảo vệ hắn trước hoàng quyền Đạo Cổ, đồng thời tế luyện pháp bảo và chuẩn bị tạo hóa cho đệ tử, thể hiện tình nghĩa sư đồ sâu nặng như phụ tử."},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","aliases":["Hứa gia gia","Tiểu Hồng"],"trangThai":"song","canhGioiCaoNhat":"không rõ trong đợt @c1868","tabs":{"diem":[{"text":"Bị Vương Lâm bắt sống, hủy ý thức gốc và luyện nguyên thần thành ma đầu.","chuong":"@c0112"},{"text":"Là ma đầu duy nhất được Vương Lâm giữ lại, trà trộn bình an trong đám hơn vạn du hồn.","chuong":"@c0280"},{"text":"Nhập tiên kiếm làm kiếm hồn, từng cản đòn bảo vệ thân thể Vương Lâm đến kiệt sức.","chuong":"@c0338"},{"text":"Phản lại Cự Ma lão tổ, bẻ kiếm chém đứt tay trái đối phương rồi quay về theo Vương Lâm.","chuong":"@c0373"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm.","chuong":"@c0596"},{"text":"Sau khi tới Tiên Cương, khôi phục ký ức trước lúc rời động phủ giới và nhận lại Vương Lâm làm chủ.","chuong":"@c1881"}],"kinhLich":[{"mucCt":"ky","text":"Hứa Lập Quốc trước hết được Lưu Kim Bưu nhắc tới như kẻ bản tính khó đổi, rất có thể xuất hiện ở nơi vui thú. Về sau Vương Lâm nhìn thấy hắn trong tầng ba một lầu các ở Đông Thành, nhận ra khí tức và tướng mạo quen thuộc, đồng thời phát hiện trên người hắn có phong ấn do người khác để lại. Lúc ấy Hứa Lập Quốc mặc hồng y, có nhiều tu sĩ bước thứ ba làm hộ vệ cung kính, vẫn ngang ngược quát mắng và tự xưng Hứa gia gia để đòi rượu ngon mấy ngàn năm.","anchor":"Khí tức và tướng mạo người này Vương Lâm vô cùng quen thuộc.","bridge":true,"khoang":"@c1868"},{"chuong":"@c1869","importance":"normal","mucCt":"gon","tieuDe":"Từng Đến Lý Phủ","text":"Hứa Lập Quốc được hồi nhắc là năm ngoái từng tới Lý Phủ, cũng đá cổng và hét đòi tiếp khách giống Lưu Kim Bưu, nhưng cú đá của hắn khi ấy không làm cánh cửa chấn động.","anchor":"Hứa Lập Quốc kia đá ra một cước không khiến cánh cửa này chấn động chút nào"},{"chuong":"@c1870","importance":"bridge","mucCt":"vua","anchor":"Lúc này đã biết Hứa Lập Quốc ở Tổ Thành, Vương Lâm cũng không nóng lòng khôi phục trí nhớ tiền kiếp trước khi chuyển thế của hắn","text":"Vương Lâm đã biết Hứa Lập Quốc ở Tổ Thành nên tạm thời không vội khôi phục ký ức tiền kiếp trước chuyển thế của hắn."},{"mucCt":"vua","text":"Hứa Lập Quốc đi cùng Đạo Phi vào hoàng cung, sợ hãi trước ánh mắt của mấy vạn tu sĩ và bị Đạo Phi đá bắt mở đường. Hắn cắn răng tiến vài bước rồi phun máu, ôm mông giả chết để né tình thế, sau đó hé mắt quan sát rồi lại nhắm mắt.","anchor":"Hứa Lập Quốc run rẩy, lúc này bị ánh mắt của cả mấy vạn tu sĩ trong sân rộng nhìn vào","bridge":true,"khoang":"@c1873"},{"chuong":"@c1874","importance":"normal","tieuDe":"Suýt tỉnh ký ức","text":"Hứa Lập Quốc đang giả chết thì bị Đạo Phi gọi dậy. Khi nhìn thấy Vương Lâm, linh hồn hắn run rẩy, theo tiềm thức gọi Sát tinh chủ và suýt thức tỉnh ký ức, nhưng bị Đạo Phi lay tỉnh rồi sợ hãi chỉ Vương Lâm là người đánh gia gia của Tiểu Hoa.","anchor":"Loại run rẩy này đến từ sâu trong linh hồn hắn","mucCt":"ky"},{"chuong":"@c1875","importance":"bridge","mucCt":"gon","tieuDe":"Được tính mang đi","text":"Hứa Lập Quốc được Vương Lâm đưa vào quyết định rời tổ thành tiên tộc để đi cổ tộc.","anchor":"Thôi, mang theo Hứa Lập Quốc rời khỏi tổ thành của tiên tộc"},{"chuong":"@c1880","importance":"normal","mucCt":"ky","tieuDe":"Ký ức tan phong","text":"Hứa Lập Quốc bị cảm giác kêu gọi kéo tới cửa đông Tổ Thành. Khi Vương Lâm nói mình phải đi và hỏi hắn ở lại hay đi theo, tầng trí nhớ bị phong ấn trong tâm thần hắn tan ra. Cảnh tượng năm xưa lập tức hiện lên trong đầu, mở lại tuyến ký ức đã bị che lấp của hắn.","anchor":"Tầng trí nhớ bị phong ấn tan ra"},{"chuong":"@c1881","importance":"major","mucCt":"ky","tieuDe":"Thức tỉnh nhận chủ","text":"Hứa Lập Quốc khôi phục ký ức trước lúc rời động phủ giới đầu thai chuyển thế, nhớ ra Vương Lâm và thân phận ma đầu từng bị luyện hóa. Hắn lập tức nhận lại Vương Lâm là chủ nhân, trở về dáng vẻ a dua nịnh nọt, tranh vị trí thân cận với Lưu Kim Bưu và phủ nhận người điên là chủ nhân của mình. Cuối chương, hắn bị Vương Lâm thu vào không gian trữ vật trước khi Vương Lâm quay lại tổ thành.","anchor":"Hắn nhớ ra Vương Lâm, nhớ ra việc đã bị đối phương luyện hóa thành ma đầu"},{"mucCt":"ky","text":"Hứa Lập Quốc đi sau Vương Lâm trong bộ dạng mặc nhiều lớp áo bông, liên tục khoe khoang những bảo y chống lạnh và châm chọc Lưu Kim Bưu đang rét run. Hắn thừa nhận chính mình từng đề nghị để hai người dựa vào tu vi đi qua Bắc Châu lạnh giá nhằm rèn luyện, nhưng bản thân lại chuẩn bị áo ấm rất kỹ. Khi Vương Lâm ra lệnh, hắn miễn cưỡng cởi vài tấm áo bông ném cho Lưu Kim Bưu rồi sau đó bị thu vào không gian trữ vật.","anchor":"Là ta nói đấy, vậy thì làm sao! Hứa Lập Quốc ta tu vi không cao như ngươi","bridge":true,"khoang":"@c1899"}],"tuViMoc":[],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"ban-be","quanHe":"Được Lưu Kim Bưu dựa vào bản tính cũ để suy đoán nơi có thể tìm thấy trong Đông Thành.","ghiChu":"Lưu Kim Bưu xin Vương Lâm cho đi tìm Hứa Lập Quốc @c1868"},{"ten":"Vương Lâm","tag":"khac","quanHe":"người muốn khôi phục ký ức tiền kiếp trước chuyển thế cho hắn","ghiChu":"Vương Lâm biết Hứa Lập Quốc ở Tổ Thành nên chưa vội hành động."},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người sai khiến và đá hắn mở đường","ghiChu":"Đạo Phi gọi hắn là Tiểu Hồng và buộc hắn thể hiện uy phong."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Được gọi đi theo","ghiChu":"Lời gọi của Vương Lâm khiến phong ấn ký ức trong Hứa Lập Quốc tan ra."},{"ten":"Lưu Kim Bưu","tag":"khac","quanHe":"người được đem ra đối chiếu","ghiChu":"Lưu Kim Bưu đá cổng và hô gọi chủ nhân Lý Phủ bằng bộ dáng giống việc hắn từng làm năm ngoái.","gap":"@c1869"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1868","@c1869","@c1870","@c1873","@c1874","@c1875","@c1880","@c1881","@c1899"],"tinhCach":"Kiêu ngạo, lải nhải và nhiều lần đòi đảo chủ tớ; thực dụng, giỏi nịnh nọt để tự bảo toàn; si mê nữ sắc, dễ mất tự chủ; nhát gan nhưng vẫn từng lập công hộ chủ","gioiTinh":"nam","vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm linh Vũ tiên kiếm","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc rồi luyện nguyên thần thành ma đầu. Từ ma đầu duy nhất được giữ lại, hắn lần lượt ẩn trong đám du hồn, nhập tiên kiếm làm kiếm hồn, được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ và trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Về sau hắn được đưa tới Tiên Cương, từng mất rồi khôi phục ký ức, tiếp tục nhận Vương Lâm làm chủ."},{"id":"ly-quang","name":"Lý Quảng","trangThai":"khong-ro","canhGioiCaoNhat":"không rõ trong đợt @c1868","tabs":{"diem":[{"text":"Dùng cây cung chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân, ghim trúng mắt trái đầu lâu Đạo Cổ Diệp Mịch rồi hóa đá tử vong","chuong":"@c1380"},{"text":"Được Thất Thải Tiên Tôn thu nạp trợ giúp trong trận chém giết Đạo Cổ Diệp Mịch","chuong":"@c1599"},{"text":"Mũi tên năm xưa bắn rơi mắt trái Đạo Cổ bị Vương Lâm thu phục làm bảo vật","chuong":"@c1482"},{"text":"Nhận truyền thừa cây cung từ lão tổ Lý gia, cung này về sau rơi vào tay Vương Lâm","chuong":"@c1870"},{"text":"Hình ảnh giương cung oai hùng được Vương Lâm hồi tưởng nhiều lần, trở thành hình mẫu bất khuất","chuong":"@c1436"}],"kinhLich":[{"chuong":"@c1868","importance":"bridge","mucCt":"gon","tieuDe":"Cung gây cảm ứng","text":"Lý Quảng được nhắc qua cây cung đang ở trong thân thể Vương Lâm, vật này có liên hệ với Lý gia và khiến Lý Phủ cảm ứng được khí tức.","anchor":"hẳn là cây cung của Lý Quảng trong thân thể ta có quan hệ với Lý gia"},{"mucCt":"gon","anchor":"Năm đó cung của lão tổ truyền thừa tới tay Lý Quảng thì mất tích không tìm thấy nữa.","text":"Lý Quảng được nhắc là người từng nhận truyền thừa cây cung của lão tổ Lý gia, cây cung nay đang ở trong tay Vương Lâm.","bridge":true,"khoang":"@c1870"},{"chuong":"@c1903","importance":"bridge","mucCt":"gon","tieuDe":"Được cân nhắc tu vi","text":"Lý Quảng được Vương Lâm nhắc khi so sánh thực lực trong Tổ Thành và khả năng đạt tới cấp Thiên Tôn.","anchor":"tu vi của Lý Quảng dựa vào những gì ta biết trong Tổ Thành"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão tổ Lý gia","tag":"ho-hang","quanHe":"người thuộc truyền thừa cung Lý gia","ghiChu":"Cung lão tổ từng truyền tới tay Lý Quảng trước khi mất tích."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người hiện giữ cây cung từng truyền tới Lý Quảng","ghiChu":"Vương Lâm hứa sau khi xong việc sẽ gửi cung về lại Lý Phủ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1868","@c1870","@c1903"],"tinhCach":"Quyết đoán, dứt khoát trong chiến đấu; thiện xạ phi phàm; oai hùng, bất khuất trước cường địch","gioiTinh":"nam","theLuc":[{"ten":"Lý Phủ","trangThai":"danh-nghia"}],"vaiTro":"Đạo sĩ áo đen bắn cung — người bắn rơi mắt trái Đạo Cổ Diệp Mịch","blurb":"Lý Quảng là đạo sĩ áo đen nổi danh với tài bắn cung, được Thất Thải Tiên Tôn thu nạp trợ giúp trong cuộc chém giết Đạo Cổ Diệp Mịch tại vùng đất cổ mộ. Ông dùng cây cung lớn mang chín đạo phong ấn bắn mũi tên chứa huyết mạch tiên nhân xuyên qua mọi trở ngại, ghim trúng mắt trái đầu lâu Diệp Mịch rồi hóa đá tử vong. Mũi tên và cây cung năm ấy về sau đều được Vương Lâm thu phục làm bảo vật, còn hình ảnh oai hùng khi giương cung củaông trở thành ký ức không phai trongâm trí Vương Lâm."},{"id":"lao-gia-trong-mat-that-ly-phu","name":"Lão già trong mật thất Lý Phủ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ trong đợt @c1868","trangThai":"song","blurb":"Lão già trấn giữ mật thất của Lý Phủ tại Đông Thành. Ông ta phát hiện giá cung của lão tổ reo vang và lập tức sai người dò tìm khí tức cây cung.","vaiTro":"Người điều động Lý gia dò cung","tinhCach":[{"text":"Cẩn trọng trước dị biến của giá cung","chuong":"@c1868"},{"text":"Ra lệnh nhanh và quyết đoán","chuong":"@c1868"}],"tabs":{"diem":[{"text":"Ngồi trong mật thất trước giá gỗ màu tím, theo dõi vật liên quan tới cung của lão tổ.","chuong":"@c1868"},{"text":"Nhận định dị biến chỉ xảy ra khi cung của lão tổ xuất hiện gần đó.","chuong":"@c1868"},{"text":"Sai Lý Vân và Lý Sơn theo mũi tên màu tím để dò khí tức cây cung.","chuong":"@c1868"}],"kinhLich":[{"chuong":"@c1868","importance":"normal","mucCt":"vua","tieuDe":"Kích hoạt dò cung","text":"Lão già trong mật thất Lý Phủ thấy giá cung của lão tổ reo vang, nhận định cung đã xuất hiện trong phạm vi gần. Ông ta dùng giá gỗ hóa ra mũi tên màu tím và ra lệnh cho Lý Vân, Lý Sơn đi dò khí tức cây cung.","anchor":"Giá cung của lão tổ reo vang.chuyện."}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Vân","tag":"su-mon","quanHe":"Sai Lý Vân theo mũi tên màu tím dò khí tức cung của lão tổ.","ghiChu":"Quan hệ cấp trên trong Lý Phủ @c1868"},{"ten":"Lý Sơn","tag":"su-mon","quanHe":"Sai Lý Sơn cùng Lý Vân dò khí tức cung của lão tổ.","ghiChu":"Quan hệ cấp trên trong Lý Phủ @c1868"}],"tuiDo":{"phapBao":[{"ten":"Giá gỗ màu tím trong mật thất Lý Phủ","trangThai":"dang-co","moTa":"Vật đặt trong mật thất, phát tiếng cung reo và hóa mũi tên màu tím khi cảm ứng cung của lão tổ.","nguon":"@c1868"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1868"]},{"id":"ly-van","name":"Lý Vân","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ trong đợt @c1868","trangThai":"khong-ro","blurb":"Tu sĩ Lý Phủ được lão già trong mật thất sai theo mũi tên màu tím dò khí tức cung của lão tổ. Chương gợi khả năng người giám sát và bỏ chạy bằng huyết ảnh là Lý Vân nhưng chưa nói thẳng.","vaiTro":"Tu sĩ Lý Phủ dò cung","tinhCach":[{"text":"Làm việc theo lệnh Lý Phủ","chuong":"@c1868"},{"text":"Liên quan trực tiếp đến cuộc dò tìm cung của lão tổ","chuong":"@c1868"}],"tabs":{"diem":[{"text":"Được gọi tên cùng Lý Sơn để theo mũi tên màu tím.","chuong":"@c1868"},{"text":"Có khả năng là người giám sát Vương Lâm, nhưng chương chưa định danh thẳng.","chuong":"@c1868"}],"kinhLich":[{"mucCt":"vua","text":"Lý Vân được lão già Lý Phủ gọi tên cùng Lý Sơn và sai theo mũi tên màu tím để dò khí tức cung của lão tổ. Trong suy nghĩ của tu sĩ huyết ảnh, Lý Sơn đã tách ra đi bắt đồng bọn của Vương Lâm, khiến khả năng kẻ giám sát Vương Lâm là Lý Vân nhưng chương chưa xác nhận trực tiếp.","anchor":"Lý Sơn tách ra với ta, ta giám sát người này còn Lý Sơn đi bắt đồng bọn của hắn.","bridge":true,"khoang":"@c1868"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già trong mật thất Lý Phủ","tag":"cap-tren","quanHe":"Nhận lệnh dò khí tức cung của lão tổ.","ghiChu":"Được gọi tên trong mật thất Lý Phủ @c1868"},{"ten":"Lý Sơn","tag":"dong-minh","quanHe":"Cùng được sai theo mũi tên màu tím dò cung.","ghiChu":"Hai người tách nhiệm vụ sau khi rời Lý Phủ @c1868"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1868"]},{"id":"ly-son","name":"Lý Sơn","trangThai":"song","canhGioiCaoNhat":"không rõ trong đợt @c1868","tabs":{"diem":[{"text":"Rao bán Phi Kiếm Tử Ngọ Kim Tiễn giả, bị vạch trần nhưng vẫn bán được hàng","chuong":"@c044"},{"text":"Ba hoa quảng cáo phích lịch đạn cho đệ tử phái Hằng Nhạc, bày trò khuyến mãi mua hai tặng một","chuong":"@c045"},{"text":"Được Lý Phủ sai cùng Lý Vân theo mũi tên màu tím truy dò khí tức lão tổ","chuong":"@c1868"}],"kinhLich":[{"chuong":"@c1868","importance":"normal","mucCt":"vua","tieuDe":"Đi bắt đồng bọn","text":"Lý Sơn được lão già Lý Phủ sai cùng Lý Vân theo mũi tên màu tím để dò khí tức cung của lão tổ. Theo suy nghĩ của tu sĩ huyết ảnh, hắn đã tách ra đi bắt đồng bọn của Vương Lâm, khiến người bỏ chạy lo Lý gia sắp chuốc đại họa.","anchor":"ta giám sát người này còn Lý Sơn đi bắt đồng bọn của hắn."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già trong mật thất Lý Phủ","tag":"cap-tren","quanHe":"Nhận lệnh dò khí tức cung của lão tổ.","ghiChu":"Được gọi tên trong mật thất Lý Phủ @c1868"},{"ten":"Lý Vân","tag":"dong-minh","quanHe":"Cùng nhận nhiệm vụ dò cung rồi tách ra hành động.","ghiChu":"Lý Sơn đi bắt đồng bọn còn người kia giám sát Vương Lâm @c1868"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1868"],"vaiTro":"Nhân vật phụ — kẻ buôn bán lừa đảo trong giới tu luyện","tinhCach":"ba hoa, láu cá; liều lĩnh bất chấp bị vạch trần; tuân lệnh bề trên","blurb":"Lý Sơn là kẻ chuyên rao bán pháp khí giả và vật phẩm kém chất lượng cho các đệ tử môn phái, bất chấp bị vạch trần vẫn tiếp tục lừa đảo. Về sau hắn được Lý Phủ sai đi truy tìm đồng bọn, cho thấy hắn thuộc quyền sai khiến của thế lực gia tộc họ Lý."},{"id":"tu-si-ly-gia-huyet-anh","name":"Tu sĩ Lý gia huyết ảnh","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Kim Tôn @c1868","trangThai":"song","blurb":"Tu sĩ Lý gia ẩn thân theo dõi và tập kích Vương Lâm trong Đông Thành. Đòn toàn lực của hắn bị Vương Lâm phá bằng một chỉ, buộc phải hóa huyết ảnh bỏ chạy.","vaiTro":"Kẻ tập kích Vương Lâm","tinhCach":[{"text":"Hành động quyết liệt khi bị phát hiện","chuong":"@c1868"},{"text":"Nhanh chóng kinh hãi khi nhận ra chênh lệch thực lực","chuong":"@c1868"}],"tabs":{"diem":[{"text":"Ẩn trong hư vô, dùng mũi tên màu tím và cung ảnh tập kích Vương Lâm.","chuong":"@c1868"},{"text":"Tu vi Kim Tôn toàn lực vẫn bị Vương Lâm tùy ý hóa giải.","chuong":"@c1868"},{"text":"Dùng thuật huyễn động hóa thành hồng ảnh bỏ chạy xa ngàn dặm.","chuong":"@c1868"}],"kinhLich":[{"chuong":"@c1868","importance":"normal","mucCt":"vua","tieuDe":"Tập kích thất bại","text":"Tu sĩ Lý gia huyết ảnh ẩn thân giám sát Vương Lâm, bị ép hiện thân rồi dùng mũi tên màu tím và một cây cung biến ảo để bắn thêm một mũi tên. Toàn lực Kim Tôn của hắn bị Vương Lâm dùng một chỉ phá sạch, khiến hắn phun máu thi triển thuật huyễn động hóa huyết ảnh bỏ chạy ngàn dặm.","anchor":"Hắn không thể nào ngờ nổi mình dựa vào tu vi Kim Tôn toàn lực"}],"tuViMoc":[{"chuong":"@c1868","canhGioi":"Kim Tôn","text":"Chương xác nhận đòn toàn lực của tu sĩ Lý gia huyết ảnh dựa vào tu vi Kim Tôn.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Theo dõi và tập kích Vương Lâm nhưng bị phá đòn, sau đó bỏ chạy.","ghiChu":"Không bị Vương Lâm truy sát vì hai bên chưa có thù oán @c1868"},{"ten":"Lý Sơn","tag":"dong-minh","quanHe":"Biết Lý Sơn đã tách ra đi bắt đồng bọn của Vương Lâm.","ghiChu":"Suy nghĩ này xuất hiện khi hắn bỏ chạy @c1868"}],"tuiDo":{"phapBao":[{"ten":"Mũi tên màu tím của Lý Phủ","trangThai":"da-dung","moTa":"Dùng trong đòn tập kích Vương Lâm nhưng bị một chỉ đánh tan.","nguon":"@c1868"},{"ten":"Cây cung biến ảo của tu sĩ Lý gia","trangThai":"da-dung","moTa":"Biến ảo ra để bắn thêm một mũi tên về phía Vương Lâm, cũng bị phá bằng một chỉ.","nguon":"@c1868"}],"danDuoc":[],"congPhap":[{"ten":"Thuật huyễn động","trangThai":"da-dung","moTa":"Thi triển để hóa thành hồng ảnh bỏ chạy xa ngàn dặm.","nguon":"@c1868"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1868"]},{"id":"nam-tu-trung-nien-truy-kich-cua-ly-phu","name":"Nam tử trung niên truy kích của Lý Phủ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Người của Lý Phủ mặc áo đen, cầm cung truy sát Lưu Kim Bưu và Hải Long trong Đông Thành. Hắn bị ánh mắt Vương Lâm chấn động hôn mê, sau đó bị lục thần thức và ném vào Lý Phủ.","vaiTro":"Kẻ truy sát của Lý Phủ","tinhCach":[{"text":"Ra tay quyết liệt khi truy sát mục tiêu","chuong":"@c1869"},{"text":"Muốn lập công bằng cách giết Hải Long và trọng thương Lưu Kim Bưu","chuong":"@c1869"}],"tabs":{"diem":[{"text":"Cầm cung bắn mũi tên thứ hai trong lúc truy sát Lưu Kim Bưu và Hải Long.","chuong":"@c1869"},{"text":"Bị ánh mắt Vương Lâm làm tâm thần chấn động, hộc máu hôn mê.","chuong":"@c1869"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm đánh ngất bằng ánh mắt, lục thần thức và ném vào Lý Phủ.","ghiChu":"Gặp trong vụ truy sát ở Đông Thành."},{"ten":"Lưu Kim Bưu","tag":"doi-thu","quanHe":"Truy sát Lưu Kim Bưu để lập công.","ghiChu":"Bắn tên khi Lưu Kim Bưu đang ở trên lưng Hải Long."},{"ten":"Hải Long","tag":"doi-thu","quanHe":"Bắn trọng thương Hải Long trong lúc truy sát.","ghiChu":"Mũi tên đen làm Hải Long tràn ngập hắc khí."}],"tuiDo":{"phapBao":[{"ten":"Cung của nam tử trung niên Lý Phủ","loai":"vũ khí","trangThai":"dang-co","moTa":"Cây cung dùng để bắn mũi tên ngưng tụ tiên khí trong lúc truy sát Lưu Kim Bưu và Hải Long.","nguon":"@c1869"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1869"]},{"id":"thanh-nien-mac-hong-y-tung-o-ly-phu","name":"Thanh niên mặc hồng y từng ở Lý Phủ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lý Phủ","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Thanh niên mặc hồng y từng liên quan tới sự việc năm trước ở Lý Phủ. Chương này chỉ nhắc rằng nếu hắn biết Lưu Kim Bưu lặp lại hành động đá cửa thì sẽ chấn động.","vaiTro":"Người từng ở Lý Phủ","tinhCach":[{"text":"Từng chứng kiến hoặc liên quan biến cố đá cửa Lý Phủ năm trước","chuong":"@c1869"},{"text":"Được dùng để đối chiếu với hành động của Lưu Kim Bưu","chuong":"@c1869"}],"tabs":{"diem":[{"text":"Được nhắc trong liên hệ giữa cú đá cửa của Lưu Kim Bưu và sự kiện năm trước tại Lý Phủ.","chuong":"@c1869"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1869"]},{"id":"may-tram-nguoi-ly-phu","name":"Mấy trăm người Lý Phủ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lực lượng đông đảo trong Lý Phủ, có cả nam lẫn nữ, đồng loạt cầm cung phát động tiễn trận. Họ kinh hãi khi mưa tên bị Vương Lâm phất tay phá tan.","vaiTro":"Cung thủ tiễn trận Lý Phủ","tinhCach":[{"text":"Hành động theo trận thế hợp lực của Lý Phủ","chuong":"@c1869"},{"text":"Hoảng sợ trước sức mạnh áp đảo của Vương Lâm","chuong":"@c1869"}],"tabs":{"diem":[{"text":"Đồng loạt bắn mấy trăm mũi tên, tạo thành mưa tên và đồ án trận pháp công kích Vương Lâm.","chuong":"@c1869"},{"text":"Không thể tin nổi khi tiễn trận bị chưởng ấn của Vương Lâm đánh sụp.","chuong":"@c1869"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cùng phát động tiễn trận công kích Vương Lâm khi hắn xông vào Lý Phủ.","ghiChu":"Tiễn trận bị chưởng ấn của Vương Lâm phá tan."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tiễn trận Lý Phủ","loai":"trận pháp","trangThai":"dang-co","moTa":"Trận pháp hợp lực bằng cung tiễn do nhiều người Lý Phủ phát động.","nguon":"@c1869"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1869"]},{"id":"lao-to-ly-gia","name":"Lão tổ Lý gia","cn":"","aliases":["lão già tóc bạc kim bào"],"gioiTinh":"nam","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Dược Thiên Tôn","trangThai":"song","blurb":"Lão tổ đứng đầu Lý Phủ tại Tổ Thành, ẩn trong thạch thất và nắm truyền thừa cung tiễn của gia tộc. Ông nhận ra Vương Lâm là Bạch Phát Dược Thiên Tôn, hạ mình nhận lỗi và mở Tiễn Các để bù đắp.","vaiTro":"Lão tổ Lý Phủ, người thương lượng với Vương Lâm sau xung đột vì cung lão tổ.","tinhCach":[{"text":"Biết tiến thoái trước cường giả vượt trội, nhanh chóng hạ thấp tư thái để giữ thể diện và an nguy cho Lý Phủ.","chuong":"@c1870"},{"text":"Rất coi trọng cây cung tổ tiên truyền lại, nhưng vẫn chấp nhận lời hứa trả sau của Vương Lâm.","chuong":"@c1870"}],"tabs":{"diem":[{"text":"Nhận ra danh hiệu Bạch Phát Dược Thiên Tôn và lập tức chuyển từ đối đầu sang hòa giải.","chuong":"@c1870"},{"text":"Dùng Tiễn Các và việc hộ vệ tới hoàng thành để bù lỗi với Vương Lâm.","chuong":"@c1870"}],"kinhLich":[{"mucCt":"ky","anchor":"Một giọng nói già nua một hồi sau từ bên trong thạch thất khổ sở truyền ra.","text":"Sau khi Vương Lâm dùng kim quang phá thế cung tiễn của Lý Phủ, lão tổ Lý gia từ thạch thất bước ra và gọi đúng danh hiệu Bạch Phát Dược Thiên Tôn. Ông giải thích giá cung tổ tiên phát ra tiếng cung reo nên từng phái hai Kim Tôn đi tìm, thừa nhận Lý Phủ hành động lỗ mãng. Để bù lỗi, ông mời Vương Lâm lưu lại Lý Phủ, cho người hộ vệ tới hoàng thành và cho phép tùy ý xem Tiễn Đạo trong Tiễn Các, đồng thời chấp nhận lời hứa sau này Vương Lâm sẽ gửi trả cung Lý Quảng.","bridge":true,"khoang":"@c1870"}],"tuViMoc":[{"chuong":"@c1870","canhGioi":"Dược Thiên Tôn","text":"Lão tổ Lý gia được đặt trong tầng lớp cường giả Dược Thiên Tôn của Lý Phủ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"cường giả được ông nhận lỗi và mời vào Tiễn Các","ghiChu":"Ông nhận ra Vương Lâm là Bạch Phát Dược Thiên Tôn, không ép trả cung ngay mà nhận lời hứa gửi trả sau."},{"ten":"Lý Quảng","tag":"ho-hang","quanHe":"người từng nhận truyền thừa cung lão tổ","ghiChu":"Cây cung truyền tới Lý Quảng rồi mất tích, nay xuất hiện trong tay Vương Lâm."},{"ten":"Dược Thiên Tôn Lý Phủ tóc nửa trắng nửa đen","tag":"dong-minh","quanHe":"cao thủ cùng Lý Phủ","ghiChu":"Cùng thuộc lực lượng cao tầng Lý Phủ trong cuộc đối đầu với Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tiễn Đạo Lý gia","loai":"tiễn đạo","trangThai":"dang-co","moTa":"Truyền thừa do lão tổ Lý gia lưu lại trong Tiễn Các, được ông cho Vương Lâm tùy ý xem xét để bù lỗi.","nguon":"@c1870"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1870"]},{"id":"duoc-thien-ton-ly-phu-toc-nua-trang-nua-den","name":"Dược Thiên Tôn Lý Phủ tóc nửa trắng nửa đen","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Dược Thiên Tôn tầng mười","trangThai":"song","blurb":"Một cao thủ Dược Thiên Tôn của Lý Phủ, ẩn trong thế trận cung tiễn khi Vương Lâm tới phủ. Ông bị Vương Lâm chỉ ra và bị kim quang trấn áp làm dây cung hóa tro bụi.","vaiTro":"Cao thủ ẩn giấu của Lý Phủ trong cuộc đối đầu với Vương Lâm.","tinhCach":[{"text":"Thận trọng trước thân phận của Vương Lâm, vừa khiếp sợ vừa do dự khi nhìn ra manh mối.","chuong":"@c1870"}],"tabs":{"diem":[{"text":"Là Dược Thiên Tôn tầng mười, một trong ba cao thủ mạnh nhất bị Vương Lâm trực tiếp điểm danh.","chuong":"@c1870"},{"text":"Dây cung trong tay bị uy áp kim quang của Vương Lâm làm đứt thành tro bụi.","chuong":"@c1870"}],"kinhLich":[{"chuong":"@c1870","importance":"normal","mucCt":"vua","tieuDe":"Bị điểm danh trấn áp","anchor":"Người này tóc nửa trắng nửa đen, nhìn chằm chằm vào Vương Lâm, ánh mắt lộ ra vẻ khiếp sợ và do dự.","text":"Dược Thiên Tôn tóc nửa trắng nửa đen ẩn trong Lý Phủ bị Vương Lâm chỉ ra là cao thủ tầng mười. Khi kim quang Tiên Cực Kiếm trấn áp toàn trường, dây cung trong tay ông bị đứt thành tro bụi và ông nhìn Vương Lâm với vẻ khiếp sợ, do dự về thân phận thật của đối phương."},{"chuong":"@c1871","importance":"bridge","mucCt":"gon","tieuDe":"Báo cáo chuyện sắc phong","text":"Lão già Dược Thiên Tôn của Lý gia đã báo cáo cho Vương Lâm toàn bộ các chuyện liên quan tới lễ sắc phong, giúp hắn biết cửu môn vốn là nghi thức tượng trưng.","anchor":"những chuyện liên quan tới sắc phong hắn đã được lão già Dược Thiên Tôn của Lý gia báo cáo toàn bộ"}],"tuViMoc":[{"chuong":"@c1870","canhGioi":"Dược Thiên Tôn tầng mười","text":"Vương Lâm chỉ rõ người này là Dược Thiên Tôn tầng mười trong ba cao thủ ẩn giấu của Lý Phủ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ áp đảo trong xung đột tại Lý Phủ","ghiChu":"Bị Vương Lâm chỉ ra nơi ẩn giấu và trấn áp dây cung."},{"ten":"Lão tổ Lý gia","tag":"dong-minh","quanHe":"cùng thuộc cao tầng Lý Phủ","ghiChu":"Đều nằm trong lực lượng cường giả của Lý Phủ khi đối diện Vương Lâm."},{"ten":"Hai Thiên Tôn tầng bảy của Lý Phủ","tag":"dong-minh","quanHe":"hai cao thủ cùng bị Vương Lâm điểm danh","ghiChu":"Ba người nếu đồng loạt ra tay có thể đạt tới tầng mười đỉnh phong theo nhận định của Vương Lâm."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người báo cáo nghi thức sắc phong","ghiChu":"Đã nói trước cho Vương Lâm các chuyện liên quan tới lễ sắc phong."}],"tuiDo":{"phapBao":[{"ten":"Cung của cao thủ Lý Phủ","loai":"cung","trangThai":"hong","moTa":"Dây cung trong tay bị kim quang trấn áp của Vương Lâm làm đứt thành tro bụi.","nguon":"@c1870"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1870","@c1871"]},{"id":"hai-thien-ton-tang-bay-cua-ly-phu","name":"Hai Thiên Tôn tầng bảy của Lý Phủ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Tôn tầng bảy","trangThai":"song","blurb":"Hai cao thủ Thiên Tôn tầng bảy ẩn giấu trong Lý Phủ cùng Dược Thiên Tôn tóc nửa trắng nửa đen. Họ bị Vương Lâm điểm danh và bị kim quang trấn áp bẻ gãy cung trong tay.","vaiTro":"Cao thủ ẩn giấu của Lý Phủ trong thế trận chống Vương Lâm.","tinhCach":[],"tabs":{"diem":[{"text":"Cùng Dược Thiên Tôn tầng mười tạo thành nhóm ba cao thủ bị Vương Lâm trực tiếp cảnh cáo.","chuong":"@c1870"},{"text":"Cung trong tay xuất hiện vô số vết nứt rồi bị bẻ gãy dưới kim quang trấn áp.","chuong":"@c1870"}],"kinhLich":[{"chuong":"@c1870","importance":"normal","mucCt":"vua","tieuDe":"Cung gãy dưới uy áp","anchor":"Còn có ba người các ngươi, một người là Dược Thiên Tôn tầng mười, hai người Thiên Tôn tầng thứ bảy","text":"Hai Thiên Tôn tầng bảy của Lý Phủ bị Vương Lâm chỉ ra trong nhóm ba cao thủ ẩn giấu và bị cảnh cáo không được tiếp tục bắn tên. Dưới kim quang trấn áp, cung trong tay họ nứt vỡ rồi bị bẻ gãy."}],"tuViMoc":[{"chuong":"@c1870","canhGioi":"Thiên Tôn tầng bảy","text":"Vương Lâm xác định hai người là Thiên Tôn tầng bảy của Lý Phủ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ áp đảo trong xung đột tại Lý Phủ","ghiChu":"Bị Vương Lâm điểm danh và trấn áp cung trong tay."},{"ten":"Dược Thiên Tôn Lý Phủ tóc nửa trắng nửa đen","tag":"dong-minh","quanHe":"cao thủ cùng ẩn giấu","ghiChu":"Cùng bị Vương Lâm cảnh cáo trong thế trận cung tiễn."}],"tuiDo":{"phapBao":[{"ten":"Cung của cao thủ Lý Phủ","loai":"cung","trangThai":"hong","moTa":"Cung trong tay hai Thiên Tôn tầng bảy bị kim quang trấn áp làm nứt và gãy.","nguon":"@c1870"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1870"]},{"id":"chin-tu-si-thien-ton-cua-ly-phu","name":"Chín tu sĩ Thiên Tôn của Lý Phủ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Tôn","trangThai":"song","blurb":"Nhóm chín Thiên Tôn của Lý Phủ cùng bắn tên, hợp lực tạo uy lực đáng kể để chặn Vương Lâm. Họ bị Vương Lâm áp chế khiến cung trong tay vỡ thành nhiều mảnh.","vaiTro":"Lực lượng Thiên Tôn tham gia thế trận cung tiễn của Lý Phủ.","tinhCach":[],"tabs":{"diem":[{"text":"Chín mũi tên hợp thành bàn tay có uy lực được so sánh với một kích toàn lực của Thiên Tôn vượt tầng bảy Thiên Tôn Niết.","chuong":"@c1870"},{"text":"Sau khi bị Vương Lâm trấn áp, họ mơ hồ đoán ra thân phận Bạch Phát Dược Thiên Tôn.","chuong":"@c1870"}],"kinhLich":[{"chuong":"@c1870","importance":"normal","mucCt":"vua","tieuDe":"Chín cung vỡ nát","anchor":"Thậm chí cung trong tay chín tu sĩ Thiên Tôn cũng run rẩy, vỡ ra thành nhiều mảnh","text":"Chín tu sĩ Thiên Tôn của Lý Phủ hợp lực bắn chín mũi tên để áp chế Vương Lâm. Khi kim quang trấn áp lan ra, cung trong tay họ run rẩy rồi vỡ thành nhiều mảnh, khiến họ mơ hồ đoán ra thân phận của Vương Lâm."}],"tuViMoc":[{"chuong":"@c1870","canhGioi":"Thiên Tôn","text":"Nhóm chín tu sĩ được nêu là Thiên Tôn của Lý Phủ.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ áp đảo trong xung đột tại Lý Phủ","ghiChu":"Họ hợp lực bắn tên nhưng bị Vương Lâm trấn áp phá cung."},{"ten":"Tộc nhân Lý Phủ","tag":"dong-minh","quanHe":"cùng phe Lý Phủ","ghiChu":"Cùng tham gia thế đối đầu ban đầu vì cung lão tổ."}],"tuiDo":{"phapBao":[{"ten":"Cung của chín tu sĩ Thiên Tôn","loai":"cung","trangThai":"hong","moTa":"Cung trong tay chín Thiên Tôn run rẩy rồi vỡ thành nhiều mảnh dưới kim quang của Vương Lâm.","nguon":"@c1870"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1870"]},{"id":"toc-nhan-ly-phu","name":"Tộc nhân Lý Phủ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Lý Phủ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Đông đảo người của Lý Phủ đối đầu Vương Lâm vì tiếng cung reo của cung lão tổ. Sau khi Vương Lâm lộ thân phận Bạch Phát Dược Thiên Tôn, họ kinh hãi trước danh tiếng đã truyền khắp Tiên Tộc.","vaiTro":"Lực lượng tộc nhân Lý Phủ tham gia vây ép Vương Lâm.","tinhCach":[{"text":"Hành động cực đoan khi liên quan tới cung lão tổ, vì cây cung có ý nghĩa đặc biệt với Lý gia.","chuong":"@c1870"}],"tabs":{"diem":[{"text":"Cung trong tay tộc nhân bị kim quang của Vương Lâm làm tan nát thành vô số mảnh nhỏ.","chuong":"@c1870"},{"text":"Nhận ra danh tiếng Vương Lâm sau khi hắn bỏ mũ để lộ mái tóc bạc.","chuong":"@c1870"}],"kinhLich":[{"mucCt":"vua","anchor":"Nhất là Lý Phủ, là một trong tứ đại vương phủ của Tổ Thành, toàn tộc bọn họ hầu như ai cũng đã nghe đồn, nhớ kỹ cái tên Vương Lâm!","text":"Tộc nhân Lý Phủ đối đầu Vương Lâm vì tiếng cung reo liên quan tới cung lão tổ. Dưới kim quang trấn áp, cung trong tay họ tan nát, rồi khi Vương Lâm lộ tóc bạc, toàn phủ kinh hãi vì nhận ra danh tiếng Bạch Phát Dược Thiên Tôn.","bridge":true,"khoang":"@c1870"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ khiến toàn phủ bị trấn áp","ghiChu":"Ban đầu cùng phe Lý Phủ đối đầu Vương Lâm, sau đó bị uy áp phá cung và kinh hãi trước thân phận của hắn."},{"ten":"Chín tu sĩ Thiên Tôn của Lý Phủ","tag":"dong-minh","quanHe":"cùng phe Lý Phủ","ghiChu":"Cùng bị kim quang của Vương Lâm trấn áp trong xung đột tại phủ."}],"tuiDo":{"phapBao":[{"ten":"Cung của tộc nhân Lý Phủ","loai":"cung","trangThai":"hong","moTa":"Cung trong tay tộc nhân Lý Phủ bị kim quang trấn áp của Vương Lâm làm tan nát thành vô số mảnh nhỏ.","nguon":"@c1870"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1870"]},{"id":"su-gia-thanh-bao-truyen-chi-cua-tien-hoang","name":"Sứ giả thanh bào truyền chỉ của Tiên Hoàng","cn":"","aliases":["sứ giả thanh bào"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng cung Tiên Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Sứ giả của Tiên Hoàng, mặc thanh bào và cầm vải trắng đến Lý Phủ truyền chỉ sắc phong cho Vương Lâm. Hắn bất mãn khi Vương Lâm không ra tiếp chỉ nhưng không dám biểu lộ.","vaiTro":"Người truyền thánh chỉ yêu cầu Vương Lâm dự đại lễ sắc phong tại Tiên Đạo Điện.","tinhCach":[{"text":"Có dáng vẻ cao ngạo khi đến truyền chỉ, nhưng biết kiềm chế trước uy danh của Vương Lâm.","chuong":"@c1870"}],"tabs":{"diem":[{"text":"Xuất hiện trên bầu trời Lý Phủ sau ba ngày, cầm tấm vải trắng truyền ý chỉ của Tiên Hoàng.","chuong":"@c1870"},{"text":"Dù bất mãn vì Vương Lâm chỉ bảo đọc chỉ, hắn không dám lộ ra thái độ phản kháng.","chuong":"@c1870"}],"kinhLich":[{"chuong":"@c1870","importance":"normal","mucCt":"vua","tieuDe":"Truyền chỉ sắc phong","anchor":"Người này mặc thanh bào, thần sắc hơi cao ngạo, trong tay cầm một tấm vải trắng","text":"Ba ngày sau, sứ giả thanh bào của Tiên Hoàng xuất hiện trên bầu trời Lý Phủ, cầm tấm vải trắng và gọi Vương Lâm ra tiếp chỉ. Khi Vương Lâm không ra mà chỉ lạnh lùng bảo đọc, hắn bất mãn nhưng không dám lộ ra, đọc ý chỉ yêu cầu Vương Lâm bảy ngày sau tới Tiên Đạo Điện rồi để lại thánh chỉ rời đi."}],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Hoàng","tag":"cap-tren","quanHe":"quân chủ sai hắn truyền chỉ","ghiChu":"Hắn thay Tiên Hoàng truyền ý chỉ sắc phong Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"người nhận thánh chỉ","ghiChu":"Gọi Vương Lâm ra tiếp chỉ nhưng phải đọc chỉ theo yêu cầu của Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Thánh chỉ sắc phong của Tiên Hoàng","loai":"chiếu chỉ","trangThai":"da-dung","moTa":"Tấm vải trắng dùng để truyền ý chỉ yêu cầu Vương Lâm tới Tiên Đạo Điện dự đại lễ sắc phong.","nguon":"@c1870"}]}},"nguon":["@c1870"]},{"id":"lien-dao-chan","name":"Liên Đạo Chân","cn":"","aliases":["Tiên Hoàng","Đạo Chân"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Liên Đạo Chân là Tiên Hoàng đời này, người đặt tên Đạo Môn cho tông phái thần bí truyền thừa từ xa xưa của quốc sư hoàng tộc. Hắn chết trong biến cố hoàng cung nhưng tin tức bị Cửu Đế áp chế, bên ngoài chỉ biết Tiên Hoàng mất tích. Sau đó linh hồn suy yếu của hắn bị Vương Lâm nắm giữ, vẫn còn uy áp cấp Đại Thiên Tôn, và từng được Vương Lâm dùng làm thước đo nhận xét Đạo Cổ Hoàng không sánh được về tu vi.","vaiTro":"Tiên Hoàng đương triều — người đặt tên Đạo Môn, biến số tại đại lễ Tiên Đạo Điện","tinhCach":"uy quyền, uy áp vượt trội; quả quyết, can thiệp trực tiếp vào triều cục","tabs":{"diem":[{"text":"Là Tiên Hoàng đương triều, đặt tên Đạo Môn cho tông phái thần bí truyền thừa của quốc sư hoàng tộc","chuong":"@c1867"},{"text":"Từ trong Tiên Đạo Điện quát Đạo Phi, khẳng định La Công khiêu chiến ân công của hắn thất bại","chuong":"@c1874"},{"text":"Chết trong biến cố hoàng cung, tin tức bị Cửu Đế áp chế, bên ngoài chỉ biết Tiên Hoàng mất tích","chuong":"@c1898"},{"text":"Được Vương Lâm dùng làm thước đo, nhận xét Đạo Cổ Hoàng không sánh được Tiên Hoàng về tu vi","chuong":"@c1907"},{"text":"Xuất hiện dưới dạng linh hồn suy yếu bị Vương Lâm nắm giữ, vẫn có uy áp Đại Thiên Tôn","chuong":"@c1915"}],"kinhLich":[{"chuong":"@c1867","importance":"normal","tieuDe":"Đặt tên Đạo Môn","mucCt":"vua","text":"Là Tiên Hoàng đời này, đặt tên Đạo Môn cho tông phái thần bí truyền thừa từ xa xưa của quốc sư hoàng tộc trong Tổ Thành. Tông phái này theo từng đời Tiên Hoàng lại đổi tên một lần.","anchor":"Tiên Hoàng đời này - Liên Đạo Chân đặt cho tông phái thần bí này một cái tên là Đạo Môn"},{"mucCt":"vua","anchor":"Đại lễ sắc phong này không biết Liên Đạo Chân sẽ làm thế nào.","text":"Sau khi nhận chỉ sắc phong, Vương Lâm nghĩ tới Liên Đạo Chân và không rõ người này sẽ làm gì trong đại lễ sắp tới. Điều đó khiến Liên Đạo Chân trở thành một biến số liên quan tới Tiên Đạo Điện.","bridge":true,"khoang":"@c1870"},{"text":"Tiên Hoàng từ trong Tiên Đạo Điện quát Đạo Phi, nói La Công khiêu chiến ân công của hắn thất bại chứ không liên quan quốc sư. Sau đó ông bước ra, vung tay đẩy Đạo Phi lui và lệnh hắc giáp cấm binh tống hắn khỏi hoàng cung.","anchor":"Tiên Hoàng cau mày, quát khẽ một tiếng","mucCt":"vua","bridge":true,"khoang":"@c1874"},{"chuong":"@c1898","importance":"normal","mucCt":"gon","tieuDe":"Cái chết bị che giấu","text":"Cái chết của Liên Đạo Chân trong biến cố hoàng cung bị Cửu Đế áp chế tin tức, bên ngoài chỉ biết Tiên Hoàng lại bế quan.","anchor":"Tin tức hoàng cung trong tổ thành bị hủy diệt, Tiên Hoàng mất mạng được Cửu Đế áp chế không cho lan ra"},{"chuong":"@c1907","importance":"bridge","mucCt":"gon","tieuDe":"Được so với Đạo Cổ Hoàng","text":"Liên Đạo Chân được Vương Lâm dùng làm thước đo khi nhận xét Đạo Cổ Hoàng không sánh được Tiên Hoàng về tu vi và khí chất.","anchor":"Người này dù tu vi hay khí chất đều không thể so sánh với Tiên Hoàng"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người đang suy đoán hành động của Liên Đạo Chân","ghiChu":"Vương Lâm nghĩ tới Liên Đạo Chân sau khi nghe tin về đại lễ sắc phong."},{"ten":"Thượng Đạo Huyền","tag":"cap-tren","quanHe":"quân chủ và quốc sư","ghiChu":"Thượng Đạo Huyền là quốc sư trọng thần bên cạnh Tiên Hoàng Liên Đạo Chân."},{"ten":"Tiên Tổ","tag":"ho-hang","quanHe":"hậu nhân huyết mạch","ghiChu":"Liên Đạo Chân thuộc dòng hậu nhân Tiên Tổ được nhắc trong cơ chế kế thừa danh hiệu Bát Cực Đại Thiên Tôn."},{"ten":"Đạo Cổ Hoàng","tag":"khac","quanHe":"Được đem ra so sánh","ghiChu":"Vương Lâm so sánh Đạo Cổ Hoàng với Tiên Hoàng và đánh giá Đạo Cổ Hoàng kém hơn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1870","@c1874","@c1867","@c1898","@c1907"]},{"id":"nguoi-dien","name":"Liên Đạo Phi","cn":"","aliases":["Đạo Phi"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Liên Đạo Phi là tu sĩ mang huyết mạch Tiên Cương, vốn là kẻ ngỗ ngược trên Tiên Cương đại lục từ thời viễn cổ, bị nhốt trong Thất Thải Giới bên trong U Minh Thú không rõ bao nhiêu năm, cô độc đến phát điên. Hắn cứu Vương Lâm bằng máu và tiên lực của mình, truyền Dịch Linh Ấn cùng ba thần thông, rồi quỳ bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt. Sau khi rời Thất Thải Giới, hắn nhiều lần bị cuốn vào biến cố quanh Vương Lâm, từng lao vào Thất Thải Thương cứu sư phụ, được ca ca cứu chữa trong hoàng cung, về sau hôn mê bị chín sợi xích xuyên thân trong địa cung và hoá thành núi dư","vaiTro":"Tu sĩ tiên tộc viễn cổ mang huyết mạch Tiên Cương — đệ tử của Vương Lâm","tinhCach":"Cô độc đến điên loạn, thường tự xưng bổn vương và nói lảm nhảm; Trọng nghĩa, nhiều lần dùng máu và thân mình cứu Vương Lâm; Tự phụ giữ thể diện nhưng dễ hoảng sợ trước nguy hiểm; Nặng tình với ca ca và ba nương","tabs":{"diem":[{"text":"Lộ diện trong Thất Thải Giới, cho Vương Lâm uống máu mình để cứu mạng, nhiều lần phun máu dùng ấn ký trên tay phải hồi phục thân thể Vương Lâm","chuong":"@c1441"},{"text":"Truyền thụ Dịch Linh Ấn hoàn chỉnh cùng ba thần thông cho Vương Lâm, quỳ dập đầu bái Vương Lâm làm sư phụ và hé lộ bí mật Tiên Chi Cửu Tuyệt","chuong":"@c1450"},{"text":"Chân tướng viễn cổ được Vương Lâm xác nhận: vốn là kẻ ngỗ ngược trên Tiên Cương đại lục, thân phận và lai lịch liên quan tới tiên tộc thời thượng cổ","chuong":"@c1628"},{"text":"Lao vào Thất Thải Thương cứu Vương Lâm, thân phát kim quang nồng đậm, cả hai bị hắc động nuốt vào hư vô","chuong":"@c1493"},{"text":"Được ca ca mặc hoàng bào kéo ra từ vòng xoáy và dùng tiên lực cứu chữa trong hoàng cung khi đang hôn mê","chuong":"@c1713"},{"text":"Hôn mê trong địa cung, toàn thân bị chín sợi xích xuyên qua, về sau hoá thành núi trong không gian xếp chồng dưới hoàng cung Tổ Thành","chuong":"@c1883"}],"kinhLich":[{"chuong":"@c1870","importance":"normal","mucCt":"vua","tieuDe":"Có thể gặp ở đại lễ","anchor":"ở đó hẳn có thể gặp được người điên.","text":"Vương Lâm đoán rằng trong đại lễ sắc phong tại Tiên Đạo Điện hẳn có thể gặp được người điên, nối tung tích của người này với hoàng cung và nghi lễ sắp tới."},{"chuong":"@c1883","importance":"normal","mucCt":"vua","tieuDe":"Bị xích trong địa cung","text":"Liên Đạo Phi hôn mê trong địa cung, mặc trường sam có hoa văn và toàn thân bị chín sợi xích xuyên qua. Hắn bị treo lơ lửng phía trên tế đàn trong bố trí liên quan Phản tổ đại pháp.","anchor":"Người này chính là người điên."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người dự đoán có thể gặp hắn tại đại lễ","ghiChu":"Vương Lâm nghĩ tới khả năng gặp người điên ở Tiên Đạo Điện."},{"ten":"Tiên Hoàng","tag":"khac","quanHe":"Ký ức bị nắm giữ","ghiChu":"Quốc sư nói Tiên Hoàng dựa vào việc nắm giữ ký ức của Liên Đạo Phi để đưa Vương Lâm tới địa cung."},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"bằng hữu có ân","ghiChu":"Từng có ân với Vương Lâm và từng cùng hắn Mộng Đạo tại Chu Tước Tinh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1870","@c1883","@c1867"]},{"id":"lao-gia-mac-thanh-y","name":"Lão già mặc thanh y","cn":"","aliases":["nô tài bất kính trong hoàng cung"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng cung Tiên Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1872","trangThai":"song","blurb":"Lão già mặc thanh y đi ra từ Tiên Đạo Điện để chủ trì bước mở đầu của lễ sắc phong Vương Lâm. Lão tuyên bố đóng cửu môn, giải thích quy chế đại lễ, cuối cùng bị khí thế của Vương Lâm ép lui.","vaiTro":"Người tuyên bố quy chế sắc phong","tinhCach":[{"text":"Giữ lễ nghi hoàng cung và nói theo quy chế sắc phong","chuong":"@c1871"},{"text":"Dễ hoảng sợ trước khí thế áp đảo của Vương Lâm","chuong":"@c1871"}],"tabs":{"diem":[{"text":"Từ Tiên Đạo Điện đi ra tuyên bố giờ lành và đóng cửu môn.","chuong":"@c1871"},{"text":"Gọi tên Bạch Phát Dược Thiên Tôn Vương Lâm và nói điều kiện bắt đầu đại lễ sắc phong.","chuong":"@c1871"},{"text":"Bị ánh mắt của Vương Lâm làm hoảng sợ lui lại trước Tiên Đạo Điện.","chuong":"@c1871"}],"kinhLich":[{"chuong":"@c1871","importance":"normal","mucCt":"vua","tieuDe":"Chủ trì cửu môn","text":"Lão già mặc thanh y từ Tiên Đạo Điện đi ra, tuyên bố giờ lành đã tới và đóng cửu môn để mở thông đạo khảo nghiệm. Sau đó lão gọi tên Vương Lâm, giải thích rằng hắn phải đi qua cửu môn tới trước mặt lão thì đại lễ sắc phong mới chính thức bắt đầu, nhưng cuối chương lại bị ánh mắt và khí thế của Vương Lâm ép lui.","anchor":"Người nói là lão già mặc thanh y đi ra từ Tiên Đạo Điện kia"},{"chuong":"@c1872","importance":"normal","mucCt":"vua","tieuDe":"Bị ném khỏi điện","text":"Lão già mặc thanh y lui lại nhưng vẫn chỉ vào Vương Lâm quát mắng trước đại lễ. Vương Lâm lập tức tiến tới túm hắn ném ra ngoài mấy vạn trượng, còn Tiên Hoàng gọi việc của hắn là bất kính với đệ nhất Dược Thiên Tôn.","anchor":"Lão già mặc thanh y này vừa mở lời thì Vương Lâm đã tiến tới gần, tay phải vung lên, túm lấy hắn ném ra ngoài."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người bị khảo nghiệm trong lễ sắc phong","ghiChu":"Lão công bố quy chế cửu môn cho Vương Lâm nhưng bị Vương Lâm ép lui."},{"ten":"Tiên Hoàng","tag":"cap-tren","quanHe":"Chủ thể sắc phong mà lão đại diện tuyên bố nghi thức","ghiChu":"Lão nói Tiên Hoàng sẽ tự mình sắc phong sau khi Vương Lâm qua cửu môn."},{"ten":"Quốc sư đại nhân","tag":"khac","quanHe":"Người sẽ tham dự nghi thức sau cửu môn","ghiChu":"Lão nói quốc sư sẽ tính toán biến hóa tương lai cho Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1871","@c1872"]},{"id":"thien-su-thu-bi-thuong","name":"Thiên Sư Thú bị thương","gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"sinh linh thiên ngoại @c1872","trangThai":"tu-vong","blurb":"Thiên Sư Thú bị thương là sinh linh thiên ngoại bị nghi thức huyết tế tiên kéo tới trong đại lễ sắc phong. Nó mang vết thương ở cổ, máu vàng chảy xuống, rồi bị Tiên Hoàng dùng lửa năm màu thiêu chết.","vaiTro":"Sinh linh bị hiến tế","tinhCach":[{"text":"Hoảng sợ bỏ chạy khỏi hư vô khi bị dòng xoáy huyết tế kéo tới.","chuong":"@c1872"},{"text":"Mang dấu hiệu liên quan ấn ký Tiên Tổ khiến tu sĩ toàn trường chú ý.","chuong":"@c1872"}],"tabs":{"diem":[{"text":"Xuất hiện từ dòng xoáy hư vô trong nghi thức huyết tế tiên.","chuong":"@c1872"},{"text":"Ở cổ có vết thương máu thịt mơ hồ và máu vàng chảy xuống.","chuong":"@c1872"},{"text":"Bị Tiên Hoàng dùng lửa năm màu thiêu diệt, sau đó chỉ còn sợi tóc bạc rơi xuống.","chuong":"@c1872"}],"kinhLich":[{"chuong":"@c1872","importance":"normal","mucCt":"vua","tieuDe":"Bị huyết tế diệt","text":"Thiên Sư Thú bị thương đang hoảng sợ bỏ chạy trong hư vô thì bị dòng xoáy huyết tế kéo tới đại lễ sắc phong. Nó bị tu sĩ nhận ra có liên hệ với ấn ký Tiên Tổ và Thiên Sư Châu, nhưng nhanh chóng bị Tiên Hoàng dùng lửa năm màu thiêu chết, để lại sợi tóc bạc kỳ dị sau biển lửa.","anchor":"Chỉ thấy con Thiên Sư Thú bị thương này trong nháy mắt chạy ra khỏi dòng xoáy"}],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"Bị Tiên Hoàng giết trong đại lễ sắc phong.","ghiChu":"Tiên Hoàng dùng lửa năm màu thiêu diệt Thiên Sư Thú."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cái chết của Thiên Sư Thú để lại sợi tóc bạc bị Vương Lâm đoạt lấy.","ghiChu":"Sợi tóc bạc xuất hiện sau khi Thiên Sư Thú bị thiêu chết."},{"ten":"Tiên Tổ","tag":"khac","quanHe":"Được nhận ra là sinh linh có ấn ký Tiên Tổ lưu lại.","ghiChu":"Tu sĩ trong đại lễ kinh hô về ấn ký Tiên Tổ trên Thiên Sư Thú."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1872"]},{"id":"la-cong","name":"La Công","aliases":["La lão đầu","lão già hồng bào","gia gia của Tiểu Hoa","lão già La gia"],"gioiTinh":"nam","theLuc":[{"ten":"Tứ đại vương phủ của Tổ Thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Dược Thiên Tôn @c1873","trangThai":"song","blurb":"La Công là lão tổ một vương phủ ngoài Lý Phủ, thuộc nhóm Dược Thiên Tôn quan sát đại lễ sắc phong. Ông chủ động khiêu chiến Vương Lâm nhưng bị đánh bại sau khi hiến tế thọ nguyên và sinh cơ.","vaiTro":"Lão tổ vương phủ khiêu chiến Vương Lâm","tinhCach":[{"text":"Quyết liệt khi ra tay, sẵn sàng trả giá bằng thọ nguyên và sinh cơ.","chuong":"@c1873"},{"text":"Giữ vai trò đại diện một thế lực vương phủ trong đại lễ sắc phong.","chuong":"@c1873"}],"tabs":{"diem":[{"text":"Là Dược Thiên Tôn thuộc một vương phủ ngoài Lý Phủ.","chuong":"@c1873"},{"text":"Dùng hắc khí ngưng ảnh và hiến tế thọ nguyên, sinh cơ để tăng uy lực.","chuong":"@c1873"}],"kinhLich":[{"mucCt":"vua","text":"La Công chủ động khiêu chiến Vương Lâm trong đại lễ sắc phong, ngưng hắc khí thành bóng đen giáp trụ rồi phun máu kích phát. Sau khi hiến tế thọ nguyên và sinh cơ để tái ngưng bóng đen cùng chiến mã, ông vẫn bị Thiên Ngưu Chàng của Vương Lâm phá tan và già yếu lui về gia tộc.","anchor":"Cái vỗ này hắn hiến tế thọ nguyên và sinh cơ, khiến hắc khí nồng đậm hơn từ trong cơ thể khuếch tán ra.","bridge":true,"khoang":"@c1873"},{"chuong":"@c1874","importance":"bridge","tieuDe":"Bị nhắc thất bại","text":"La Công được Tiên Hoàng nhắc là đã khiêu chiến ân công của Đạo Phi và thất bại, khiến Đạo Phi hiểu lẫn thành chuyện gia gia của Tiểu Hoa bị đánh.","anchor":"La Công khiêu chiến ân công ngươi thất bại","mucCt":"gon"}],"tuViMoc":[{"chuong":"@c1873","canhGioi":"Dược Thiên Tôn","text":"Xuất hiện trong nhóm lão tổ vương phủ với thân phận Dược Thiên Tôn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ khiêu chiến","ghiChu":"Chủ động khiêu chiến Vương Lâm và bị đánh bại."},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người được Đạo Phi bênh vực nhầm","ghiChu":"Đạo Phi thấy ông già yếu sau trận đấu nên tưởng ông bị quốc sư bắt nạt."},{"ten":"Tiểu Hoa","tag":"ho-hang","quanHe":"Được Đạo Phi gọi là gia gia của Tiểu Hoa","ghiChu":"Quan hệ chỉ được nhắc qua lời Đạo Phi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Hắc khí ngưng ảnh hiến tế","trangThai":"dang-co","moTa":"Thần thông ngưng hắc khí thành bóng đen giáp trụ, có thể tăng uy lực bằng máu tươi, thọ nguyên và sinh cơ.","nguon":"@c1873"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1873","@c1874"]},{"id":"thieu-nien-thanh-y-di-cung-dao-phi","name":"Thiếu niên thanh y đi cùng Đạo Phi","aliases":[],"gioiTinh":"nam","trangThai":"song","blurb":"Thiếu niên thanh y đi cùng Đạo Phi khi hắn xông vào hoàng cung Tiên Tộc. Cậu liên tục sợ hãi can ngăn vì biết nơi này là hoàng cung.","vaiTro":"Người đi cùng Đạo Phi","tinhCach":[{"text":"Nhút nhát và hoảng sợ trước uy nghi hoàng cung.","chuong":"@c1873"},{"text":"Vẫn liều mạng ôm chân Đạo Phi để ngăn hắn gây họa.","chuong":"@c1873"}],"tabs":{"diem":[{"text":"Đi cạnh Đạo Phi khi nhóm này xuất hiện ngoài cửu môn hoàng cung.","chuong":"@c1873"},{"text":"Ôm chặt chân Đạo Phi để ngăn hắn lao vào Thượng Huyền Đạo quốc sư.","chuong":"@c1873"}],"kinhLich":[{"mucCt":"vua","text":"Thiếu niên thanh y đi cùng Đạo Phi vào hoàng cung trong trạng thái sợ hãi và liên tục cầu khẩn vì nơi này là hoàng cung. Khi Đạo Phi định lao tới Thượng Huyền Đạo quốc sư, cậu ôm chặt chân hắn để cản lại, dù bị kéo lê vẫn không buông.","anchor":"Thiếu niên kia bị dọa cho tới mặt tái mét, mặc kệ thanh niên mặc hoa sam giãy thế nào nhưng cũng không buông chân hắn ra.","bridge":true,"khoang":"@c1873"},{"text":"Thiếu niên áo xanh hầu bên cạnh Đạo Phi và được yêu cầu phân tích sự việc. Hắn dùng chuyện lò đan dược cùng món quà dành cho Hải Tử Thiên Tôn để khuyên Đạo Phi rời đi, rồi cùng Hứa Lập Quốc đuổi theo khi Đạo Phi bị cuốn lui.","anchor":"Thiếu niên áo xanh kia vẻ mặt đau khổ","mucCt":"vua","bridge":true,"khoang":"@c1874"}],"tuViMoc":[],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"dong-hanh","quanHe":"Người đi cùng và can ngăn","ghiChu":"Cậu ôm chân Đạo Phi để ngăn hắn gây chuyện với quốc sư."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1873","@c1874"]},{"id":"tieu-thanh","name":"Tiểu Thanh","gioiTinh":"khong-ro","trangThai":"khong-ro","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1873","importance":"bridge","mucCt":"gon","tieuDe":"Bị gọi mở đường","text":"Tiểu Thanh được Đạo Phi gọi trong nhóm phải mở đường khi hắn xông vào hoàng cung.","anchor":"Tiểu Hồng, Tiểu Thanh, Tiểu Bạch, Tiểu Lam, các ngươi mở đường cho bổn vương!"}],"tuViMoc":[],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người bị Đạo Phi gọi mở đường","ghiChu":"Chỉ được nhắc trong mệnh lệnh của Đạo Phi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1873"]},{"id":"tieu-bach","name":"Tiểu Bạch","gioiTinh":"khong-ro","trangThai":"khong-ro","tabs":{"diem":[{"text":"Bị Thiết Nham bắt, cúi đầu chấp nhận làm thú cưỡi cho Chu Như mười tuổi","chuong":"@c0334"},{"text":"Có linh trí và độc thoại nội tâm, tự xưng hổ gia, hưởng nhiều hổ cái ở Chu Tước Sơn","chuong":"@c0567"},{"text":"Nằm lười sau lưng Chu Như trên đỉnh Chu Tước Sơn, không rời nửa bước","chuong":"@c0663"},{"text":"Theo Chu Như bay tới chỗ Vương Lâm trong Côn Hư cảnh, vẫn kinh sợ hắn từ năm xưa","chuong":"@c1052"},{"text":"Được Đạo Phi gọi mở đường khi xông vào hoàng cung","chuong":"@c1873"}],"kinhLich":[{"chuong":"@c1873","importance":"bridge","mucCt":"gon","tieuDe":"Bị gọi mở đường","text":"Tiểu Bạch được Đạo Phi gọi trong nhóm phải mở đường khi hắn xông vào hoàng cung.","anchor":"Tiểu Hồng, Tiểu Thanh, Tiểu Bạch, Tiểu Lam, các ngươi mở đường cho bổn vương!"}],"tuViMoc":[],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người bị Đạo Phi gọi mở đường","ghiChu":"Chỉ được nhắc trong mệnh lệnh của Đạo Phi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1873"],"vaiTro":"Thú cưỡi của Chu Như — lão hổ hắc văn đạo hạnh trăm năm","tinhCach":"kiêu ngạo, tự tôn (tự xưng hổ gia, chỉ chấp nhận cúi/ngẩng đầu); lười nhác; trung thành bất đắc dĩ","blurb":"Tiểu Bạch là lão hổ hắc văn tu vi Trúc Cơ kỳ, đạo hạnh hơn trăm năm, bị Thiết Nham bắt về làm thú cưỡi cho Chu Như từ thuở nàng mười tuổi. Dù bản tính kiêu ngạo và tự xưng hổ gia, nó vẫn theo sát Chu Như suốt hành trình, kể cả khi đối diện Vương Lâm — kẻ khiến nó kinh sợ từ năm xưa. Hiện đang cùng Chu Như trong Tiên Ngọc Bảo Tháp."},{"id":"tieu-lam","name":"Tiểu Lam","gioiTinh":"khong-ro","trangThai":"khong-ro","blurb":"Tiểu Lam được Đạo Phi gọi tên trong nhóm phải mở đường khi hắn xông vào hoàng cung. Chương này chưa tách rõ thân phận hay hành động riêng của Tiểu Lam.","vaiTro":"Người được Đạo Phi gọi mở đường","tinhCach":[{"text":"Chưa rõ tính cách qua chương này.","chuong":"@c1873"}],"tabs":{"diem":[{"text":"Được Đạo Phi gọi cùng Tiểu Hồng, Tiểu Thanh và Tiểu Bạch để mở đường.","chuong":"@c1873"}],"kinhLich":[{"chuong":"@c1873","importance":"bridge","mucCt":"gon","tieuDe":"Bị gọi mở đường","text":"Tiểu Lam được Đạo Phi gọi trong nhóm phải mở đường khi hắn xông vào hoàng cung.","anchor":"Tiểu Hồng, Tiểu Thanh, Tiểu Bạch, Tiểu Lam, các ngươi mở đường cho bổn vương!"}],"tuViMoc":[],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người bị Đạo Phi gọi mở đường","ghiChu":"Chỉ được nhắc trong mệnh lệnh của Đạo Phi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1873"]},{"id":"tieu-hoa","name":"Tiểu Hoa","gioiTinh":"khong-ro","trangThai":"song","blurb":"Tiểu Hoa được Đạo Phi nhắc tới khi ông gọi La Công là gia gia của Tiểu Hoa. Chương này chưa cho Tiểu Hoa xuất hiện trực tiếp.","vaiTro":"Người được Đạo Phi nhắc tới","tinhCach":[{"text":"Chưa rõ tính cách qua chương này.","chuong":"@c1873"}],"tabs":{"diem":[{"text":"Được Đạo Phi dùng làm lý do khi tưởng La Công bị bắt nạt.","chuong":"@c1873"}],"kinhLich":[{"chuong":"@c1873","importance":"bridge","mucCt":"gon","tieuDe":"Được Đạo Phi nhắc","text":"Tiểu Hoa được Đạo Phi nhắc khi hắn gọi La Công là gia gia của Tiểu Hoa.","anchor":"Ai dám bắt nạt gia gia của Tiểu Hoa nhà ta."},{"chuong":"@c1881","importance":"bridge","mucCt":"gon","tieuDe":"Bị Đạo Phi nhắc tới","text":"Tiểu Hoa được Đạo Phi nhắc tới trong lời buộc tội Vương Lâm đã đả thương gia gia của nàng và cướp Tiểu Hồng.","anchor":"Chính là ngươi, ngươi đã đả thương gia gia của Tiều Hoa Hoa"}],"tuViMoc":[],"nhanMach":[{"ten":"La Công","tag":"ho-hang","quanHe":"Được gọi là cháu của La Công","ghiChu":"Quan hệ chỉ xuất hiện qua lời Đạo Phi."},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người nhắc tới Tiểu Hoa","ghiChu":"Đạo Phi nhắc Tiểu Hoa khi tưởng La Công bị bắt nạt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1873","@c1881"],"aliases":["Tiểu Hoa Hoa"]},{"id":"nu-tu-o-ben-canh-dao-phi","name":"Nữ tử ở bên cạnh Đạo Phi","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nữ tử từng ở bên cạnh Đạo Phi khi hắn được tìm thấy. Đến chương này, Tiên Hoàng cho biết nàng đã tỉnh lại và đang cảm ngộ tại nơi bế quan của tiên tổ.","vaiTro":"Đầu mối bên cạnh Đạo Phi","tinhCach":[{"text":"Thân phận chưa rõ, liên hệ trực tiếp tới giai đoạn Đạo Phi trở về.","chuong":"@c1875"},{"text":"Đang ở nơi bế quan của tiên tổ sau khi tỉnh lại.","chuong":"@c1875"}],"tabs":{"diem":[{"text":"Từng xuất hiện bên cạnh Đạo Phi khi hắn được tìm thấy.","chuong":"@c1875"},{"text":"Hiện đã tỉnh lại và ở nơi bế quan của tiên tổ cảm ngộ.","chuong":"@c1875"}],"kinhLich":[{"mucCt":"vua","text":"Nữ tử ở bên cạnh Đạo Phi được Tiên Hoàng nhắc là đã tỉnh lại và hiện đang cảm ngộ tại nơi bế quan của tiên tổ. Sự tồn tại của nàng trở thành đầu mối chưa rõ về quãng thời gian Đạo Phi trở về.","anchor":"ở bên cạnh hắn còn có một nữ tử, nàng đó hiện giờ cũng đã tỉnh lại","bridge":true,"khoang":"@c1875"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Phi","tag":"khac","quanHe":"Từng ở bên cạnh Đạo Phi khi hắn được tìm thấy.","ghiChu":"Hiện nàng đã tỉnh lại và đang ở nơi bế quan của tiên tổ."},{"ten":"Tiên Hoàng","tag":"khac","quanHe":"Được Tiên Hoàng nhắc đến khi nói với Vương Lâm về Đạo Phi.","ghiChu":"Tiên Hoàng cho biết nàng đang cảm ngộ tại nơi bế quan của tiên tổ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1875"]},{"id":"ba-lao-gia-thien-ton-phuc-kich-phia-sau-vuong-lam","name":"Ba lão già Thiên Tôn phục kích phía sau Vương Lâm","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Thiên Tôn @c1876","trangThai":"tu-vong","blurb":"Ba lão già Thiên Tôn xa lạ phục kích phía sau Vương Lâm trong sát cục phố dài. Họ ra tay đúng lúc Vương Lâm bị giam cầm nhưng bị thân thể cường hãn của hắn phản sát.","vaiTro":"Phục binh Thiên Tôn","tinhCach":[{"text":"Ra tay theo bố cục phục kích","chuong":"@c1876"},{"text":"Liều lĩnh áp sát trong khoảnh khắc phong ấn","chuong":"@c1876"}],"tabs":{"diem":[{"text":"Hiện ra trong gió tuyết phía sau Vương Lâm khi sát cục phát động.","chuong":"@c1876"},{"text":"Dùng chưởng trái đánh lén nhưng bị phản chấn và giết chết.","chuong":"@c1876"}],"kinhLich":[{"mucCt":"vua","text":"Ba lão già Thiên Tôn hiện ra sau lưng Vương Lâm, nhân lúc hắn bị phong ấn mà dùng chưởng trái đánh lén. Họ bị Vương Lâm lùi mạnh va vào phản chấn lộ mặt, hai người bị bóp nát đầu và hút nguyên thần, người còn lại cũng bị va chạm tới chết.","anchor":"Đây là ba lão già trông cực kỳ xa lạ đối với Vương Lâm","bridge":true,"khoang":"@c1876"}],"tuViMoc":[{"chuong":"@c1876","canhGioi":"Thiên Tôn","text":"Ba người được xác định thuộc tu vi Thiên Tôn khi tham gia vòng vây sát Vương Lâm.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Phục kích và bị giết","ghiChu":"Đánh lén Vương Lâm trong sát cục phố dài rồi bị phản sát."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1876"]},{"id":"muoi-hai-thien-ton-con-lai-trong-vong-vay-dau","name":"Mười hai Thiên Tôn còn lại trong vòng vây đầu","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Thiên Tôn @c1876","trangThai":"song","blurb":"Mười hai Thiên Tôn tiếp tục vây sát Vương Lâm sau khi ba đồng bọn phía sau bị giết. Họ phối hợp huyết độn, điểm chỉ phong ấn và ngân kiếm để đẩy Vương Lâm vào thương thế nặng.","vaiTro":"Phục binh vây sát","tinhCach":[{"text":"Tấn công quyết liệt không dừng lại","chuong":"@c1876"},{"text":"Phối hợp nhiều hướng để tăng sức phong ấn","chuong":"@c1876"}],"tabs":{"diem":[{"text":"Ba người phía trước dùng huyết độn áp sát Vương Lâm.","chuong":"@c1876"},{"text":"Sáu người hai bên điểm chỉ khiến phong ấn trong cơ thể Vương Lâm tăng mạnh.","chuong":"@c1876"},{"text":"Ba người phía trên dùng ngân kiếm, một kiếm đâm vào thiên linh Vương Lâm.","chuong":"@c1876"}],"kinhLich":[{"mucCt":"vua","text":"Sau khi ba đồng bọn chết, mười hai Thiên Tôn còn lại vẫn lao tới Vương Lâm không dừng. Ba người phía trước dùng huyết độn tăng tốc, sáu người hai bên điểm chỉ thúc phong ấn trong cơ thể hắn tăng vọt, còn ba người phía trên dùng ngân kiếm khiến một kiếm đâm vào thiên linh Vương Lâm ba tấc.","anchor":"Mười hai người còn lại không dừng lại chút nào mà lao thẳng tới Vương Lâm","bridge":true,"khoang":"@c1876"}],"tuViMoc":[{"chuong":"@c1876","canhGioi":"Thiên Tôn","text":"Nhóm này thuộc mười lăm người đều có tu vi Thiên Tôn trong vòng vây đầu.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Vây sát","ghiChu":"Phối hợp nhiều hướng để công kích Vương Lâm trên phố dài."}],"tuiDo":{"phapBao":[{"ten":"Ba ngân kiếm của Thiên Tôn phía trên","trangThai":"dang-co","moTa":"Ba ngân kiếm dùng từ phía trên để đâm xuống thiên linh Vương Lâm.","nguon":"@c1876"}],"danDuoc":[],"congPhap":[{"ten":"Huyết độn thuật của ba Thiên Tôn phía trước","trangThai":"da-dung","moTa":"Ba Thiên Tôn phía trước phun máu thi triển để tăng tốc áp sát.","nguon":"@c1876"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1876"]},{"id":"ba-hu-anh-den-duoi-dat","name":"Ba hư ảnh đen dưới đất","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ @c1876","trangThai":"khong-ro","blurb":"Ba hư ảnh đen lao ra từ nền đất dưới chân Vương Lâm trong lớp phục kích tiếp theo. Chúng giống nguyên thần và nhằm nhập vào thân thể hắn.","vaiTro":"Hư ảnh phục kích","tinhCach":[{"text":"Ẩn dưới đất để đánh vào thân thể Vương Lâm","chuong":"@c1876"},{"text":"Hành động theo sát cục nhiều lớp","chuong":"@c1876"}],"tabs":{"diem":[{"text":"Toàn thân đen kịt như hòa vào gió tuyết.","chuong":"@c1876"},{"text":"Tự điểm lên thân thể rồi lao thẳng vào thân thể Vương Lâm như nguyên thần.","chuong":"@c1876"}],"kinhLich":[{"chuong":"@c1876","importance":"bridge","mucCt":"gon","tieuDe":"Lao ra từ đất","text":"Ba hư ảnh đen từ dưới đất lao ra và nhằm nhập vào thân thể Vương Lâm như nguyên thần.","anchor":"Ba đạo hư ảnh này thân thể đen kịt"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Phục kích","ghiChu":"Lao vào thân thể Vương Lâm trong lớp sát cục tiếp theo."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1876"]},{"id":"chin-than-anh-tao-bang-long-phia-truoc-pho","name":"Chín thân ảnh tạo băng long phía trước phố","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ @c1876","trangThai":"song","blurb":"Chín thân ảnh phục kích phía trước phố dài, hợp lực tạo băng long công kích Vương Lâm. Khi Thiên Ngưu hiển hóa phá băng long, họ phun máu, tái mặt và bị cuốn bay.","vaiTro":"Nhóm hợp kích băng long","tinhCach":[{"text":"Phối hợp theo phương thức đặc biệt","chuong":"@c1876"},{"text":"Hoảng sợ khi băng long bị phá","chuong":"@c1876"}],"tabs":{"diem":[{"text":"Cùng bắt quyết và dung hợp để tạo băng long phía trên bầu trời.","chuong":"@c1876"},{"text":"Bị phản chấn khi Thiên Ngưu phá nát băng long.","chuong":"@c1876"}],"kinhLich":[{"mucCt":"vua","text":"Chín thân ảnh hiện ra phía trước phố dài, cùng bắt quyết theo phương thức đặc biệt để tạo băng long dữ tợn đánh vào Vương Lâm. Khi Vương Lâm hiển hóa Thiên Ngưu húc nát băng long, chín người hoảng sợ phun máu, tái mặt và bị cuốn bay.","anchor":"Chín người đồng thời giơ tay bắt quyết","bridge":true,"khoang":"@c1876"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Hợp kích","ghiChu":"Dùng băng long hợp kích công kích Vương Lâm rồi bị phá."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Băng long hợp kích","trangThai":"da-dung","moTa":"Chín người hợp lực tạo băng long công kích Vương Lâm.","nguon":"@c1876"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1876"]},{"id":"chin-nguoi-vay-hai-tu-thien-ton","name":"Chín người vây Hải Tử Thiên Tôn","cn":"","aliases":["Chín người vây Hài Tử Thiên Tôn"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Nhóm sát thủ bị cưỡng ép nâng tu vi","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1876","trangThai":"tu-vong","blurb":"Chín người vây quanh Hải Tử Thiên Tôn ở phía sau sát cục phố dài. Họ không lộ sát khí, chỉ ngăn nàng thoát ra cứu viện Vương Lâm.","vaiTro":"Nhóm vây giữ Hải Tử","tinhCach":[{"text":"Chỉ vây giữ mà không ra sát thủ","chuong":"@c1876"},{"text":"Phối hợp để tách Hải Tử Thiên Tôn khỏi Vương Lâm","chuong":"@c1876"}],"tabs":{"diem":[{"text":"Vây quanh Hải Tử Thiên Tôn nhưng không có sát khí.","chuong":"@c1876"},{"text":"Mục đích là ngăn nàng đi ra trợ giúp Vương Lâm.","chuong":"@c1876"},{"text":"Đang bao vây Hải Tử Thiên Tôn trước khi Vương Lâm lao tới.","chuong":"@c1877"},{"text":"Bị sương đen nuốt sạch, chỉ còn chín bộ hài cốt héo rũ.","chuong":"@c1877"}],"kinhLich":[{"chuong":"@c1876","importance":"bridge","mucCt":"gon","tieuDe":"Vây giữ Hải Tử","text":"Chín người không có sát khí chỉ vây Hải Tử Thiên Tôn để ngăn nàng thoát ra cứu viện Vương Lâm.","anchor":"chín người này không có sát khí, chỉ vây không cho nàng đi ra"},{"mucCt":"vua","text":"Chín người đang bao vây Hải Tử Thiên Tôn bỏ chạy khi thấy Vương Lâm hóa sương đen tàn sát. Họ bị sương mù đuổi kịp và nuốt sạch, để lại chín bộ hài cốt héo rũ.","anchor":"chín người kia sau khi nhìn thấy cảnh tượng kinh khủng vừa rồi lúc này liền bỏ qua bao vây Hải Tử Thiên Tôn","bridge":true,"khoang":"@c1877"}],"tuViMoc":[],"nhanMach":[{"ten":"Hải Tử Thiên Tôn","tag":"doi-thu","quanHe":"Vây giữ","ghiChu":"Chỉ vây không giết, khiến nàng không thể cứu viện Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Gián tiếp chia cắt","ghiChu":"Ngăn Hải Tử Thiên Tôn trợ giúp Vương Lâm trong sát cục."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1876","@c1877"]},{"id":"muoi-hai-than-anh-vay-cong-vuong-lam","name":"Mười hai thân ảnh vây công Vương Lâm","gioiTinh":"khong-ro","theLuc":[{"ten":"Nhóm sát thủ bị cưỡng ép nâng tu vi","trangThai":"gan-bo"}],"trangThai":"tu-vong","blurb":"Nhóm tu sĩ thuộc lớp vây công đầu tiên quanh Vương Lâm trong phố tuyết. Họ có sức mạnh cấp Thiên Tôn giả tạo nhưng bị Thiên Ngưu phá tan đội hình.","vaiTro":"địch nhân vây công đầu","tinhCach":[{"text":"liều chết vây sát theo bố trí sát cục","chuong":"@c1877"},{"text":"tu vi bị cưỡng ép nâng lên trong thời hạn ngắn","chuong":"@c1877"}],"tabs":{"diem":[{"text":"Trực tiếp bao vây quanh thân Vương Lâm khi Thiên Ngưu hiện ra.","chuong":"@c1877"},{"text":"Sáu người bị phản chấn nát tay, ba người cùng kiếm bị đánh bật, ba hắc ảnh nghi đoạt xá bị nuốt.","chuong":"@c1877"}],"kinhLich":[{"chuong":"@c1877","importance":"normal","mucCt":"vua","tieuDe":"Bị Thiên Ngưu phá vây","text":"Mười hai thân ảnh trực tiếp công kích quanh thân Vương Lâm lúc Thiên Ngưu hiện ra. Sáu người bị phản chấn nát tay, ba người cùng thanh kiếm bị đánh bật, còn ba hắc ảnh nghi định đoạt xá bị Thiên Ngưu hút nuốt.","anchor":"mười hai thân ảnh xung quanh Vương Lâm bị tấn công trực tiếp"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"vây sát","ghiChu":"Là lớp địch đầu tiên bị Thiên Ngưu phá tan."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1877"]},{"id":"chin-nguoi-hoa-bang-long","name":"Chín người hóa băng long","gioiTinh":"khong-ro","theLuc":[{"ten":"Nhóm sát thủ bị cưỡng ép nâng tu vi","trangThai":"gan-bo"}],"trangThai":"tu-vong","blurb":"Nhóm địch hóa thành băng long trong đợt vây sát ở phố tuyết. Họ bị Thiên Ngưu lao xuyên trong lúc vòng vây đầu tiên tan vỡ.","vaiTro":"địch nhân hóa băng long","tinhCach":[{"text":"tham gia vây sát theo đội hình đã bố trí","chuong":"@c1877"},{"text":"tu vi thuộc nhóm bị cưỡng ép nâng lên cấp Thiên Tôn","chuong":"@c1877"}],"tabs":{"diem":[{"text":"Hóa thành băng long cuốn về phía sau chiến trường.","chuong":"@c1877"},{"text":"Bị Thiên Ngưu truy đuổi và lao xuyên khi kim ngưu bạo phát.","chuong":"@c1877"}],"kinhLich":[{"chuong":"@c1877","importance":"normal","mucCt":"vua","tieuDe":"Bị kim ngưu xuyên phá","text":"Chín người hóa băng long bị Thiên Ngưu truy đuổi sau khi vòng vây đầu tiên tan vỡ. Họ kêu thảm khi kim ngưu lao tới và nằm trong nhóm hơn ba mươi kẻ bị cưỡng ép nâng lên cấp Thiên Tôn.","anchor":"đuổi theo chín người hóa thành băng long đang cuốn về phía sau kia"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"vây sát","ghiChu":"Bị Thiên Ngưu do Vương Lâm gọi ra đánh tan."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1877"]},{"id":"ba-than-anh-ao-trang-gan-duoc-thien-ton","name":"Ba thân ảnh áo trắng gần Dược Thiên Tôn","gioiTinh":"khong-ro","theLuc":[{"ten":"Nhóm sát thủ bị cưỡng ép nâng tu vi","trangThai":"gan-bo"}],"trangThai":"tu-vong","blurb":"Ba kẻ áo trắng xuất hiện trong đợt sát kích thứ hai ở phố tuyết. Họ có lực lượng gần Dược Thiên Tôn và chỉ dùng gió tuyết bạo cùng tự bạo để ép Vương Lâm.","vaiTro":"địch nhân đợt sát kích thứ hai","tinhCach":[{"text":"ra tay theo lối hi sinh để tiêu hao Vương Lâm","chuong":"@c1877"},{"text":"thần thông đơn giản nhưng uy lực lớn nhờ tu vi bị nâng cao","chuong":"@c1877"}],"tabs":{"diem":[{"text":"Xuất hiện trong gió tuyết với lực lượng gần Dược Thiên Tôn.","chuong":"@c1877"},{"text":"Chỉ thi triển cuồng phong gió tuyết và tự bạo thân thể.","chuong":"@c1877"}],"kinhLich":[{"chuong":"@c1877","importance":"normal","mucCt":"vua","tieuDe":"Tự bạo ép Vương Lâm","text":"Ba thân ảnh áo trắng xuất hiện trong gió tuyết với lực lượng gần tới Dược Thiên Tôn. Khi giao chiến với Vương Lâm, họ chỉ dùng hai thức là cuồng phong gió tuyết và tự bạo, buộc Vương Lâm phải dùng Dịch Linh Ấn đối kháng.","anchor":"Ba người mặc áo trắng ở phía trước cũng không thi triển nhiều thần thông, chỉ có hai thức"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"tập kích","ghiChu":"Dùng gió tuyết bạo và tự bạo để công kích Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1877"]},{"id":"hai-hon-khai-su-gia-ao-den","name":"Hai Hồn khải sứ giả áo đen","gioiTinh":"khong-ro","theLuc":[{"ten":"Nhóm sát thủ bị cưỡng ép nâng tu vi","trangThai":"gan-bo"}],"trangThai":"tu-vong","blurb":"Hai hắc y nhân xuất hiện sau ba áo trắng, có tu vi Dược Thiên Tôn và hắc phong hóa hắc xà. Vương Lâm nhận ra họ là Hồn khải sứ giả xa lạ được nâng tu vi và được ban hồn phong.","vaiTro":"Hồn khải sứ giả trong sát cục","tinhCach":[{"text":"ẩn thân trong lớp sát kích thứ hai của phố tuyết","chuong":"@c1877"},{"text":"được ban sức mạnh bất thường để đạt cấp Dược Thiên Tôn","chuong":"@c1877"}],"tabs":{"diem":[{"text":"Có tu vi Dược Thiên Tôn nhưng không thuộc nhóm Dược Thiên Tôn có hồn khải mà Vương Lâm từng biết.","chuong":"@c1877"},{"text":"Triển khai hắc phong hóa thành hai con rắn lớn màu đen.","chuong":"@c1877"}],"kinhLich":[{"mucCt":"vua","text":"Hai Hồn khải sứ giả áo đen xuất hiện sau ba áo trắng, có tu vi Dược Thiên Tôn và hắc phong hóa thành hai rắn đen. Vương Lâm nhận ra họ là Hồn khải sứ giả xa lạ, suy đoán họ được nâng tu vi bằng thủ đoạn đặc biệt và được ban hồn phong, rồi giết một kẻ bằng va chạm nổ tung và chẻ đôi kẻ còn lại bằng đường đao đỏ trên mi tâm.","anchor":"Hai người này không ngờ có được tu vi của Dược Thiên Tôn","bridge":true,"khoang":"@c1877"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"giao chiến","ghiChu":"Bị Vương Lâm giết trong đợt sát kích thứ hai."}],"tuiDo":{"phapBao":[{"ten":"Hồn khải","loai":"giáp","trangThai":"dang-co","moTa":"Dấu hiệu khiến Vương Lâm nhận ra họ là Hồn khải sứ giả xa lạ.","nguon":"@c1877"},{"ten":"Hồn phong","loai":"ấn ban sức mạnh","trangThai":"dang-co","moTa":"Theo suy đoán của Vương Lâm, họ được ban hồn phong cùng với việc bị nâng tu vi.","nguon":"@c1877"}],"danDuoc":[],"congPhap":[{"ten":"Hắc phong hóa hắc xà","loai":"thần thông","trangThai":"da-dung","moTa":"Giơ tay khiến hắc phong trong gió tuyết hóa thành hai con rắn đen lớn.","nguon":"@c1877"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1877"]},{"id":"chu-nhan-ngon-tay-bi-an","name":"Chủ nhân ngón tay bí ẩn","gioiTinh":"khong-ro","trangThai":"song","blurb":"Kẻ chưa lộ mặt đứng sau ngón tay tập kích Vương Lâm ở phố tuyết. Vương Lâm xác định người này là kẻ bố trí đồ án giam cầm chiến lực quanh chiến trường.","vaiTro":"kẻ bố trí sát cục bí ẩn","tinhCach":[{"text":"ra tay ẩn mật, chờ thời điểm Vương Lâm bị thương mới tập kích","chuong":"@c1877"},{"text":"có khả năng bố trí đồ án giam cầm chiến lực quanh chiến trường","chuong":"@c1877"}],"tabs":{"diem":[{"text":"Chưa lộ thân phận, chỉ lộ qua một bàn tay điểm vào gáy Vương Lâm.","chuong":"@c1877"},{"text":"Được Vương Lâm nhận định là chủ nhân của đồ án giam cầm bốn phía.","chuong":"@c1877"}],"kinhLich":[{"chuong":"@c1877","importance":"normal","mucCt":"ky","tieuDe":"Ngón tay tập kích sau lưng","text":"Chủ nhân ngón tay bí ẩn chưa lộ mặt nhưng được Vương Lâm xác định là người bố trí đồ án giam cầm chiến lực quanh chiến trường. Sau khi Vương Lâm vừa giết đợt địch thứ hai và chống cốt âm đao xuống đất, kẻ này dùng một bàn tay vô thanh vô tức hiện sau lưng điểm vào gáy hắn. Đòn tập kích buộc Vương Lâm kích hoạt chuẩn bị bằng phân thân và trận mảnh đao để phá giam cầm rồi đối kháng bằng một chỉ.","anchor":"Cũng chính là chủ nhân của ngón tay này đã bố trí đồ án ở bốn phía"},{"mucCt":"vua","text":"Trong sát cục phố tuyết, kẻ này dùng lời về Hữu và Không khiến ngón tay tan rồi tái ngưng tụ, đồng thời hóa giải nhiều tầng lực lượng trên một chỉ của Vương Lâm. Hắn còn tuyên bố tông môn của mình đã dùng lực lượng mạnh nhất để giết Vương Lâm.","anchor":"Vì giết ngươi, lúc này đã dùng tới lực lượng mạnh nhất của tông môn ta rồi","bridge":true,"khoang":"@c1878"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"tập kích và giam cầm","ghiChu":"Bố trí đồ án giam cầm rồi dùng ngón tay tập kích sau lưng Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Đồ án giam cầm chiến lực","loai":"trận pháp","trangThai":"da-dung","moTa":"Bố trí ở bốn phía để giam cầm, hạn chế chiến lực của Vương Lâm.","nguon":"@c1877"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1877","@c1878"],"canhGioiCaoNhat":"Không rõ","theLuc":[{"ten":"Tông môn của người phát ra giọng nói bình tĩnh","trangThai":"gan-bo"}],"aliases":["Người phát ra giọng nói bình tĩnh","Chủ ngón tay thần bí"]},{"id":"gan-tram-tu-si-cam-cung-trong-pho-tuyet","name":"Gần trăm tử sĩ cầm cung trong phố tuyết","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Tử sĩ trong sát cục phố tuyết","trangThai":"gan-bo"},{"ten":"Tông môn của người phát ra giọng nói bình tĩnh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Nhóm tử sĩ hiện ra trên mái nhà hai bên phố tuyết để tập kích Vương Lâm. Họ dùng máu và sinh mạng ngưng tụ mũi tên, sau đó tiêu tán cả thân thể lẫn hài cốt.","vaiTro":"Tử sĩ tập kích trong sát cục","tinhCach":[{"text":"Không màng sinh tử khi ra tay","chuong":"@c1878"},{"text":"Hành động đồng loạt theo sát cục","chuong":"@c1878"}],"tabs":{"diem":[{"text":"Đồng loạt hiện ra trên mái nhà hai bên phố và giương cung nhắm vào Vương Lâm.","chuong":"@c1878"},{"text":"Phun máu lên mũi tên tuyết rồi dùng sinh mạng đổi lấy hơn trăm mũi tên máu.","chuong":"@c1878"}],"kinhLich":[{"chuong":"@c1878","importance":"normal","mucCt":"vua","tieuDe":"Đổi mạng bắn tên","text":"Gần trăm tử sĩ hiện ra trên mái nhà hai bên phố, đồng loạt giương cung và phun máu lên mũi tên tuyết. Thân thể họ nhanh chóng héo rủ rồi tiêu tán, đổi mạng để bắn hơn trăm mũi tên máu vào Vương Lâm.","anchor":"Thân thể bọn họ dùng tốc độ mắt thường có thể trông thấy, lập tức héo rủ đi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"tập kích","ghiChu":"Dùng mũi tên máu đổi mạng để công kích Vương Lâm."}],"tuiDo":{"phapBao":[{"ten":"Cung của tử sĩ","loai":"pháp khí","trangThai":"dang-co","moTa":"Dùng để bắn mũi tên máu ngưng tụ từ tuyết, máu và sinh mạng tử sĩ.","nguon":"@c1878"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1878"]},{"id":"may-van-tu-si-hac-bao-ngoai-pho-giam-cam","name":"Mấy vạn tu sĩ hắc bào ngoài phố giam cầm","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Tu sĩ hắc bào ngoài phố giam cầm","trangThai":"gan-bo"},{"ten":"Tông môn của người phát ra giọng nói bình tĩnh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Nhóm tu sĩ hắc bào quy mô mấy vạn người ngồi bên ngoài con phố bị giam cầm. Họ bị một lực lượng dung hợp để tạo vòng giam cầm, trong đó hơn trăm người tiếp tục hiến thân đưa nguyên thần vào phố.","vaiTro":"Nguồn lực duy trì giam cầm","tinhCach":[{"text":"Bị huy động làm nguồn lực cho sát cục","chuong":"@c1878"},{"text":"Có nhóm sẵn sàng hiến thân theo bố trí","chuong":"@c1878"}],"tabs":{"diem":[{"text":"Ngồi bên ngoài con phố, hợp lực tạo thành lực giam cầm bao phủ chiến trường.","chuong":"@c1878"},{"text":"Hơn trăm người nuốt đan dược rồi để thân thể sụp đổ, nguyên thần hóa khói bay vào phố.","chuong":"@c1878"}],"kinhLich":[{"chuong":"@c1878","importance":"normal","mucCt":"vua","tieuDe":"Duy trì phố giam cầm","text":"Mấy vạn tu sĩ hắc bào ngồi bên ngoài con phố, bị một lực lượng dung hợp thành nguồn lực giam cầm chiến trường. Sau đó hơn trăm người trong số họ nuốt đan dược, thân thể sụp đổ, nguyên thần hóa khói bay vào trong phố.","anchor":"Vương Lâm lập tức thấy bên ngoài con phố này có mấy vạn tu sĩ mặc hắc bào đang ngồi"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"tham gia vây giết","ghiChu":"Hợp lực duy trì giam cầm và hiến nguyên thần vào sát cục nhằm giết Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Đan dược của tu sĩ hắc bào","loai":"đan dược","trangThai":"da-dung","moTa":"Hơn trăm tu sĩ hắc bào dường như nuốt đan dược rồi thân thể sụp đổ, nguyên thần hóa khói bay vào phố.","nguon":"@c1878"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1878"]},{"id":"tram-than-anh-thien-ton-trong-gio-tuyet","name":"Trăm thân ảnh Thiên Tôn trong gió tuyết","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Tông môn của người phát ra giọng nói bình tĩnh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Thiên Tôn","trangThai":"song","blurb":"Trăm thân ảnh do nguyên thần của hơn trăm tu sĩ hắc bào hóa thành trong con phố tuyết. Sau khi xuất hiện, họ bộc phát tu vi Thiên Tôn và không màng sinh tử lao vào Vương Lâm.","vaiTro":"Đợt công kích nguyên thần Thiên Tôn","tinhCach":[{"text":"Không màng sinh tử trong sát cục","chuong":"@c1878"},{"text":"Xuất hiện như lực lượng hiến thân của tông môn bí ẩn","chuong":"@c1878"}],"tabs":{"diem":[{"text":"Được hình thành từ nguyên thần của hơn trăm tu sĩ hắc bào bay vào con phố.","chuong":"@c1878"},{"text":"Vừa hiện thân đã bộc phát tu vi Thiên Tôn để lao vào Vương Lâm.","chuong":"@c1878"}],"kinhLich":[{"chuong":"@c1878","importance":"normal","mucCt":"vua","tieuDe":"Hóa thân Thiên Tôn","text":"Sau khi hơn trăm tu sĩ hắc bào hiến thân, nguyên thần của họ hóa thành khói bay vào phố và biến thành trăm thân ảnh. Những thân ảnh này lập tức bộc phát tu vi Thiên Tôn, không màng sinh tử lao về phía Vương Lâm.","anchor":"Bọn họ sau khi xuất hiện liền bộc phát ra tu vi Thiên Tôn"}],"tuViMoc":[{"chuong":"@c1878","canhGioi":"Thiên Tôn","text":"Khi xuất hiện trong phố tuyết, trăm thân ảnh bộc phát tu vi Thiên Tôn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"lao vào công kích","ghiChu":"Là đợt tấn công tiếp theo trong sát cục nhằm tiêu hao và vây giết Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1878"]},{"id":"than-anh-anh-sang-mau-trang-trong-hu-vo","name":"Thân ảnh ánh sáng màu trắng trong hư vô","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ @c1879","trangThai":"tu-vong","blurb":"Kẻ ẩn trong hư vô điều động tử sĩ và nhiều lần dùng ngón tay công kích Vương Lâm. Cuối chương, hắn bị Vương Lâm kéo ra, phủ định là quốc sư rồi bóp nát.","vaiTro":"Kẻ phục kích trong hư vô","tinhCach":[{"text":"Ẩn nấp trong hư vô để ra tay và điều khiển tử sĩ","chuong":"@c1879"},{"text":"Dùng lời lẽ lạnh lùng gắn với lực hóa Vô","chuong":"@c1879"}],"tabs":{"diem":[{"text":"Nhiều lần dùng ngón tay từ hư vô công kích Vương Lâm.","chuong":"@c1879"},{"text":"Ra lệnh cho mấy vạn thân ảnh tiến vào giết Vương Lâm.","chuong":"@c1879"},{"text":"Bị Vương Lâm kéo khỏi hư vô, khẳng định không phải quốc sư rồi bóp nát.","chuong":"@c1879"}],"kinhLich":[{"chuong":"@c1879","importance":"normal","mucCt":"vua","tieuDe":"Bị kéo khỏi hư vô","text":"Thân ảnh ánh sáng màu trắng ẩn trong hư vô, dùng ngón tay hóa Vô công kích Vương Lâm và điều động mấy vạn thân ảnh vây giết hắn. Cuối cùng, kẻ này bị Vương Lâm kéo ra khỏi hư vô, bị nói thẳng không phải quốc sư rồi bị bóp nát.","anchor":"một thân ảnh toàn thân tỏa ra ánh sáng màu trắng bị hắn lôi từ trong hư vô ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm đánh tan công kích và bóp nát thân thể.","ghiChu":"Đối đầu trực tiếp trong trận phục kích @c1879"},{"ten":"Hải Tử Thiên Tôn","tag":"khac","quanHe":"Hải Tử Thiên Tôn chứng kiến hắn bị Vương Lâm kéo khỏi hư vô.","ghiChu":"Có mặt trong cùng chiến trường @c1879"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Ngón tay hóa Vô","trangThai":"dang-co","moTa":"Dùng một chỉ từ hư vô khiến mục tiêu hướng tới tiêu tán thành Vô.","nguon":"@c1879"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1879"]},{"id":"may-tram-tu-si-may-van-than-anh-mo-ho","name":"Mấy trăm tử sĩ / mấy vạn thân ảnh mơ hồ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không rõ @c1879","trangThai":"tu-vong","blurb":"Nhóm tử sĩ và thân ảnh mơ hồ liên tục hiện ra theo nhiều lớp để vây giết Vương Lâm. Họ tự bạo, kết trận và tràn vào chiến trường nhưng lần lượt bị trạng thái tóc đen của Vương Lâm tiêu diệt.","vaiTro":"Tử sĩ phục kích Vương Lâm","tinhCach":[{"text":"Không sợ chết và liên tục lao vào vây giết","chuong":"@c1879"},{"text":"Hành động theo lệnh của kẻ ẩn trong hư vô","chuong":"@c1879"}],"tabs":{"diem":[{"text":"Tự bạo và kết trận để vây giết Vương Lâm.","chuong":"@c1879"},{"text":"Từng lớp xuất hiện từ mấy trăm đến mấy vạn thân ảnh.","chuong":"@c1879"},{"text":"Bị sát lục lôi đình và trạng thái tóc đen của Vương Lâm diệt sạch.","chuong":"@c1879"}],"kinhLich":[{"chuong":"@c1879","importance":"normal","mucCt":"vua","tieuDe":"Bị diệt trong tuyết","text":"Mấy trăm tử sĩ và mấy vạn thân ảnh mơ hồ liên tục xuất hiện, tự bạo hoặc kết trận để vây giết Vương Lâm. Dưới sát lục lôi đình, hắc khí hủy diệt và ánh mắt của Vương Lâm tóc đen, họ lần lượt tan nát rồi hóa thành mây khói.","anchor":"Trong nháy mắt, mấy vạn thân ảnh nhất tề xuất hiện"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Vây giết Vương Lâm nhưng bị tiêu diệt.","ghiChu":"Đối thủ tập thể trong trận phục kích @c1879"},{"ten":"Thân ảnh ánh sáng màu trắng trong hư vô","tag":"cap-tren","quanHe":"Hành động theo lệnh của kẻ ẩn trong hư vô.","ghiChu":"Bị điều động tiến vào giết Vương Lâm @c1879"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Trận pháp địa khí của tử sĩ","trangThai":"da-dung","moTa":"Trăm tử sĩ dẫn địa khí hóa thành bàn tay đen khổng lồ chụp Vương Lâm nhưng bị phá tan.","nguon":"@c1879"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1879"]},{"id":"ngu-hanh-chan-than-nhan-vat","name":"Ngũ hành chân thân","trangThai":"khong-ro","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1880","importance":"normal","mucCt":"vua","tieuDe":"Bị thu hồi bổn nguyên","text":"Ngũ hành chân thân chắn trước Vương Lâm tóc đen cùng các bổn nguyên khác nhưng bị hắn xem là vật do chính mình ngưng tụ. Chỉ một cái phất tay của Vương Lâm tóc đen khiến chân thân sụp đổ thành các đạo bổn nguyên rồi dung nhập vào tay phải hắn.","anchor":"thân thể ầm ầm sụp đổ, từ trạng thái chân thân bất ngờ hóa thành mấy đạo bổn nguyên"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1880"]},{"id":"co-khai-thien-ton","name":"Cô Khai Thiên Tôn","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Thiên Tôn","trangThai":"khong-ro","blurb":"Cô Khai Thiên Tôn là người từng cùng Song Tử Đại Thiên Tôn hứa giúp Vương Lâm một lần. Lời hứa này trở thành chỗ dựa để Vương Lâm tiến vào hoàng thành đối đầu Tiên Hoàng.","vaiTro":"người từng hứa giúp Vương Lâm","tinhCach":[{"text":"giữ vai trò trong ước định giúp Vương Lâm","chuong":"@c1882"}],"tabs":{"diem":[{"text":"Từng cùng Song Tử Đại Thiên Tôn để lại lời hứa giúp Vương Lâm một lần.","chuong":"@c1882"}],"kinhLich":[{"chuong":"@c1882","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc trong ước định","text":"Cô Khai Thiên Tôn được nhắc là người cùng Song Tử Đại Thiên Tôn từng hứa giúp Vương Lâm, khiến hắn có chỗ dựa khi tới hoàng thành.","anchor":"Đây chính là lời hứa của Cô Khai Thiên Tôn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"từng hứa giúp","ghiChu":"Lời hứa của Cô Khai Thiên Tôn và Song Tử được Vương Lâm dùng trong lần tiến vào hoàng cung."},{"ten":"Song Tử Đại Thiên Tôn","tag":"dong-minh","quanHe":"cùng lập ước định","ghiChu":"Cùng Song Tử Đại Thiên Tôn từng hứa giúp Vương Lâm một lần."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1882"]},{"id":"may-van-hac-giap-cam-binh","name":"Mấy vạn hắc giáp cấm binh","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Hoàng cung Tiên Tộc","trangThai":"gan-bo"},{"ten":"Hắc giáp cấm binh hoàng cung","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"tu-vong","blurb":"Mấy vạn hắc giáp cấm binh là đội quân chắn trước hoàng cung trong ngày Vương Lâm xông tới. Họ hợp sát khí thành Long Quỷ nhưng bị sát lục hủy diệt của Vương Lâm quét sạch.","vaiTro":"đội quân chắn hoàng cung","tinhCach":[{"text":"kỷ luật, đồng loạt hợp sát khí chống địch","chuong":"@c1882"},{"text":"trung thành với phòng tuyến hoàng cung","chuong":"@c1882"}],"tabs":{"diem":[{"text":"Có thể hợp sát khí của mấy vạn người thành Long Quỷ công kích.","chuong":"@c1882"},{"text":"Bị Vương Lâm diệt sạch trước cửa hoàng cung.","chuong":"@c1882"}],"kinhLich":[{"chuong":"@c1882","importance":"normal","mucCt":"vua","tieuDe":"Bị diệt trước hoàng cung","text":"Mấy vạn hắc giáp cấm binh chặn trước hoàng cung, đồng loạt ngưng sát khí thành Long Quỷ lao vào mây đen của Vương Lâm. Khi Long Quỷ sụp đổ, họ bị sát lục hủy diệt quét qua, chết hết thành hài cốt rồi hóa tro.","anchor":"Bên ngoài hoàng cung có đội ngủ mấy vạn hắc giáp cấm binh"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị diệt","ghiChu":"Chặn đường Vương Lâm trước hoàng cung và bị hắn quét sạch."}],"tuiDo":{"phapBao":[{"ten":"Hắc giáp","loai":"giáp","trangThai":"mat","moTa":"Hắc giáp tỏa hắc quang của cấm binh, cùng sát khí hợp thành Long Quỷ.","nguon":"@c1882"}],"danDuoc":[],"congPhap":[{"ten":"Long Quỷ sát khí hợp nhất","loai":"quân trận sát khí","trangThai":"da-dung","moTa":"Mấy vạn cấm binh hợp sát khí thành Long Quỷ để chặn Vương Lâm.","nguon":"@c1882"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1882"]},{"id":"long-quy","name":"Long Quỷ","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Hắc giáp cấm binh hoàng cung","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"tu-vong","blurb":"Long Quỷ là hồn phách và sát khí do hắc giáp cấm binh ngưng tụ. Nó hiện ra để chặn mây đen của Vương Lâm nhưng nhanh chóng sụp đổ.","vaiTro":"hồn thú sát khí của cấm binh","tinhCach":[{"text":"hung lệ, do sát khí vô tận hình thành","chuong":"@c1882"}],"tabs":{"diem":[{"text":"Được hình thành từ sát khí của mấy vạn hắc giáp cấm binh.","chuong":"@c1882"},{"text":"Có đầu rồng, đuôi rồng và dấu ấn mặt quỷ trước khi sụp đổ dưới sát lục hủy diệt của Vương Lâm.","chuong":"@c1882"}],"kinhLich":[{"chuong":"@c1882","importance":"normal","mucCt":"gon","tieuDe":"Tan vỡ trong mây đen","text":"Long Quỷ được hắc giáp cấm binh ngưng tụ từ sát khí để chặn Vương Lâm, nhưng vừa lao vào mây đen đã run rẩy, gào thét rồi sụp đổ.","anchor":"Long Quỷ là hồn phách của hắc giáp"}],"tuViMoc":[],"nhanMach":[{"ten":"Mấy vạn hắc giáp cấm binh","tag":"khac","quanHe":"do sát khí hợp thành","ghiChu":"Là hồn phách và sát khí do đội cấm binh ngưng tụ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"bị phá tan","ghiChu":"Bị sát lục hủy diệt của Vương Lâm áp đảo và làm sụp đổ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1882"]},{"id":"co-to","name":"Cổ tổ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cổ Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (@c1908)","trangThai":"khong-ro","blurb":"Thủy tổ của Cổ Tộc, tồn tại sinh ra trước khi thiên địa hình thành, thề hủy diệt Tiên Tộc vì chúng muốn nô dịch hắn. Cảnh giới được xếp ngang hàng Tiên Tổ, vượt trên Đại Thiên Tôn; từng giao hồn huyết cho hậu nhân và bố trí hơn mười vạn đại trận trong Đạo Cổ hoàng cung, để lại cấm chế cùng trận pháp chờ người kế thừa. Hồn huyết, ký ức và ý chí của ông tiếp tục ảnh hưởng sâu sắc đến Vương Lâm, nhiều lần hiện hư ảnh trợ chiến và trở thành chuẩn mực sức mạnh tối thượng của Cổ Tộc.","vaiTro":"Thủy tổ Cổ Tộc — nguồn gốc huyết mạch và ý chí nghịch tiên","tinhCach":"Ngạo nghễ bá đạo, không chấp nhận bị nô dịch; ý chí nghịch thiên bất khuất; mưu tính thâm viễn, bố cục xuyên thời đại","tabs":{"diem":[{"text":"Xuất hiện trong mộng Vương Lâm dưới hình dạng nam tử tướng mạo tầm thường, thân thể khổng lồ, lộ nguồn gốc sinh trước thiên địa và ý chí thề diệt Tiên Tộc","chuong":"@c1616"},{"text":"Ngân nhãn tái hiện trên ba mươi sáu quận Cổ Quốc, ngân quang phủ khắp, nhìn về phía Tiên Tộc","chuong":"@c1704"},{"text":"Ký ức được kích phát qua ngọc giản: Cổ Tổ từng một chỉ nghiền nát dị thú, thể hiện sức mạnh vượt xa tầm hiểu biết","chuong":"@c1915"},{"text":"Hư ảnh xuất hiện trong Cửu Khúc, đồng bộ động tác với Vương Lâm để giết Diệp Đạo, rồi điểm một chỉ vào ngọn núi","chuong":"@c1921"},{"text":"Được xác nhận là người bố trí hơn mười vạn đại trận trong Đạo Cổ hoàng cung, mưu tính bao trùm toàn bộ lãnh địa cũ của Cổ Tộc","chuong":"@c1922"},{"text":"Từng bắt sinh mệnh sương mù và phong ấn thành U Quận theo truyền thuyết Cổ Tộc","chuong":"@c1904"}],"kinhLich":[{"chuong":"@c1883","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc cùng Tiên Tổ","text":"Cổ tổ được nhắc trong lời quốc sư rằng trước đây ngay cả Tiên Tổ và Cổ tổ cũng không có thần thông mở động phủ giới.","anchor":"bao gồm cả Tiên Tổ và cồ tổ cũng đều như vậy"},{"chuong":"@c1888","importance":"bridge","mucCt":"gon","tieuDe":"Hồn huyết chống kim quang","text":"Hồn huyết Cổ Tổ trong thân thể Vương Lâm được nhắc là tồn tại ngang hàng với truyền thừa tu vi của Tiên Tổ, khiến kim quang không thể lấn át hoàn toàn.","anchor":"Hồn huyết của cổ Tổ là vật tồn tại ngang hàng với truyền thừa tu vi của tổ"},{"chuong":"@c1904","importance":"bridge","mucCt":"gon","tieuDe":"Phong ấn sương mù U Quận","text":"Cổ Tổ được nhắc trong truyền thuyết đã bắt sinh mệnh sương mù và phong ấn thành U Quận.","anchor":"sau khi bị Cổ Tổ bắt, liền phong ấn thành một quận"},{"chuong":"@c1908","importance":"bridge","mucCt":"gon","text":"Máu tươi của Cổ Tổ, nhất là một giọt Hồn Huyết, trở thành nguyên nhân khiến Đạo Cổ Hoàng ghen ghét và nhằm vào Vương Lâm.","anchor":"cho dù ngươi còn có cả một giọt Hồn Huyết của Cổ Tổ"}],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Tổ","tag":"khac","quanHe":"Cùng được nhắc trong cổ sử","ghiChu":"Cả hai được nêu trong lời quốc sư về thần thông mở động phủ giới."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1883","@c1888","@c1904","@c1906","@c1908"]},{"id":"lao-to-cua-dai-hon-mon","name":"Lão tổ của Đại Hồn Môn","cn":"","aliases":["Thiên tài của tộc quốc sư"],"gioiTinh":"nam","theLuc":[{"ten":"Đại Hồn Môn","trangThai":"gan-bo"},{"ten":"Tộc của quốc sư","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1883","trangThai":"khong-ro","blurb":"Lão tổ của Đại Hồn Môn là thiên tài thuộc tộc quốc sư. Ông từng rời khỏi tổ thành nhưng theo lời quốc sư vẫn khó thoát khỏi cái chết vì phong ấn truyền thừa của Tiên Tổ.","vaiTro":"Lão tổ Đại Hồn Môn","tinhCach":[{"text":"Từng tìm cách rời khỏi giới hạn của tộc","chuong":"@c1883"},{"text":"Được xem là thiên tài trong tộc quốc sư","chuong":"@c1883"}],"tabs":{"diem":[{"text":"Là thiên tài của tộc quốc sư và có liên hệ trực tiếp với Đại Hồn Môn.","chuong":"@c1883"},{"text":"Được nêu làm bằng chứng cho việc tộc quốc sư khó thoát khỏi phong ấn tổ thành.","chuong":"@c1883"}],"kinhLich":[{"mucCt":"vua","text":"Lão tổ của Đại Hồn Môn được quốc sư nói là thiên tài của tộc hắn. Người này từng rời khỏi tổ thành nhưng vẫn khó thoát chết, cho thấy phong ấn Tiên Tổ để lại trên tộc quốc sư rất khó vượt qua.","anchor":"Lão tổ của Đại Hồn Môn là thiên tài của tộc ta","bridge":true,"khoang":"@c1883"}],"tuViMoc":[],"nhanMach":[{"ten":"Thượng Huyền Đạo","tag":"ho-hang","quanHe":"Cùng tộc","ghiChu":"Quốc sư gọi lão tổ Đại Hồn Môn là thiên tài của tộc mình."},{"ten":"Đại Hồn Môn","tag":"khac","quanHe":"Lão tổ sáng lập hoặc lão tổ của môn phái","ghiChu":"Được nhắc qua danh xưng lão tổ của Đại Hồn Môn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1883"]},{"id":"lien-van-quyet","name":"Tiên Tổ Liên Vân Quyết","aliases":["Tiên Tổ","Liên Vân Quyết"],"trangThai":"tu-vong","canhGioiCaoNhat":"Tiên Tổ @c1887","tabs":{"kinhLich":[{"chuong":"@c1887","importance":"major","mucCt":"ky","tieuDe":"Đầu Tiên Tổ xuất thế","text":"Chương xác nhận Liên Vân Quyết chính là Tiên Tổ, thủy tổ của Tiên hoàng và cả Tiên tộc, người từng trấn áp bảy mươi hai sinh linh thiên ngoại thành bảy mươi hai châu và sáng tạo Thiên Tôn Niết. Đầu của ông bị xé khỏi thân thể, được giấu trong ngọn núi hình đầu, khi xuất thế tỏa uy áp kinh thiên động địa. Mắt phải của đầu Tiên Tổ mở ra, hút đốm sáng vàng của Minh Đạo Tôn rồi hút Vương Lâm vào trong.","anchor":"Hắn chính là Tiên Tổ, chính là Liên Vân Quyết"},{"chuong":"@c1889","importance":"major","mucCt":"vua","tieuDe":"Đầu bị dùng làm pháp bảo","text":"Cái đầu đã chết của Tiên Tổ bị đặt ở trung tâm kế hoạch của quốc sư và Tiên hoàng. Hai mắt do thân thể Vương Lâm và Đạo Phi tạo thành, suýt mở miệng giải phong ấn nhưng bị máu vàng của Tiên hoàng khống chế và được xem như pháp bảo mạnh nhất để kế thừa tu vi tiên tổ.","anchor":"Cái đầu này tử vong đã nhiều năm, không thể sống lại được"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người bị hút vào mắt phải Tiên Tổ","ghiChu":"Mắt phải của đầu Tiên Tổ hút Vương Lâm vào nơi diễn ra tranh đoạt truyền thừa."},{"ten":"Thượng Huyền Đạo","tag":"khac","quanHe":"Người triệu hồi đầu Tiên Tổ","ghiChu":"Quốc sư dùng đầu Tiên Tổ làm trung tâm kế hoạch truyền thừa và đoạt thân."},{"ten":"Tiên hoàng","tag":"ho-hang","quanHe":"Thủy tổ","ghiChu":"Liên Vân Quyết được nêu là thủy tổ của tiên hoàng."}],"tuViMoc":[],"diem":[{"text":"Tự xưng Liên Vân Quyết, lưu lại cảm ngộ Bát Cực Đạo trong Thiên Tôn Niết cho người vượt tầng mười một","chuong":"@c1856"},{"text":"Bị tu sĩ phong ấn ở Đông Lâm Tông oán niệm là hèn hạ","chuong":"@c1859"},{"text":"Được xác nhận là Tiên Tổ, thủy tổ của Tiên hoàng và Tiên tộc, từng trấn áp bảy cõi","chuong":"@c1887"},{"text":"Cái đầu đã chết bị dùng làm trung tâm kế hoạch của quốc sư và Tiên hoàng, đôi mắt gắn từ thân thể Vương Lâm","chuong":"@c1889"}]},"nguon":["@c1887","@c1889"],"vaiTro":"Tiên Tổ — thủy tổ của Tiên hoàng và Tiên tộc, người lưu cảm ngộ Bát Cực Đạo trong Thiên Tôn Niết","blurb":"Liên Vân Quyết là Tiên Tổ, thủy tổ của Tiên hoàng và toàn bộ Tiên tộc, từng trấn áp bảy cõi. Giọng nói của nhân vật này vang lên khi Vương Lâm vượt tầng mười một Thiên Tôn Niết, tuyên bố đã lưu lại cảm ngộ Bát Cực Đạo tại đó. Sau khi chết, cái đầu của Tiên Tổ bị đặt làm trung tâm trong kế hoạch của quốc sư và Tiên hoàng, với đôi mắt được gắn từ thân thể Vương Lâm."},{"id":"quoc-su-gia-cua-dieu-vong-toc","name":"Quốc sư giả của Điệu Vong Tộc","cn":"","aliases":["Quốc sư vừa mới chết"],"gioiTinh":"nam","theLuc":[{"ten":"Điệu Vong Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1891","trangThai":"tu-vong","blurb":"Tộc nhân Điệu Vong Tộc từng chiếm thân thể Vương Lâm và tự nhận gánh sứ mệnh quốc sư. Trước khi bị Tiên Hoàng xóa sạch, hắn nhớ ra mình chỉ là vỏ bọc do quốc sư đời thứ nhất sắp đặt.","vaiTro":"Vỏ bọc quốc sư Điệu Vong Tộc","tinhCach":[{"text":"Mang chấp niệm hoàn thành sứ mệnh giải phong ấn chủng tộc","chuong":"@c1891"},{"text":"Bị ký ức phong ấn khiến thân phận thật bị che lấp","chuong":"@c1891"}],"tabs":{"diem":[{"text":"Tưởng mình là quốc sư của Điệu Vong Tộc nhưng trước khi chết mới nhớ lại chân tướng.","chuong":"@c1891"},{"text":"Từng được quốc sư đời thứ nhất đưa lên vị trí quốc sư và truyền thụ thần thông bổn tộc.","chuong":"@c1891"}],"kinhLich":[{"chuong":"@c1891","importance":"normal","mucCt":"ky","tieuDe":"Bị diệt sau giải phong","text":"Sau khi Tiên Hoàng giải khai phong ấn Điệu Vong Tộc, quốc sư giả trong thân thể Vương Lâm xúc động vì tưởng mục tiêu cả đời đã hoàn thành. Ngay sau đó, sức mạnh Tiên Hoàng tràn vào thân thể Vương Lâm, xóa sạch dấu vết của hắn khiến hắn hình thần câu diệt. Trước khi chết, hắn nhớ lại mình không phải quốc sư thật mà chỉ là người được quốc sư đời thứ nhất đưa lên làm vỏ bọc để bảo vệ bé gái quốc sư chân chính.","anchor":"Hắn nhớ được nữ tử kia chính là quốc sư đời thứ nhất, hắn không phải quốc sư"},{"chuong":"@c1892","importance":"bridge","mucCt":"gon","text":"Quốc sư vừa mới chết được xác nhận là tộc nhân Điệu Vong Tộc cuối cùng ngoài Hải Tử.","anchor":"Điệu Vong Tộc ngoại trừ Hài Tử ra, còn một tộc nhân cuối cùng, chính là quốc sư vừa mới chết"}],"tuViMoc":[],"nhanMach":[{"ten":"Tiên Hoàng","tag":"doi-thu","quanHe":"Bị diệt khẩu","ghiChu":"Bị Tiên Hoàng xóa sạch sau khi phong ấn Điệu Vong Tộc được giải."},{"ten":"Quốc sư đời thứ nhất của Điệu Vong Tộc","tag":"su-mon","quanHe":"Người đưa hắn lên làm quốc sư giả","ghiChu":"Nữ tử này truyền thụ thần thông bổn tộc cho hắn."},{"ten":"Hải Tử Thiên Tôn","tag":"khac","quanHe":"Vỏ bọc bảo vệ quốc sư thật","ghiChu":"Ký ức trước khi chết cho thấy bé gái mất tích mới là quốc sư chân chính."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Thần thông bổn tộc Điệu Vong Tộc","trangThai":"dang-co","moTa":"Được quốc sư đời thứ nhất truyền thụ sau khi bị đưa lên làm quốc sư giả.","nguon":"@c1891"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1891","@c1892"]},{"id":"quoc-su-doi-thu-nhat-cua-dieu-vong-toc","name":"Quốc sư đời thứ nhất của Điệu Vong Tộc","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Điệu Vong Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1891","trangThai":"tu-vong @c1891","blurb":"Nữ tử trong ký ức trước khi chết của quốc sư giả, là quốc sư đời thứ nhất của Điệu Vong Tộc. Nàng sinh ra bé gái quốc sư thật, đưa một tộc nhân lên làm quốc sư giả và truyền thần thông bổn tộc cho hắn trước khi qua đời.","vaiTro":"Quốc sư đời đầu Điệu Vong Tộc","tinhCach":[{"text":"Sắp đặt vỏ bọc để bảo vệ quốc sư thật","chuong":"@c1891"},{"text":"Gánh truyền thừa thần thông bổn tộc trong giai đoạn tộc gần tuyệt diệt","chuong":"@c1891"}],"tabs":{"diem":[{"text":"Là quốc sư đời thứ nhất được quốc sư giả nhớ lại trước khi chết.","chuong":"@c1891"},{"text":"Đưa quốc sư giả lên vị trí quốc sư và truyền thụ thần thông cho hắn.","chuong":"@c1891"}],"kinhLich":[{"chuong":"@c1891","importance":"normal","mucCt":"vua","tieuDe":"Sắp đặt quốc sư giả","text":"Trong ký ức hồi tỉnh của quốc sư giả, nữ tử này mới là quốc sư đời thứ nhất của Điệu Vong Tộc. Nàng sinh ra bé gái quốc sư thật, đưa quốc sư giả lên vị trí quốc sư để che giấu chân tướng và truyền thụ thần thông bổn tộc cho hắn trước khi qua đời.","anchor":"Đứa bé gái này bố của nó là ai hắn không biết"}],"tuViMoc":[],"nhanMach":[{"ten":"Quốc sư giả của Điệu Vong Tộc","tag":"su-mon","quanHe":"Người truyền thụ thần thông","ghiChu":"Nàng đưa hắn lên làm quốc sư giả và truyền thụ thần thông bổn tộc."},{"ten":"Hải Tử Thiên Tôn","tag":"cha-me","quanHe":"Mẹ của quốc sư thật","ghiChu":"Ký ức cho biết bé gái quốc sư thật là con của nàng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Thần thông bổn tộc Điệu Vong Tộc","trangThai":"dang-co","moTa":"Truyền thụ cho quốc sư giả sau khi đưa hắn lên vị trí quốc sư.","nguon":"@c1891"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1891"]},{"id":"thien-tai-dieu-vong-toc-sang-tao-dai-hon-mon","name":"Thiên tài Điệu Vong Tộc sáng tạo Đại Hồn Môn","cn":"","aliases":["Thiên tài Điệu Vong Tộc","lão tổ sáng lập Đại Hồn Môn"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Điệu Vong Tộc","trangThai":"gan-bo"},{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1891","trangThai":"khong-ro","blurb":"Thiên tài Điệu Vong Tộc năm xưa nghĩ ra kế hoạch truyền thừa nhằm chờ thân thể thích hợp cho tộc nhân đoạt xá. Người này giả vờ bất hòa, rời khỏi nơi bị phong ấn và sáng tạo Đại Hồn Môn để kế hoạch được lưu truyền.","vaiTro":"Người sáng tạo Đại Hồn Môn","tinhCach":[{"text":"Mưu tính lâu dài cho sự tồn tục của Điệu Vong Tộc","chuong":"@c1891"},{"text":"Biết che giấu ý đồ bằng việc giả vờ bất hòa và rời đi","chuong":"@c1891"}],"tabs":{"diem":[{"text":"Được Hải Tử nhắc là người nghĩ ra kế hoạch then chốt của Điệu Vong Tộc.","chuong":"@c1891"},{"text":"Sáng tạo Đại Hồn Môn sau khi rời khỏi nơi bị phong ấn.","chuong":"@c1891"}],"kinhLich":[{"chuong":"@c1891","importance":"normal","mucCt":"vua","tieuDe":"Sáng tạo Đại Hồn Môn","text":"Hải Tử hé lộ thiên tài Điệu Vong Tộc năm xưa là người nghĩ ra kế hoạch chờ thân thể thích hợp để tộc nhân đoạt xá. Người này giả vờ bất hòa, tìm cách rời khỏi nơi bị phong ấn, sáng tạo Đại Hồn Môn và truyền lại kế hoạch cho đời sau.","anchor":"cuối cùng có thể rời khỏi nơi này thành công, sáng tạo ra Đại Hồn Môn"},{"chuong":"@c1892","importance":"normal","mucCt":"vua","tieuDe":"Lộ vai trò sáng lập","text":"Thiên tài Điệu Vong Tộc được xác nhận là người nghĩ ra kế hoạch đời đời kế tục, từng giúp Cửu Đế thành Đại Thiên Tôn và đổi lấy lời trợ giúp. Người này còn sáng lập Đại Hồn Môn, tính ra Vương Lâm sẽ xuất hiện ở Thiên Ngưu Châu để bố trí bước đầu tiếp xúc.","anchor":"Vị tiền bối thiên tài của Điệu Vong Tộc kia đã sáng lập ra Đại Hồn Môn"}],"tuViMoc":[],"nhanMach":[{"ten":"Hải Tử Thiên Tôn","tag":"dong-minh","quanHe":"Người kế thừa kế hoạch","ghiChu":"Hải Tử là quốc sư thật, người công khai giải thích kế hoạch do thiên tài này để lại."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1891","@c1892"]},{"id":"quoc-su-doi-truoc","name":"Quốc sư đời trước","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Điệu Vong tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1892","trangThai":"khong-ro","blurb":"Quốc sư đời trước là người thuộc kế hoạch Điệu Vong Tộc sau khi Tiên hoàng kế vị. Bà tìm Cửu Đế theo bố trí tổ tiên và cùng sinh ra Hải Tử.","vaiTro":"Mẹ Hải Tử trong kế hoạch","tinhCach":[{"text":"Hành động theo kế hoạch tổ tiên","chuong":"@c1892"},{"text":"Gắn với bố cục giải phong ấn Điệu Vong Tộc","chuong":"@c1892"}],"tabs":{"diem":[{"text":"Tìm Cửu Đế sau khi Tiên hoàng kế vị để thực hiện kế hoạch Điệu Vong Tộc.","chuong":"@c1892"},{"text":"Là mắt xích dẫn tới sự ra đời của Hải Tử.","chuong":"@c1892"}],"kinhLich":[{"chuong":"@c1892","importance":"normal","mucCt":"vua","tieuDe":"Sinh ra Hải Tử","text":"Quốc sư đời trước được Cửu Đế nhắc là người đã tìm tới hắn sau khi Tiên hoàng kế vị. Bà dựa theo kế hoạch của tổ tiên Điệu Vong Tộc để cùng Cửu Đế sinh ra Hải Tử, tạo biến số cho việc phá phong ấn Tiên Tổ.","anchor":"quốc sư đời trước đã tìm tới ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Cửu Đế Đại Thiên Tôn","tag":"khac","quanHe":"người phối hợp kế hoạch","ghiChu":"Cùng tham dự bố trí sinh ra Hải Tử."},{"ten":"Hải Tử Thiên Tôn","tag":"cha-me","quanHe":"mẹ","ghiChu":"Sinh ra Hải Tử trong kế hoạch Điệu Vong Tộc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1892"]},{"id":"thanh-nguu-chan-nhan","name":"Thanh Ngưu chân nhân","gioiTinh":"nam","trangThai":"song @c1898","tabs":{"diem":[{"text":"Được xác nhận là lão tổ Đại Hồn Môn, tu vi cao thâm, có bổn nguyên chân thân và nắm giữ địa hỏa chủ mạch Thiên Ngưu Châu","chuong":"@c1722"},{"text":"Dùng hàn bổn nguyên chân thân chờ Vương Lâm trên Thiên Sơn, trực tiếp yêu cầu hắn","chuong":"@c1732"},{"text":"Bổn tôn tại Đại Hồn Môn kích động nhận ra Vương Lâm chính là người tổ tiên từng tiên đoán","chuong":"@c1734"},{"text":"Hiện thân phân xử giữa Vương Lâm và Viêm Loan, dung hợp bổn nguyên chân thân với bổn tôn và để lộ khí tức Không Kiếp hậu kỳ","chuong":"@c1735"},{"text":"Giải thích bí mật tầng chín, tầng mười Tàng Hồn Các và xác nhận công lao Đan Hải của Vương Lâm","chuong":"@c1758"},{"text":"Vẫn bế quan và để lại lệnh giữ ngọn núi từng ban cho Vương Lâm làm cấm địa","chuong":"@c1898"}],"kinhLich":[{"chuong":"@c1892","importance":"bridge","mucCt":"gon","text":"Thanh Ngưu chân nhân được Vương Lâm nhớ lại là người từng dặn hắn sau ba trăm năm trở về Đại Hồn Môn nhận vật do lão tổ để lại.","anchor":"Thanh Ngưu chân nhân của Đại Hồn Môn năm đó đã từng nói"},{"chuong":"@c1898","importance":"bridge","mucCt":"vua","tieuDe":"Giữ núi cũ","text":"Thanh Ngưu chân nhân vẫn bế quan và để lại lệnh giữ ngọn núi từng ban cho Vương Lâm làm cấm địa, về sau người trong môn hiểu ra khi danh tiếng Bạch Phát Dược Thiên Tôn của Vương Lâm truyền về.","anchor":"Hắn chỉ nói một điều là giữ là ngọn núi năm đó ban cho Vương Lâm"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"giữ núi cũ cho Vương Lâm","ghiChu":"Ra lệnh bảo tồn ngọn núi từng ban cho Vương Lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1892","@c1898"],"vaiTro":"Lão tổ Đại Hồn Môn — người nắm địa hỏa chủ mạch Thiên Ngưu Châu","tinhCach":"Kiên nhẫn chờ đợi người trong tiên đoán; nhìn xa và biết trọng dụng Vương Lâm; thận trọng quan sát biến cục; cứng rắn khi giao nhiệm vụ","blurb":"Thanh Ngưu chân nhân là lão tổ Đại Hồn Môn, được nhắc tới là tu vi cao thâm, có bổn nguyên chân thân và nắm giữ nơi có địa hỏa chủ mạch Thiên Ngưu Châu. Ông nhận ra Vương Lâm liên quan đến tiên đoán của tổ tiên, đưa hắn vào bố cục của Đại Hồn Môn bằng đạo thuật, ngọc giản và các nhiệm vụ nặng nề. Về sau ông vẫn bế quan, đồng thời để lại lệnh giữ ngọn núi từng ban cho Vương Lâm làm cấm địa."},{"id":"cuu-de","name":"Cửu Đế","cn":"","aliases":["Đại Thiên Tôn tiên tộc"],"gioiTinh":"nam","theLuc":[{"ten":"Tiên tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn @c1896","trangThai":"song @c1898","blurb":"Cửu Đế là Đại Thiên Tôn mạnh nhất trong nhóm Đại Thiên Tôn tiên tộc được nhắc ở chương này. Ông đang suy yếu vì Trớ Thuật quấn thân và vừa giao chiến với Song Tử, nhưng vẫn đủ sức áp chế cục diện bằng uy thế và tính toán.","vaiTro":"Đại Thiên Tôn tiên tộc","tinhCach":[{"text":"Tính toán sâu, xem cân bằng tiên tộc và cổ tộc là trọng yếu","chuong":"@c1896"},{"text":"Cứng rắn, sẵn sàng dùng sinh tử uy hiếp để giữ Liên Đạo Phi","chuong":"@c1896"}],"tabs":{"diem":[{"text":"Lộ rằng mình cùng Điệu Vong tộc từng bố cục quanh di vật Tiên Tổ, nhưng người thu hoạch lớn nhất lại là Vương Lâm.","chuong":"@c1896"},{"text":"Chấp nhận cho Vương Lâm mang đầu lâu Tiên Tổ đi nhưng quyết không cho mang Liên Đạo Phi.","chuong":"@c1896"}],"kinhLich":[{"chuong":"@c1896","importance":"normal","mucCt":"ky","tieuDe":"Tối hậu thư Liên Đạo Phi","text":"Cửu Đế hóa mặt trời trắng thành bạch lang chặn Vương Lâm cứu Đạo Nhất nhưng bị một cước Đại Thiên Tôn Chi Dương bức lui trong lúc bản thân đang bị Trớ Thuật quấn thân. Ông ép Đạo Nhất giao đầu lâu trẻ con để giữ mạng một Đại Thiên Tôn cho tiên tộc, rồi lộ bố cục với Điệu Vong tộc và kế hoạch chia di vật Tiên Tổ nhằm xóa bỏ Tiên Hoàng nhất mạch. Cuối cùng ông cho phép Vương Lâm mang đầu lâu Tiên Tổ đi, nhưng ra tối hậu thư không được mang Liên Đạo Phi, dọa buông áp chế Trớ Thuật để liều mạng nếu Vương Lâm cưỡng ép.","anchor":"Lão phu có thể cho ngươi mang đầu lâu của Tiên Tổ đi, nhưng không thể cho ngươi mang Liên Đạo Phi đi!"},{"chuong":"@c1897","importance":"normal","mucCt":"vua","tieuDe":"Trớ Thuật khó áp chế","text":"Cửu Đế ban đầu dùng việc không áp chế Trớ Thuật trong thân để uy hiếp Vương Lâm, rồi bác bỏ khả năng đặt đầu tiên tổ về chỗ cũ vì đầu đã bị chia cắt. Cuối chương, hắc khí trên người hắn lan tràn khó áp chế, nhưng hắn không trách Hài Tử và nhận định kết giao với Vương Lâm sẽ có lợi cho tộc họ.","anchor":"Bỏ qua, lại để đầu của tiên tổ vào chồ cũ cũng không thể có tác dụng trấn áp nữa"},{"chuong":"@c1898","importance":"normal","mucCt":"vua","tieuDe":"Che tin rồi bế quan","text":"Cửu Đế áp chế tin Tiên Hoàng chết và đưa Hài Tử trở về Đế Sơn bế quan. Nhờ tu vi bản thân cùng thần thông Điệu Vong tộc của Hài Tử, Trớ Thuật trong cơ thể hắn có thể dần tiêu tán.","anchor":"Sau khi Cửu Đế mang theo Hài Tử trở về Đế Sơn liền lập tức bế quan"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối đầu và treo món nợ sau khi Vương Lâm phá bố cục, đoạt đầu lâu trẻ con và muốn mang Liên Đạo Phi đi.","ghiChu":"Phát sinh xung đột trực tiếp tại @c1896"},{"ten":"Đạo Nhất","tag":"dong-minh","quanHe":"Cùng phe Đại Thiên Tôn tiên tộc, Cửu Đế ra tay giữ mạng Đạo Nhất để tiên tộc không mất thêm Đại Thiên Tôn.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Song Tử","tag":"doi-thu","quanHe":"Từng giao chiến trước đó và bị Cửu Đế đe dọa bằng số phận Tử Dương tông.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Hài Tử","tag":"dong-minh","quanHe":"Gọi Hài Tử mượn lực Điệu Vong tộc cứu Đạo Nhất.","ghiChu":"Thể hiện rõ tại @c1896"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Trớ Thuật","trangThai":"bi-tac-dong","moTa":"Bị Trớ Thuật quấn thân nên phải phân thần áp chế và hẹn sau khi khu trừ sẽ đòi công bằng với Vương Lâm.","nguon":"@c1896"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1896","@c1897","@c1898"]},{"id":"dao-nhat","name":"Đạo Nhất","cn":"","aliases":["Đạo Khất"],"gioiTinh":"nam","theLuc":[{"ten":"Tiên tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn @c1896","trangThai":"song @c1898","blurb":"Đạo Nhất là Đại Thiên Tôn tiên tộc bị Trớ Thuật bộc phát dữ dội trong chương này. Ông bị Vương Lâm đánh ngã và dẫm dưới chân, sau đó buộc phải giao đầu lâu trẻ con để thoát thân.","vaiTro":"Đại Thiên Tôn tiên tộc","tinhCach":[{"text":"Kiêu ngạo, khó chấp nhận khuất nhục trước Vương Lâm","chuong":"@c1896"},{"text":"Quyết liệt, từng muốn đồng quy vu tận khi bị dồn vào thế chết","chuong":"@c1896"}],"tabs":{"diem":[{"text":"Bị Trớ Thuật bộc phát khiến huyết nhục chia lìa, quá nửa thân ngoài hóa dạng xương khô.","chuong":"@c1896"},{"text":"Trước khi trốn, nhìn Vương Lâm như muốn khắc sâu mối hận bị dẫm dưới chân.","chuong":"@c1896"}],"kinhLich":[{"chuong":"@c1896","importance":"normal","mucCt":"ky","tieuDe":"Giao đầu lâu thoát thân","text":"Đạo Nhất bị Trớ Thuật bộc phát toàn diện, hắc khí tràn thân và huyết nhục bong tróc, vẫn rút loan đao màu đen muốn đồng quy vu tận với Vương Lâm. Đòn này bị chín mươi chín hư ảnh của Vương Lâm vượt qua, khiến ông bị điểm mi tâm rơi xuống đất, rồi bị đạp ngực khuất phục giữa lúc Hài Tử ra tay cứu viện cũng không ngăn được. Dưới áp lực của Cửu Đế và nguy cơ tu vi tổn hại nặng hơn, Đạo Nhất giao đầu lâu trẻ con tràn tử khí cho Vương Lâm rồi phá hư vô trốn mất.","anchor":"Vương Lâm, ngươi muốn giết bổn tôn. vậy thì đồng quy vu tận với bổn tôn đi!"},{"chuong":"@c1898","importance":"normal","mucCt":"ky","tieuDe":"Tàn nhẫn phân chú","text":"Đạo Nhất mang thân thể tàn tạ về Đạo Nhất Tông bế quan. Vì Trớ Thuật đã bộc phát toàn bộ, hắn triệu tập Dược Thiên Tôn, Kim tôn và tu sĩ bước thứ ba dưới trướng để cưỡng ép phân tán nguyền rủa. Hành động này khiến tông môn gần như thành tử tông.","anchor":"Loại hành động tàn nhẫn này khiến Đạo Nhất Tông hầu như trở thành tử tông"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm đánh ngã, dẫm ngực và ép giao đầu lâu trẻ con.","ghiChu":"Xung đột trực tiếp tại @c1896"},{"ten":"Cửu Đế","tag":"dong-minh","quanHe":"Được Cửu Đế can thiệp giữ mạng và ép giao đầu lâu để thoát khỏi Vương Lâm.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Hài Tử","tag":"dong-minh","quanHe":"Được Hài Tử dùng lực Điệu Vong tộc tạo sóng gợn bảo hộ.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Dược Thiên Tôn","tag":"cap-tren","quanHe":"cưỡng ép thuộc hạ chia sẻ Trớ Thuật","ghiChu":"Triệu tập Dược Thiên Tôn vào việc phân tán nguyền rủa."}],"tuiDo":{"phapBao":[{"ten":"Đầu lâu trẻ con tràn ngập tử khí","loai":"dị bảo","trangThai":"mat","moTa":"Bị buộc giao cho Vương Lâm sau khi bị dẫm ngực và bị Cửu Đế ép nhượng bộ.","nguon":"@c1896"},{"ten":"Loan đao màu đen của Đạo Nhất","loai":"loan đao","trangThai":"dang-co","moTa":"Dùng trong đòn đồng quy vu tận, chém sụp hơn chín mươi hư ảnh của Vương Lâm nhưng không trúng bản thể.","nguon":"@c1896"}],"danDuoc":[],"congPhap":[{"ten":"Trớ Thuật","trangThai":"bi-tac-dong","moTa":"Bộc phát toàn diện trên thân Đạo Nhất, khiến thân thể tổn hại nặng và cản trở việc thi triển thần thông.","nguon":"@c1896"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1896","@c1898"]},{"id":"hai-tu","name":"Hài Tử","cn":"","aliases":["Hải Tử","Hải Tử Thiên Tôn"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Điệu Vong tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1896","trangThai":"song @c1898","blurb":"Hài Tử (còn gọi Hải Tử) là thành viên Điệu Vong tộc, hoạt động bên cạnh Cửu Đế với vai trò vừa chiến đấu vừa suy tính. Nàng từng mượn lực Điệu Vong tộc cứu viện Đạo Nhất, dùng Liên Đạo Phi trấn áp linh hồn, trợ giúp Cửu Đế hóa giải Trớ Thuật tại Đế Sơn, và phối hợp tính toán thời hạn mở Thái Cổ Thần Cảnh.","vaiTro":"Truyền nhân Điệu Vong tộc — trợ thủ tính toán bên cạnh Cửu Đế","tinhCach":"Lạnh tĩnh, tính toán mưu lược; trung thành với Cửu Đế; hành sự có nguyên tắc, không trực tiếp công kích kẻ ngoài thỏa thuận","tabs":{"diem":[{"text":"Được Cửu Đế gọi ra tay, mượn lực Điệu Vong tộc cứu viện Đạo Nhất, đổi lại không trực tiếp công kích Vương Lâm","chuong":"@c1896"},{"text":"Giải thích việc tộc nàng chọn Liên Đạo Phi để trấn áp linh hồn bảy mươi hai châu","chuong":"@c1897"},{"text":"Theo Cửu Đế về Đế Sơn, dùng thần thông Điệu Vong tộc trợ giúp tiêu tán Trớ Thuật","chuong":"@c1898"},{"text":"Thừa nhận giới hạn tính toán, chỉ tính ra được Thái Cổ Thần Cảnh mở hoàn toàn","chuong":"@c1928"},{"text":"Phối hợp Cửu Đế suy tính thời hạn Thái Cổ Thần Cảnh mở ra","chuong":"@c1929"}],"kinhLich":[{"chuong":"@c1896","importance":"normal","mucCt":"vua","tieuDe":"Cứu viện Đạo Nhất","text":"Hài Tử được Cửu Đế gọi ra tay cứu Đạo Nhất, đổi lại việc không trực tiếp công kích Vương Lâm. Hài Tử mượn lực lượng Điệu Vong tộc niệm chú, tạo tầng sóng gợn màu lam bao phủ Đạo Nhất khiến Vương Lâm truy kích như lún vào bùn, nhưng vẫn bị tơ đen của Vương Lâm xuyên qua.","anchor":"Lấy lực lượng của Điệu Vong tộc, hóa thành suy nghĩ của người sống, ý niệm của người chết."},{"chuong":"@c1897","importance":"normal","mucCt":"ky","tieuDe":"Dùng Liên Đạo Phi trấn áp","text":"Hài Tử giải thích cấm cung cần đầu tiên tổ trấn áp linh hồn bảy mươi hai châu, còn tộc nàng đã chọn Liên Đạo Phi làm vật thay thế vì hắn có huyết mạch và truyền thừa tu vi tiên tổ. Nàng tuyên bố nếu Vương Lâm cố chấp mang Liên Đạo Phi đi thì sẽ ra tay ngăn cản. Sau đó nàng thi triển bí thuật khiến Liên Đạo Phi tỏa kim quang, ngưng thành Đại Thiên Tôn ngủ say, rồi cuối chương buồn bã nhìn theo Vương Lâm.","anchor":"Hắn có huyết mạch của tiên tổ, còn được truyền thừa một phần tu vi của tiên tổ"},{"chuong":"@c1898","importance":"normal","mucCt":"vua","tieuDe":"Trợ Cửu Đế hóa chú","text":"Hài Tử theo Cửu Đế trở về Đế Sơn và dùng thần thông của Điệu Vong tộc trợ giúp tiêu tán Trớ Thuật. Về sau, Vương Lâm nhắc rằng chuyện thiên tài Điệu Vong tộc lợi dụng hắn đã được nói với Hài Tử là xóa bỏ.","anchor":"lại có Hải Tử dùng thần thông của Điệu Vong tộc trợ giúp"}],"tuViMoc":[],"nhanMach":[{"ten":"Cửu Đế","tag":"dong-minh","quanHe":"Nhận lời Cửu Đế ra tay cứu Đạo Nhất trong cục diện giao chiến.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Đạo Nhất","tag":"dong-minh","quanHe":"Dùng sóng gợn lam bảo hộ Đạo Nhất khỏi Vương Lâm.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Dùng sóng gợn lam cản bước truy kích của Vương Lâm.","ghiChu":"Thể hiện rõ tại @c1896"},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"người bị nàng dùng bí thuật biến thành Đại Thiên Tôn ngủ say","ghiChu":"Nàng dùng Liên Đạo Phi thay đầu tiên tổ trấn áp bảy mươi hai châu."},{"ten":"Vương Lâm","tag":"khac","quanHe":"được nhắc trong việc xóa bỏ chuyện lợi dụng","ghiChu":"Vương Lâm nói chuyện thiên tài Điệu Vong tộc lợi dụng hắn đã được xóa bỏ với Hài Tử."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1896","@c1897","@c1898"]},{"id":"lao-to-dai-hon-mon","name":"Lão tổ Đại Hồn Môn","aliases":["thiên tài Điệu Vong tộc"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ trong đợt này","trangThai":"khong-ro @c1898","tabs":{"diem":[{"text":"Tặng Vương Lâm mai rùa chứa bản đồ và giới thiệu Đại Thiên Tôn, trở thành manh mối quan trọng cho chuyến đi hoàng thành","chuong":"@c1822"},{"text":"Bị Vương Lâm suy đoán đã tính ra trước việc Tiên Hoàng đoạt xá và phân tán","chuong":"@c1897"},{"text":"Được Vương Lâm nhận định là thiên tài vượt đời, bố trí kế hoạch xuyên ngàn vạn năm","chuong":"@c1898"},{"text":"Ngọc giản tính toán do ông để lại giúp Vương Lâm nhìn rõ quá trình tàn hồn Lý Mộ Uyển bị dung hợp","chuong":"@c1919"},{"text":"Ngọc giản tiếp tục phát huy tác dụng, giúp Vương Lâm nhìn thấy quốc sư thần bí","chuong":"@c1921"}],"kinhLich":[{"chuong":"@c1897","importance":"bridge","mucCt":"vua","tieuDe":"Bị nghi tính trước","text":"Vương Lâm suy đoán lão tổ Đại Hồn Môn có thể đã tính ra việc Tiên Hoàng đoạt xá người điên, tự bạo và phân tán Trớ Thuật nhưng cố ý không nói ra hoặc ngăn cản.","anchor":"lão tổ của Đại Hồn Môn rất có thể cũng đã tính toán ra nhưng không nói ra và ngăn cản"},{"chuong":"@c1898","importance":"normal","mucCt":"ky","tieuDe":"Hài cốt khẩn cầu","text":"Vương Lâm nhận định lão tổ Đại Hồn Môn là thiên tài vượt đời, người đã bố trí kế hoạch xuyên ngàn vạn năm để giải phong ấn Điệu Vong tộc. Cuối chương hé lộ bộ hài cốt trên tầng mười Tàng Hồn các chính là lão tổ Đại Hồn Môn, linh hồn bị nhốt trong hài cốt và quỳ trước tượng Vương Lâm. Hắn dâng não khô cùng trái tim đã ngừng đập, cầu xin tha thứ qua vô số năm.","anchor":"Mà bộ hài cốt thì chính là lão tổ Đại Hồn Môn. thiên tài của Điệu Vong tộc"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người nghi ngờ tính toán của hắn","ghiChu":"Vương Lâm liên hệ sự khách khí của lão tổ với chuỗi biến cố trong cấm cung."},{"ten":"Tiên Hoàng","tag":"khac","quanHe":"người trong chuỗi biến cố hắn bị nghi đã tính trước","ghiChu":"Vương Lâm cho rằng hắn có thể đã biết chuyện Tiên Hoàng đoạt xá và tự bạo."},{"ten":"Điệu Vong tộc","tag":"khac","quanHe":"thiên tài của tộc","ghiChu":"Kế hoạch của hắn nhằm giải phong ấn tộc nhân."},{"ten":"Đồ Thanh","tag":"cap-tren","quanHe":"ban chức trưởng lão","ghiChu":"Từng ban thưởng chức trưởng lão cho Đồ Thanh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1897","@c1898"],"vaiTro":"Lão tổ Đại Hồn Môn — thiên tài mưu lược bố cục xuyên ngàn vạn năm","tinhCach":"mưu trí thâm viễn, tính toán tinh mật vượt thời đại","blurb":"Lão tổ Đại Hồn Môn là nhân vật được Vương Lâm đánh giá là thiên tài vượt đời, người đã bố trí kế hoạch xuyên ngàn vạn năm. Ông từng tặng Vương Lâm mai rùa chứa bản đồ, giới thiệu về các Đại Thiên Tôn, đồng thời để lại ngọc giản tính toán giúp Vương Lâm nhìn rõ nhiều bí ẩn then chốt liên quan đến Tiên Tộc và hoàng thành."},{"id":"vo-phong","name":"Võ Phong","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Đại Thiên Tôn @c1898","trangThai":"song @c1898","blurb":"Một Đại Thiên Tôn của tiên tộc, sau biến cố hoàng cung trở về Bắc châu bế quan trong sông băng. Hắn mang Trớ Thuật trong người nhưng có điều kiện hóa giải nhẹ hơn Đạo Nhất và Cửu Đế.","vaiTro":"Đại Thiên Tôn tiên tộc","tinhCach":[{"text":"thận trọng trong biến cố, ít trực tiếp ra tay","chuong":"@c1898"},{"text":"chịu đựng bế quan để tự hóa giải nguyền rủa","chuong":"@c1898"}],"tabs":{"diem":[{"text":"Trở về dòng sông băng Bắc châu và tự đóng băng toàn thân để xua Trớ Thuật.","chuong":"@c1898"},{"text":"Đã đạt được hai tai của Tiên Tổ, có khả năng tăng tu vi sau khi trừ sạch hắc khí.","chuong":"@c1898"}],"kinhLich":[{"chuong":"@c1898","importance":"normal","mucCt":"vua","tieuDe":"Đóng băng hóa chú","text":"Võ Phong trở về dòng sông băng tại Bắc châu và lập tức đóng băng toàn thân để xua Trớ Thuật. Vì hắn ít ra tay trong biến cố, Trớ Thuật dễ hóa giải hơn Đạo Nhất và Cửu Đế, lại có hai tai Tiên Tổ giúp tu vi tăng sau khi thanh trừ hắc khí.","anchor":"Võ Phong về tới dòng sông băng tại Bắc châu lập tức đóng băng toàn thân"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Nhất","tag":"khac","quanHe":"cùng chịu Trớ Thuật sau biến cố","ghiChu":"Được so sánh về mức độ khó hóa giải Trớ Thuật."},{"ten":"Cửu Đế","tag":"khac","quanHe":"cùng chịu Trớ Thuật sau biến cố","ghiChu":"Được so sánh về mức độ khó hóa giải Trớ Thuật."},{"ten":"Tiên Tổ","tag":"khac","quanHe":"giữ bộ phận thân thể","ghiChu":"Đạt được hai tai của Tiên Tổ."}],"tuiDo":{"phapBao":[{"ten":"Hai tai của Tiên Tổ","trangThai":"dang-co","moTa":"Chiến lợi phẩm giúp tu vi Võ Phong có thể tăng sau khi hóa giải Trớ Thuật.","nguon":"@c1898"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1898"]},{"id":"viem-loan","name":"Viêm Loan","trangThai":"song @c1898","tabs":{"diem":[{"text":"Là nữ tu Không Kiếp sơ kỳ, lão tổ Đại Hồn Môn bế quan gần địa hỏa mạch tại Viêm Mạch Phong.","chuong":"@c1726"},{"text":"Phát hiện địa hỏa chủ mạch bị hấp thu, nổi sát cơ và dung nhập đại địa truy kích Vương Lâm.","chuong":"@c1728"},{"text":"Tại Tàng Hồn Các, đánh cược với Vương Lâm bằng cây ô màu lam rồi để mất pháp bảo vì kiêu ngạo.","chuong":"@c1740"},{"text":"Giao bản đồ biển cho Vương Lâm khi nhận ra hắn cần thủy bổn nguyên, giúp hắn xác định lộ trình về phía Đông.","chuong":"@c1745"},{"text":"Tham gia chiến sự Thiên Ngưu, cùng các tu sĩ Đại Hồn Môn giao chiến với lực lượng Lục Ma Châu.","chuong":"@c1760"},{"text":"Cùng các tu sĩ Không Kiếp tiễn Vương Lâm rời đi, rồi dẫn tu sĩ Thiên Ngưu đệ tam huyệt rút đi.","chuong":"@c1786"}],"kinhLich":[{"chuong":"@c1898","importance":"bridge","mucCt":"vua","tieuDe":"Ở lại núi cũ","text":"Viêm Loan nay có địa vị cao trong Đại Hồn Môn và có thể quyết định một số đại sự. Nàng vẫn không rời ngọn núi cũ, thường nhìn về động phủ năm xưa của Vương Lâm trong trầm mặc.","anchor":"Viêm Loan trương lão năm xưa lúc này đã ở vị trí cao trong Đại Hồn Môn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"nhớ động phủ cũ","ghiChu":"Thường nhìn về động phủ năm xưa của Vương Lâm."},{"ten":"Phàn San Lộ","tag":"su-mon","quanHe":"sư phụ","ghiChu":"Phàn San Lộ vẫn là đệ tử của nàng."},{"ten":"Phàn San Mộng","tag":"su-mon","quanHe":"sư phụ","ghiChu":"Phàn San Mộng vẫn là đệ tử của nàng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1898"],"vaiTro":"Lão tổ Không Kiếp của Đại Hồn Môn","tinhCach":"quyết liệt khi truy kích kẻ xâm phạm địa hỏa; kiêu ngạo hiếu thắng; biết nhún nhường trước cường giả; quan sát thận trọng","blurb":"Viêm Loan là lão tổ Đại Hồn Môn, nữ tu Không Kiếp sơ kỳ bế quan tại Viêm Mạch Phong và là sư tôn của Phàn San Lộ, Phàn San Mộng. Nàng nhiều lần va chạm với Vương Lâm quanh địa hỏa mạch, Tàng Hồn Các và chiến sự Thiên Ngưu, về sau cùng các tu sĩ Không Kiếp chứng kiến Vương Lâm rời đi. Tới hậu kỳ, nàng vẫn ở lại núi cũ, có địa vị cao và có thể quyết định một số đại sự trong Đại Hồn Môn."},{"id":"phan-san-lo","name":"Phàn San Lộ","trangThai":"song @c1898","tabs":{"diem":[{"text":"Từ hắc động xuất thủ đỡ chỉ phong bảy màu cứu Vương Lâm, tiết lộ thân phận đệ tử Đại Hồn Môn và đề nghị hợp tác","chuong":"@c1597"},{"text":"Bị Vương Lâm vạch trần giả dạng Phàn San Mộng, buộc phải thừa nhận thân phận thật là Phàn San Lộ","chuong":"@c1603"},{"text":"Trao ngọc giản chứa bản đồ tế đàn và thuật thôn hồn cho Vương Lâm, lập thệ huyết liên minh","chuong":"@c1605"},{"text":"Nhờ huyết mạch Tiên Cương tự mở đại môn động phủ giới, rời đi trở về quê hương","chuong":"@c1694"},{"text":"Tu luyện tại Viêm Mạch Phong, mở động phủ địa hỏa chủ mạch tiếp đón Vương Lâm","chuong":"@c1727"},{"text":"Theo sư tôn Viêm Loan nghênh chiến Vương Lâm; tư oán năm xưa đã dần hóa giải","chuong":"@c1898"}],"kinhLich":[{"chuong":"@c1898","importance":"bridge","mucCt":"gon","tieuDe":"Vẫn theo Viêm Loan","text":"Phàn San Lộ vẫn là đệ tử của Viêm Loan, tư oán năm xưa với Vương Lâm đã hóa giải và dần bị thời gian làm phai nhạt.","anchor":"Phàn San Lộ, Phàn San Mộng vẫn là đệ tử của nàng như trước"}],"tuViMoc":[],"nhanMach":[{"ten":"Viêm Loan","tag":"su-mon","quanHe":"đệ tử","ghiChu":"Vẫn theo Viêm Loan tại Đại Hồn Môn."},{"ten":"Vương Lâm","tag":"khac","quanHe":"tư oán đã hóa giải","ghiChu":"Tư oán năm xưa đã dần bị quên đi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1898"],"vaiTro":"Đệ nhất phi Thất Đạo Tông — đệ tử hạch tâm Đại Hồn Môn, muội muội Phàn San Mộng","tinhCach":"Cẩn trọng, không dễ tin người từ Tiên Cương đại lục; kiên nhẫn chờ cơ hội báo thù; trọng lời hứa, giữ thệ ước; quyết đoán trong chiến đấu","blurb":"Phàn San Lộ là đệ nhất phi trong thất phi của Thất Đạo Tông, thân phận thật là muội của Phàn San Mộng và đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn. Bị Thất Thải Thiên Tôn truy sát, nàng ẩn náu trong hắc động khe sâu Yêu Tông cũ, sau đó xuất thủ cứu Vương Lâm và thiết lập thệ huyết liên minh, trao bản đồ tế đàn cùng thuật thôn hồn. Rời động phủ giới trở về Tiên Cương đại lục, nàng tu luyện tại Viêm Mạch Phong dưới trng sư tôn Viêm Loan; tư oán năm xưa với Vương Lâm dần được thời gian hóa giải."},{"id":"phan-san-mong","name":"Phàn San Mộng","trangThai":"song @c1898","tabs":{"diem":[{"text":"Lộ diện từ thân xác Phàn San Lộ, xưng danh và tiết lộ bí mật Thái Cổ Thần Cảnh","chuong":"@c1599"},{"text":"Thi triển Đại Hồn chân ảo thuật từ xa nhằm biến Vương Lâm thành con rối, bị phá giải","chuong":"@c1604"},{"text":"Phản bội Thất Thải Thiên Tôn, câu dẫn Liên Đạo Phi dẫn ngoại nhân can thiệp","chuong":"@c1606"},{"text":"Được xác nhận là đạo lữ duy nhất của Thất Thải Thiên Tôn","chuong":"@c1651"},{"text":"Bị Vương Lâm chỉ mặt đòi làm nữ hầu trước mặt sư tôn Viêm Loan","chuong":"@c1735"},{"text":"Tư oán với Vương Lâm dần hóa giải, vẫn theo sư tôn Viêm Loan","chuong":"@c1898"}],"kinhLich":[{"chuong":"@c1898","importance":"bridge","mucCt":"gon","tieuDe":"Vẫn theo Viêm Loan","text":"Phàn San Mộng vẫn là đệ tử của Viêm Loan, tư oán năm xưa với Vương Lâm đã hóa giải và dần bị thời gian làm phai nhạt.","anchor":"Phàn San Lộ, Phàn San Mộng vẫn là đệ tử của nàng như trước"}],"tuViMoc":[],"nhanMach":[{"ten":"Viêm Loan","tag":"su-mon","quanHe":"đệ tử","ghiChu":"Vẫn theo Viêm Loan tại Đại Hồn Môn."},{"ten":"Vương Lâm","tag":"khac","quanHe":"tư oán đã hóa giải","ghiChu":"Tư oán năm xưa đã dần bị quên đi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1898"],"vaiTro":"Tỷ tỷ Phàn San Lộ — đệ tử hạch tâm Đại Hồn Môn, cựu đạo lữ duy nhất của Thất Thải Thiên Tôn","tinhCach":"Mưu mô thâm trầm, giỏi ẩn nhẫn chờ thời; phản trắc, sẵn sàng phản bội đồng minh để mưu lợi; tự phụ về trí mưu nhưng hay đánh giá thấp đối thủ; cam chịu khi thất thế, dần buông bỏ oán hận","blurb":"Phàn San Mộng là tỷ tỷ của Phàn San Lộ, đệ tử trung tâm Đại Hồn Môn và một trong song kiêu, tu luyện nặng về Huyễn Thuật, đồng thời là đạo lữ duy nhất của Thất Thải Thiên Tôn. Năm xưa nàng phản bội Thất Thải Thiên Tôn, câu dẫn Liên Đạo Phi can thiệp, rồi ẩn mình trong băng sơn ở Tiên Cương đại lục và từng ký sinh trong thân xác muội muội. Sau khi mưu kế biến Vương Lâm thành con rối bằng Đại Hồn chân ảo thuật bị phá giải, nàng rơi vào thế bị động, phải theo sư tôn Viêm Loan tới Viêm Mạch Phong và cuối cùng bị Vương Lâm sai khiến như nữ hầu, tư oán dần hóa giải theo thời gian."},{"id":"do-thanh","name":"Đồ Thanh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1898","trangThai":"song @c1898","blurb":"Đỗ Thanh là người sáng lập kiêm thái thượng trưởng lão Thương Long Tông, một khôi lỗi thân thể con rối đối ngoại xưng Không Kiếp sơ kỳ nhưng thực tế tu vi chỉ dừng ở bảy lần Huyền Kiếp. Khi xuất ngoại trở về phát hiện tông phái bị hủy diệt, ông rống giận kinh thiên và truy sát Vương Lâm suốt hơn hai mươi ngày, cuối cùng bị bảy đạo bổn nguyên cùng kim ấn mang khí tức Đại Thiên Tôn trấn áp nên từ bỏ ý truy sát, chuyển sang hộ pháp cho Vương Lâm. Về sauông trở thành trưởng lão mới của Đại Hồn Môn.","vaiTro":"Sáng lập kiêm thái thượng trưởng lão Thương Long Tông — khôi lỗi tu vi bảy lần Huyền Kiếp","tinhCach":"Phẫn nộ dữ dội và truy sát không ngừng khi tông phái bị hủy; biết đánh giá tình thế, chịu khuất phục trước thực lực áp đảo; trọng lời hứa, chuyển từ đối đầu sang hộ pháp tận tâm; cẩn trọng suy đoán lai lịch đối phương qua manh mối pháp thuật","tabs":{"diem":[{"text":"Người đầu tiên của Thương Long Tông đạt cảnh giới Không Kiếp (đối ngoại), thực chất bảy lần Huyền Kiếp","chuong":"@c1715"},{"text":"Trở về phát hiện tông phái bị hủy diệt, rống giận kinh thiên, phát lệnh truy sát Vương Lâm","chuong":"@c1711"},{"text":"Truy kích Vương Lâm hơn hai mươi ngày, nội tâm liên tục dao động trước các manh mối pháp thuật","chuong":"@c1715"},{"text":"Bị bảy đạo bổn nguyên và kim ấn Đại Thiên Tôn trấn áp, từ bỏ ý truy sát","chuong":"@c1718"},{"text":"Chuyển sang hộ pháp cho Vương Lâm, chứng kiến ngưng tụ bổn nguyên chân thân và trấn áp long hồn","chuong":"@c1720"},{"text":"Trở thành trưởng lão mới của Đại Hồn Môn, thân thể là con rối chứ không phải huyết nhục","chuong":"@c1898"}],"kinhLich":[{"chuong":"@c1898","importance":"normal","mucCt":"vua","tieuDe":"Trưởng lão thân rối","text":"Đồ Thanh trở thành trưởng lão mới của Đại Hồn Môn. Thân thể hắn không phải huyết nhục mà là con rối, nguyên thần ngưng tụ thành thân thể, chức trưởng lão do lão tổ Đại Hồn Môn ban thưởng chứ không nhờ tu vi đạt chuẩn.","anchor":"Người này tên là Đồ Thanh, thân thể cũng không phải là huyết nhục mà là một con rối"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão tổ Đại Hồn Môn","tag":"cap-tren","quanHe":"được ban chức trưởng lão","ghiChu":"Chức vị trưởng lão của Đồ Thanh do lão tổ Đại Hồn Môn ban thưởng."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Thân thể con rối","trangThai":"dang-co","moTa":"Thân thể không phải huyết nhục, nguyên thần ngưng tụ thành thân thể.","nguon":"@c1898"}]}},"nguon":["@c1898"]},{"id":"con-ran-nho-hinh-rong","name":"Con rắn nhỏ hình rồng","aliases":["ngũ long của Lưu Kim Bưu"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Con rắn nhỏ hình rồng đi cùng Lưu Kim Bưu trong hành trình qua Hàn Châu. Nó giúp chủ nhân chống lại hàn khí bằng hơi thở của mình.","vaiTro":"Linh thú đi cùng Lưu Kim Bưu","tinhCach":[{"text":"Trung thành đi theo Lưu Kim Bưu","chuong":"@c1899"},{"text":"Có khả năng hỗ trợ chống lạnh","chuong":"@c1899"}],"tabs":{"diem":[{"text":"Nằm trên vai Lưu Kim Bưu trong lúc vượt qua vùng tuyết lạnh.","chuong":"@c1899"},{"text":"Mỗi khi Lưu Kim Bưu sắp đông cứng lại thì thở ra một hơi giúp hắn chống chịu.","chuong":"@c1899"}],"kinhLich":[{"mucCt":"gon","text":"Con rắn nhỏ hình rồng nằm trên vai Lưu Kim Bưu và thở khí giúp hắn tiếp tục chống chịu hàn khí trên đường qua Hàn Châu.","anchor":"mỗi khi phát hiện ra nam tử kia sắp đông cứng lại liền thở ra một hơi","bridge":true,"khoang":"@c1899"}],"tuViMoc":[],"nhanMach":[{"ten":"Lưu Kim Bưu","tag":"dong-minh","quanHe":"đi theo","ghiChu":"Nằm trên vai Lưu Kim Bưu và hỗ trợ hắn chống lạnh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1899"]},{"id":"tieu-dao-hoa","name":"Tiểu Đào Hoa","gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Tiểu Đào Hoa được Hứa Lập Quốc nhắc tới khi khoe cuộc sống sung sướng tại tổ thành. Chưa có thêm hành động độc lập trong chương này.","vaiTro":"Người hầu được nhắc tới","tinhCach":[{"text":"Chưa rõ tính cách","chuong":"@c1899"}],"tabs":{"diem":[{"text":"Được Hứa Lập Quốc nhắc cùng Tiểu Đào Hồng và Tiểu Đào Lam trong lời khoe khoang.","chuong":"@c1899"}],"kinhLich":[{"chuong":"@c1899","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc ở tổ thành","text":"Tiểu Đào Hoa được Hứa Lập Quốc nhắc đến khi hắn khoe chuyện được hầu hạ ở tổ thành.","anchor":"còn có Tiểu Đào Hoa. Tiểu Đào Hồng. Tiểu Đào Lam hầu hạ bên giường"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"được nhắc trong lời khoe khoang","ghiChu":"Hứa Lập Quốc nhắc Tiểu Đào Hoa khi kể về cuộc sống ở tổ thành."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1899"]},{"id":"tieu-dao-hong","name":"Tiểu Đào Hồng","gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Tiểu Đào Hồng được Hứa Lập Quốc nhắc cùng Tiểu Đào Hoa và Tiểu Đào Lam. Chương này chỉ cho biết nàng nằm trong lời khoe khoang về cuộc sống ở tổ thành.","vaiTro":"Người hầu được nhắc tới","tinhCach":[{"text":"Chưa rõ tính cách","chuong":"@c1899"}],"tabs":{"diem":[{"text":"Được nhắc trong nhóm người hầu bên cạnh Hứa Lập Quốc tại tổ thành.","chuong":"@c1899"}],"kinhLich":[{"chuong":"@c1899","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc ở tổ thành","text":"Tiểu Đào Hồng được Hứa Lập Quốc nhắc đến trong lời khoe khoang về những ngày sung sướng.","anchor":"còn có Tiểu Đào Hoa. Tiểu Đào Hồng. Tiểu Đào Lam hầu hạ bên giường"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"được nhắc trong lời khoe khoang","ghiChu":"Hứa Lập Quốc nhắc Tiểu Đào Hồng khi kể về cuộc sống ở tổ thành."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1899"]},{"id":"tieu-dao-lam","name":"Tiểu Đào Lam","gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"không rõ","trangThai":"khong-ro","blurb":"Tiểu Đào Lam được Hứa Lập Quốc nhắc tới trong đoạn khoe cuộc sống ở tổ thành. Chưa có thêm chi tiết riêng ngoài lời nhắc này.","vaiTro":"Người hầu được nhắc tới","tinhCach":[{"text":"Chưa rõ tính cách","chuong":"@c1899"}],"tabs":{"diem":[{"text":"Được Hứa Lập Quốc nhắc cùng Tiểu Đào Hoa và Tiểu Đào Hồng.","chuong":"@c1899"}],"kinhLich":[{"chuong":"@c1899","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc ở tổ thành","text":"Tiểu Đào Lam được Hứa Lập Quốc nhắc đến khi hắn trêu tức Lưu Kim Bưu bằng chuyện hưởng thụ ở tổ thành.","anchor":"còn có Tiểu Đào Hoa. Tiểu Đào Hồng. Tiểu Đào Lam hầu hạ bên giường"}],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"được nhắc trong lời khoe khoang","ghiChu":"Hứa Lập Quốc nhắc Tiểu Đào Lam khi kể về cuộc sống ở tổ thành."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1899"]},{"id":"thanh-thuy","name":"Thanh Thủy","gioiTinh":"nam","trangThai":"song","tabs":{"diem":[{"text":"Vốn là thái tử Thanh Thủy Quốc, sau biến cố cố quốc bị diệt đã thức tỉnh Cực Cảnh, quay về bảy ngày đẫm máu tàn sát kẻ thù rồi tự phong ấn vì sát nghiệp quá nặng","chuong":"@c1462"},{"text":"Hiện thân bảo hộ Vương Lâm trước Huyết Thần Tử, lấy thân phận truyền nhân Bạch Phàm công khai nhận sư đệ và truyền thừa tiên thuật Hoán Vũ, Tát Đậu Thành Binh","chuong":"@c0816"},{"text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá Không Môn, đột phá vào Không Niết Sơ Kỳ — bước thứ ba","chuong":"@c1467"},{"text":"Hóa thân thành Vương Lâm tọa trấn đài chiến Vân Hải, thay sư đệ bế quan ứng chiến, bị Hư Thần Thiên Tôn trọng thương gần chết","chuong":"@c1494"},{"text":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn, giải thích cuộc đời thê thảm và nguồn gốc sức mạnh","chuong":"@c1650"},{"text":"Cùng con gái Hồng Điệp bước vào chuyển thế đầu thai, nhờ Vương Lâm nếu tìm được con gái thì thay mình chiếu cố","chuong":"@c1696"}],"kinhLich":[{"chuong":"@c1900","importance":"bridge","mucCt":"gon","tieuDe":"Chưa tìm thấy ở tiên tộc","text":"Thanh Thủy được Vương Lâm nhắc trong tiếc nuối vì trước khi rời tiên tộc hắn đã tìm kiếm nhưng không gặp.","anchor":"Đáng tiếc là ở tiên tộc ta lại không tìm được Thanh Thủy"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1900"],"vaiTro":"Tiên quân Cực Cảnh — sư huynh đồng mạch Bạch Phàm của Vương Lâm, phách thứ nhất Thất Thải Tiên Tôn","tinhCach":"trọng nghĩa đồng môn, nhiều lần xả thân bảo hộ Vương Lâm; sát phạt quyết liệt, mang sát nghiệp nặng nề từ viễn cổ; thận trọng đa nghi, không dễ tin người; nặng tình thân, nguyện cùng con gái chuyển thế đầu thai","blurb":"Thanh Thủy vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới, sau khi cố quốc bị diệt vong đã thức tỉnh Cực Cảnh, quay về tàn sát kẻ thù rồi mang sát nghiệp cùng cực và tự phong ấn. Là sư huynh đồng mạch Bạch Phàm của Vương Lâm, ông nhiều lần hiện thân bảo hộ, truyền thừa tiên thuật Hoán Vũ và Tát Đậu Thành Binh, về sau dùng sát lục bổn nguyên phá Không Môn bước vào Không Niết Sơ Kỳ. Thân phận được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cuối cùng ông cùng con gái Hồng Điệp bước vào chuyển thế, nhờ Vương Lâm chiếu cố con gái nếu tìm được."},{"id":"tu-do","name":"Tư Đồ","gioiTinh":"nam","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"chuong":"@c1900","importance":"bridge","mucCt":"gon","tieuDe":"Chưa tìm thấy ở tiên tộc","text":"Tư Đồ được Vương Lâm nhắc trong nhóm người quen chưa tìm được trước khi rời tiên tộc.","anchor":"không tìm được Thanh Thủy, không tìm được Tư Đồ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1900"]},{"id":"ly-thien-mai","name":"Lý Thiến Mai","gioiTinh":"nu","trangThai":"song","tabs":{"diem":[{"text":"Thiên tài tu đạo truyền kỳ Vân Hải tinh vực: 5 tuổi nhập đạo, hơn 1200 năm đạt Toái Niết hậu kỳ","chuong":"@c1090"},{"text":"Luận đạo cùng Vương Lâm tại Bồng Lai, đặt ba câu hỏi về thiên — đạo — nơi đi, kết hẹn ước trăm năm","chuong":"@c1097"},{"text":"Bất chấp lệnh cấm rời chiến trường Yêu Tông, vượt tinh vực tìm Vương Lâm, bị Phá Thiên Tông đoạn tuyệt sư đồ","chuong":"@c1200"},{"text":"Suốt mười năm hy sinh máu tươi và tinh huyết chăm sóc tượng đá Vương Lâm tại đại lục hoang dã, kiệt sức gần mất sinh cơ","chuong":"@c1214"},{"text":"Được Vương Lâm tiếp nhận sau khi khôi phục ký ức, xác nhận tình cảm giữa hai người","chuong":"@c1583"},{"text":"Quyết định chuyển thế đầu thai, nguyện chờ Vương Lâm trong luân hồi, là người cuối cùng rời đi","chuong":"@c1697"}],"kinhLich":[{"chuong":"@c1900","importance":"bridge","mucCt":"gon","tieuDe":"Chưa tìm thấy ở tiên tộc","text":"Lý Thiến Mai được Vương Lâm nhắc là một trong những người hắn chưa tìm thấy ở tiên tộc.","anchor":"Cũng không tìm được Lý Thiến Mai"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1900"],"vaiTro":"Nữ tu sĩ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ của Vương Lâm","tinhCach":"ham hỏi đạo, trọng bản tâm; nặng tình và giữ hẹn; kiên định trước sư mệnh, tông lệnh; sẵn sàng hy sinh vì người mình chọn","blurb":"Lý Thiến Mai, bí danh Lý Oánh Chi, là thiên chi kiêu nữ Vân Hải tinh vực xuất thân Phá Thiên Tông, năm tuổi nhập đạo, hơn 1200 năm tu luyện đạt Toái Niết hậu kỳ. Nàng kết giao với Vương Lâm qua luận đạo tại Bồng Lai, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp tông lệnh vượt tinh vực tìm hắn, bị đoạn tuyệt sư đồ và hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm suốt mười năm đến kiệt quệ mất trí nhớ. Sau khi dần khôi phục ký ức và được Vương Lâm tiếp nhận, nàng quyết định chuyển thế đầu thai, nguyện chờ hắn trong luân hồi."},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","aliases":["Uyển Nhi"],"gioiTinh":"nu","trangThai":"khong-ro","tabs":{"diem":[{"text":"Bị Song Tu Môn truy sát vì Thiên Ly đan, được Vương Lâm cứu giúp, mở đầu mối duyên giữa hai người","chuong":"@c0123"},{"text":"Trong bốn năm đồng hành tại Tu Ma Hải, khắc 18.974 ngọc giản đan phương, thể hiện thiên phú luyện đan phi phàm","chuong":"@c0135"},{"text":"Ba lần Kết Anh thất bại, thọ nguyên cạn kiệt không quá mười năm, thân xác suy kiệt tang thương","chuong":"@c0302"},{"text":"Thân xác hóa xương khô, kim đan nứt vỡ, nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành Chu Như","chuong":"@c0313"},{"text":"Từ chối cắn nuốt hồn phách Chu Như, tự đẩy nguyên anh ra khỏi thân thể để cứu cô bé, hy sinh cơ hội tái sinh","chuong":"@c0381"},{"text":"Tàn hồn được phát hiện dung nhập trong thân Tống Trí, Vương Lâm dùng một năm phân tách tàn hồn ra, nhưng hồn phách vẫn thiếu một phần chưa rõ tung tích","chuong":"@c0929"}],"kinhLich":[{"chuong":"@c1900","importance":"normal","mucCt":"vua","tieuDe":"Hồn phách còn thiếu","text":"Lý Mộ Uyển được Vương Lâm nhớ tới với đau thương. Tình trạng một tia hồn phách chưa rõ tung tích tiếp tục là mục tiêu khiến hắn muốn đạt tới Đại Thiên Tôn để tìm kiếm.","anchor":"Một tia hồn phách của nàng rốt cục đang ở nơi nào"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1900"],"vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, tu sĩ tài hoa luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp; kiên cường chịu đựng trước thọ nguyên cạn kiệt và ba lần Kết Anh thất bại; nặng tình sâu sắc với Vương Lâm; giàu lòng trắc ẩn, tự từ bỏ cơ hội tái sinh để cứu Chu Như","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ, nổi bật với thiên phú luyện đan và trận pháp, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu giúp, cùng hắn trải qua bốn năm đồng hành tại Tu Ma Hải. Sau hơn trăm năm, ba lần Kết Anh thất bại khiến thọ nguyên cạn kiệt, thân xác hóa xương khô, nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành bé gái Chu Như nhưng cuối cùng nàng tự đẩy nguyên anh ra để cứu Chu Như, rồi được Vương Lâm gìn giữ nguyên anh suốt hàng trăm năm. Tới mốc sau cùng, tàn hồn nàng được phát hiện dung nhập trong thân Tống Trí và được Vương Lâm dùng một năm phân "},{"id":"diep-mich","name":"Diệp Mịch","gioiTinh":"nam","trangThai":"khong-ro","tabs":{"diem":[{"text":"Hóa thân thể khổng lồ chém giết trong vùng đất cổ mộ nhưng bị bắn rơi mắt trái, khiến truyền thừa về sau không hoàn chỉnh","chuong":"@c1481"},{"text":"Khí tức Đạo Cổ biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu bùng phát từ chín quan tài trên tấm bia đá khổng lồ","chuong":"@c1576"},{"text":"Nguyên thần ngưng tụ từ huyết mưu đoạt xá Vương Lâm, bị đánh bại và tiêu tán vĩnh viễn","chuong":"@c1672"},{"text":"Trái tim khổng lồ trăm trượng ở tầng cuối cổ mộ mang thần niệm oán hận được truyền thừa cho Vương Lâm","chuong":"@c1680"},{"text":"Năm đó chỉ đạt ba giọt máu cổ tổ, bị Vương Lâm — người thừa kế — vượt qua","chuong":"@c1613"},{"text":"Được suy xét có thực lực tương đương Thiên Tôn trong hệ thống lực lượng Cổ Tộc","chuong":"@c1903"}],"kinhLich":[{"mucCt":"vua","text":"Diệp Mịch được Vương Lâm nhắc là người liên quan tới huyết kiếm và đầu lâu truyền thừa. Vương Lâm nhớ lời hứa với ông và dự định tìm hậu nhân Diệp Mịch trong chuyến tới Đạo Cổ.","anchor":"Ta cuối cùng sau khi truyền thừa đầu lâu của Diệp Mịch đã từng hứa với hắn","bridge":true,"khoang":"@c1900"},{"chuong":"@c1903","importance":"bridge","mucCt":"gon","tieuDe":"Được so sánh thực lực","text":"Diệp Mịch được Vương Lâm dùng làm mốc suy xét về hệ thống lực lượng Cổ Tộc và khả năng tương đương Thiên Tôn.","anchor":"Vậy có thể thấy Diệp Mịch rất có khả năng có thực lực tương đương với Thiên Tôn"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1900","@c1903"],"vaiTro":"Đạo Cổ — chủ nhân cổ mộ truyền thừa, nguồn gốc sức mạnh thể chất mà Vương Lâm thừa kế","tinhCach":"kiên ngạnh bất khuất, dù thất bại vẫn lưu lại truyền thừa cho hậu nhân; mưu tính thâm viễn, ẩn giấu nguyên thần trong huyết mưu đoạt xá người thừa kế; oán niệm dai dẳng, thần niệm thê lương tồn tại đến tận di thể cuối cùng","blurb":"Diệp Mịch, được gọi là Đạo Cổ, là chủ nhân vùng đất cổ mộ và nguồn gốc toàn bộ truyền thừa thể chất mà Vương Lâm tiếp nhận. Năm xưa từng hóa thân thể khổng lồ chém giết trong cổ mộ, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh; di thể gồm đầu lâu, hai cánh tay, trái tim cùng lầu các địa phủ chứa ba thần hồn lần lượt được Vương Lâm dung hợp. Nguyên thần ẩn trong huyết từng mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn, trái tim khổng lồ trăm trượng ở tầng sâu nhất cổ mộ mang thần niệm oán hận trở thành di sản truyền th"},{"id":"van-thu","name":"Văn Thú","gioiTinh":"khong-ro","trangThai":"song","tabs":{"diem":[{"text":"Đột phá từ hạ phẩm linh cấp lên trung phẩm linh cấp, tương đương Nguyên Anh hậu kỳ đại viên mãn.","chuong":"@c0266"},{"text":"Được xác nhận là hung thú đến từ tinh không, sống bằng cắn nuốt vạn vật và hung tính vượt xa yêu thú tu chân.","chuong":"@c0479"},{"text":"Sau trăm năm tế luyện bằng lượng nguyên tinh khổng lồ, lột xác thành công với khí tức ngang Tịnh Niết.","chuong":"@c1153"},{"text":"Tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới rồi xác lập vương quyền trong đàn Văn Thú.","chuong":"@c1169"},{"text":"Bất chấp nguy hiểm lột xác nhiều lần, hi sinh thân thể để đưa giọt máu của Vương Lâm vào đài cao và đánh thức chủ nhân.","chuong":"@c1703"},{"text":"Sau khi tới Tiên Cương đại lục, tiếp tục hiện thân làm tọa kỵ, nhiều lần chở Vương Lâm di chuyển và thoát thân.","chuong":"@c1773"}],"kinhLich":[{"chuong":"@c1900","importance":"normal","mucCt":"vua","tieuDe":"Bay theo về cổ Tộc","text":"Văn Thú được Vương Lâm thả ra trong hành trình về cổ Tộc. Nó bay theo trên bầu trời và phát tiếng rít vui sướng.","anchor":"Điểm đen đó chính là Văn Thú"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1900"],"vaiTro":"Linh thú tọa kỵ trung thành của Vương Lâm","tinhCach":"Trung thành hộ chủ; hung mãnh khát máu; nặng tình đồng tộc; kiên quyết tìm chủ","blurb":"Văn Thú, còn được gọi là con muỗi khổng lồ, là hung thú đến từ tinh không và trở thành tọa kỵ, linh thú hộ chủ lâu dài của Vương Lâm. Nó trải qua nhiều lần lột xác, khuất phục các đàn Văn Thú tại Phong Tiên Giới, tiến hóa thành Văn Thú Vương mới và tiếp tục theo Vương Lâm qua hư vô đến Tiên Cương đại lục."},{"id":"dai-han-co-than-thu-nhat-o-hac-thach-thanh","name":"Đại hán Cổ Thần thứ nhất ở Hắc Thạch Thành","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hắc Thạch Thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cổ Thần năm tinh @c1901","trangThai":"song","blurb":"Binh sĩ bì giáp Cổ Thần năm tinh ở cửa Hắc Thạch Thành. Hắn ban đầu chặn hỏi Vương Lâm, sau đó cung kính dâng ngọc giản bản đồ khi thấy chín tinh điểm cổ Thần.","vaiTro":"Binh sĩ cửa Hắc Thạch Thành","tinhCach":[{"text":"Làm đúng chức trách kiểm tra thân phận người vào thành","chuong":"@c1901"},{"text":"Kính sợ cửu tinh cổ Thần và nhanh chóng đổi thái độ","chuong":"@c1901"}],"tabs":{"diem":[{"text":"Chất vấn Vương Lâm vì hắn đứng ngoài thành quá lâu và không lập tức vào thành.","chuong":"@c1901"},{"text":"Dâng ngọc giản bản đồ sơ lược cho Vương Lâm sau khi nhận ra địa vị cửu tinh cổ Thần.","chuong":"@c1901"}],"kinhLich":[{"mucCt":"vua","text":"Đại hán Cổ Thần thứ nhất chặn hỏi Vương Lâm ở cửa Hắc Thạch Thành, yêu cầu lệnh bài thân phận theo lệnh cấm thành. Sau khi thấy Vương Lâm hiển lộ chín tinh điểm, hắn kính cẩn xưng thần thánh đại nhân và dâng ngọc giản bản đồ tuy chỉ ghi rõ vài quận phụ cận.","anchor":"Ngọc giản này của tiểu nhân ghi chép không được đầy đủ","bridge":true,"khoang":"@c1901"}],"tuViMoc":[{"chuong":"@c1901","canhGioi":"Cổ Thần năm tinh","text":"Khi xuất hiện tại cửa Hắc Thạch Thành, hắn được mô tả là đại hán Cổ Thần năm tinh.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người bị kiểm tra rồi được kính phục","ghiChu":"Chặn hỏi Vương Lâm trước khi nhận ra cửu tinh cổ Thần."},{"ten":"Đại hán Cổ Thần thứ hai ở Hắc Thạch Thành","tag":"dong-minh","quanHe":"đồng bạn canh cửa","ghiChu":"Cùng kiểm tra thân phận người ngoài thành."}],"tuiDo":{"phapBao":[{"ten":"Ngọc giản bản đồ của binh sĩ Hắc Thạch Thành","loai":"ngọc giản bản đồ","trangThai":"mat","moTa":"Đã dâng cho Vương Lâm.","nguon":"@c1901"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1901"]},{"id":"dai-han-co-than-thu-hai-o-hac-thach-thanh","name":"Đại hán Cổ Thần thứ hai ở Hắc Thạch Thành","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hắc Thạch Thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cổ Thần năm tinh @c1901","trangThai":"song","blurb":"Binh sĩ bì giáp Cổ Thần năm tinh cùng đồng bạn canh cửa Hắc Thạch Thành. Hắn yêu cầu Vương Lâm đưa tộc ấn rồi cùng lui lại hành lễ khi thấy chín tinh điểm.","vaiTro":"Binh sĩ cửa Hắc Thạch Thành","tinhCach":[{"text":"Cứng rắn khi thi hành kiểm tra thân phận","chuong":"@c1901"},{"text":"Tỏ ra kính sợ trước địa vị cửu tinh cổ Thần","chuong":"@c1901"}],"tabs":{"diem":[{"text":"Yêu cầu Vương Lâm xuất trình tộc ấn cổ tộc.","chuong":"@c1901"},{"text":"Cùng đồng bạn hành lễ sau khi Vương Lâm hiển lộ chín tinh điểm.","chuong":"@c1901"}],"kinhLich":[{"mucCt":"vua","text":"Đại hán Cổ Thần thứ hai cùng đồng bạn chặn hỏi Vương Lâm bên ngoài Hắc Thạch Thành và yêu cầu hắn lấy tộc ấn ra. Khi Vương Lâm hiện chín tinh điểm, hắn cùng những binh sĩ khác đổi sang thái độ cung kính.","anchor":"Còn nữa. đem tộc ấn của ngươi ra đây","bridge":true,"khoang":"@c1901"}],"tuViMoc":[{"chuong":"@c1901","canhGioi":"Cổ Thần năm tinh","text":"Khi xuất hiện tại cửa Hắc Thạch Thành, hắn được mô tả là đại hán Cổ Thần năm tinh.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người bị kiểm tra rồi được kính phục","ghiChu":"Chặn hỏi Vương Lâm trước khi nhận ra cửu tinh cổ Thần."},{"ten":"Đại hán Cổ Thần thứ nhất ở Hắc Thạch Thành","tag":"dong-minh","quanHe":"đồng bạn canh cửa","ghiChu":"Cùng kiểm tra thân phận người ngoài thành."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1901"]},{"id":"nam-binh-si-bi-giap-con-lai-ngoai-cua-hac-thach-thanh","name":"Năm binh sĩ bì giáp còn lại ngoài cửa Hắc Thạch Thành","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Hắc Thạch Thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Nhóm năm binh sĩ bì giáp canh ngoài cửa Hắc Thạch Thành. Họ chứng kiến Vương Lâm hiển lộ chín tinh điểm và cùng hành lễ xưng thần thánh đại nhân.","vaiTro":"Binh sĩ cửa thành","tinhCach":[{"text":"Phục tùng kỷ luật thành trì","chuong":"@c1901"},{"text":"Kính sợ biểu tượng cửu tinh cổ Thần","chuong":"@c1901"}],"tabs":{"diem":[{"text":"Cùng đổi sắc mặt và tiến tới hành lễ khi nhận ra chín tinh điểm trên mi tâm Vương Lâm.","chuong":"@c1901"}],"kinhLich":[{"mucCt":"gon","text":"Năm binh sĩ bì giáp còn lại ngoài cửa Hắc Thạch Thành thấy phản ứng của hai đồng bạn và chín tinh điểm của Vương Lâm thì cùng tiến lên ôm quyền xưng thần thánh đại nhân.","anchor":"cả đám lập tức thần sắc đột biến, đều tiến đến hướng về phía Vương Lâm ôm quyền","bridge":true,"khoang":"@c1901"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"người được họ kính lễ","ghiChu":"Họ xưng Vương Lâm là thần thánh đại nhân sau khi thấy cửu tinh cổ Thần."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1901"]},{"id":"thanh-chu-hac-thach-thanh","name":"Thành chủ Hắc Thạch Thành","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Hắc Thạch Thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Người đứng đầu Hắc Thạch Thành được nhắc qua mệnh lệnh cấm thành. Lệnh của thành chủ buộc bốn cửa thành dọn sạch để nghênh đón hoàng tử và sứ đoàn Đạo Cổ.","vaiTro":"Người ra lệnh cấm thành","tinhCach":[{"text":"Quyết đoán trong việc chuẩn bị nghênh đón sứ đoàn","chuong":"@c1901"},{"text":"Nắm quyền điều phối cửa thành Hắc Thạch Thành","chuong":"@c1901"}],"tabs":{"diem":[{"text":"Ra lệnh dọn sạch bốn cửa thành và cấm thành ba ngày.","chuong":"@c1901"}],"kinhLich":[{"chuong":"@c1901","importance":"bridge","mucCt":"gon","tieuDe":"Lệnh cấm thành","text":"Thành chủ Hắc Thạch Thành được nhắc là người hạ lệnh dọn cửa thành để nghênh đón hoàng tử và sứ đoàn Đạo Cổ.","anchor":"bọn tại hạ phụng mệnh của thành chủ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1901"]},{"id":"hoang-tu-dao-co","name":"Hoàng tử Đạo Cổ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng tộc Đạo Cổ","trangThai":"gan-bo"},{"ten":"Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Hoàng tử thuộc Đạo Cổ được Hắc Thạch Thành chuẩn bị nghênh đón cùng sứ đoàn Đạo Cổ. Chương này chưa trực tiếp xuất hiện nhưng sự hiện diện sắp tới của hắn khiến thành trì phong tỏa.","vaiTro":"Hoàng tử được nghênh đón","tinhCach":[{"text":"Chưa thể hiện trực tiếp trong chương này","chuong":"@c1901"},{"text":"Địa vị đủ khiến Hắc Thạch Thành dọn sạch bốn cửa nghênh tiếp","chuong":"@c1901"}],"tabs":{"diem":[{"text":"Là nhân vật được Hắc Thạch Thành chuẩn bị nghênh đón cùng sứ đoàn Đạo Cổ.","chuong":"@c1901"}],"kinhLich":[{"chuong":"@c1901","importance":"bridge","mucCt":"gon","tieuDe":"Được Hắc Thạch nghênh đón","text":"Hoàng tử Đạo Cổ được nhắc là đối tượng sắp cùng sứ đoàn Đạo Cổ tới Hắc Thạch Thành.","anchor":"nghênh đón hoàng tử cùng với sứ đoàn của Đạo cổ tới"}],"tuViMoc":[],"nhanMach":[{"ten":"Hoàng đế Đạo cổ","tag":"ho-hang","quanHe":"cùng hoàng tộc Đạo Cổ","ghiChu":"Đều thuộc tuyến hoàng tộc Đạo Cổ được nhắc trong sự kiện sứ đoàn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1901"]},{"id":"hoang-de-dao-co","name":"Hoàng đế Đạo cổ","cn":"","aliases":["cổ Hoàng"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng tộc Đạo Cổ","trangThai":"gan-bo"},{"ten":"Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1902","trangThai":"song","blurb":"Hoàng đế của Đạo cổ được nhắc qua tin đồn muốn chọn phi tần. Tin này là nguyên nhân khiến sứ đoàn Đạo Cổ mấy trăm năm tìm mỹ nữ khắp cổ tộc.","vaiTro":"Hoàng đế Đạo cổ","tinhCach":[{"text":"Chưa trực tiếp xuất hiện trong chương này","chuong":"@c1901"},{"text":"Ý định chọn phi tần tạo ảnh hưởng rộng tới hoạt động của sứ đoàn","chuong":"@c1901"}],"tabs":{"diem":[{"text":"Tin đồn hoàng đế muốn chọn phi tần khiến sứ đoàn Đạo Cổ tìm mỹ nữ khắp cổ tộc.","chuong":"@c1901"}],"kinhLich":[{"chuong":"@c1901","importance":"bridge","mucCt":"gon","tieuDe":"Tin chọn phi tần","text":"Hoàng đế Đạo cổ được nhắc trong tin đồn muốn chọn phi tần, kéo theo việc sứ đoàn Đạo Cổ tìm mỹ nữ nhiều năm.","anchor":"Nghe nói.nghe nói hoàng đế Đạo cổ muốn chọn phi tần"}],"tuViMoc":[],"nhanMach":[{"ten":"Hoàng tử Đạo Cổ","tag":"ho-hang","quanHe":"cùng hoàng tộc Đạo Cổ","ghiChu":"Cùng thuộc tuyến hoàng tộc Đạo Cổ được nhắc trong chương."},{"ten":"Kế Đô hoàng tử","tag":"ho-hang","quanHe":"Hoàng quyền liên quan tới việc Kế Đô hoàng tử đi cùng sứ đoàn.","ghiChu":"Được nhắc ngoài Hắc Thạch thành @c1902"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1901","@c1902"]},{"id":"dai-han-bao-tin-ngoai-hac-thach-thanh","name":"Đại hán báo tin ngoài Hắc Thạch thành","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hắc Thạch thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ @c1902","trangThai":"song","blurb":"Một đại hán ở ngoài Hắc Thạch thành, người nói cho Vương Lâm biết tin về Kế Đô hoàng tử và sứ đoàn Đạo Cổ. Lời của hắn khiến Vương Lâm quyết định ở lại chờ cơ hội hỏi tin mười hai quận Đạo Cổ.","vaiTro":"Người báo tin ngoài thành","tinhCach":[{"text":"Biết tin tức về phong thành và sứ đoàn","chuong":"@c1902"},{"text":"Tuân phục lễ nghi trong Hắc Thạch thành","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Nói việc sứ đoàn đi cùng Kế Đô hoàng tử phải được cổ Hoàng đồng ý.","chuong":"@c1902"},{"text":"Cùng những đại hán khác quỳ khi thành chủ và hai thánh xuất hiện.","chuong":"@c1902"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Báo tin cho Vương Lâm về Kế Đô hoàng tử và sứ đoàn Đạo Cổ.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Lương Vân","tag":"cap-tren","quanHe":"Quỳ theo lễ khi thành chủ xuất hiện.","ghiChu":"Ngoài Hắc Thạch thành @c1902"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902"]},{"id":"luong-van","name":"Lương Vân","cn":"","aliases":["thành chủ Hắc Thạch thành","đại hán mặc kim giáp"],"gioiTinh":"nam","theLuc":[{"ten":"Hắc Thạch thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1903","trangThai":"song","blurb":"Lương Vân là thành chủ Hắc Thạch thành, mặc kim giáp và có địa vị đứng đầu nhóm ra nghênh Kế Đô hoàng tử. Ông đối đãi Vương Lâm khách khí nhưng vẫn tuân lễ nghi hoàng quyền, kinh hãi khi Vương Lâm không quỳ.","vaiTro":"Thành chủ Hắc Thạch thành","tinhCach":[{"text":"Khách khí khi tiếp người lạ có thực lực","chuong":"@c1902"},{"text":"Thận trọng với lễ nghi hoàng quyền","chuong":"@c1902"},{"text":"Có trách nhiệm giữ uy nghiêm Hắc Thạch thành","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Dẫn Khổng Ti, Mạch Lạc và gần một ngàn binh sĩ ra ngoài thành.","chuong":"@c1902"},{"text":"Tự giới thiệu là thành chủ Hắc Thạch thành và mời Vương Lâm ở lại.","chuong":"@c1902"},{"text":"Hỏi Vương Lâm về giai đoạn dung yêu luyện ma sau đệ nhị tôn.","chuong":"@c1902"},{"text":"Kinh hãi khi Vương Lâm không quỳ trước Kế Đô hoàng tử.","chuong":"@c1902"},{"text":"Mặc kim giáp, dẫn đầu nhóm người từ Hắc Thạch thành ra ngoài thành.","chuong":"@c1902"},{"text":"Nhận ra Vương Lâm có chín tinh điểm và dùng thái độ khách khí để thăm dò.","chuong":"@c1902"},{"text":"Biết hệ thống tu luyện thông, dung, luyện và nhắc tới dung yêu luyện ma.","chuong":"@c1902"},{"text":"Mặc kim giáp, dẫn đầu gần một ngàn binh sĩ cùng Khổng Ti và Mạch Lạc ra ngoài Hắc Thạch thành.","chuong":"@c1902"},{"text":"Nhận định Vương Lâm là thần thánh vượt qua đệ nhị tôn và hỏi về giai đoạn dung yêu luyện ma.","chuong":"@c1902"}],"kinhLich":[{"chuong":"@c1902","importance":"normal","mucCt":"ky","tieuDe":"Nghênh tiếp ngoài thành","text":"Lương Vân mặc kim giáp, dẫn Khổng Ti, Mạch Lạc và gần một ngàn binh sĩ ra ngoài Hắc Thạch thành. Ông tự xưng là thành chủ, tiếp đãi Vương Lâm khách khí, mời hắn ở lại chờ Kế Đô hoàng tử và hỏi về dung yêu luyện ma. Khi Kế Đô hoàng tử xuất hiện, Lương Vân quỳ lạy, kinh hãi vì Vương Lâm vẫn đứng và muốn tự tay giết hắn nhưng bị hoàng tử ngăn.","anchor":"Tại hạ là Lương Vân - thành chủ Hắc Thạch thành, không biết tộc hữu tới Hắc Thạch thành ta có cần trợ giúp gì chăng"},{"mucCt":"vua","text":"Lương Vân từng lộ sát ý với Vương Lâm vì chuyện không quỳ. Khi chứng kiến Cổ Yêu bị ánh mắt Vương Lâm làm sợ hãi, hắn run rẩy rồi theo lệnh Kế Đô đi mời Tống Trí.","anchor":"Đại hán mặc kim giáp kia thân thể cũng run rẩy","bridge":true,"khoang":"@c1903"},{"chuong":"@c1904","importance":"bridge","mucCt":"gon","tieuDe":"Bị phong khẩu","text":"Lương Vân bị Kế Đô truyền âm cấm tiết lộ mọi việc liên quan tới Vương Lâm tại Hắc Thạch Thành.","anchor":"ba người các ngươi sẽ bị tru di cửu tộc"}],"tuViMoc":[{"chuong":"@c1902","canhGioi":"thần thánh vượt qua đệ nhị tôn","text":"Lương Vân được mô tả thuộc tầng thần thánh và dùng cách nói sau đệ nhị tôn khi hỏi Vương Lâm về dung yêu luyện ma.","importance":"minor"},{"chuong":"@c1902","canhGioi":"thần thánh","text":"Lương Vân được mô tả là thần thánh của Hắc Thạch thành và bàn với Vương Lâm về giai đoạn sau đệ nhị tôn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tiếp đãi khách khí, mời ở lại chờ Kế Đô hoàng tử, sau đó kinh hãi vì Vương Lâm không quỳ.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Khổng Ti","tag":"dong-minh","quanHe":"Cùng ra ngoài thành nghênh đón Kế Đô hoàng tử.","ghiChu":"Thuộc nhóm Hắc Thạch thành @c1902"},{"ten":"Mạch Lạc","tag":"dong-minh","quanHe":"Cùng ra ngoài thành nghênh đón Kế Đô hoàng tử.","ghiChu":"Thuộc nhóm Hắc Thạch thành @c1902"},{"ten":"Kế Đô hoàng tử","tag":"cap-tren","quanHe":"Quỳ lạy và nghe lệnh trước uy nghi hoàng tử.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Tống Trí cô nương","tag":"khac","quanHe":"người được hắn mời ra theo lệnh Kế Đô","ghiChu":"Liên quan chuyến tuyển phi @c1903"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902","@c1903","@c1904"]},{"id":"khong-ti","name":"Khổng Ti","cn":"","aliases":["yêu thánh Hắc Thạch thành","Yêu Thánh"],"gioiTinh":"nam","theLuc":[{"ten":"Hắc Thạch thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1903","trangThai":"song","blurb":"Khổng Ti là yêu thánh của Hắc Thạch thành, nam tử trung niên mặc thanh sam với mắt trái có dị tượng yêu khí. Ông cùng Lương Vân và Mạch Lạc tiếp xúc Vương Lâm trước khi Kế Đô hoàng tử tới.","vaiTro":"Yêu thánh Hắc Thạch thành","tinhCach":[{"text":"Giữ lễ khi tự giới thiệu","chuong":"@c1902"},{"text":"Quan sát thận trọng người lạ có chín tinh điểm","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Tự giới thiệu với Vương Lâm bằng tên Khổng Ti.","chuong":"@c1902"},{"text":"Cùng nhóm Hắc Thạch thành chú ý tới chín tinh điểm trên mi tâm Vương Lâm.","chuong":"@c1902"},{"text":"Là nam tử trung niên mặc thanh sam, mắt trái có yêu khí biến hóa.","chuong":"@c1902"},{"text":"Tự giới thiệu ngắn gọn với Vương Lâm và cùng nhóm Lương Vân dò hỏi lai lịch hắn.","chuong":"@c1902"},{"text":"Tự giới thiệu với Vương Lâm và cùng Lương Vân dò hỏi lai lịch hắn.","chuong":"@c1902"},{"text":"Sững sờ khi Vương Lâm là người duy nhất không quỳ trước Kế Đô hoàng tử.","chuong":"@c1902"}],"kinhLich":[{"chuong":"@c1902","importance":"normal","mucCt":"vua","tieuDe":"Yêu thánh ra mặt","text":"Khổng Ti đi sau Lương Vân ra ngoài Hắc Thạch thành, chú ý tới chín tinh điểm trên mi tâm Vương Lâm và tự giới thiệu với hắn. Khi Kế Đô hoàng tử giáng lâm, ông quỳ lạy như mọi người rồi sững sờ trước việc Vương Lâm vẫn đứng.","anchor":"Không chỉ có hắn. còn cả hai người đằng sau cũng hầu như đồng thời quay đầu lại, ánh mắt ngưng tụ tái chín tinh điểm trên mi tâm Vương Lâm"},{"mucCt":"vua","text":"Khổng Ti chứng kiến Vương Lâm đi xuyên qua bàn tay Cổ Yêu mà không thấy yêu lực lan ra. Việc ấy khiến tâm thần hắn chấn động vì thủ đoạn của Vương Lâm vượt khỏi nhận biết thông thường của hắn.","anchor":"trong tâm thần Khổng Ti lúc này cũng nổi lên sóng gió ngập trời","bridge":true,"khoang":"@c1903"},{"chuong":"@c1904","importance":"bridge","mucCt":"gon","tieuDe":"Nghe lệnh phong khẩu","text":"Khổng Ti là một trong ba người bị Kế Đô cấm truyền ra chuyện liên quan tới Vương Lâm ở Hắc Thạch Thành.","anchor":"ba người các ngươi không được truyên ra ngoài"}],"tuViMoc":[{"chuong":"@c1902","canhGioi":"yêu thánh","text":"Khổng Ti được giới thiệu là yêu thánh của Hắc Thạch thành.","importance":"minor"}],"nhanMach":[{"ten":"Lương Vân","tag":"dong-minh","quanHe":"Cùng ra ngoài thành nghênh đón Kế Đô hoàng tử.","ghiChu":"Thuộc nhóm Hắc Thạch thành @c1902"},{"ten":"Mạch Lạc","tag":"dong-minh","quanHe":"Cùng ra ngoài thành nghênh đón Kế Đô hoàng tử.","ghiChu":"Thuộc nhóm Hắc Thạch thành @c1902"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Tự giới thiệu với Vương Lâm và quan sát lai lịch hắn.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Kế Đô hoàng tử","tag":"cap-tren","quanHe":"đối tượng quỳ lạy","ghiChu":"Khổng Ti quỳ lạy khi Kế Đô hoàng tử xuất hiện."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902","@c1903","@c1904"]},{"id":"mach-lac","name":"Mạch Lạc","cn":"","aliases":["ma thánh Hắc Thạch thành"],"gioiTinh":"nam","theLuc":[{"ten":"Hắc Thạch thành","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Ma thánh @c1902","trangThai":"song","blurb":"Mạch Lạc là ma thánh của Hắc Thạch thành, thanh niên mặc hắc y có khí chất bạo ngược sát lục. Hắn khinh thường việc Vương Lâm chưa có khí tức yêu ma và cho rằng Vương Lâm vẫn còn lần mò ở giai đoạn thông, dung, luyện.","vaiTro":"Ma thánh Hắc Thạch thành","tinhCach":[{"text":"Tính tình không tốt và lời lẽ thẳng gắt","chuong":"@c1902"},{"text":"Coi trọng khí tức yêu ma trong tu luyện cổ tộc","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Được Lương Vân giới thiệu là ma thánh tính tình không tốt.","chuong":"@c1902"},{"text":"Nhận xét Vương Lâm chưa có khí tức yêu ma nên còn ở giai đoạn thông, dung, luyện.","chuong":"@c1902"},{"text":"Là thanh niên mặc hắc y, khí chất bạo ngược sát lục nổi rõ.","chuong":"@c1902"},{"text":"Nhận xét Vương Lâm không có khí tức yêu ma nên còn lần mò trong thông, dung, luyện.","chuong":"@c1902"},{"text":"Kinh hãi khi Vương Lâm không quỳ trước Kế Đô hoàng tử.","chuong":"@c1902"}],"kinhLich":[{"chuong":"@c1902","importance":"normal","mucCt":"vua","tieuDe":"Ma thánh nhận xét","text":"Mạch Lạc đi sau Lương Vân ra ngoài Hắc Thạch thành và được giới thiệu là ma thánh tính tình không tốt. Hắn chê Vương Lâm không có khí tức yêu ma, cho rằng Vương Lâm vẫn đang lần mò ở giai đoạn thông, dung, luyện, rồi quỳ lạy khi Kế Đô hoàng tử xuất hiện.","anchor":"Mạch Lạc này là ma thánh, tính tình không tốt mong Vương huynh chớ để bụng"}],"tuViMoc":[{"chuong":"@c1902","canhGioi":"ma thánh","text":"Mạch Lạc được Lương Vân gọi là ma thánh của Hắc Thạch thành.","importance":"minor"}],"nhanMach":[{"ten":"Lương Vân","tag":"dong-minh","quanHe":"Cùng ra ngoài thành nghênh đón Kế Đô hoàng tử.","ghiChu":"Thuộc nhóm Hắc Thạch thành @c1902"},{"ten":"Khổng Ti","tag":"dong-minh","quanHe":"Cùng ra ngoài thành nghênh đón Kế Đô hoàng tử.","ghiChu":"Thuộc nhóm Hắc Thạch thành @c1902"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Nhận xét Vương Lâm chưa có khí tức yêu ma.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Kế Đô hoàng tử","tag":"cap-tren","quanHe":"đối tượng quỳ lạy","ghiChu":"Mạch Lạc quỳ lạy khi Kế Đô hoàng tử xuất hiện."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902"]},{"id":"ke-do-hoang-tu","name":"Kế Đô hoàng tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng tộc Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không cập nhật trong @c1905","trangThai":"song","blurb":"Kế Đô hoàng tử xuất hiện trên đỉnh đầu cổ Yêu Đà Lạc được Hắc Thạch thành quỳ lạy nghênh đón; ban đầu hắn coi việc Vương Lâm không quỳ là bất kính và ra lệnh xử trí, nhưng sau khi nhận ra thực lực đối phương liền chuyển sang cung kính, giao Tống Trí cho Đạo Cổ sứ đoàn, mời Vương Lâm tới hành cung và quỳ xin nhận làm nghĩa phụ. Hắn từng tặng Vương Lâm ngọc giản chứa sức mạnh một chỉ của Cổ Tổ, món quà sau đó phát huy tác dụng trọng yếu trong thực chiến.","vaiTro":"Hoàng tử cổ tộc — mưu lược gia chủ động kết giao Vương Lâm","tinhCach":"quyết đoán, thấy thế bất lợi lập tức chuyển thái độ; mưu trí, chủ động tra thân phận đối phương trước khi hành động; biết nhún mình, sẵn sàng quỳ lạy để đạt mục đích chính trị","tabs":{"diem":[{"text":"Ban đầu muốn xử trí Vương Lâm vì không quỳ, sau khi thấy Cổ Yêu sợ hãi quỳ phục liền thay đổi thái độ","chuong":"@c1903"},{"text":"Giao Tống Trí cho Đạo Cổ sứ đoàn, đổi sang cung kính với Vương Lâm và mời tới hành cung U Quận","chuong":"@c1904"},{"text":"Quỳ xin nhận Vương Lâm làm nghĩa phụ, thừa nhận đã tra ra thân phận kép của Vương Lâm nhờ suy đoán từ nhiều nguồn","chuong":"@c1905"},{"text":"Động cơ kết giao được lý giải qua quyền Đại Thiên Tôn trong việc lựa chọn hoàng tôn","chuong":"@c1907"},{"text":"Tặng Vương Lâm ngọc giản chứa thần thông một chỉ cực mạnh của Cổ Tổ, sau được Vương Lâm sử dụng trong thực chiến","chuong":"@c1915"},{"text":"Được nhắc tới dự đại lễ phong hậu nhờ mối liên hệ với sứ đoàn từng tuyển được Tống Trí","chuong":"@c1916"}],"kinhLich":[{"mucCt":"vua","text":"Kế Đô hoàng tử ban đầu muốn xử trí Vương Lâm vì không quỳ trước hoàng quyền. Sau khi thấy Cổ Yêu sợ hãi quỳ phục, hắn tái mặt, đổi sang kính cẩn nhận lỗi, xin bồi thường và sai Lương Vân mời Tống Trí đi theo sứ đoàn Đạo Cổ.","anchor":"Sắc mặt Kế Đô hoàng tử tái nhợt","bridge":true,"khoang":"@c1903"},{"mucCt":"ky","text":"Kế Đô giao Tống Trí cho Đạo Cổ sứ đoàn, sau đó đổi sang cung kính với Vương Lâm và mời hắn tới hành cung U Quận. Hắn phong khẩu ba người chứng kiến ở Hắc Thạch Thành, giới thiệu lai lịch Đại Cổ Yêu rồi bái kiến Vương Lâm bằng danh hiệu Bạch Phát Dược Thiên Tôn.","anchor":"Vãn bối cũng không phải là đã theo dõi tiền bối, tiền bối xuất hiện ở Hắc Thạch Thành","bridge":true,"khoang":"@c1904"},{"chuong":"@c1905","importance":"normal","mucCt":"ky","tieuDe":"Quỳ xin nghĩa phụ","text":"Kế Đô thừa nhận đã tra ra thân phận kép của Vương Lâm nhờ suy đoán từ Đạo Cổ, phụ hoàng và Tống Thiên Đại Thiên Tôn, đồng thời dùng lần gặp ở Hắc Thạch Thành để nghiệm chứng. Bị Vương Lâm truy hỏi, hắn khai quốc sư là cậu ruột đã hao tổn tính mạng bói ra cơ hội đổi vận và bảo hắn đi theo sứ đoàn Đạo Cổ. Hắn quỳ lạy xin làm nghĩa tử, dâng tổ giản cùng dịch mộc bản nguyên để đổi lấy khả năng được Vương Lâm trợ giúp trong cuộc tranh ngôi Thủy Cổ Hoàng.","anchor":"Tiền bối, vãn bối nguyện trở thành nghĩa tử của ngài, từ này về sau ngài chính là nghĩa phụ của vãn bối."},{"chuong":"@c1907","importance":"bridge","mucCt":"vua","tieuDe":"Được lý giải động cơ","text":"Kế Đô hoàng tử được Vương Lâm nhớ tới khi hiểu quyền Đại Thiên Tôn trong việc lựa chọn hoàng tôn, qua đó lý giải vì sao Kế Đô từng muốn mượn chiến lực của hắn để được Đại Thiên Tôn coi trọng.","anchor":"Khó trách Kế Đô hoàng tử của Thủy Cổ nhất mạch lại muốn nhờ ta trợ giúp"}],"tuViMoc":[],"nhanMach":[{"ten":"Đà Lạc","tag":"dong-minh","quanHe":"Cổ Yêu chở Kế Đô hoàng tử và nhận lệnh giết Vương Lâm.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Nữ tử áo lam phía sau Kế Đô hoàng tử","tag":"dong-minh","quanHe":"Đi cùng Kế Đô hoàng tử trên đỉnh đầu Đà Lạc.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Coi Vương Lâm không quỳ là bất kính và sai Đà Lạc giết hắn.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Bảy người trên cổ Ma","tag":"khac","quanHe":"Tiếp đón nhóm bảy người trên cổ Ma khi họ tới.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Lương Vân","tag":"cap-tren","quanHe":"ra lệnh cho Lương Vân đi mời Tống Trí","ghiChu":"Quan hệ chủ tớ hoặc cấp trên trong Thủy Cổ @c1903"},{"ten":"Tống Trí cô nương","tag":"khac","quanHe":"người được hắn sai mời ra cho sứ đoàn Đạo Cổ","ghiChu":"Liên quan việc tuyển phi @c1903"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người được cầu làm nghĩa phụ","ghiChu":"Kế Đô xem Vương Lâm là cơ hội đổi vận và trợ lực tranh ngôi."},{"ten":"Hoàng muội của Kế Đô","tag":"ho-hang","quanHe":"Muội muội song sinh","ghiChu":"Nàng đứng sau Kế Đô, cùng chứng kiến cuộc cầu viện Vương Lâm."},{"ten":"Quốc sư Thủy Cổ","tag":"ho-hang","quanHe":"Cậu ruột và người chỉ điểm","ghiChu":"Quốc sư dùng tính mạng bói quẻ, chỉ cho Kế Đô cơ hội đổi vận."},{"ten":"Phụ hoàng của Kế Đô","tag":"cha-me","quanHe":"Phụ hoàng","ghiChu":"Người sắp thoái vị, khiến bảy hoàng tử bước vào cuộc tranh tân hoàng."},{"ten":"Mẫu hậu của Kế Đô","tag":"cha-me","quanHe":"Mẫu hậu","ghiChu":"Được nhắc qua quan hệ với quốc sư, người là đệ đệ của bà."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Từng muốn nhờ trợ giúp","ghiChu":"Vương Lâm suy ra động cơ của Kế Đô khi hiểu quyền chọn hoàng tôn của Đại Thiên Tôn."},{"ten":"Khổng Ti","tag":"cap-tren","quanHe":"bề trên được quỳ lạy","ghiChu":"Khổng Ti quỳ lạy khi Kế Đô hoàng tử xuất hiện."},{"ten":"Mạch Lạc","tag":"cap-tren","quanHe":"bề trên được quỳ lạy","ghiChu":"Mạch Lạc quỳ lạy khi Kế Đô hoàng tử xuất hiện."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902","@c1903","@c1904","@c1905","@c1907"]},{"id":"da-lac","name":"Đà Lạc","cn":"","aliases":["cổ Yêu Đà Lạc","cổ Yêu của Kế Đô"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng tộc Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cổ Yêu mạnh tương tự Thiên Tôn tiên tộc @c1902","trangThai":"song","blurb":"Đà Lạc là cổ Yêu một sừng màu xanh, mặc giáp xanh, thân hình mấy vạn trượng và chở Kế Đô hoàng tử giáng lâm ngoài Hắc Thạch thành. Theo lệnh hoàng tử, hắn vung tay chụp giết Vương Lâm.","vaiTro":"Cổ Yêu của Kế Đô hoàng tử","tinhCach":[{"text":"Tuân lệnh Kế Đô hoàng tử","chuong":"@c1902"},{"text":"Ra tay hung mãnh bằng yêu khí ngập trời","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Xé trời xuất hiện với hư ảnh cổ Yêu một sừng màu xanh.","chuong":"@c1902"},{"text":"Yêu khí khiến Vương Lâm liên tưởng tới tu sĩ Thiên Tôn phía tiên tộc.","chuong":"@c1902"},{"text":"Theo lệnh Kế Đô hoàng tử, dùng bàn tay khổng lồ chụp về phía Vương Lâm.","chuong":"@c1902"},{"text":"Thân hình mấy vạn trượng, đầu một sừng màu xanh và mặc giáp xanh.","chuong":"@c1902"},{"text":"Yêu khí mạnh đến mức Vương Lâm so sánh với tu sĩ Thiên Tôn phía tiên tộc.","chuong":"@c1902"},{"text":"Chở Kế Đô hoàng tử xuất hiện bằng cách xé trời bước ra.","chuong":"@c1902"},{"text":"Là hư ảnh cổ Yêu một sừng màu xanh, mặc giáp xanh, thân hình mấy vạn trượng.","chuong":"@c1902"},{"text":"Sau lệnh của hoàng tử, dùng tay phải khổng lồ chụp giết Vương Lâm.","chuong":"@c1902"}],"kinhLich":[{"chuong":"@c1902","importance":"normal","mucCt":"vua","tieuDe":"Chụp giết Vương Lâm","text":"Đà Lạc xé trời giáng lâm dưới hình dạng cổ Yêu một sừng màu xanh, chở Kế Đô hoàng tử trên đỉnh đầu. Khi Kế Đô hoàng tử ra lệnh, hắn gầm thét và dùng bàn tay khổng lồ chụp về phía Vương Lâm, móng tay hóa thành hắc tuyến mang yêu khí ngập trời.","anchor":"Lập tức cổ Yêu mấy vạn trượng dưới thân hắn phát ra tiếng gầm thét"}],"tuViMoc":[{"chuong":"@c1902","canhGioi":"cổ Yêu","text":"Đà Lạc được nhận ra là cổ Yêu không tầm thường, có yêu khí mạnh khiến Vương Lâm liên tưởng tới tu sĩ Thiên Tôn bên tiên tộc.","importance":"minor"}],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"cap-tren","quanHe":"Chở Kế Đô hoàng tử và tuân lệnh giết Vương Lâm.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Theo lệnh Kế Đô hoàng tử ra tay chụp giết Vương Lâm.","ghiChu":"Ngoài Hắc Thạch thành @c1902"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902"]},{"id":"nu-tu-ao-lam-phia-sau-ke-do-hoang-tu","name":"Nữ tử áo lam phía sau Kế Đô hoàng tử","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Hoàng tộc Đạo Cổ","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Không rõ @c1902","trangThai":"song","blurb":"Nữ tử áo lam đi cùng Kế Đô hoàng tử trên đỉnh đầu cổ Yêu Đà Lạc. Nàng chú ý tới Vương Lâm khi hắn là người duy nhất không quỳ.","vaiTro":"Người đi cùng Kế Đô hoàng tử","tinhCach":[{"text":"Quan sát Vương Lâm với vẻ kinh ngạc","chuong":"@c1902"},{"text":"Im lặng đứng sau Kế Đô hoàng tử","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Đứng phía sau Kế Đô hoàng tử trên đỉnh đầu cổ Yêu.","chuong":"@c1902"},{"text":"Nhìn Vương Lâm kinh ngạc khi hắn không quỳ.","chuong":"@c1902"}],"kinhLich":[{"mucCt":"vua","text":"Nàng theo Kế Đô tới hành cung U Quận và từng định lên tiếng nhưng bị Kế Đô trừng mắt ngăn lại. Khi nghe Kế Đô gọi Vương Lâm là Bạch Phát Dược Thiên Tôn, nàng kinh hãi lùi lại và không thể tin.","anchor":"Chỉ thấy nữ tử kia vẻ mặt không thể tin, liên tục lùi lại mấy bước","bridge":true,"khoang":"@c1904"}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"dong-minh","quanHe":"Đi cùng Kế Đô hoàng tử trên đỉnh đầu Đà Lạc.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Kinh ngạc nhìn Vương Lâm khi hắn là người duy nhất không quỳ.","ghiChu":"Ngoài Hắc Thạch thành @c1902"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902","@c1904"]},{"id":"bay-nguoi-tren-co-ma","name":"Bảy người trên cổ Ma","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Sứ đoàn Đạo Cổ","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Không rõ @c1902","trangThai":"song","blurb":"Bảy người gồm năm nam hai nữ đứng trên đỉnh đầu cổ Ma vạn trượng và xuất hiện sau cổ Yêu Đà Lạc. Họ chào Kế Đô hoàng tử rồi bị Vương Lâm đang đứng hấp dẫn sự chú ý.","vaiTro":"Nhóm khách trên cổ Ma","tinhCach":[{"text":"Giữ lễ với Kế Đô hoàng tử","chuong":"@c1902"},{"text":"Chú ý nhanh tới khác thường trong lễ nghênh đón","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Gồm năm nam hai nữ đứng trên đầu cổ Ma.","chuong":"@c1902"},{"text":"Hướng về Kế Đô hoàng tử ôm quyền vái chào.","chuong":"@c1902"},{"text":"Chú ý tới Vương Lâm vì hắn là người duy nhất đứng giữa toàn thành đang quỳ.","chuong":"@c1902"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"khac","quanHe":"Chào Kế Đô hoàng tử khi xuất hiện trên cổ Ma.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Cổ Ma chở sứ đoàn","tag":"khac","quanHe":"Đứng trên đỉnh đầu cổ Ma khi xuất hiện.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chú ý tới Vương Lâm vì hắn không quỳ.","ghiChu":"Ngoài Hắc Thạch thành @c1902"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902"]},{"id":"co-ma-cho-su-doan","name":"Cổ Ma chở sứ đoàn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Sứ đoàn Đạo Cổ","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Cổ Ma vạn trượng @c1902","trangThai":"song","blurb":"Cổ Ma chở sứ đoàn là hư ảnh cổ Ma vạn trượng xuất hiện sau Đà Lạc, toàn thân đen kịt và hai mắt đỏ bừng bạo ngược. Trên đỉnh đầu hắn có bảy người đứng để chào Kế Đô hoàng tử.","vaiTro":"Cổ Ma chở nhóm bảy người","tinhCach":[{"text":"Mang dáng vẻ điên cuồng bạo ngược","chuong":"@c1902"},{"text":"Làm vật cưỡi hoặc nơi đứng cho bảy người tới gặp Kế Đô hoàng tử","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Là hư ảnh cổ Ma vạn trượng có đôi sừng cong sau đỉnh đầu.","chuong":"@c1902"},{"text":"Toàn thân đen kịt, hai mắt đỏ bừng đầy vẻ điên cuồng bạo ngược.","chuong":"@c1902"},{"text":"Chở bảy người xuất hiện sau cổ Yêu Đà Lạc.","chuong":"@c1902"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Bảy người trên cổ Ma","tag":"khac","quanHe":"Chở bảy người trên đỉnh đầu khi xuất hiện.","ghiChu":"Ngoài Hắc Thạch thành @c1902"},{"ten":"Kế Đô hoàng tử","tag":"khac","quanHe":"Xuất hiện trong lúc Kế Đô hoàng tử tiếp khách.","ghiChu":"Ngoài Hắc Thạch thành @c1902"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1902"]},{"id":"thanh-nien-mac-hac-y","name":"Thanh niên mặc hắc y","aliases":["Ma Thánh","Thanh niên mặc áo đen"],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Cổ Quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1903","trangThai":"song","blurb":"Một Ma Thánh bên phía Thủy Cổ, chứng kiến Vương Lâm đối mặt Cổ Yêu tại Hắc Thạch Thành. Hắn từng sinh chiến ý nhưng lập tức bị thực lực của Vương Lâm làm tan rã.","vaiTro":"Ma Thánh Thủy Cổ chứng kiến biến cố","tinhCach":[{"text":"hiếu chiến khi thấy đối thủ mạnh","chuong":"@c1903"},{"text":"biết sợ trước uy áp vượt xa dự liệu","chuong":"@c1903"}],"tabs":{"diem":[{"text":"Từng nổi chiến ý khi thấy Vương Lâm thong dong trước đòn của Cổ Yêu.","chuong":"@c1903"},{"text":"Chiến ý tan rã khi Cổ Yêu quỳ phục trước Vương Lâm.","chuong":"@c1903"}],"kinhLich":[{"mucCt":"vua","text":"Thanh niên mặc hắc y ban đầu xem nhẹ Vương Lâm và sinh chiến ý sau khi thấy hắn tránh đòn của Cổ Yêu. Khi Cổ Yêu bị Vương Lâm ép quỳ, chiến ý trong mắt hắn lập tức tan rã.","anchor":"chiến ý trong mắt thanh niên mặc hắc y lập tức tan rã","bridge":true,"khoang":"@c1903"},{"chuong":"@c1904","importance":"bridge","mucCt":"gon","tieuDe":"Bị cấm tiết lộ","text":"Thanh niên mặc hắc y cùng Lương Vân và Khổng Ti bị Kế Đô cấm để lộ tin tức về Vương Lâm.","anchor":"càng không cho phép người khác truyền ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903","@c1904"]},{"id":"diep-hai","name":"Diệp Hải","aliases":["lão già sứ đoàn Đạo Cổ","lão già trên đỉnh đầu Cổ Ma"],"gioiTinh":"nam","theLuc":[{"ten":"Sứ đoàn Đạo Cổ tuyển phi","trangThai":"gan-bo"},{"ten":"Đạo Cổ Quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hai mươi bảy tinh điểm, hiện ba hư ảnh Cổ Thần, Cổ Ma, Cổ Yêu @c1903","trangThai":"song","blurb":"Lão già mạnh nhất trong bảy người thuộc sứ đoàn Đạo Cổ tuyển phi. Hắn được Đạo Cổ Hoàng ban danh Diệp Hải, có hai mươi bảy tinh điểm và giao ngọc giản bản đồ Đạo Cổ hoàng thành cho Vương Lâm.","vaiTro":"đầu mục sứ đoàn Đạo Cổ tuyển phi","tinhCach":[{"text":"cẩn trọng trước uy áp vượt quá bản thân","chuong":"@c1903"},{"text":"cung kính khi đối diện người mạnh hơn","chuong":"@c1903"}],"tabs":{"diem":[{"text":"Lộ chín tinh điểm ở mi tâm, chín tinh điểm ở mắt trái và chín tinh điểm ở mắt phải.","chuong":"@c1903"},{"text":"Sau lưng hiện ba hư ảnh Cổ Thần, Cổ Ma, Cổ Yêu khi chịu áp lực từ Vương Lâm.","chuong":"@c1903"},{"text":"Tự xưng được Đạo Cổ Hoàng ban danh là Diệp Hải.","chuong":"@c1903"}],"kinhLich":[{"chuong":"@c1903","importance":"normal","mucCt":"ky","tieuDe":"Giao bản đồ hoàng thành","text":"Diệp Hải dẫn sứ đoàn Đạo Cổ tới Thủy Cổ Quốc tuyển phi và lộ ra hai mươi bảy tinh điểm cùng ba hư ảnh khi bị uy áp của Vương Lâm ép lui. Hắn cung kính tự xưng được Đạo Cổ Hoàng ban danh, trình bày việc tuyển phi đã đi qua sáu nơi và giao ngọc giản bản đồ Đạo Cổ hoàng thành cho Vương Lâm.","anchor":"tại hạ được Đạo Cổ Hoàng ban danh là Diệp Hải"},{"chuong":"@c1904","importance":"normal","mucCt":"vua","tieuDe":"Tiếp nhận Tống Trí","text":"Diệp Hải xác nhận Tống Trí có họ Tống và nhận nàng theo Đạo Cổ sứ đoàn đi tuyển phi. Hắn hứa nếu nàng không thể thành phi thì sẽ đưa nàng trở về, rồi cùng sứ đoàn rời Hắc Thạch Thành.","anchor":"Nếu không thể thành phi, thì tại hạ cũng sẽ đưa nữ tử này về"}],"tuViMoc":[{"chuong":"@c1903","canhGioi":"Hai mươi bảy tinh điểm","text":"Diệp Hải hiện tổng cộng hai mươi bảy tinh điểm ở mi tâm và hai mắt, đồng thời hiện ba hư ảnh Cổ Thần, Cổ Ma, Cổ Yêu.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"bị Vương Lâm uy áp và giao bản đồ","ghiChu":"Gặp tại Hắc Thạch Thành @c1903"},{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"người ban danh Diệp Hải và là hoàng đế mà sứ đoàn phục vụ","ghiChu":"Diệp Hải tự thuật @c1903"},{"ten":"Tống Trí cô nương","tag":"khac","quanHe":"Người được hắn tiếp nhận vào sứ đoàn","ghiChu":"Hắn nhận Tống Trí theo sứ đoàn và hứa sẽ đưa về nếu nàng không thành phi."}],"tuiDo":{"phapBao":[{"ten":"Ngọc giản bản đồ Đạo Cổ hoàng thành","loai":"ngọc giản bản đồ","trangThai":"da-dung","moTa":"Lấy ra giao cho Vương Lâm theo yêu cầu.","nguon":"@c1903"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903","@c1904"]},{"id":"sau-thanh-vien-su-doan-dao-co-con-lai","name":"Sáu thành viên sứ đoàn Đạo Cổ còn lại","gioiTinh":"khong-ro","theLuc":[{"ten":"Sứ đoàn Đạo Cổ tuyển phi","trangThai":"gan-bo"},{"ten":"Đạo Cổ Quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"trong nhóm có bốn người cửu tinh thần thánh và hai người bước vào đoạn thông, dung, luyện @c1903","trangThai":"song","blurb":"Sáu người đi cùng Diệp Hải trong sứ đoàn Đạo Cổ tuyển phi. Khi Vương Lâm bước tới, họ lui lại và bộc phát lực lượng Cổ Tộc.","vaiTro":"thành viên sứ đoàn Đạo Cổ","tinhCach":[{"text":"khiếp sợ trước uy áp của Vương Lâm","chuong":"@c1903"}],"tabs":{"diem":[{"text":"Cùng Diệp Hải đứng trên đầu Cổ Ma của sứ đoàn Đạo Cổ.","chuong":"@c1903"},{"text":"Trong sáu người có người đạt cửu tinh thần thánh và người đã bước vào đoạn thông, dung, luyện.","chuong":"@c1903"}],"kinhLich":[{"chuong":"@c1903","importance":"normal","mucCt":"vua","tieuDe":"Lui trước uy áp","text":"Sáu thành viên còn lại của sứ đoàn Đạo Cổ ban đầu đứng trên đầu Cổ Ma xem diễn biến ở Hắc Thạch Thành. Khi Vương Lâm tiến tới, họ lập tức lui lại và bộc phát lực lượng Cổ Tộc để chống đỡ áp lực.","anchor":"sáu người còn lại lập tức lui lại phía sau"}],"tuViMoc":[],"nhanMach":[{"ten":"Diệp Hải","tag":"dong-minh","quanHe":"đồng hành trong sứ đoàn Đạo Cổ tuyển phi","ghiChu":"Cùng xuất hiện trên đầu Cổ Ma @c1903"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903"]},{"id":"hai-nu-tu-duoc-chon-cua-su-doan-dao-co","name":"Hai nữ tử được chọn của sứ đoàn Đạo Cổ","gioiTinh":"nu","theLuc":[{"ten":"Sứ đoàn Đạo Cổ tuyển phi","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"không rõ @c1903","trangThai":"song","blurb":"Hai nữ tử đã được sứ đoàn Đạo Cổ lựa chọn trong chuyến tuyển phi. Họ xuất hiện từ sóng gợn trên đầu Cổ Ma và cúi chào Vương Lâm với vẻ sợ hãi.","vaiTro":"người được chọn trong chuyến tuyển phi","tinhCach":[{"text":"sợ hãi trước uy thế của Vương Lâm","chuong":"@c1903"}],"tabs":{"diem":[{"text":"Được Diệp Hải gọi ra từ sóng gợn trên đầu Cổ Ma.","chuong":"@c1903"}],"kinhLich":[{"chuong":"@c1903","importance":"bridge","mucCt":"gon","tieuDe":"Cúi chào Vương Lâm","text":"Hai nữ tử đã được chọn trong chuyến tuyển phi xuất hiện và sợ hãi cúi chào Vương Lâm.","anchor":"Trong mắt hai nữ tử này mang theo vẻ sợ hãi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903"]},{"id":"tong-tri-co-nuong","name":"Tống Trí cô nương","aliases":["Tống Trí","nữ tử áo xanh Hắc Thạch Thành"],"gioiTinh":"nu","theLuc":[{"ten":"Thủy Cổ Quốc","trangThai":"danh-nghia"},{"ten":"Sứ đoàn Đạo Cổ tuyển phi","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"không rõ @c1904","trangThai":"song","blurb":"Nữ tử áo xanh ở Hắc Thạch Thành được Kế Đô hoàng tử sai Lương Vân mời ra để đi theo sứ đoàn Đạo Cổ. Nàng có khí tức thanh thuần và xuất hiện ở khoảnh khắc ánh mắt giao nhau với Vương Lâm.","vaiTro":"nữ tử được chọn cho sứ đoàn Đạo Cổ","tinhCach":[{"text":"khí chất thanh thuần","chuong":"@c1903"},{"text":"bình tĩnh ngẩng đầu nhìn Vương Lâm khi xuất hiện","chuong":"@c1903"}],"tabs":{"diem":[{"text":"Được Kế Đô hoàng tử chỉ danh mời ra để đi theo sứ đoàn Đạo Cổ.","chuong":"@c1903"},{"text":"Tướng mạo không tuyệt mỹ nhưng tràn ngập khí tức thanh thuần.","chuong":"@c1903"},{"text":"Ánh mắt nàng gặp ánh mắt Vương Lâm giữa không trung.","chuong":"@c1903"},{"text":"Mang huyết mạch Cổ Yêu nhưng trên người không có yêu khí lượn lờ.","chuong":"@c1904"},{"text":"Thuộc phân chi xa của Đại Thiên Tôn Tống gia nhất mạch, dòng của nàng tại Hắc Thạch Thành vẫn là vọng tộc.","chuong":"@c1904"},{"text":"Bị Kế Đô giao cho Đạo Cổ sứ đoàn đi tuyển phi dù trong lòng không muốn bị chọn.","chuong":"@c1904"}],"kinhLich":[{"chuong":"@c1903","importance":"normal","mucCt":"vua","tieuDe":"Gặp ánh mắt Vương Lâm","text":"Tống Trí cô nương được Lương Vân mời ra theo lệnh Kế Đô để đi theo sứ đoàn Đạo Cổ. Nàng mặc áo xanh, mang khí tức thanh thuần và khi bước ra đã ngẩng đầu nhìn về phía Vương Lâm.","anchor":"Mời Tống Trí cô nương ra đi theo sứ đoàn Đạo Cổ đi"},{"chuong":"@c1904","importance":"normal","mucCt":"ky","tieuDe":"Bị đưa đi tuyển phi","text":"Tống Trí xuất hiện ngoài Hắc Thạch Thành và được xác nhận là người họ Tống mà Kế Đô muốn giao cho Đạo Cổ sứ đoàn. Nàng lặng lẽ đi theo sứ đoàn tuyển phi, trong lòng lưu luyến Hắc Thạch Thành và mong bản thân không bị chọn trúng.","anchor":"Hi vọng mình không bị chọn trúng Nếu ta không xinh đẹp như thế này, hẳn sẽ không bị chọn trúng"}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"khac","quanHe":"người ra lệnh mời nàng đi theo sứ đoàn Đạo Cổ","ghiChu":"Liên quan chuyến tuyển phi @c1903"},{"ten":"Lương Vân","tag":"khac","quanHe":"người được sai đi mời nàng ra","ghiChu":"Xuất hiện tại cửa thành @c1903"},{"ten":"Vương Lâm","tag":"khac","quanHe":"ánh mắt giao nhau khi nàng xuất hiện","ghiChu":"Khoảnh khắc cuối chương @c1903"},{"ten":"Kế Đô hoàng tử","tag":"cap-tren","quanHe":"Người giao nàng cho Đạo Cổ sứ đoàn","ghiChu":"Kế Đô xác nhận thân phận họ Tống của nàng rồi ra lệnh nàng theo sứ đoàn đi tuyển phi."},{"ten":"Diệp Hải","tag":"khac","quanHe":"Người tiếp nhận nàng vào sứ đoàn","ghiChu":"Diệp Hải nói nếu nàng không thể thành phi thì sẽ đưa nàng về."},{"ten":"Đạo Cổ sứ đoàn","tag":"khac","quanHe":"Sứ đoàn đưa nàng đi tuyển phi","ghiChu":"Nàng rời Hắc Thạch Thành theo sứ đoàn."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903","@c1904"]},{"id":"dai-co-yeu-cua-ke-do","name":"Đại Cổ Yêu của Kế Đô","aliases":["Cổ Yêu của Kế Đô"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thủy Cổ Quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không cập nhật trong @c1905","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"mucCt":"vua","text":"Đại Cổ Yêu của Kế Đô chụp xuống Vương Lâm nhưng không thể chạm vào hắn. Khi Vương Lâm quay lại nhìn và chất vấn, nó sợ hãi cực độ, lui lại rồi quỳ một gối bái lạy.","anchor":"thân thể cao lớn kia cuống quít bái lạy Vương Lâm","bridge":true,"khoang":"@c1903"},{"mucCt":"vua","text":"Đại Cổ Yêu ngoan ngoãn để Vương Lâm đứng trên đầu và đưa Kế Đô cùng Vương Lâm tới U Quận. Tại hành cung, Kế Đô nói nó vốn là chiến sĩ cấm vệ Thủy Cổ, từng dung hợp hai mươi bảy tinh nhưng thất bại nên thoái hóa thành yêu thể mất thần trí.","anchor":"lại một lần nữa thoái hóa trở thành yêu thể, mất đi thần trí","bridge":true,"khoang":"@c1904"},{"chuong":"@c1905","importance":"bridge","mucCt":"gon","text":"Đại Cổ Yêu của Kế Đô được Vương Lâm nhắc như quân cờ Kế Đô từng cố ý để ra tay nhằm nghiệm chứng nghi ngờ về thân phận hắn.","anchor":"Cho nên hắn mới cố ý để Đại Cổ Yêu kia ra tay, chính là để nghiệm chứng suy đoán của hắn có chính xác hay không."}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"cap-tren","quanHe":"Cổ Yêu đi theo Kế Đô","ghiChu":"Ra tay khi Kế Đô muốn xử trí Vương Lâm @c1903"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"tấn công nhưng bị Vương Lâm áp phục","ghiChu":"Quỳ bái sau một ánh mắt @c1903"},{"ten":"Kế Đô hoàng tử","tag":"dong-minh","quanHe":"Thuộc hạ được dùng để thử thân phận Vương Lâm","ghiChu":"Kế Đô cố ý để Đại Cổ Yêu ra tay để nghiệm chứng suy đoán."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903","@c1904","@c1905"]},{"id":"co-ma-cua-su-doan-dao-co","name":"Cổ Ma của sứ đoàn Đạo Cổ","aliases":["Cổ Ma của Đạo Cổ sứ đoàn"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Sứ đoàn Đạo Cổ tuyển phi","trangThai":"gan-bo"},{"ten":"Đạo Cổ Quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Cổ Ma @c1903","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"mucCt":"vua","text":"Cổ Ma của sứ đoàn Đạo Cổ vốn hai mắt đỏ bừng và đầy vẻ bạo ngược. Khi Vương Lâm đi tới, nó nức nở, run rẩy phủ phục, để hắn bước theo cánh tay lên đỉnh đầu.","anchor":"Cổ Ma vốn đỏ bừng, tỏa ra vẻ bạo ngược và điên cuồng","bridge":true,"khoang":"@c1903"},{"mucCt":"vua","text":"Sau khi Đạo Cổ sứ đoàn đón được Tống Trí, Cổ Ma gào lên, xé mở khe trời và hóa thành sương đen chui vào biến mất. Nó chở sứ đoàn bắt đầu hành trình nhiều tháng trở về Đạo Cổ.","anchor":"rồi Cổ Ma kia bỗng nhiên ngẩng đầu lên, ngửa mặt lên trời gào thét","bridge":true,"khoang":"@c1904"}],"tuViMoc":[],"nhanMach":[{"ten":"Diệp Hải","tag":"dong-minh","quanHe":"chở Diệp Hải và sứ đoàn Đạo Cổ","ghiChu":"Đứng dưới bảy người trong sứ đoàn @c1903"},{"ten":"Vương Lâm","tag":"khac","quanHe":"phủ phục để Vương Lâm bước lên","ghiChu":"Bị uy thế của Vương Lâm áp chế @c1903"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903","@c1904"]},{"id":"dao-co-hoang","name":"Đạo Cổ Hoàng","aliases":["Diệp Đạo","nam tử mặc hoàng bào","Đạo Cổ hoàng tôn"],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ Quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (@c1908)","trangThai":"song","tabs":{"diem":[{"text":"Được Diệp Hải nhắc đến với tư cách hoàng đế ban danh và là quân chủ của sứ đoàn tuyển phi","chuong":"@c1903"},{"text":"Bị Kế Đô nhận định là kẻ khó dung nạp người tài như Vương Lâm","chuong":"@c1905"},{"text":"Biến sắc trước khói xanh dị biến rồi đích thân giáng lâm trước Đạo Cổ Điện, ra lệnh dung hợp linh hồn","chuong":"@c1907"},{"text":"Tới Đạo Cổ Điện xác nhận người gây biến hóa hương lô, ban ân nhưng giấu sát ý vì ghen ghét Vương Lâm","chuong":"@c1908"},{"text":"Chủ trì việc dung hợp tàn hồn vào nữ tử suốt nhiều trăm năm để chuẩn bị phong hậu","chuong":"@c1910"},{"text":"Hoảng sợ khi Vương Lâm vào đại điện nhưng vẫn dùng tử quang hộ thân và mượn danh Cổ Đạo Đại Thiên Tôn","chuong":"@c1920"}],"kinhLich":[{"chuong":"@c1903","importance":"bridge","mucCt":"gon","tieuDe":"Được nhắc qua sứ đoàn","text":"Đạo Cổ Hoàng được Diệp Hải nhắc là người ban danh cho hắn và là hoàng đế mà sứ đoàn tuyển phi phục vụ.","anchor":"tại hạ được Đạo Cổ Hoàng ban danh là Diệp Hải"},{"chuong":"@c1905","importance":"bridge","mucCt":"vua","text":"Đạo Cổ Hoàng bị Kế Đô nhận định là khó dung nạp người như Vương Lâm, khiến Kế Đô tin Vương Lâm ở Đạo Cổ sẽ không vui và cuối cùng có thể rời đi.","anchor":"Với sự hiểu biết của ta về Đạo Cổ Hoàng, nghĩa phụ ở nơi đó nhất định không vui."},{"chuong":"@c1906","importance":"normal","mucCt":"vua","tieuDe":"Biến sắc trước khói xanh","text":"Đạo Cổ Hoàng đứng trên lầu các cao nhất trong hoàng cung, đang nghe lão già báo việc tuyển phi thì thấy khói xanh Đạo Cổ Điện dị biến. Ban đầu ông cau mày lệnh tra người khiến lư hương tỏa khói, rồi chấn động khi khói xanh khom mình như không chịu nổi một vái.","anchor":"Nam tử mặc hoàng bào cau mày, chậm rãi nói nhưng lời nói còn chưa dứt thì lại chấn động toàn thân"},{"chuong":"@c1907","importance":"normal","mucCt":"ky","tieuDe":"Giáng lâm trước Đạo Cổ Điện","text":"Đạo Cổ Hoàng đứng trong hoàng thành, cảm nhận khí tức Hồn Huyết và ra lệnh nhanh chóng dung hợp linh hồn nhóm phi tử vừa tuyển. Cuối chương, hắn mang tử khí cùng gần trăm cường giả Cổ Tộc tới Đạo Cổ Điện, bái kiến Huyền La Tôn và nói vì thấy khói hương ba ngày trước cuồn cuộn lên trời nên tới xem cường giả mới. Tại đó, hắn nghe Huyền La công khai Vương Lâm là đệ tử sẽ thay ông bảo vệ Đạo Cổ nhất mạch khi chuyển thế.","anchor":"Ba ngày trước Diệp Đạo phát hiện ra khói hương nơi này cuồn cuộn thẳng thiên"},{"chuong":"@c1908","importance":"normal","mucCt":"ky","tieuDe":"Ban ân giấu sát ý","text":"Đạo Cổ Hoàng tới Đạo Cổ Điện để xác nhận người gây biến hóa hương lô, đồng thời ghen ghét Vương Lâm vì được Huyền La nhận làm đệ tử, có máu Cổ Tổ và danh Bạch Phát Dược Thiên Tôn. Bề ngoài hắn công bố Vương Lâm ngang hàng mình, ban ngọc bội ra vào hoàng cung và giao việc chọn hoàng tôn tương lai. Khi trở về hoàng cung, hắn lộ dã tâm muốn bắt Vương Lâm quỳ nhiều lần và chờ Huyền La chuyển thế để dùng quyền lực giết Vương Lâm.","anchor":"trẫm sẽ cho ngươi biết quyền lực của trẫm, giết ngươi sẽ dễ như trở bàn tay"}],"tuViMoc":[],"nhanMach":[{"ten":"Diệp Hải","tag":"cap-duoi","quanHe":"ban danh cho Diệp Hải","ghiChu":"Được Diệp Hải tự thuật @c1903"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người có khả năng khó được dung nạp","ghiChu":"Theo nhận định của Kế Đô, Đạo Cổ Hoàng không giữ nổi cường giả như Vương Lâm."},{"ten":"Kế Đô hoàng tử","tag":"doi-thu","quanHe":"Người đánh giá bất lợi","ghiChu":"Kế Đô dùng hiểu biết về Đạo Cổ Hoàng để đặt cược Vương Lâm sẽ rời Đạo Cổ."},{"ten":"Lão già trong hoàng cung Đạo Cổ","tag":"cap-tren","quanHe":"chủ thượng được báo cáo","ghiChu":"Nghe lão già cung kính bẩm báo tình hình tuyển phi."},{"ten":"Lão già hầu cận Đạo Cổ Hoàng trong hoàng thành","tag":"khac","quanHe":"Hầu cận nhận lệnh","ghiChu":"Người này quỳ nhận lệnh khi Đạo Cổ Hoàng yêu cầu đẩy nhanh việc dung hợp linh hồn phi tử."},{"ten":"Hai lão già sau lưng Đạo Cổ Hoàng","tag":"dong-minh","quanHe":"Cường giả đi theo","ghiChu":"Hai lão già khí tức không kém Dược Thiên Tôn khom người đi theo Đạo Cổ Hoàng khi hắn xuất hiện."},{"ten":"Thường Thị","tag":"khac","quanHe":"Lão già bên cạnh","ghiChu":"Thường Thị lên tiếng ép Vương Lâm quỳ theo tộc quy trước Đạo Cổ Hoàng."},{"ten":"Huyền La","tag":"dong-minh","quanHe":"Đại Thiên Tôn của Đạo Cổ","ghiChu":"Đạo Cổ Hoàng bái kiến Huyền La Tôn trước Đạo Cổ Điện."},{"ten":"Thường Thị","tag":"dong-minh","quanHe":"Tùy tùng bên cạnh, bị ông quở lui rồi giao truyền cáo toàn tộc.","ghiChu":"Thường Thị làm công cụ nêu quy củ hoàng quyền trước Vương Lâm."},{"ten":"Lão già trong hoàng cung Đạo Cổ","tag":"khac","quanHe":"thuộc hạ báo việc","ghiChu":"Lão già đứng sau Đạo Cổ Hoàng, cung kính báo cáo việc tuyển phi trước khi dị tượng khói xanh xuất hiện."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903","@c1905","@c1906","@c1907","@c1908"],"vaiTro":"Hoàng đế Đạo Cổ quốc — quân chủ mà sứ đoàn tuyển phi phục vụ","tinhCach":"đa nghi, khó dung nạp kẻ tài cao; ghen ghét trước ân sủng người khác nhận được; tàn nhẫn giấu sau lớp vỏ ban ân","blurb":"Đạo Cổ Hoàng là hoàng đế cai trị Đạo Cổ quốc, từng ban danh cho Diệp Hải và là đối tượng phục vụ của sứ đoàn tuyển phi. Khi khói xanh dị biến bùng phát trong hoàng cung, hắn đích thân tới Đạo Cổ Điện xác nhận nguồn gốc biến cố, đồng thời bộc lộ sát ý ngầm đối với Vương Lâm. Về sau hắn chủ trì việc dung hợp tàn hồn vào nữ tử để chuẩn bị phong hậu, và khi Vương Lâm xông vào đại điện, hắn hoảng sợ nhưng vẫn dùng tử quang hộ thân cùng danh nghĩa Cổ Đạo Đại Thiên Tôn để đối phó."},{"id":"that-thai-tien-ton","name":"Thất Thải Tiên Tôn","gioiTinh":"nam","trangThai":"khong-ro","tabs":{"diem":[{"text":"Từ bỏ đạo lữ, phong tỏa Thất Đạo Tông để đoạt bảo vật quý bên trong","chuong":"@c1586"},{"text":"Bị Liên Đạo Phi oanh kích thân thể vỡ nát, nguyên thần và tam hồn thất phách tán ra, mỗi phần hóa thành thực thể riêng biệt","chuong":"@c1650"},{"text":"Năm xưa đạt được một mảnh nhỏ thiên đạo, phát hiện thiên đạo và Thiên Nghịch, là người duy nhất nhìn thấy chân thân thiên đạo","chuong":"@c1631"},{"text":"Hồn phách hiện thân qua thân Chiến lão quỷ, chiếm quyền kiểm soát và nhận định thiên đạo có cực hạn","chuong":"@c1633"},{"text":"Lộ ra tên thật thời trẻ là Tô Đạo, thuộc tông phái trên đại lục Tiên Cương, từng bị Chu Lập khinh thị ngược đãi tại Đông Lâm Tông","chuong":"@c1684"},{"text":"Thất phách bị Thiên Vận Tử nuốt, phách nguyên thủy bị nuốt từ lần thức tỉnh sớm hơn ở thái cổ","chuong":"@c1627"}],"kinhLich":[{"chuong":"@c1903","importance":"bridge","mucCt":"gon","tieuDe":"Nhắc chuyện cầu viện","text":"Thất Thải Tiên Tôn được nhắc trong suy luận của Vương Lâm về việc từng tìm Lý Quảng trợ giúp.","anchor":"cho nên Thất Thải mới tìm tới Lý Quảng nhờ trợ gúp"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1903"],"vaiTro":"Cường giả thượng cổ — chủ nhân động phủ giới Côn Hư, người duy nhất từng nhìn thấy chân thân thiên đạo","tinhCach":"tâm cơ thâm trầm, không từ thủ đoạn; chấp nhất truy tìm thiên đạo và hồn phách; thời trẻ nhu nhược, từng chịu khinh thị; si tình đa tình","blurb":"Thất Thải Tiên Tôn, tên thật thời trẻ là Tô Đạo, xuất thân từ một tông phái trên đại lục Tiên Cương, từng bị khinh thị và ngược đãi tại Đông Lâm Tông. Về sau trở thành cường giả thượng cổ, chủ nhân động phủ giới Côn Hư tinh vực, người phát hiện thiên đạo cùng Thiên Nghịch và là người duy nhất được ghi nhận đã nhìn thấy chân thân thiên đạo. Sau khi bị Liên Đạo Phi oanh kích đến thân thể vỡ nát, tam hồn thất phách tán ra khắp nơi, kéo theo hàng loạt biến cố liên quan Chiến lão quỷ, Tạ Thanh, Thiên Vận Tử, Thất Đạo Tông và Đại Hồn Môn."},{"id":"hoang-muoi-cua-ke-do","name":"Hoàng muội của Kế Đô","aliases":["nữ tử bên cạnh Kế Đô hoàng tử","muội muội song sinh của Kế Đô"],"gioiTinh":"nu","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hoàng muội song sinh của Kế Đô hoàng tử, thuộc Thủy Cổ nhất mạch. Nàng chứng kiến Kế Đô quỳ xin Vương Lâm làm nghĩa phụ và tỏ rõ sự lo ngại trước canh bạc lớn của huynh trưởng.","vaiTro":"Hoàng muội chứng kiến canh bạc Thủy Cổ","tinhCach":[{"text":"Thận trọng khi nghe thân phận thật của Vương Lâm","chuong":"@c1905"},{"text":"Lo lắng trước quyết định đánh cược của Kế Đô","chuong":"@c1905"}],"tabs":{"diem":[{"text":"Là muội muội song sinh của Kế Đô hoàng tử.","chuong":"@c1905"},{"text":"Cùng Kế Đô quỳ xuống khi Kế Đô muốn giữ Vương Lâm.","chuong":"@c1905"},{"text":"Cuối chương chất vấn Kế Đô liệu canh bạc với Vương Lâm có đáng hay không.","chuong":"@c1905"}],"kinhLich":[{"chuong":"@c1905","importance":"normal","mucCt":"vua","tieuDe":"Chứng kiến cầu viện","text":"Hoàng muội của Kế Đô được giới thiệu là muội muội song sinh khi đang đứng sau Kế Đô trong đại điện. Nàng nghe thân phận đệ tử Huyền La của Vương Lâm thì tái mặt, sau đó do dự quỳ theo Kế Đô và cuối chương hỏi việc đánh cược lớn như vậy có đáng không.","anchor":"Đây là hoàng muội của vãn bối, là muội muội song sinh của ta."}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"ho-hang","quanHe":"Huynh trưởng song sinh","ghiChu":"Nàng đi cùng Kế Đô trong cuộc gặp Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người được Kế Đô cầu viện","ghiChu":"Nàng chứng kiến Kế Đô xin nhận Vương Lâm làm nghĩa phụ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1905"]},{"id":"tong-thien-dai-thien-ton","name":"Tống Thiên Đại Thiên Tôn","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","blurb":"Đại Thiên Tôn được Kế Đô nhắc tới trong quá trình suy đoán thân phận của Vương Lâm. Sự trợ giúp của ông giúp Kế Đô nối Bạch Phát Dược Thiên Tôn của Tiên Tộc với đệ tử Huyền La của Đạo Cổ.","vaiTro":"Đại Thiên Tôn trợ giúp suy đoán","tinhCach":[{"text":"Có vị thế đủ khiến Kế Đô đem ra so sánh uy áp","chuong":"@c1905"},{"text":"Liên quan đến suy đoán thân phận kép của Vương Lâm","chuong":"@c1905"}],"tabs":{"diem":[{"text":"Được Kế Đô nhắc là người trợ giúp suy đoán thân phận Vương Lâm.","chuong":"@c1905"},{"text":"Uy áp của Tống Thiên được Kế Đô dùng làm chuẩn để so sánh với Vương Lâm.","chuong":"@c1905"}],"kinhLich":[{"chuong":"@c1905","importance":"bridge","mucCt":"vua","text":"Tống Thiên Đại Thiên Tôn được Kế Đô nhắc là người từng trợ giúp hắn suy đoán mối liên hệ giữa Bạch Phát Dược Thiên Tôn và đệ tử Huyền La.","anchor":"Ta từ Đạo Cổ nhất mạch bắt đầu điều tra, cuối cùng nhờ sự trợ giúp của Tống Thiên Đại Thiên Tôn mới đoán ra được."}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"dong-minh","quanHe":"Người trợ giúp suy đoán","ghiChu":"Tống Thiên giúp Kế Đô đoán ra thân phận kép của Vương Lâm."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đối tượng suy đoán thân phận","ghiChu":"Tên tuổi Vương Lâm được nối với Bạch Phát Dược Thiên Tôn nhờ suy đoán này."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1905"]},{"id":"quoc-su-thuy-co","name":"Quốc sư Thủy Cổ","aliases":["cậu của Kế Đô"],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Quốc sư Thủy Cổ là cậu ruột của hoàng tử Kế Đô, em trai mẫu hậu. Mười năm trước ông xuất quan, hao tổn tính mạng để bói ra cơ hội đổi vận cho cháu, chỉ Kế Đô đi theo sứ đoàn Đạo Cổ rồi tự tuyệt bỏ mình.","vaiTro":"Quốc sư nước Kế Đô — cậu ruột của hoàng tử Kế Đô, dùng mạng bói vận cho cháu","tinhCach":"tận tụy vì huyết thân; quyết đoán, dám đánh đổi tính mạng lấy một quẻ","tabs":{"diem":[{"text":"Dùng mạng bói vận cho Kế Đô, chỉ ra cơ hội đổi mệnh rồi tự tuyệt","chuong":"@c1905"}],"kinhLich":[{"chuong":"@c1905","importance":"major","mucCt":"ky","tieuDe":"Dùng mạng bói vận","text":"Quốc sư Thủy Cổ được Kế Đô khai là cậu ruột, đệ đệ của mẫu hậu hắn. Mười năm trước, ông xuất quan, dùng cái giá tiêu hao tính mạng để bói cho Kế Đô một quẻ, chỉ hắn đi cùng sứ đoàn Đạo Cổ vì sẽ gặp người có thể đổi vận. Sau lời tiên đoán rằng nắm được cơ duyên thì vận mệnh biến hóa, không nắm được thì sống không quá trăm năm, ông tự tuyệt bỏ mình.","anchor":"Mười năm trước hắn xuất quan, dùng cái giá tiêu hao tính mạng để tính cho ta một quẻ"}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"ho-hang","quanHe":"Cậu ruột và người chỉ điểm","ghiChu":"Ông dùng sinh mạng bói ra cơ hội đổi vận cho Kế Đô."},{"ten":"Mẫu hậu của Kế Đô","tag":"ho-hang","quanHe":"Đệ đệ","ghiChu":"Quốc sư là đệ đệ của mẫu hậu Kế Đô."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người trong lời bói","ghiChu":"Lời bói của quốc sư khiến Kế Đô xem Vương Lâm là cơ hội đổi vận."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1905"]},{"id":"phu-hoang-cua-ke-do","name":"Phụ hoàng của Kế Đô","aliases":["Thủy Cổ Hoàng đương nhiệm"],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Phụ hoàng của Kế Đô là Thủy Cổ Hoàng đương nhiệm được nhắc trong bối cảnh chọn tân hoàng. Ông từng ban tổ giản cho Kế Đô và nay đã đến tuổi muốn thoái vị.","vaiTro":"Thủy Cổ Hoàng sắp chọn người kế vị","tinhCach":[{"text":"Giữ quyền quyết định việc tuyển tân hoàng Thủy Cổ","chuong":"@c1905"},{"text":"Từng ban trọng bảo hoàng tử cho Kế Đô","chuong":"@c1905"}],"tabs":{"diem":[{"text":"Được nhắc là người đã tới tuổi muốn thoái vị và chọn tân hoàng trong bảy người con trai.","chuong":"@c1905"},{"text":"Từng ban tổ giản cho Kế Đô sau khi hắn sinh ra.","chuong":"@c1905"}],"kinhLich":[{"chuong":"@c1905","importance":"normal","mucCt":"gon","tieuDe":"Chuẩn bị thoái vị","text":"Phụ hoàng của Kế Đô được nhắc là Thủy Cổ Hoàng đương nhiệm đã tới tuổi muốn thoái vị, mở ra cuộc tuyển tân hoàng giữa bảy hoàng tử.","anchor":"Hôm nay phụ hoàng đã tới tuổi muốn tính chuyện thoái vị, bắt đầu tuyển tân hoàng trong bảy người chúng ta"}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"cha-me","quanHe":"Phụ hoàng","ghiChu":"Ông là người ban tổ giản cho Kế Đô và đặt bối cảnh tranh ngôi."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1905"]},{"id":"mau-hau-cua-ke-do","name":"Mẫu hậu của Kế Đô","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Mẫu hậu của Kế Đô được nhắc qua quan hệ huyết thống với quốc sư Thủy Cổ. Quốc sư là đệ đệ của bà và là người dùng mạng bói vận cho Kế Đô.","vaiTro":"Mẫu hậu của Kế Đô","tinhCach":[{"text":"Được nhắc qua quan hệ gia tộc với quốc sư","chuong":"@c1905"},{"text":"Liên quan gián tiếp đến căn nguyên lời bói đổi vận của Kế Đô","chuong":"@c1905"}],"tabs":{"diem":[{"text":"Là mẫu hậu của Kế Đô hoàng tử.","chuong":"@c1905"},{"text":"Quốc sư Thủy Cổ là đệ đệ của bà.","chuong":"@c1905"}],"kinhLich":[{"chuong":"@c1905","importance":"bridge","mucCt":"gon","text":"Mẫu hậu của Kế Đô được nhắc khi Kế Đô khai quốc sư là cậu ruột, tức đệ đệ của bà.","anchor":"Quốc sư là cậu của ta, là đệ đệ của mẫu hậu ta."}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"cha-me","quanHe":"Mẫu hậu","ghiChu":"Mẹ của Kế Đô."},{"ten":"Quốc sư Thủy Cổ","tag":"ho-hang","quanHe":"Tỷ muội ruột trong hoàng tộc","ghiChu":"Quốc sư là đệ đệ của bà."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1905"]},{"id":"lao-gia-trong-hoang-cung-dao-co","name":"Lão già trong hoàng cung Đạo Cổ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng quyền Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ trong chương này","trangThai":"song","blurb":"Lão già hầu cận trong hoàng cung Đạo Cổ, xuất hiện bên cạnh Đạo Cổ Hoàng khi hoàng cung chứng kiến dị tượng khói xanh từ Đạo Cổ Điện. Ông phụ trách bẩm báo việc tuyển phi và lập tức bị cảnh tượng khói xanh làm chấn động.","vaiTro":"hầu cận hoàng cung Đạo Cổ","tinhCach":[{"text":"cung kính khi bẩm báo với Đạo Cổ Hoàng","chuong":"@c1906"},{"text":"thận trọng trước dị tượng vượt thường thức","chuong":"@c1906"}],"tabs":{"diem":[{"text":"Bẩm báo việc tuyển phi đã tìm được ba mươi mốt nữ tử và đang kiểm tra dung hợp.","chuong":"@c1906"},{"text":"Chứng kiến khói xanh Đạo Cổ Điện biến dị rồi hít sâu lui lại khi cảnh tượng trở nên kinh khủng.","chuong":"@c1906"}],"kinhLich":[{"chuong":"@c1906","importance":"normal","mucCt":"gon","tieuDe":"Báo việc tuyển phi","text":"Lão già cung kính báo với Đạo Cổ Hoàng rằng đợt tuyển phi tìm được ba mươi mốt nữ tử và đang kiểm tra dung hợp, rồi sững sờ lui lại khi khói xanh Đạo Cổ Điện dị biến.","anchor":"Phía sau nam tử mặc hoàng bào, một lão già thần sắc cung kính đang thấp giọng nói."}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"thuộc hạ trong hoàng cung","ghiChu":"Cung kính bẩm báo việc tuyển phi cho Đạo Cổ Hoàng."},{"ten":"Đạo Cổ Hoàng","tag":"khac","quanHe":"thuộc hạ","ghiChu":"Lão già đứng phía sau Đạo Cổ Hoàng và báo cáo việc tuyển phi trong hoàng cung Đạo Cổ."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1906"]},{"id":"lao-gia-hau-can-dao-co-hoang-trong-hoang-thanh","name":"Lão già hầu cận Đạo Cổ Hoàng trong hoàng thành","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng quyền Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1907","trangThai":"song","blurb":"Lão hầu cận đứng phía sau Đạo Cổ Hoàng trong hoàng thành. Khi Đạo Cổ Hoàng ra lệnh đẩy nhanh việc dung hợp linh hồn phi tử mới tuyển, lão lập tức quỳ xuống nhận mệnh.","vaiTro":"Hầu cận trong hoàng thành","tinhCach":[{"text":"Kính sợ Đạo Cổ Hoàng, không dám thở mạnh khi hầu bên cạnh.","chuong":"@c1907"},{"text":"Nhanh chóng tuân lệnh khi được sai phái.","chuong":"@c1907"}],"tabs":{"diem":[{"text":"Theo hầu Đạo Cổ Hoàng lúc hắn cảm nhận khí tức Hồn Huyết trong hoàng thành.","chuong":"@c1907"},{"text":"Quỳ xuống nhận lệnh dung hợp linh hồn nhóm phi tử vừa tuyển.","chuong":"@c1907"}],"kinhLich":[{"mucCt":"vua","text":"Lão già hầu cận đứng sau Đạo Cổ Hoàng, sợ hãi tới mức không dám thở mạnh. Khi Đạo Cổ Hoàng yêu cầu nhanh chóng dung hợp linh hồn các phi tử mới tuyển, lão vội quỳ xuống nhận lệnh.","anchor":"Lão già kia vội vàng quỳ xuống đất","bridge":true,"khoang":"@c1907"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"Chủ thượng","ghiChu":"Lão hầu cận nhận lệnh trực tiếp từ Đạo Cổ Hoàng trong hoàng thành."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1907"]},{"id":"chin-nguoi-duoi-truong-huyen-la","name":"Chín người dưới trướng Huyền La","cn":"","aliases":["bảy nam hai nữ Đạo Cổ trước Đạo Cổ Điện"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"hai mươi bảy tinh điểm viên mãn, danh hiệu Đạo Cổ @c1907","trangThai":"song","blurb":"Chín người gồm bảy nam hai nữ, đều đạt hai mươi bảy tinh điểm viên mãn với danh hiệu Đạo Cổ. Họ vốn là thuộc hạ của Huyền La, sau được giao cho Vương Lâm và bái kiến hắn là Thiếu Thiên Tôn trước Đạo Cổ Điện.","vaiTro":"Chín cường giả Đạo Cổ dưới trướng Huyền La, được giao phục mệnh Vương Lâm","tinhCach":"trung thành tuyệt đối với chủ nhân; kỷ luật tập thể cao","tabs":{"diem":[{"text":"Xuất hiện trước Đạo Cổ Điện, bái kiến Vương Lâm là Thiếu Thiên Tôn và quy phục dưới trướng hắn","chuong":"@c1907"},{"text":"Toàn bộ chín người đều đạt hai mươi bảy tinh điểm viên mãn,ang danh hiệu Đạo Cổ","chuong":"@c1907"}],"kinhLich":[{"chuong":"@c1907","importance":"major","mucCt":"ky","tieuDe":"Quy phục Thiếu Thiên Tôn","text":"Chín người dưới trướng Huyền La xuất hiện trước Đạo Cổ Điện, trong đó có bảy nam hai nữ và đều có tu vi bất phàm sau khi đạt hai mươi bảy tinh điểm viên mãn cùng danh hiệu Đạo Cổ. Họ bị khí thế của Vương Lâm làm tâm thần chấn động, đồng loạt bái kiến hắn là Thiếu Thiên Tôn. Sau đó, họ quỳ nghênh Đạo Cổ Hoàng với vẻ cung kính và cuồng nhiệt.","anchor":"Trong chín người này có bảy nam hai nữ, tu vi bất phàm"}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền La","tag":"cap-tren","quanHe":"Chủ thượng cũ","ghiChu":"Huyền La dẫn họ ra trước Đạo Cổ Điện và giao cho Vương Lâm nghe lệnh."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Thiếu Thiên Tôn được bái kiến","ghiChu":"Chín người bái kiến Vương Lâm là Thiếu Thiên Tôn và từ nay nghe theo hiệu lệnh của hắn."},{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"Hoàng tôn được nghênh đón","ghiChu":"Khi Đạo Cổ Hoàng xuất hiện, chín người quỳ xuống cung kính nghênh đón."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1907"]},{"id":"lao-gia-manh-nhat-trong-chin-nguoi-duoi-truong-huyen-la","name":"Lão già mạnh nhất trong chín người dưới trướng Huyền La","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"tương đương Dược Thiên Tôn @c1907","trangThai":"song","blurb":"Lão già có tu vi cao nhất trong chín thuộc hạ của Huyền La. Khí tức của lão khiến Vương Lâm cảm giác tương tự tu sĩ Dược Thiên Tôn của Tiên Tộc.","vaiTro":"Cường giả mạnh nhất trong nhóm chín người","tinhCach":[{"text":"Ẩn trong hàng ngũ thuộc hạ Huyền La, chưa bộc lộ nhiều lời nói riêng.","chuong":"@c1907"},{"text":"Cùng nhóm bái kiến Vương Lâm theo sự sắp đặt của Huyền La.","chuong":"@c1907"}],"tabs":{"diem":[{"text":"Là người mạnh nhất trong chín thuộc hạ của Huyền La.","chuong":"@c1907"},{"text":"Mang lại cho Vương Lâm cảm giác như tu sĩ Dược Thiên Tôn.","chuong":"@c1907"}],"kinhLich":[{"chuong":"@c1907","importance":"normal","mucCt":"vua","tieuDe":"Lộ khí tức Dược Thiên Tôn","text":"Trong chín thuộc hạ của Huyền La, lão già này là người có tu vi cao nhất. Khí tức của lão khiến Vương Lâm cảm thấy tương tự một tu sĩ Dược Thiên Tôn của Tiên Tộc.","anchor":"Người này bất ngờ mang lại cho Vương Lâm cảm giác như tu sĩ Dược Thiên Tôn"}],"tuViMoc":[],"nhanMach":[{"ten":"Chín người dưới trướng Huyền La","tag":"dong-minh","quanHe":"Thành viên mạnh nhất","ghiChu":"Lão thuộc nhóm chín cường giả được Huyền La giao cho Vương Lâm."},{"ten":"Huyền La","tag":"cap-tren","quanHe":"Chủ thượng","ghiChu":"Lão nằm trong hàng ngũ dưới trướng Huyền La."},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Thiếu Thiên Tôn được bái kiến","ghiChu":"Lão cùng nhóm chín người bái kiến Vương Lâm sau khi bị khí thế chấn động."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1907"]},{"id":"dai-han-vai-tram-truong-trong-tu-khi","name":"Đại hán vài trăm trượng trong tử khí","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"},{"ten":"Hoàng quyền Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ @c1907","trangThai":"song","blurb":"Đại hán khổng lồ xuất hiện từ tử khí trên bầu trời trước Đạo Cổ Điện. Hắn mở đầu đoàn cường giả Cổ Tộc giáng lâm cùng Đạo Cổ Hoàng.","vaiTro":"Cường giả Cổ Tộc mở đường trong tử khí","tinhCach":[{"text":"Xuất hiện uy thế trong đoàn nghênh Cổ Hoàng.","chuong":"@c1907"},{"text":"Chưa có lời nói riêng trong chương này.","chuong":"@c1907"}],"tabs":{"diem":[{"text":"Từ tử khí vươn cánh tay khổng lồ rồi bước ra.","chuong":"@c1907"},{"text":"Là người xuất hiện đầu tiên trong đoàn gần trăm cường giả Cổ Tộc.","chuong":"@c1907"}],"kinhLich":[{"chuong":"@c1907","importance":"normal","mucCt":"vua","tieuDe":"Bước ra từ tử khí","text":"Khi tử khí phủ bầu trời trước Đạo Cổ Điện, đại hán vài trăm trượng vươn cánh tay khổng lồ rồi bước ra. Sự xuất hiện của hắn mở đầu cho đoàn gần trăm cường giả Cổ Tộc giáng lâm cùng Đạo Cổ Hoàng.","anchor":"Một đại hán vài trăm trượng bước ra khỏi nơi đó"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"Đi theo khi giáng lâm","ghiChu":"Đại hán xuất hiện trong đoàn cường giả đi cùng Đạo Cổ Hoàng."},{"ten":"Gần trăm cường giả Cổ Thần, Cổ Yêu, Cổ Ma đi theo Cổ Hoàng","tag":"dong-minh","quanHe":"Cùng đoàn giáng lâm","ghiChu":"Đại hán là người mở đầu đoàn cường giả xuất hiện từ tử khí."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1907"]},{"id":"gan-tram-cuong-gia-co-than-co-yeu-co-ma-di-theo-co-hoang","name":"Gần trăm cường giả Cổ Thần, Cổ Yêu, Cổ Ma đi theo Cổ Hoàng","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"},{"ten":"Hoàng quyền Đạo Cổ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"phần lớn so với Kim Tôn, một số đạt Thiên Tôn @c1907","trangThai":"song","blurb":"Đoàn gần trăm cường giả Cổ Tộc gồm Cổ Thần, Cổ Yêu và Cổ Ma đi theo Đạo Cổ Hoàng. Họ xuất hiện từ tử khí, đứng chỉnh tề trên trời và quỳ nghênh Cổ Hoàng.","vaiTro":"Đoàn cường giả hộ giá Cổ Hoàng","tinhCach":[{"text":"Cung kính và cuồng nhiệt khi nghênh đón Cổ Hoàng.","chuong":"@c1907"},{"text":"Xuất hiện có trật tự trong uy thế hoàng quyền Đạo Cổ.","chuong":"@c1907"}],"tabs":{"diem":[{"text":"Gồm cả Cổ Thần, Cổ Yêu và Cổ Ma.","chuong":"@c1907"},{"text":"Phần lớn có chiến lực so với Kim Tôn, một số không nhiều đạt Thiên Tôn.","chuong":"@c1907"},{"text":"Đứng chỉnh tề trên trời và quỳ nghênh Cổ Hoàng.","chuong":"@c1907"}],"kinhLich":[{"mucCt":"vua","text":"Đoàn gần trăm cường giả Cổ Thần, Cổ Yêu và Cổ Ma lần lượt xuất hiện từ tử khí trên bầu trời trước Đạo Cổ Điện. Họ đứng chỉnh tề trên không, quỳ nghênh Cổ Hoàng và thể hiện uy thế của hoàng quyền Đạo Cổ.","anchor":"trong đó có cả Cổ Thần, Cổ Yêu, Cổ Ma","bridge":true,"khoang":"@c1907"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"Cường giả hộ giá","ghiChu":"Đoàn cường giả xuất hiện cùng Đạo Cổ Hoàng và quỳ nghênh hắn."},{"ten":"Đại hán vài trăm trượng trong tử khí","tag":"dong-minh","quanHe":"Cùng đoàn giáng lâm","ghiChu":"Đại hán vài trăm trượng mở đầu sự xuất hiện của đoàn cường giả."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1907"]},{"id":"hai-lao-gia-sau-lung-dao-co-hoang","name":"Hai lão già sau lưng Đạo Cổ Hoàng","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng quyền Đạo Cổ","trangThai":"gan-bo"},{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khí tức không kém Dược Thiên Tôn @c1907","trangThai":"song","blurb":"Hai lão già khom người đi sau Đạo Cổ Hoàng khi hắn bước ra khỏi tử khí. Vương Lâm nhận thấy khí tức của họ không kém Dược Thiên Tôn của Tiên Tộc.","vaiTro":"Cường giả hộ giá Đạo Cổ Hoàng","tinhCach":[{"text":"Cung kính đi sau Đạo Cổ Hoàng.","chuong":"@c1907"},{"text":"Chưa bộc lộ lời nói riêng trong chương này.","chuong":"@c1907"}],"tabs":{"diem":[{"text":"Theo sau Đạo Cổ Hoàng khi hắn giáng lâm trước Đạo Cổ Điện.","chuong":"@c1907"},{"text":"Có khí tức không kém Dược Thiên Tôn.","chuong":"@c1907"}],"kinhLich":[{"chuong":"@c1907","importance":"normal","mucCt":"vua","tieuDe":"Theo Cổ Hoàng hiện thân","text":"Hai lão già khom người đi theo Diệp Đạo khi Đạo Cổ Hoàng bước ra khỏi tử khí. Vương Lâm nhận thấy khí tức của họ không kém Dược Thiên Tôn của Tiên Tộc.","anchor":"Hai người này không ngờ lại có khí tức không kém Dược Thiên Tôn"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"Cường giả hộ giá","ghiChu":"Hai lão già đi sau Đạo Cổ Hoàng khi hắn giáng lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1907"]},{"id":"thuong-thi","name":"Thường Thị","cn":"","aliases":["lão già tùy tùng Đạo Cổ hoàng tôn","lão già bên cạnh Đạo Cổ Hoàng quát Vương Lâm"],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng quyền Đạo Cổ","trangThai":"gan-bo"},{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Tu vi có thể so với Dược Thiên Tôn của Tiên Tộc (@c1908)","trangThai":"song","blurb":"Lão già bên cạnh Đạo Cổ Hoàng, người trực tiếp quát Vương Lâm trước Đạo Cổ Điện. Lão viện tộc quy rằng trừ Đại Thiên Tôn, tộc nhân Đạo Cổ gặp Đạo Cổ hoàng tôn đều phải quỳ.","vaiTro":"Tùy tùng hoàng tôn gây xung đột lễ nghi","tinhCach":[{"text":"Cứng rắn bảo vệ lễ nghi hoàng quyền Đạo Cổ.","chuong":"@c1907"},{"text":"Trực tiếp, gay gắt khi đối diện Vương Lâm.","chuong":"@c1907"}],"tabs":{"diem":[{"text":"Đứng bên cạnh Đạo Cổ Hoàng trong cảnh trước Đạo Cổ Điện.","chuong":"@c1907"},{"text":"Viện tộc quy ép Vương Lâm quỳ trước Đạo Cổ hoàng tôn.","chuong":"@c1907"},{"text":"Có tu vi sánh với Dược Thiên Tôn của Tiên Tộc.","chuong":"@c1908"},{"text":"Là người trực tiếp bắt Vương Lâm quỳ trước Đạo Cổ hoàng tôn.","chuong":"@c1908"},{"text":"Bị ánh mắt và huyết mạch lực của Vương Lâm làm chấn động.","chuong":"@c1908"}],"kinhLich":[{"chuong":"@c1907","importance":"normal","mucCt":"vua","tieuDe":"Ép Vương Lâm quỳ lạy","text":"Sau khi Huyền La công khai thân phận mới của Vương Lâm, Thường Thị lên tiếng quát hắn trước mặt Đạo Cổ Hoàng. Lão viện tộc quy rằng phàm là tộc nhân Đạo Cổ, trừ Đại Thiên Tôn ra, khi nhìn thấy Đạo Cổ hoàng tôn đều phải quỳ lạy.","anchor":"Dựa theo tộc quy, phàm là tộc nhân, trừ Đại Thiên Tôn ra"},{"chuong":"@c1908","importance":"normal","mucCt":"vua","tieuDe":"Ép quỳ thất thế","text":"Thường Thị đứng ra bắt Vương Lâm quỳ trước Đạo Cổ hoàng tôn theo quy củ Đạo Cổ. Khi Vương Lâm nhìn lại, ông sắc mặt trắng bệch, Cổ Tộc lực chấn động và huyết mạch run rẩy, rồi bị hoàng tôn quở lui và nhận lệnh truyền cáo toàn tộc.","anchor":"Lão già kia có tu vi có thể so với Dược Thiên Tôn của Tiên Tộc"}],"tuViMoc":[],"nhanMach":[{"ten":"Đạo Cổ Hoàng","tag":"cap-tren","quanHe":"Chủ thượng được bảo vệ lễ nghi","ghiChu":"Thường Thị đứng cạnh Đạo Cổ Hoàng và lên tiếng vì lễ nghi hoàng tôn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Ép quỳ theo tộc quy","ghiChu":"Thường Thị trực tiếp quát Vương Lâm phải quỳ trước Đạo Cổ Hoàng."},{"ten":"Huyền La","tag":"doi-thu","quanHe":"Bị Huyền La ngăn việc ép Vương Lâm quỳ.","ghiChu":"Xung đột vì thân phận đệ tử của Huyền La."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1907","@c1908"]},{"id":"dai-thien-ton-doi-thu-nhat-cua-dao-co-nhat-mach","name":"Đại Thiên Tôn đời thứ nhất của Đạo Cổ nhất mạch","gioiTinh":"khong-ro","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn (@c1908)","trangThai":"khong-ro","blurb":"Đại Thiên Tôn đời thứ nhất của Đạo Cổ nhất mạch là người phát hiện đầm lầy cổ chiến trường ở Bình Thiên Quận. Ông bố trí cấm chế phong ấn để bảo tồn nơi này nguyên vẹn và truyền lại cho hậu nhân.","vaiTro":"Đại Thiên Tôn đời trước","tinhCach":[{"text":"Biết giữ lại cơ duyên tu hành cho hậu thế.","chuong":"@c1908"}],"tabs":{"diem":[{"text":"Phát hiện đầm lầy phía bắc Bình Thiên Quận.","chuong":"@c1908"},{"text":"Bố trí cấm chế phong ấn để bảo tồn đầm lầy nguyên vẹn.","chuong":"@c1908"}],"kinhLich":[{"chuong":"@c1908","importance":"normal","mucCt":"gon","tieuDe":"Để lại đầm lầy","text":"Đại Thiên Tôn đời thứ nhất của Đạo Cổ nhất mạch từng phát hiện đầm lầy cổ chiến trường ở Bình Thiên Quận và bố trí cấm chế phong ấn, để nơi này về sau được Huyền La dùng làm cơ duyên tu hành cho Vương Lâm.","anchor":"Nơi này là do Đại Thiên Tôn đời thứ nhất của Đạo Cổ nhất mạch phát hiện ra"}],"tuViMoc":[],"nhanMach":[{"ten":"Huyền La","tag":"su-mon","quanHe":"Đời trước để lại đầm lầy cho Huyền La tiếp nhận.","ghiChu":"Huyền La giữ nơi này để giúp Vương Lâm tu hành."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1908"]},{"id":"ke-do","name":"Kế Đô hoàng tử","aliases":["Kế Đô"],"nguon":["@c1902"],"gioiTinh":"nam","theLuc":[{"ten":"Cổ tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Kế Đô hoàng tử là hoàng tử cổ tộc xuất hiện trên đầu cổ Yêu Đà Lạc. Hắn được Hắc Thạch thành đồng loạt quỳ lạy và lập tức xử tội Vương Lâm vì không quỳ.","vaiTro":"Hoàng tử cổ tộc đi cùng Đà Lạc, tiếp nhóm bảy người trên cổ Ma và ra lệnh giết Vương Lâm.","tinhCach":[{"text":"Coi trọng lễ nghi và uy quyền hoàng tộc, xem việc không quỳ là bất kính.","chuong":"@c1902"},{"text":"Ra quyết định tàn nhẫn, trực tiếp sai Đà Lạc giết Vương Lâm thay vì để Lương Vân xử lý.","chuong":"@c1902"}],"tabs":{"diem":[{"text":"Đứng trên đỉnh đầu cổ Yêu Đà Lạc khi giáng lâm ngoài Hắc Thạch thành.","chuong":"@c1902"},{"text":"Được mọi người trong ngoài thành quỳ lạy, riêng Vương Lâm không quỳ.","chuong":"@c1902"},{"text":"Tiếp bảy người trên cổ Ma rồi ra lệnh cho Đà Lạc giết Vương Lâm.","chuong":"@c1902"}],"kinhLich":[{"chuong":"@c1902","importance":"normal","mucCt":"ky","tieuDe":"Lệnh giết Vương Lâm","text":"Kế Đô hoàng tử xuất hiện trên đầu cổ Yêu Đà Lạc, phía sau có một nữ tử áo lam, khiến mọi người trong ngoài Hắc Thạch thành quỳ lạy. Hắn trước hết mỉm cười tiếp bảy người trên cổ Ma, sau đó chú ý tới Vương Lâm là người duy nhất không quỳ. Sau khi hỏi Lương Vân và biết Vương Lâm mới xuất hiện, hắn không cho Lương Vân tự xử mà trực tiếp ra lệnh cho Đà Lạc giết Vương Lâm.","anchor":"Thanh niên mặc hoàng bào hướng về phía bảy người trên cổ Ma mỉm cười"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"người bị xử tội bất kính","ghiChu":"Kế Đô hoàng tử ra lệnh cho Đà Lạc giết Vương Lâm vì hắn không quỳ."},{"ten":"Đà Lạc","tag":"dong-minh","quanHe":"cổ Yêu dưới quyền","ghiChu":"Kế Đô hoàng tử đứng trên đầu Đà Lạc và sai hắn ra tay."},{"ten":"Lương Vân","tag":"cap-tren","quanHe":"hoàng tử được nghênh tiếp","ghiChu":"Kế Đô hoàng tử hỏi Lương Vân về thân phận Vương Lâm."},{"ten":"Nữ tử áo lam phía sau Kế Đô hoàng tử","tag":"khac","quanHe":"người đi cùng","ghiChu":"Nữ tử áo lam đứng phía sau Kế Đô hoàng tử trên đầu cổ Yêu."},{"ten":"Bảy người trên cổ Ma","tag":"khac","quanHe":"khách được tiếp","ghiChu":"Kế Đô hoàng tử hướng về bảy người trên cổ Ma mỉm cười và nói chuyện."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}}}]};
